# tags.type: Martı yolculuğu vs Muhabbet (aktif yolculuk/dispatch yalnız TAG_TYPE_NORMAL)
TAG_TYPE_NORMAL = "normal"
TAG_TYPE_MUHABBET = "muhabbet"


def _validate_tags_insert_payload(row: dict, *, source: str) -> None:
    """tags INSERT: type zorunlu; DB default kullanılmamalı."""
    t = row.get("type")
    if t != TAG_TYPE_NORMAL and t != TAG_TYPE_MUHABBET:
        logger.error(
            "[tag-insert] error=missing_or_invalid_type invalid=%r source=%s row_keys=%s",
            t,
            source,
            sorted(row.keys()),
        )
        raise ValueError(
            "tags insert requires explicit type (%r or %r); source=%s"
            % (TAG_TYPE_NORMAL, TAG_TYPE_MUHABBET, source)
        )


def tags_insert_with_type_required(supabase_client: Client, row: dict, *, source: str):
    """tags satırı insert — type yoksa ValueError (Postgres'e gitmeden)."""
    _validate_tags_insert_payload(row, source=source)
    r = supabase_client.table("tags").insert(row).execute()
    if r.data:
        log_src = "muhabbet" if row.get("type") == TAG_TYPE_MUHABBET else "ride"
        logger.info("[tag-insert] type=%s source=%s", row.get("type"), log_src)
    return r


def _check_netgsm_env_on_startup() -> None:
    """
    NetGSM SMS gönderimi için gerekli env değişkenlerini kontrol eder.
    Değerleri loglamaz (şifre sızmasın); sadece eksik anahtarları uyarır.
    """
    # Not: Geriye dönük uyumluluk için USERCODE yerine NETGSM_USERNAME,
    # MSGHEADER yerine NETGSM_MNGHEADER da destekleniyor.
    usercode = (os.getenv("NETGSM_USERCODE") or os.getenv("NETGSM_USERNAME") or "").strip()
    password = (os.getenv("NETGSM_PASSWORD") or "").strip()
    msgheader = (os.getenv("NETGSM_MSGHEADER") or os.getenv("NETGSM_MNGHEADER") or "").strip()
    filter_raw = os.getenv("NETGSM_FILTER")

    missing: list[str] = []
    if not usercode:
        missing.append("NETGSM_USERCODE")
    if not password:
        missing.append("NETGSM_PASSWORD")
    if not msgheader:
        missing.append("NETGSM_MSGHEADER")
    if filter_raw is None:
        missing.append("NETGSM_FILTER")

    if missing:
        # NETGSM_FILTER koddaki varsayılan ile çalışabilir (default "0"); yine de görünür olsun.
        logger.warning(
            "⚠️ NetGSM env eksik/boş: %s. SMS gönderimi 'credentials missing' hatası verebilir. "
            "Sunucuda .env / environment variables kontrol edin.",
            ", ".join(missing),
        )

_check_netgsm_env_on_startup()


