# Aktif kullanıcılar: {user_id: socket_id}
connected_users = {}
# Aktif kullanıcılar (çoklu soket): {user_id: set(socket_id)}
connected_user_sids: dict[str, set[str]] = {}
# sid -> kayıtlı user_id anahtarları (disconnect temizliği için)
socket_sid_to_keys: dict[str, set[str]] = {}
# connect sid -> düşürülmüş user_id (muhabbet socket yöneticileri için)
socket_id_to_user: dict[str, str] = {}


def muhabbet_room(conversation_id: str) -> str:
    """Leylek Muhabbeti socket odası — tek biçim: `muhabbet_` + conversation_id (küçük harf UUID)."""
    c = str(conversation_id or "").strip().lower()
    return f"muhabbet_{c}" if c else "muhabbet_"


def muhabbet_trip_room(session_id: str) -> str:
    """Leylek Teklif Sende trip-like oturum odası; normal ride odalarıyla karışmaz."""
    sid = str(session_id or "").strip().lower()
    return f"muhabbet_trip_{sid}" if sid else "muhabbet_trip_"


# Leylek Muhabbeti FCM: (receiver_user_id, conversation_id) -> time.monotonic() son push
_muhabbet_last_push_mono: dict[tuple[str, str], float] = {}


def _muhabbet_message_push_rate_allow(receiver: str, conversation_id: str) -> bool:
    """Aynı sohbet için 60 sn içinde tekrar push yok (socket message her zaman room'da)."""
    ru = str(receiver or "").strip().lower()
    cc = str(conversation_id or "").strip().lower()
    if not ru or not cc:
        return False
    now = time.monotonic()
    key = (ru, cc)
    prev = _muhabbet_last_push_mono.get(key)
    if prev is not None and (now - prev) < 60.0:
        logger.info(
            "[muhabbet_send] push skipped rate_limit receiver=%s conversation_id=%s",
            ru[:13],
            cc,
        )
        return False
    _muhabbet_last_push_mono[key] = now
    return True


def _muhabbet_user_socket_online(uid: str) -> bool:
    """Socket `register` sonrası connected_users haritasında aktif sid var mı (push dedupe)."""
    u = (uid or "").strip().lower()
    if not u:
        return False
    return bool(connected_users.get(u) or connected_users.get(uid))


def _muhabbet_socket_uid_from_sid(sid: str) -> Optional[str]:
    return (socket_id_to_user.get(sid) or None) if sid else None


def _muhabbet_parse_client_message_id(raw: Any) -> Tuple[Optional[str], Optional[str]]:
    """İstemci message_id (UUID). Dönüş: (id_küçük_harf, hata_metni). hata_metni doluysa isteği reddet."""
    if raw is None:
        return (None, None)
    s = str(raw).strip()
    if not s:
        return (None, None)
    try:
        return (str(uuid.UUID(s)).lower(), None)
    except (ValueError, AttributeError, TypeError):
        return (None, "Geçersiz message_id (UUID gerekli)")


def _muhabbet_room_peer_count(room: str) -> int:
    """Oda üyesi sayısı (gönderen dahil). Bilinmiyorsa -1."""
    try:
        return sum(1 for _ in sio.manager.get_participants("/", room))
    except Exception:
        return -1


@sio.event
async def connect(sid, environ):
    print(f"SOCKET CONNECTED: {sid}")
    _pi = (environ or {}).get("PATH_INFO") or ""
    logger.info(
        "SOCKET_CONNECT sid=%s path_info=%s (nginx /socket.io/ → bu süreç olmalı; /api ile karıştırma)",
        sid,
        _pi[:160],
    )
    logger.info(f"🔌 Socket bağlandı: {sid}")
    logger.info(f"🔌 Toplam bağlı: {len(connected_users) + 1}")

@sio.event
async def disconnect(sid):
    print("❌ SOCKET CLIENT DISCONNECTED:", sid)
    socket_id_to_user.pop(sid, None)
    mapped_keys = socket_sid_to_keys.pop(sid, set())
    for key in list(mapped_keys):
        try:
            sset = connected_user_sids.get(key)
            if sset and sid in sset:
                sset.discard(sid)
                if not sset:
                    connected_user_sids.pop(key, None)
            cur = connected_users.get(key)
            if cur == sid:
                nxt = None
                sset2 = connected_user_sids.get(key)
                if sset2:
                    nxt = next(iter(sset2), None)
                if nxt:
                    connected_users[key] = nxt
                else:
                    connected_users.pop(key, None)
        except Exception:
            pass
    # Aynı sid'e kayıtlı tüm key'leri kaldır (orijinal + normalized user_id)
    to_remove = [uid for uid, s in connected_users.items() if s == sid]
    for uid in to_remove:
        del connected_users[uid]
    if to_remove:
        logger.info(f"🔌 Socket ayrıldı: {sid} (user: {to_remove})")
        for uid in to_remove:
            if not isinstance(uid, str):
                continue
            _uid = uid.strip()
            if not _uid:
                continue
            _sids = _all_sids_for_registered_user(_uid)
            logger.info("[SOCKET MAP] user_id=%s sids=%s", _uid[:96], _sids)
    else:
        logger.info(f"🔌 Socket ayrıldı: {sid}")

def _normalize_user_room(user_id: str) -> str:
    """UUID/user_id için tutarlı room adı (büyük/küçük harf uyumsuzluğunu önler)."""
    if not user_id:
        return ""
    return f"user_{str(user_id).strip().lower()}"


@sio.event
async def register(sid, data):
    """Kullanıcı kaydı — JWT (delete-account ile aynı access token) zorunlu; user_id yalnızca token sub."""
    if not isinstance(data, dict):
        data = {}
    client_declares_uid = str(data.get("user_id") or "").strip()
    logger.info(
        "SOCKET_REGISTER_ATTEMPT sid=%s client_declares_user_id=%s role=%s",
        sid,
        client_declares_uid or None,
        (data.get("role") if isinstance(data, dict) else None),
    )
    token = (data.get("token") or "").strip()
    if not token:
        logger.warning("Socket register reddedildi sid=%s: token yok", sid)
        try:
            await sio.emit(
                "registered",
                {"success": False, "error": "auth_required"},
                room=sid,
            )
        except Exception:
            pass
        await sio.disconnect(sid)
        return

    authed_uid = verify_access_token(token)
    if not authed_uid:
        logger.warning("Socket register reddedildi sid=%s: geçersiz token", sid)
        try:
            await sio.emit(
                "registered",
                {"success": False, "error": "invalid_token"},
                room=sid,
            )
        except Exception:
            pass
        await sio.disconnect(sid)
        return

    role = data.get("role")
    raw = str(authed_uid).strip()
    try:
        resolved_uid = await resolve_user_id(raw)
    except Exception:
        resolved_uid = None
    if not resolved_uid:
        logger.warning(
            "[SOCKET WARNING] fallback to raw sub sid=%s token_sub=%s client_user_id=%s",
            sid,
            raw[:96],
            client_declares_uid[:96],
        )
        resolved_uid = raw
    resolved_uid = str(resolved_uid).strip()
    resolved_lower = resolved_uid.lower()
    raw_lower = raw.lower()

    if client_declares_uid and client_declares_uid.lower() != resolved_lower:
        logger.warning(
            "SOCKET_REGISTER_USER_ID_MISMATCH sid=%s client_user_id=%s token_resolved=%s",
            sid,
            client_declares_uid,
            resolved_uid,
        )

    # Dual mapping: hem users.id hem auth_id(sub) anahtarlarında sid bulunabilir.
    connected_users[resolved_uid] = sid
    connected_users[resolved_lower] = sid
    connected_user_sids.setdefault(resolved_uid, set()).add(sid)
    connected_user_sids.setdefault(resolved_lower, set()).add(sid)
    socket_sid_to_keys.setdefault(sid, set()).update({resolved_uid, resolved_lower})
    if raw_lower and raw_lower != resolved_lower:
        connected_users[raw_lower] = sid
        connected_user_sids.setdefault(raw_lower, set()).add(sid)
        socket_sid_to_keys.setdefault(sid, set()).add(raw_lower)
    socket_id_to_user[sid] = resolved_lower
    logger.info("[SOCKET MAP] user_id=%s sids=%s", resolved_lower[:96], _all_sids_for_registered_user(resolved_lower))
    logger.info("[SOCKET MAP FULL] connected_users keys=%s", list(connected_users.keys()))

    room_names = {
        _normalize_user_room(resolved_uid),
        _normalize_user_room(resolved_lower),
    }
    if raw_lower and raw_lower != resolved_lower:
        room_names.add(_normalize_user_room(raw_lower))
    if client_declares_uid:
        room_names.add(_normalize_user_room(client_declares_uid))
    room_names = {r for r in room_names if r}
    room_name = _normalize_user_room(resolved_uid)
    for rn in sorted(room_names):
        await sio.enter_room(sid, rn)
        logger.info("[SOCKET USER ROOM] joined sid=%s room=%s", sid, rn)
    print(f"JOIN ROOM: {resolved_uid}")
    logger.info("JOIN ROOM: %s", resolved_uid)

    logger.info("SOCKET_USER_ID sid=%s user_id=%s", sid, resolved_uid)
    try:
        _rc = sum(1 for _ in sio.manager.get_participants("/", room_name))
    except Exception:
        _rc = -1
    logger.info("SOCKET_JOIN_ROOM sid=%s room=%s room_member_count=%s", sid, room_name, _rc)

    _ru_short = (resolved_uid[:12] + "…") if len(resolved_uid) > 12 else resolved_uid
    logger.info(
        "📱 Kullanıcı kayıtlı (JWT): sid=%s room=%s user=%s",
        sid,
        room_name,
        _ru_short,
    )
    await sio.emit(
        "registered",
        {
            "success": True,
            "room": room_name,
            "user_id": resolved_uid,
            "resolved_user_id": resolved_uid,
        },
        room=sid,
    )
    logger.info("[socket_register] %s", json.dumps({"user_id": resolved_lower, "sid": sid}, ensure_ascii=False))

    if role == "driver":
        try:
            asyncio.create_task(emit_existing_waiting_offers_to_driver(resolved_uid))
        except Exception:
            pass


@sio.on("join_user_room")
async def sio_join_user_room(sid, data):
    """Client reconnect sonrası kişisel user_<id> odasını yeniden garanti eder."""
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    if not uid:
        logger.warning("[SOCKET USER ROOM] join_user_room not_registered sid=%s", sid)
        await sio.emit("user_room_joined", {"success": False, "error": "not_registered"}, room=sid)
        return
    raw_user = str(data.get("user_id") or data.get("userId") or uid).strip()
    keys = {uid, uid.lower()}
    try:
        resolved = await resolve_user_id(raw_user or uid)
        if resolved:
            keys.add(str(resolved).strip())
            keys.add(str(resolved).strip().lower())
    except Exception:
        pass
    if raw_user:
        keys.add(raw_user)
        keys.add(raw_user.lower())
    rooms = {_normalize_user_room(k) for k in keys if k}
    for room in sorted(r for r in rooms if r):
        await sio.enter_room(sid, room)
        logger.info("[SOCKET USER ROOM] joined sid=%s room=%s via=join_user_room", sid, room)
    await sio.emit("user_room_joined", {"success": True, "user_id": uid, "rooms": sorted(rooms)}, room=sid)

@sio.event
async def call_user(sid, data):
    """Arama başlat - karşı tarafa bildir"""
    caller_id = data.get('caller_id')
    receiver_id = data.get('receiver_id')
    call_id = data.get('call_id')
    channel_name = data.get('channel_name')
    agora_token = data.get('agora_token')
    call_type = data.get('call_type', 'audio')
    caller_name = data.get('caller_name', 'Bilinmeyen')
    
    logger.info(f"📞 Arama isteği: {caller_id} -> {receiver_id} (call_id: {call_id})")
    logger.info(f"📱 Bağlı kullanıcılar: {list(connected_users.keys())}")
    
    receiver_sid = _connected_sid_for_user(str(receiver_id)) if receiver_id else None
    
    _ic_payload = {
        'call_id': call_id,
        'caller_id': caller_id,
        'caller_name': caller_name,
        'channel_name': channel_name,
        'agora_token': agora_token,
        'call_type': call_type,
        'target_user_id': str(receiver_id).strip(),
    }
    try:
        await emit_socket_event_to_user(str(receiver_id).strip(), 'incoming_call', _ic_payload)
    except Exception as _ice:
        logger.warning("incoming_call emit_socket_event_to_user failed: %s", _ice)

    if receiver_sid:
        logger.info(f"📲 Gelen arama bildirimi gönderildi: {receiver_id} (sid: {receiver_sid})")
        await sio.emit('call_ringing', {'success': True, 'receiver_online': True}, room=sid)
    else:
        logger.warning(f"⚠️ Alıcı çevrimdışı veya kayıtlı değil: {receiver_id}")
        logger.warning(f"⚠️ Kayıtlı kullanıcılar: {connected_users}")
        try:
            _ic_body = f"{_push_first_name(caller_name, 14) or 'Karşı taraf'} sizi arıyor • Yanıtlamak için dokun"
            if len(_ic_body) > 72:
                _ic_body = _ic_body[:69] + "…"
            asyncio.create_task(send_push_notification(
                receiver_id,
                "Gelen arama",
                _ic_body,
                {
                    "type": "incoming_call",
                    "call_id": call_id,
                    "caller_id": caller_id,
                    "caller_name": caller_name,
                    "channel_name": channel_name,
                    "agora_token": agora_token,
                    "call_type": call_type,
                    "target_user_id": str(receiver_id).strip(),
                }
            ))
        except Exception as push_err:
            logger.warning(f"⚠️ Offline arama push gönderilemedi: {push_err}")
        await sio.emit('call_ringing', {'success': False, 'receiver_online': False, 'reason': 'user_offline'}, room=sid)

@sio.event
async def accept_call(sid, data):
    """Aramayı kabul et"""
    call_id = data.get('call_id')
    caller_id = data.get('caller_id')
    receiver_id = data.get('receiver_id')
    
    logger.info(f"✅ Arama kabul edildi: {call_id}")
    
    # Arayana bildir
    caller_sid = connected_users.get(caller_id)
    if caller_sid:
        await sio.emit('call_accepted', {
            'call_id': call_id,
            'accepted_by': receiver_id
        }, room=caller_sid)
    try:
        _started = {
            "call_id": call_id,
            "caller_id": str(caller_id).strip() if caller_id else "",
            "receiver_id": str(receiver_id).strip() if receiver_id else "",
        }
        if _started["caller_id"]:
            await emit_socket_event_to_user(_started["caller_id"], "call_started", _started)
        if _started["receiver_id"]:
            await emit_socket_event_to_user(_started["receiver_id"], "call_started", _started)
    except Exception as _cse:
        logger.warning("accept_call call_started emit failed: %s", _cse)

@sio.event
async def reject_call(sid, data):
    """Aramayı reddet — hem arayana hem aranan kullanıcıya call_rejected (socket senkron)."""
    call_id = data.get('call_id')
    caller_id = data.get('caller_id')
    receiver_id = data.get('receiver_id')

    logger.info(f"❌ Arama reddedildi: {call_id}")
    payload = {'call_id': call_id, 'rejected_by': receiver_id}
    if caller_id:
        try:
            await emit_socket_event_to_user(str(caller_id).strip(), 'call_rejected', payload)
        except Exception as emit_err:
            logger.warning(f"reject_call emit_socket_event_to_user failed: {emit_err}")
    else:
        logger.warning("reject_call: caller_id eksik, call_rejected gönderilemedi")
    if receiver_id:
        try:
            await emit_socket_event_to_user(str(receiver_id).strip(), 'call_rejected', payload)
        except Exception as emit_err:
            logger.warning(f"reject_call callee emit failed: {emit_err}")

@sio.event
async def end_call(sid, data):
    """Aramayı sonlandır"""
    call_id = data.get('call_id')
    caller_id = data.get('caller_id')
    receiver_id = data.get('receiver_id')
    ended_by = data.get('ended_by')
    
    logger.info(f"📴 Arama sonlandırıldı: {call_id} (by: {ended_by})")
    
    # Her iki tarafa da bildir
    for user_id in [caller_id, receiver_id]:
        if user_id and user_id != ended_by:
            user_sid = connected_users.get(user_id)
            if user_sid:
                await sio.emit('call_ended', {
                    'call_id': call_id,
                    'ended_by': ended_by
                }, room=user_sid)

# ==================== PUAN SİSTEMİ ====================
# 100 puan = 5 yıldız; 75 puan = 4 yıldız
# Yeni kayıtlar 75 puan / 4.0 yıldız ile başlar
# Tek taraflı bitirme = -3 puan

def points_to_rating(points: int) -> float:
    """Puanı yıldıza çevir (100 puan = 5 yıldız)"""
    if points >= 100:
        return 5.0
    elif points <= 0:
        return 1.0
    else:
        # 0-100 arası = 1-5 yıldız
        return 1.0 + (points / 100) * 4.0

async def deduct_points(user_id: str, points: int, reason: str):
    """Kullanıcıdan puan düş"""
    try:
        # Mevcut puanı al
        result = supabase.table("users").select("points, rating").eq("id", user_id).execute()
        if result.data:
            current_points = result.data[0].get("points", 75)
            new_points = max(0, current_points - points)
            new_rating = points_to_rating(new_points)
            
            # Güncelle
            supabase.table("users").update({
                "points": new_points,
                "rating": new_rating,
                "updated_at": datetime.utcnow().isoformat()
            }).eq("id", user_id).execute()
            
            logger.info(f"📉 Puan düşürüldü: {user_id} -{points} puan ({reason}). Yeni: {new_points} puan, {new_rating:.1f} yıldız")
            return new_points, new_rating
    except Exception as e:
        logger.error(f"Puan düşürme hatası: {e}")
    return None, None

# ==================== TRIP END SOCKET EVENTS ====================

@sio.event
async def force_end_trip(sid, data):
    """Yolculuğu ANINDA bitir — HTTP ile aynı (karşı taraf onayı sonradan)."""
    data = data or {}
    tag_id = data.get("tag_id")
    ender_id = data.get("ender_id")
    ender_type = data.get("ender_type")
    logger.info(f"🔚 FORCE END TRIP (socket): {tag_id} by {ender_id} ({ender_type})")
    try:
        result = await apply_force_end_trip_and_notify(str(tag_id).strip(), str(ender_id).strip(), ender_type)
        if result.get("success"):
            await sio.emit(
                "trip_end_confirmed",
                {
                    "success": True,
                    "tag_id": tag_id,
                    "points_deducted": 0,
                    "new_points": result.get("new_points"),
                    "new_rating": result.get("new_rating"),
                    "idempotent": result.get("idempotent"),
                },
                room=sid,
            )
        else:
            await sio.emit(
                "trip_end_confirmed",
                {"success": False, "error": result.get("error", "Bilinmeyen hata")},
                room=sid,
            )
    except Exception as e:
        logger.error(f"Force end trip error: {e}")
        await sio.emit("trip_end_confirmed", {"success": False, "error": str(e)}, room=sid)

@sio.event
async def request_trip_end_socket(sid, data):
    """Socket üzerinden trip sonlandırma isteği - ANINDA bildirim"""
    tag_id = data.get('tag_id')
    requester_id = data.get('requester_id')
    requester_type = data.get('requester_type')  # 'passenger' veya 'driver'
    target_user_id = data.get('target_user_id')  # Karşı tarafın ID'si
    
    logger.info(f"🔚 Socket trip end request: {tag_id} by {requester_id} ({requester_type})")
    
    # Supabase'e kaydet
    try:
        supabase.table("tags").update({
            "end_request": {
                "requester_id": requester_id,
                "user_type": requester_type,
                "requested_at": datetime.utcnow().isoformat(),
                "status": "pending"
            }
        }).eq("id", tag_id).execute()
    except Exception as e:
        logger.error(f"Trip end request save error: {e}")
    
    # Karşı tarafa ANINDA bildirim gönder
    target_sid = connected_users.get(target_user_id)
    if target_sid:
        await sio.emit('trip_end_request', {
            'tag_id': tag_id,
            'requester_id': requester_id,
            'requester_type': requester_type
        }, room=target_sid)
        logger.info(f"📲 Trip end request sent to: {target_user_id}")
        await sio.emit('trip_end_request_sent', {'success': True}, room=sid)
    else:
        logger.warning(f"⚠️ Target user offline: {target_user_id}")
        await sio.emit('trip_end_request_sent', {'success': True, 'target_offline': True}, room=sid)

@sio.event
async def respond_trip_end_socket(sid, data):
    """Socket üzerinden trip sonlandırma isteğine cevap - ANINDA"""
    tag_id = data.get('tag_id')
    responder_id = data.get('responder_id')
    approved = data.get('approved', True)
    requester_id = data.get('requester_id')  # İsteği yapan kişi
    
    logger.info(f"🔚 Socket trip end response: {tag_id} approved={approved}")
    
    try:
        if approved:
            # Trip'i tamamla
            supabase.table("tags").update({
                "status": "completed",
                "completed_at": datetime.utcnow().isoformat(),
                "end_request": None,
                "end_type": "mutual"
            }).eq("id", tag_id).execute()
            
            # Her iki tarafa da bildir
            for user_id in [responder_id, requester_id]:
                user_sid = connected_users.get(user_id)
                if user_sid:
                    await sio.emit('trip_completed', {
                        'tag_id': tag_id,
                        'completed_at': datetime.utcnow().isoformat(),
                        'mutual': True
                    }, room=user_sid)
            
            logger.info(f"✅ Trip completed via socket (mutual): {tag_id}")
        else:
            # İsteği reddet
            result = supabase.table("tags").select("end_request").eq("id", tag_id).execute()
            if result.data and result.data[0].get("end_request"):
                end_request = result.data[0]["end_request"]
                end_request["status"] = "rejected"
                supabase.table("tags").update({"end_request": end_request}).eq("id", tag_id).execute()
            
            # İsteği yapana reddi bildir
            requester_sid = connected_users.get(requester_id)
            if requester_sid:
                await sio.emit('trip_end_rejected', {
                    'tag_id': tag_id,
                    'rejected_by': responder_id
                }, room=requester_sid)
            
            logger.info(f"❌ Trip end rejected: {tag_id}")
    except Exception as e:
        logger.error(f"Trip end response error: {e}")


