# Rolling batch: bellek + dispatch_queue tablosu (sürücü polling / çoklu worker toleransı)
BATCH_SIZE = 5
try:
    _rbt = float(os.getenv("DISPATCH_BATCH_TIMEOUT_SECONDS", "20").strip().replace(",", "."))
    ROLLING_DISPATCH_BATCH_TIMEOUT_SECONDS = max(15.0, min(60.0, _rbt))
except (TypeError, ValueError):
    ROLLING_DISPATCH_BATCH_TIMEOUT_SECONDS = 20.0
DISPATCH_TIMEOUT = int(round(ROLLING_DISPATCH_BATCH_TIMEOUT_SECONDS))
try:
    _dr = float(os.getenv("DISPATCH_RADIUS_KM", "20").strip().replace(",", "."))
    DISPATCH_RADIUS_KM = max(5.0, min(100.0, _dr))
except (TypeError, ValueError):
    DISPATCH_RADIUS_KM = 20.0
SEQUENTIAL_DISPATCH_RADIUS_KM = DISPATCH_RADIUS_KM
BROADCAST_RADIUS_KM = DISPATCH_RADIUS_KM

# tag_id -> asyncio.Task (20s zamanlayıcı)
rolling_dispatch_tasks: dict = {}
# tag_id -> rolling state (in-memory): full_tag, current_batch, batch_seq, excluded_driver_ids, relax_vehicle_on_empty
rolling_dispatch_index: dict = {}

# Sürücüye aynı tag teklif FCM: socket register + set-ride-vehicle-kind + reconnect kısa aralıkta aynı push'u tetikleyebilir.
_offer_push_dedupe_lock = asyncio.Lock()
_offer_push_last_sent_mono: dict[tuple[str, str], float] = {}
OFFER_PUSH_DEDUPE_WINDOW_SEC = 120.0

# dispatch_queue tablosu (sql_migrations/schema_updates.sql) — bilinmeyen kolonla insert tüm kaydı düşürürdü
DISPATCH_QUEUE_DB_KEYS = frozenset(
    {
        "id",
        "tag_id",
        "driver_id",
        "priority",
        "status",
        "created_at",
        "sent_at",
        "responded_at",
    }
)

# ==================== PROMOSYON KODU SİSTEMİ ====================
import random
import string

def generate_promo_code(length: int = 8) -> str:
    """Rastgele promosyon kodu üret"""
    chars = string.ascii_uppercase + string.digits
    return ''.join(random.choice(chars) for _ in range(length))

async def get_dispatch_config() -> dict:
    """Config tablosundan dispatch ayarlarını oku, yoksa default kullan"""
    try:
        result = supabase.table("config").select("*").eq("key", "dispatch_config").execute()
        if result.data:
            import json
            return json.loads(result.data[0].get("value", "{}"))
    except:
        pass
    return DISPATCH_CONFIG

def _dispatch_env_flag(name: str) -> bool:
    return os.getenv(name, "").strip().lower() in ("1", "true", "yes", "on")


async def find_eligible_drivers(
    pickup_lat: float,
    pickup_lng: float,
    exclude_ids: list = None,
    passenger_vehicle_kind: Optional[str] = None,
    radius_km: Optional[float] = None,
    *,
    vehicle_filter: bool = True,
) -> list:
    """
    Uygun sürücüleri bul ve öncelik sırasına göre sırala
    Kriterler: online, aktif paket, mesafe içinde
    Araç talebi (car) / motorcycle katı eşleşmesi; sürücüde vehicle_kind yoksa eff=car.
    vehicle_filter=False: mesafe/online dışında araç tipi eşleşmesi atlanır (yedek tarama).
    Sıralama: mesafe (yakın), rating (yüksek)
    """
    try:
        r_km = float(radius_km) if radius_km is not None else float(SEQUENTIAL_DISPATCH_RADIUS_KM)
        pref = _canonical_vehicle_kind(passenger_vehicle_kind) or "car"

        # Online ve aktif paketi olan sürücüleri getir
        now = datetime.utcnow().isoformat()
        query = supabase.table("users").select(
            "id, name, rating, latitude, longitude, driver_active_until, driver_online, driver_details"
        ).eq("driver_online", True)
        query = _apply_driver_active_until_filter(query, now)

        result = query.execute()

        if not result.data:
            logger.warning(
                "find_eligible_drivers: driver_online=true kayıt yok — sürücü uygulamasında çevrimiçi ve konum açık mı?"
            )
            return []

        eligible_drivers = []
        exclude_set = {str(x).strip().lower() for x in (exclude_ids or []) if x is not None}
        online_count = len(result.data)
        logger.info(
            "find_eligible_drivers debug: online_rows=%s pickup=(%.5f,%.5f) r_km=%s pref=%s vehicle_filter=%s",
            online_count,
            float(pickup_lat),
            float(pickup_lng),
            r_km,
            pref,
            vehicle_filter,
        )
        no_loc = excluded = vehicle_mismatch = too_far = 0

        plat_f, plng_f = float(pickup_lat), float(pickup_lng)
        _match_t0 = time.time()
        origin_points: list[tuple[str, float, float]] = []
        driver_by_id: dict[str, dict] = {}
        for driver in result.data:
            if str(driver["id"]).strip().lower() in exclude_set:
                excluded += 1
                continue

            if driver.get("latitude") is None or driver.get("longitude") is None:
                no_loc += 1
                continue
            if (
                str(driver.get("latitude", "")).strip() == ""
                or str(driver.get("longitude", "")).strip() == ""
            ):
                no_loc += 1
                continue

            if vehicle_filter:
                eff = _driver_vehicle_kind_from_row(driver)
                if eff is None:
                    eff = "car"
                if not _driver_matches_passenger_vehicle_pref(eff, pref):
                    vehicle_mismatch += 1
                    continue

            try:
                d_la = float(driver["latitude"])
                d_lo = float(driver["longitude"])
            except (TypeError, ValueError):
                no_loc += 1
                continue

            if not _match_bbox_prefilter_deg(plat_f, plng_f, d_la, d_lo):
                too_far += 1
                continue

            did = str(driver["id"]).strip().lower()
            origin_points.append((did, d_la, d_lo))
            driver_by_id[did] = driver

        try:
            meta = await get_real_route_meta_batch_origins_to_dest(plat_f, plng_f, origin_points)
        except Exception as e:
            logger.error("[MATCH] find_eligible_drivers batch failed: %s", e, exc_info=True)
            meta = {}
        logger.info("[MATCH] MATCH_TIME find_eligible_drivers_batch_s: %.4f", time.time() - _match_t0)
        eligible_drivers = []
        for did, row in meta.items():
            road_km = float(row.get("distance_km", 0))
            if road_km > r_km:
                continue
            drv = driver_by_id.get(did)
            if not drv:
                continue
            eligible_drivers.append(
                {
                    "driver_id": did,
                    "driver_name": drv.get("name", "Sürücü"),
                    "distance_km": round(road_km, 2),
                    "duration_min": int(max(1, round(float(row.get("duration_min", 1))))),
                    "rating": drv.get("rating", 4.0) or 4.0,
                }
            )
        eligible_drivers.sort(key=lambda x: (x["distance_km"], -x["rating"]))
        logger.info(
            "[MATCH] final_included driver_ids=%s count=%d pickup=(%.5f,%.5f)",
            [e["driver_id"] for e in eligible_drivers],
            len(eligible_drivers),
            plat_f,
            plng_f,
        )
        if not eligible_drivers:
            if not origin_points:
                logger.info(
                    "[MATCH] find_eligible empty reason=no_origin_points online_rows=%s",
                    online_count,
                )
            elif not meta:
                logger.info(
                    "[MATCH] find_eligible empty reason=no_routing_results origins=%d",
                    len(origin_points),
                )
            else:
                logger.info(
                    "[MATCH] find_eligible empty reason=all_gt_radius_r_km=%s meta_keys=%d",
                    r_km,
                    len(meta),
                )
            logger.warning(
                "find_eligible_drivers: 0 uygun — online=%s no_latlng=%s excluded=%s vehicle_mismatch=%s "
                "too_far=%s pref=%s r_km=%s pickup=(%.5f,%.5f) vehicle_filter=%s",
                online_count,
                no_loc,
                excluded,
                vehicle_mismatch,
                too_far,
                pref,
                r_km,
                float(pickup_lat),
                float(pickup_lng),
                vehicle_filter,
            )
        else:
            logger.info(
                "find_eligible_drivers: eligible=%s / online=%s pref=%s r_km=%s vehicle_filter=%s",
                len(eligible_drivers),
                online_count,
                pref,
                r_km,
                vehicle_filter,
            )
        return eligible_drivers

    except Exception as e:
        logger.error(f"❌ Find eligible drivers error: {e}")
        return []

async def create_dispatch_queue(tag_id: str, tag_data: dict) -> bool:
    """
    Tag için dispatch queue oluştur
    Uygun sürücüleri bul, sırala ve queue'ya ekle
    """
    try:
        config = await get_dispatch_config()
        max_drivers = config.get("max_driver_dispatch", 5)
        
        pref = _canonical_vehicle_kind(tag_data.get("passenger_preferred_vehicle"))
        if pref is None and tag_data.get("passenger_id"):
            try:
                pr = (
                    supabase.table("users")
                    .select("driver_details")
                    .eq("id", tag_data["passenger_id"])
                    .limit(1)
                    .execute()
                )
                if pr.data:
                    pref = _passenger_preferred_vehicle_from_row(pr.data[0])
            except Exception as ex:
                logger.warning(f"Yolcu araç tercihi okunamadı: {ex}")
        pref = pref or "car"
        
        # Yolcunun kendisi sürücü listesine girmesin (aynı hesap / test)
        excl = []
        if tag_data.get("passenger_id"):
            excl.append(tag_data["passenger_id"])
        
        # Uygun sürücüleri bul
        drivers = await find_eligible_drivers(
            tag_data.get("pickup_lat", 0),
            tag_data.get("pickup_lng", 0),
            exclude_ids=excl,
            passenger_vehicle_kind=pref,
        )
        
        if not drivers:
            logger.warning(f"⚠️ Dispatch: Tag {tag_id} için uygun sürücü bulunamadı")
            return False
        
        # En iyi N sürücüyü seç
        selected_drivers = drivers[:max_drivers]
        
        # Queue'ya ekle
        queue_entries = []
        for idx, driver in enumerate(selected_drivers):
            entry = {
                "id": str(uuid.uuid4()),
                "tag_id": tag_id,
                "driver_id": driver["driver_id"],
                "driver_name": driver["driver_name"],
                "priority": idx + 1,
                "distance_km": driver["distance_km"],
                "status": "waiting",
                "created_at": datetime.utcnow().isoformat(),
                "sent_at": None,
                "responded_at": None,
            }
            queue_entries.append(entry)
        
        # Supabase'e kaydet — yalnızca tabloda gerçekten olan kolonlar (şemada driver_name/distance_km yok;
        # eski kod bilinmeyen kolonlarla insert atınca tüm kayıt düşer; socket çoklu worker'da kaçarsa polling de kurtarmazdı.)
        try:
            for entry in queue_entries:
                db_row = {k: entry[k] for k in DISPATCH_QUEUE_DB_KEYS if k in entry}
                supabase.table("dispatch_queue").insert(db_row).execute()
        except Exception as db_err:
            logger.error(
                f"Dispatch queue DB kayıt hatası — teklif socket ile gidebilir ama "
                f"dispatch-pending-offer (polling) çalışmaz; tablo/FK kontrol edin: {db_err}"
            )
        
        # In-memory'de tut
        dispatch_queues[tag_id] = queue_entries
        
        logger.info(f"✅ Dispatch queue oluşturuldu: tag={tag_id}, {len(queue_entries)} sürücü")
        return True
        
    except Exception as e:
        logger.error(f"❌ Create dispatch queue error: {e}")
        return False


async def _driver_offer_push_fcm_deduped(resolved_driver_id: str, offer_tag_id, offer_data: dict) -> None:
    """
    Tek FCM / log satırı; (driver_id, tag_id) için OFFER_PUSH_DEDUPE_WINDOW_SEC içinde tekrar gönderilmez.
    Socket emit her seferinde çalışır; yalnız push dedupe (reconnect / çift register).
    """
    if not offer_tag_id:
        return
    key = (str(resolved_driver_id).strip().lower(), str(offer_tag_id).strip())
    now = time.monotonic()
    reserved = False
    ok = False
    try:
        async with _offer_push_dedupe_lock:
            prev = _offer_push_last_sent_mono.get(key)
            if prev is not None and (now - prev) < OFFER_PUSH_DEDUPE_WINDOW_SEC:
                logger.info(
                    "Push FCM offer dedupe skip dedupe_key=%s|%s age_s=%.2f window_s=%s",
                    key[0],
                    key[1],
                    now - prev,
                    OFFER_PUSH_DEDUPE_WINDOW_SEC,
                )
                return
            _offer_push_last_sent_mono[key] = now
            reserved = True
            if len(_offer_push_last_sent_mono) > 3000:
                cutoff = now - OFFER_PUSH_DEDUPE_WINDOW_SEC * 4
                for k2, ts in list(_offer_push_last_sent_mono.items()):
                    if ts < cutoff:
                        del _offer_push_last_sent_mono[k2]
        ok = await send_trip_push_and_log(
            resolved_driver_id,
            "new_ride_request",
            "Yeni teklif geldi",
            _push_body_offer_from_context(offer_data),
            _new_offer_push_data_from_offer(offer_data),
        )
        if ok:
            logger.info(
                "Push FCM driver=%s tag=%s",
                key[0][:13] + ("…" if len(key[0]) > 13 else ""),
                offer_tag_id,
            )
        else:
            logger.warning(
                "Push FCM failed driver=%s tag=%s",
                key[0][:13] + ("…" if len(key[0]) > 13 else ""),
                offer_tag_id,
            )
    except Exception as e:
        logger.warning(
            "Push FCM exception driver=%s tag=%s: %s",
            key[0][:13] + ("…" if len(key[0]) > 13 else ""),
            offer_tag_id,
            e,
        )
    finally:
        if reserved and not ok:
            try:
                async with _offer_push_dedupe_lock:
                    _offer_push_last_sent_mono.pop(key, None)
            except Exception:
                pass


async def emit_new_passenger_offer_to_driver(driver_id, offer_data: dict) -> bool:
    """
    Teklif socket event'i: önce doğrudan sid (connected_users), yoksa user room.
    Pasif / çevrimdışı / paketsiz / konumsuz sürücüye gönderilmez (True=socket gönderildi).
    """
    try:
        raw = str(driver_id).strip().lower() if driver_id is not None else ""
        if not raw:
            logger.warning("emit_new_passenger_offer_to_driver: boş driver_id")
            return False
        try:
            resolved = await resolve_user_id(raw)
            if resolved:
                raw = str(resolved).strip().lower()
        except Exception:
            pass
        if not await is_driver_eligible_for_dispatch_offer(raw):
            logger.info(
                "emit_new_passenger_offer_to_driver: atlandı (aktif değil) driver=%s tag=%s",
                raw[:13] + "…" if len(raw) > 13 else raw,
                offer_data.get("tag_id"),
            )
            return False
        logger.info(
            "[normal_ride_emit_offer] tag_id=%s driver_id=%s is_rolling_batch=%s is_broadcast=%s is_dispatch=%s",
            offer_data.get("tag_id"),
            str(raw)[:96],
            offer_data.get("is_rolling_batch"),
            offer_data.get("is_broadcast"),
            offer_data.get("is_dispatch"),
        )
        # Çoklu sekme / reconnect: tüm sid'ler + user odası (tek sid map anahtarı kaçırmasın).
        await emit_socket_event_to_user(raw, "new_passenger_offer", offer_data)

        # FCM: yalnız send_trip_push_and_log → send_push_notification (Expo token kullanılmaz).
        offer_tag_id = offer_data.get("tag_id")
        resolved_driver_id = raw

        try:
            asyncio.create_task(_driver_offer_push_fcm_deduped(resolved_driver_id, offer_tag_id, offer_data))
        except Exception as e:
            logger.warning("Push create_task failed: %s", e)
        return True
    except Exception as e:
        logger.error(f"new_passenger_offer emit hatası: {e}")
        return False


async def emit_existing_waiting_offers_to_driver(driver_id: str) -> None:
    """
    Bekleyen (status='waiting') yolcu tekliflerini, bu an sisteme/ekrana giren sürücüye yeniden gönder.
    Amaç: Sürücü teklif oluştuktan sonra girerse eski teklifleri de görsün.
    """
    try:
        if not driver_id:
            return
        if not supabase:
            return

        cfg = await get_dispatch_config()
        matching_radius_km = float(cfg.get("matching_radius_km", DISPATCH_CONFIG.get("matching_radius_km", 20)))
        timeout_sec = int(cfg.get("driver_offer_timeout", DISPATCH_CONFIG.get("driver_offer_timeout", 10)))

        resolved_driver_id = await resolve_user_id(driver_id)
        if not await is_driver_eligible_for_dispatch_offer(resolved_driver_id):
            return
        drv_res = (
            supabase.table("users")
            .select("id, latitude, longitude, driver_details")
            .eq("id", resolved_driver_id)
            .limit(1)
            .execute()
        )
        if not drv_res.data:
            return
        drv = drv_res.data[0]
        driver_lat = drv.get("latitude")
        driver_lng = drv.get("longitude")
        if driver_lat is None or driver_lng is None:
            return

        driver_eff = _effective_driver_vehicle_kind(drv) or "car"

        waiting_tags = (
            supabase.table("tags")
            .select(
                "id, passenger_id, passenger_name, pickup_lat, pickup_lng, pickup_location, "
                "dropoff_lat, dropoff_lng, dropoff_location, final_price, distance_km, estimated_minutes, "
                "passenger_preferred_vehicle, passenger_payment_method"
            )
            .eq("type", TAG_TYPE_NORMAL)
            .eq("status", "waiting")
            .execute()
        )
        if not waiting_tags.data:
            return

        d_la_f = float(driver_lat)
        d_lo_f = float(driver_lng)
        _match_t0 = time.time()
        tag_points: list[tuple[str, float, float]] = []
        tag_by_id: dict[str, dict] = {}
        for tag in waiting_tags.data:
            tag_lat = tag.get("pickup_lat")
            tag_lng = tag.get("pickup_lng")
            if tag_lat is None or tag_lng is None:
                continue
            passenger_pref = _canonical_vehicle_kind(tag.get("passenger_preferred_vehicle")) or "car"
            if not _driver_matches_passenger_vehicle_pref(driver_eff, passenger_pref):
                continue
            try:
                tla = float(tag_lat)
                tlo = float(tag_lng)
            except (TypeError, ValueError):
                continue
            tid = str(tag.get("id")).strip()
            tag_points.append((tid, tla, tlo))
            tag_by_id[tid] = tag

        try:
            pickup_meta = await get_real_route_meta_batch(d_la_f, d_lo_f, tag_points)
        except Exception as e:
            logger.error("[MATCH] emit_existing_waiting_offers batch failed: %s", e, exc_info=True)
            pickup_meta = {}
        logger.info(
            "[MATCH] MATCH_TIME emit_existing_waiting_offers_batch_s: %.4f driver=%s",
            time.time() - _match_t0,
            resolved_driver_id,
        )
        accepted_tag_ids: list[str] = []
        for tid, row in pickup_meta.items():
            road_km = float(row.get("distance_km", 0))
            if road_km > matching_radius_km:
                continue
            tag = tag_by_id.get(tid)
            if not tag:
                continue
            passenger_pref = _canonical_vehicle_kind(tag.get("passenger_preferred_vehicle")) or "car"
            pu_km = round(road_km, 1)
            pu_min = int(max(1, round(float(row.get("duration_min", 1)))))

            offer_data = {
                "tag_id": str(tag.get("id")).strip(),
                "passenger_id": tag.get("passenger_id"),
                "passenger_name": tag.get("passenger_name") or "Yolcu",
                "pickup_location": tag.get("pickup_location"),
                "pickup_lat": tag.get("pickup_lat"),
                "pickup_lng": tag.get("pickup_lng"),
                "dropoff_location": tag.get("dropoff_location"),
                "dropoff_lat": tag.get("dropoff_lat"),
                "dropoff_lng": tag.get("dropoff_lng"),
                "offered_price": tag.get("final_price") or tag.get("offered_price") or 0,
                "distance_km": tag.get("distance_km") or 0,
                "estimated_minutes": tag.get("estimated_minutes") or 0,
                "trip_distance_km": tag.get("distance_km") or 0,
                "trip_duration_min": tag.get("estimated_minutes") or 0,
                "dispatch_timeout": timeout_sec,
                "is_dispatch": True,
                "passenger_vehicle_kind": passenger_pref,
                "distance_to_pickup": pu_km,
                "pickup_distance_km": pu_km,
                "pickup_eta_min": pu_min,
                "time_to_passenger_min": pu_min,
                "passenger_payment_method": tag.get("passenger_payment_method"),
            }

            try:
                await emit_new_passenger_offer_to_driver(driver_id, offer_data)
                accepted_tag_ids.append(str(tag.get("id")))
            except Exception as e:
                logger.error(
                    "[MATCH] emit_existing_waiting_offers emit failed tag_id=%s: %s",
                    tid,
                    e,
                    exc_info=True,
                )
        logger.info("[MATCH] emit_existing final_included tag_ids=%s", accepted_tag_ids)
        if not accepted_tag_ids and tag_points:
            if not pickup_meta:
                logger.info(
                    "[MATCH] emit_existing empty reason=no_routing_results driver=%s points=%d",
                    resolved_driver_id,
                    len(tag_points),
                )
            else:
                logger.info(
                    "[MATCH] emit_existing empty reason=all_gt_radius driver=%s radius_km=%s meta=%d",
                    resolved_driver_id,
                    matching_radius_km,
                    len(pickup_meta),
                )
    except Exception as e:
        logger.warning(f"emit_existing_waiting_offers_to_driver error: {e}")


async def emit_passenger_offer_revoked(
    driver_id: str,
    tag_id: str,
    *,
    revoke_reason: str = "passenger_cancelled",
):
    """Önceki sürücü teklifi artık göremesin (sıralı dispatch timeout / iptal vb.)."""
    try:
        raw = str(driver_id).strip().lower() if driver_id else ""
        sid = connected_users.get(raw) or connected_users.get(str(driver_id).strip()) if driver_id else None
        payload = {"tag_id": tag_id, "revoke_reason": str(revoke_reason or "unknown")}
        if sid:
            await sio.emit("passenger_offer_revoked", payload, to=sid)
        else:
            await sio.emit("passenger_offer_revoked", payload, room=_normalize_user_room(raw or str(driver_id)))
    except Exception as e:
        logger.warning(f"passenger_offer_revoked emit hatası: {e}")


async def _emit_driver_on_the_way_route(tag_row: dict, resolved_driver_id: str) -> None:
    """Eşleşme sonrası: sürücü konumu → alış rotası; driver_on_the_way + ride_matched (sürücü navigasyon uyumu)."""
    if not supabase or not isinstance(tag_row, dict):
        return
    did = str(resolved_driver_id or "").strip()
    if not did:
        return
    plat, plng = tag_row.get("pickup_lat"), tag_row.get("pickup_lng")
    if plat is None or plng is None:
        logger.warning("driver_on_the_way skip: missing pickup tag_id=%s", tag_row.get("id"))
        return
    try:
        p_la = float(plat)
        p_lo = float(plng)
    except (TypeError, ValueError):
        logger.warning("driver_on_the_way skip: invalid pickup coords tag_id=%s", tag_row.get("id"))
        return

    dlat: Any = None
    dlng: Any = None
    try:
        udrv = (
            supabase.table("users")
            .select("latitude, longitude")
            .eq("id", did)
            .limit(1)
            .execute()
        )
        if not udrv.data and "-" in did:
            udrv = (
                supabase.table("users")
                .select("latitude, longitude")
                .eq("id", did.lower())
                .limit(1)
                .execute()
            )
        if udrv.data:
            dlat = udrv.data[0].get("latitude")
            dlng = udrv.data[0].get("longitude")
    except Exception as ex_udrv:
        logger.warning("driver_on_the_way users lookup (non-fatal): %s", ex_udrv)

    if dlat is None or dlng is None:
        logger.warning("driver_on_the_way skip: missing driver coords driver_id=%s", did[:96])
        return
    try:
        d_la = float(dlat)
        d_lo = float(dlng)
    except (TypeError, ValueError):
        logger.warning("driver_on_the_way skip: invalid driver coords driver_id=%s", did[:96])
        return

    droplat, droplng = tag_row.get("dropoff_lat"), tag_row.get("dropoff_lng")
    if droplat is None or droplng is None:
        logger.warning("driver_on_the_way skip: missing dropoff coords tag_id=%s", tag_row.get("id"))
        return
    try:
        d2_la = float(droplat)
        d2_lo = float(droplng)
    except (TypeError, ValueError):
        logger.warning("driver_on_the_way skip: invalid dropoff coords tag_id=%s", tag_row.get("id"))
        return

    pickup_route = await get_route_info(d_la, d_lo, p_la, p_lo)
    trip_route = await get_route_info(p_la, p_lo, d2_la, d2_lo)
    if (
        not isinstance(pickup_route, dict)
        or not isinstance(trip_route, dict)
        or str(pickup_route.get("source", "")).strip().lower() == "haversine_fallback"
        or str(trip_route.get("source", "")).strip().lower() == "haversine_fallback"
    ):
        logger.warning(
            "driver_on_the_way skip: non-road route source tag_id=%s driver_id=%s pickup_source=%s trip_source=%s",
            tag_row.get("id"),
            did[:96],
            pickup_route.get("source") if isinstance(pickup_route, dict) else None,
            trip_route.get("source") if isinstance(trip_route, dict) else None,
        )
        return
    try:
        pickup_distance_km = (
            float(pickup_route["distance_km"]) if pickup_route and pickup_route.get("distance_km") is not None else None
        )
        pickup_eta_min = (
            int(round(float(pickup_route["duration_min"])))
            if pickup_route and pickup_route.get("duration_min") is not None
            else None
        )
        trip_distance_km = (
            float(trip_route["distance_km"]) if trip_route and trip_route.get("distance_km") is not None else None
        )
        trip_duration_min = (
            int(round(float(trip_route["duration_min"])))
            if trip_route and trip_route.get("duration_min") is not None
            else None
        )
    except (TypeError, ValueError, KeyError):
        pickup_distance_km = None
        pickup_eta_min = None
        trip_distance_km = None
        trip_duration_min = None
    if (
        pickup_distance_km is None
        or pickup_eta_min is None
        or trip_distance_km is None
        or trip_duration_min is None
    ):
        logger.warning(
            "driver_on_the_way skip: real route metrics unavailable tag_id=%s driver_id=%s",
            tag_row.get("id"),
            did[:96],
        )
        return

    route_out: dict[str, Any] = {
        "pickup_distance_km": pickup_distance_km,
        "pickup_eta_min": pickup_eta_min,
        "distance_to_passenger_km": pickup_distance_km,
        "time_to_passenger_min": pickup_eta_min,
        "trip_distance_km": trip_distance_km,
        "trip_duration_min": trip_duration_min,
        "distance_km": trip_distance_km,
        "estimated_minutes": trip_duration_min,
    }
    if isinstance(pickup_route, dict):
        op = pickup_route.get("overview_polyline")
        if isinstance(op, str) and len(op) > 2:
            route_out["overview_polyline"] = op
        coords = pickup_route.get("coordinates")
        if isinstance(coords, list) and len(coords) >= 2:
            route_out["coordinates"] = coords

    tag_out = {k: v for k, v in tag_row.items() if v is not None}
    tag_out["pickup_distance_km"] = pickup_distance_km
    tag_out["pickup_eta_min"] = pickup_eta_min
    tag_out["distance_to_passenger_km"] = pickup_distance_km
    tag_out["time_to_passenger_min"] = pickup_eta_min
    tag_out["trip_distance_km"] = trip_distance_km
    tag_out["trip_duration_min"] = trip_duration_min
    tag_out["distance_km"] = trip_distance_km
    tag_out["estimated_minutes"] = trip_duration_min
    tag_out["route_info"] = route_out
    body = {
        "tag": tag_out,
        "route": route_out,
        "pickup_lat": p_la,
        "pickup_lng": p_lo,
        "pickup_distance_km": pickup_distance_km,
        "pickup_eta_min": pickup_eta_min,
        "distance_to_passenger_km": pickup_distance_km,
        "time_to_passenger_min": pickup_eta_min,
        "trip_distance_km": trip_distance_km,
        "trip_duration_min": trip_duration_min,
        "distance_km": trip_distance_km,
        "estimated_minutes": trip_duration_min,
        "duration": trip_duration_min,
        "route_info": route_out,
    }
    print("[ROUTE_ACCEPT] driver_to_pickup=", pickup_distance_km, pickup_eta_min)
    print("[ROUTE_ACCEPT] pickup_to_dropoff=", trip_distance_km, trip_duration_min)
    print("[ROUTE_ACCEPT] emit_driver_id=", did, "tag_id=", tag_row.get("id"))
    room = f"user_{did}"
    print("ROUTE TO DRIVER:", did, route_out)
    print("ROOM:", room)
    try:
        await sio.emit("driver_on_the_way", body, room=room)
        await sio.emit("ride_matched", body, room=room)
    except Exception as ex:
        logger.warning("driver_on_the_way / ride_matched emit failed driver_id=%s err=%s", did[:96], ex)


async def emit_socket_event_to_user(user_id, event_name: str, payload: dict) -> None:
    """Kullanıcıya socket event: connected_users’daki tüm sid’lere to=emit; yoksa user_<uuid> odası."""
    try:
        if user_id is None:
            return
        raw_in = str(user_id).strip()
        if not raw_in:
            return
        canonical_lo = raw_in.lower()
        keys_to_try: set[str] = set()
        keys_to_try.add(raw_in)
        keys_to_try.add(canonical_lo)
        resolved_uid = None
        try:
            resolved_uid = await resolve_user_id(raw_in)
            if resolved_uid:
                rs = str(resolved_uid).strip()
                if rs:
                    keys_to_try.add(rs)
                    keys_to_try.add(rs.lower())
        except Exception:
            pass

        # Reverse alias lookup: aynı sid seti altındaki tüm key alias'larını da dahil et.
        alias_keys: set[str] = set()
        initial_sids: set[str] = set()
        for k in list(keys_to_try):
            for sid in connected_user_sids.get(str(k), set()):
                if sid:
                    initial_sids.add(str(sid))
        if initial_sids:
            for k, sid_set in connected_user_sids.items():
                if not sid_set:
                    continue
                for sid in sid_set:
                    if str(sid) in initial_sids:
                        alias_keys.add(str(k))
                        break
        keys_to_try.update(alias_keys)

        all_sids: set[str] = set()
        for key in keys_to_try:
            for sid in connected_user_sids.get(str(key), set()):
                if sid:
                    all_sids.add(str(sid))

        room = _normalize_user_room(str(resolved_uid or canonical_lo))
        sid_count = len(all_sids)
        logger.info(
            "[socket_emit_user] %s",
            json.dumps(
                {
                    "event": event_name,
                    "user_id": canonical_lo[:96],
                    "resolved": str(resolved_uid or "").lower()[:96] if resolved_uid else "",
                    "sid_count": sid_count,
                    "room": room,
                    "keys": sorted(keys_to_try)[:12],
                },
                ensure_ascii=False,
            ),
        )
        if sid_count == 0:
            logger.warning(
                "[socket_emit_user] sid_empty event=%s user=%s room=%s — yalnız oda denemesi",
                event_name,
                canonical_lo[:48],
                room,
            )

        if all_sids:
            for sid in all_sids:
                try:
                    await sio.emit(event_name, payload, to=sid)
                except Exception as em:
                    logger.warning("%s emit to=sid sid=%s err=%s", event_name, sid, em)
            try:
                await sio.emit(event_name, payload, room=room)
            except Exception as em:
                logger.warning("%s emit room=%s err=%s", event_name, room, em)
            if event_name == "message_ack":
                logger.info("[muhabbet_ack] sent user=%s sids=%s room=%s", canonical_lo, sorted(all_sids), room)
        else:
            try:
                await sio.emit(event_name, payload, room=room)
            except Exception as em:
                logger.warning("%s emit room_fallback_failed room=%s err=%s", event_name, room, em)
            if event_name == "message_ack":
                logger.info("[muhabbet_ack] sent user=%s sids=[] room_fallback=%s", canonical_lo, room)
    except Exception as e:
        logger.warning("%s emit hatası: %s", event_name, e)


async def notify_conversation_updated(
    conversation_id: str,
    reason: str,
    actor_user_id: Optional[str] = None,
) -> None:
    cid = str(conversation_id or "").strip().lower()
    if not cid:
        return
    try:
        uuid.UUID(cid)
    except ValueError:
        logger.warning(
            "[muhabbet_notify] type=conversation_updated conversation_id=%s reason=%s target_user_id= err=bad_uuid",
            cid,
            reason,
        )
        return
    try:
        r = supabase.table("conversations").select("user_a,user_b,updated_at").eq("id", cid).limit(1).execute()
        if not r.data:
            logger.warning(
                "[muhabbet_notify] type=conversation_updated conversation_id=%s reason=%s target_user_id= err=no_row",
                cid,
                reason,
            )
            return
        row = dict(r.data[0])
        ua = str(row.get("user_a") or "").strip().lower()
        ub = str(row.get("user_b") or "").strip().lower()
        version_raw = row.get("updated_at")
        version = version_raw if version_raw else datetime.now(timezone.utc).isoformat()
        payload = {"conversation_id": cid, "reason": reason, "version": version}
        targets = [u for u in {ua, ub} if u]
        for uid_tgt in targets:
            logger.info(
                "[muhabbet_notify] type=conversation_updated conversation_id=%s reason=%s target_user_id=%s",
                cid,
                reason,
                uid_tgt[:13] if uid_tgt else "",
            )
            try:
                await emit_socket_event_to_user(uid_tgt, "conversation_updated", payload)
            except Exception as em:
                logger.warning(
                    "[muhabbet_notify] conversation_updated emit failed target=%s err=%s",
                    uid_tgt[:13] if uid_tgt else "",
                    em,
                )
        _ = actor_user_id
    except Exception as e:
        logger.warning("[muhabbet_notify] conversation_updated failed conversation_id=%s err=%s", cid, e)


async def notify_trip_session_updated(
    session_id: str,
    reason: str,
    actor_user_id: Optional[str] = None,
) -> None:
    sid = str(session_id or "").strip().lower()
    if not sid:
        return
    try:
        uuid.UUID(sid)
    except ValueError:
        logger.warning(
            "[muhabbet_notify] type=trip_session_updated session_id=%s reason=%s target_user_id= err=bad_uuid",
            sid,
            reason,
        )
        return
    try:
        r = supabase.table("muhabbet_trip_sessions").select("*").eq("id", sid).limit(1).execute()
        if not r.data:
            logger.warning(
                "[muhabbet_notify] type=trip_session_updated session_id=%s reason=%s target_user_id= err=no_row",
                sid,
                reason,
            )
            return
        row = dict(r.data[0])
        version_raw = row.get("updated_at")
        version = version_raw if version_raw else datetime.now(timezone.utc).isoformat()
        payload = {"session_id": sid, "reason": reason, "version": version}
        targets: set[str] = set()
        for k in ("passenger_id", "driver_id"):
            u = str(row.get(k) or "").strip().lower()
            if u:
                targets.add(u)
        try:
            pr = (
                supabase.table("muhabbet_trip_passengers")
                .select("passenger_user_id")
                .eq("session_id", sid)
                .execute()
            )
            for pr_row in pr.data or []:
                pu = str(pr_row.get("passenger_user_id") or "").strip().lower()
                if pu:
                    targets.add(pu)
        except Exception as pe:
            logger.debug("[muhabbet_notify] trip passengers select skipped session_id=%s err=%s", sid[:12], pe)

        trip_rm = muhabbet_trip_room(sid)
        try:
            await sio.emit("trip_session_updated", payload, room=trip_rm)
        except Exception as em:
            logger.warning("[muhabbet_notify] trip_session_updated room emit failed session_id=%s err=%s", sid[:12], em)

        for uid_tgt in sorted(targets):
            logger.info(
                "[muhabbet_notify] type=trip_session_updated session_id=%s reason=%s target_user_id=%s",
                sid,
                reason,
                uid_tgt[:13] if uid_tgt else "",
            )
            try:
                await emit_socket_event_to_user(uid_tgt, "trip_session_updated", payload)
            except Exception as em:
                logger.warning(
                    "[muhabbet_notify] trip_session_updated emit failed target=%s err=%s",
                    uid_tgt[:13] if uid_tgt else "",
                    em,
                )
        _ = actor_user_id
    except Exception as e:
        logger.warning("[muhabbet_notify] trip_session_updated failed session_id=%s err=%s", sid, e)


def _socketio_room_member_count(room: str) -> int:
    """user_<id> odasındaki socket sayısı (bilinmiyorsa -1)."""
    try:
        return sum(1 for _ in sio.manager.get_participants("/", room))
    except Exception:
        pass
    return -1


def _connected_sid_for_user(user_id: str) -> str | None:
    """connected_users içinde esnek anahtar eşleşmesi ile sid bul."""
    if user_id is None:
        return None
    u = str(user_id).strip()
    if not u:
        return None
    ul = u.lower()
    sid = connected_users.get(u) or connected_users.get(ul)
    if sid:
        return sid
    for k, s in list(connected_users.items()):
        if isinstance(k, str) and k.strip().lower() == ul:
            return s
    return None


def _all_sids_for_registered_user(user_id: str) -> list[str]:
    """Aynı user_id için connected_users anahtarlarında görünen tüm benzersiz sid'ler (reconnect / çok sekme)."""
    ul = str(user_id or "").strip().lower()
    if not ul:
        return []
    direct = connected_user_sids.get(ul)
    if direct:
        return sorted(str(s) for s in direct if s)
    seen: set[str] = set()
    out: list[str] = []
    for k, s in list(connected_users.items()):
        if not isinstance(k, str) or not s:
            continue
        if str(k).strip().lower() != ul:
            continue
        ss = str(s)
        if ss not in seen:
            seen.add(ss)
            out.append(ss)
    return out


async def emit_trip_force_ended_to_party(
    target_user_id: str,
    payload: dict,
    log_label: str,
    tag_id: str,
) -> bool:
    """
    Zorla bitir sonrası trip_force_ended: önce user room, sonra sid map (room boş / üyelik drift ihtimali).
    Dönüş: en az bir alıcı yolu (oda dolu veya sid biliniyor) varsa ve emit'ler exception vermediyse True.
    """
    raw_display = str(target_user_id).strip()
    raw_l = raw_display.lower()
    room = _normalize_user_room(raw_l)
    room_n = _socketio_room_member_count(room)
    sid_hit = _connected_sid_for_user(raw_display) or _connected_sid_for_user(raw_l)
    # room_n < 0: sayım başarısız — room emit yine denendiği için iyimser kabul
    had_recipient = bool(sid_hit) or (room_n > 0) or (room_n < 0)
    err = False
    try:
        await sio.emit("trip_force_ended", payload, room=room)
    except Exception as ex:
        err = True
        logger.warning("%s room_emit_fail tag_id=%s room=%s err=%s", log_label, tag_id, room, ex)
    if sid_hit:
        try:
            await sio.emit("trip_force_ended", payload, to=sid_hit)
        except Exception as ex:
            err = True
            logger.warning("%s sid_emit_fail tag_id=%s sid=%s err=%s", log_label, tag_id, sid_hit, ex)
    logger.info(
        "%s tag_id=%s target_user=%s room=%s room_member_count=%s sid=%s",
        log_label,
        tag_id,
        raw_display,
        room,
        room_n,
        sid_hit or "none",
    )
    return bool(had_recipient and not err)


FORCE_END_COUNTERPARTY_KIND = "force_end_counterparty"


async def resolve_force_end_counterparty(
    tag_id: str,
    responder_id: str,
    initiator_id: str,
    approved: bool,
) -> dict:
    """Zorla bitirmede karşı taraf onayı: onay=0 ceza, red=zorla bitirene -5. end_request.status resolved ise idempotent."""
    tid = str(tag_id).strip()
    try:
        rr = await resolve_user_id(str(responder_id).strip())
        if rr:
            rr = str(rr).strip()
        else:
            rr = str(responder_id).strip()
    except Exception:
        rr = str(responder_id).strip()

    try:
        ir = await resolve_user_id(str(initiator_id).strip())
        if ir:
            ir = str(ir).strip()
        else:
            ir = str(initiator_id).strip()
    except Exception:
        ir = str(initiator_id).strip()

    try:
        tr = supabase.table("tags").select("*").eq("id", tid).limit(1).execute()
    except Exception as e:
        logger.error(f"resolve_force_end_counterparty: tag okunamadı: {e}")
        return {"success": False, "error": "TAG okunamadı"}

    if not tr.data:
        return {"success": False, "error": "TAG bulunamadı"}

    tag = tr.data[0]
    st_tag = (tag.get("status") or "").lower()
    if st_tag in ("completed", "cancelled"):
        return {"success": True, "idempotent": True, "approved": approved, "message": "Yolculuk zaten sonlanmış"}

    req = tag.get("end_request")
    if not isinstance(req, dict) or req.get("kind") != FORCE_END_COUNTERPARTY_KIND:
        return {"success": False, "error": "Bekleyen zorla bitir onayı yok"}

    if str(req.get("status") or "").lower() == "resolved":
        return {"success": True, "idempotent": True, "approved": approved}

    ini = str(req.get("initiator_id") or "").strip()
    ini_type = str(req.get("initiator_type") or "").strip().lower()
    try:
        ini_r = await resolve_user_id(ini) if ini else None
        if ini_r:
            ini_r = str(ini_r).strip()
        else:
            ini_r = ini
    except Exception:
        ini_r = ini

    if not ini_r or ini_r.lower() != ir.lower():
        return {"success": False, "error": "Zorla bitiren bilgisi uyuşmuyor"}

    if ini_type not in ("driver", "passenger"):
        return {"success": False, "error": "Geçersiz zorla bitiren rolü"}

    pid = tag.get("passenger_id")
    did = tag.get("driver_id")
    try:
        pid_r = await resolve_user_id(str(pid).strip()) if pid else None
        if pid_r:
            pid_r = str(pid_r).strip()
    except Exception:
        pid_r = str(pid).strip() if pid else None
    try:
        did_r = await resolve_user_id(str(did).strip()) if did else None
        if did_r:
            did_r = str(did_r).strip()
    except Exception:
        did_r = str(did).strip() if did else None

    if not pid_r or not did_r:
        return {"success": False, "error": "Eşleşme bilgisi eksik"}

    counterparty = pid_r if ini_type == "driver" else did_r
    if str(counterparty).strip().lower() != rr.lower():
        return {"success": False, "error": "Onay için yetkiniz yok"}

    now_iso = datetime.utcnow().isoformat()
    new_points, new_rating = None, None
    if not approved:
        new_points, new_rating = await deduct_points(ini_r, 5, "Zorla bitirme karşı tarafça onaylanmadı")
        logger.info("force_end_penalty_minus_5 user=%s new_points=%s", ini_r[:12], new_points)

    pending_req_snapshot = dict(req) if isinstance(req, dict) else {}
    prev_status = tag.get("status") or "matched"
    prev_completed_at = tag.get("completed_at")
    prev_ended_by = tag.get("ended_by")
    prev_end_type = tag.get("end_type")

    resolved_req = {
        **req,
        "status": "resolved",
        "resolved_at": now_iso,
        "responder_approved": approved,
    }
    try:
        supabase.table("tags").update(
            {
                "status": "completed",
                "completed_at": now_iso,
                "ended_by": ini_r,
                "end_type": "force",
                "end_request": resolved_req,
            }
        ).eq("id", tid).execute()
    except Exception as e:
        logger.error(f"resolve_force_end_counterparty: tag güncellenemedi: {e}")
        return {"success": False, "error": str(e)}

    try:
        supabase.table("chat_messages").delete().eq("tag_id", tid).execute()
    except Exception as chat_err:
        logger.error(
            "resolve_force_end_counterparty: sohbet silinemedi, tag tamamlanması geri alınıyor: %s",
            chat_err,
        )
        try:
            rollback_er = dict(pending_req_snapshot)
            supabase.table("tags").update(
                {
                    "status": prev_status,
                    "completed_at": prev_completed_at,
                    "ended_by": prev_ended_by,
                    "end_type": prev_end_type,
                    "end_request": rollback_er,
                }
            ).eq("id", tid).execute()
        except Exception as rb_err:
            logger.error("resolve_force_end_counterparty: rollback başarısız tag=%s err=%s", tid, rb_err)
        return {"success": False, "error": "Sohbet silinemedi; yolculuk durumu geri alındı"}

    invalidate_tag_cache(tid, pid_r, did_r)

    ender_name = ""
    try:
        _en = supabase.table("users").select("name").eq("id", ini_r).limit(1).execute()
        if _en.data:
            ender_name = (str(_en.data[0].get("name") or "")).strip()
    except Exception:
        pass

    payload_base = {
        "tag_id": tid,
        "ended_by": ini_r,
        "ender_id": ini_r,
        "ender_type": ini_type,
        "ender_name": ender_name,
        "passenger_id": pid_r,
        "driver_id": did_r,
        "completed_at": now_iso,
        "should_rate": False,
        "force_end_resolved": True,
        "passenger_approved_force_end": approved,
    }
    logger.info(
        "FORCE_END_RESOLVE_START tag_id=%s passenger_id=%s driver_id=%s",
        tid,
        pid_r,
        did_r,
    )
    passenger_emit_ok = False
    driver_emit_ok = False
    for uid in [pid_r, did_r]:
        if not uid:
            continue
        raw_l = str(uid).strip().lower()
        is_passenger_target = raw_l == str(pid_r).strip().lower()
        _emit_label = "FORCE_END_EMIT_PASSENGER_ROOM" if is_passenger_target else "FORCE_END_EMIT_DRIVER_ROOM"
        is_initiator = str(uid).strip().lower() == ini_r.lower()
        penalty = 0 if approved else 5
        pl = {
            **payload_base,
            "points_deducted": penalty if is_initiator else 0,
            "new_points": new_points if (is_initiator and not approved) else None,
            "new_rating": new_rating if (is_initiator and not approved) else None,
        }
        try:
            ok = await emit_trip_force_ended_to_party(uid, pl, _emit_label, tid)
        except Exception as emit_err:
            ok = False
            logger.warning("resolve_force_end_counterparty trip_force_ended: %s", emit_err)
        if is_passenger_target:
            passenger_emit_ok = ok
        else:
            driver_emit_ok = ok

    logger.info(
        "FORCE_END_EMIT_DONE tag_id=%s passenger_emit_ok=%s driver_emit_ok=%s",
        tid,
        passenger_emit_ok,
        driver_emit_ok,
    )

    return {
        "success": True,
        "approved": approved,
        "new_points": new_points,
        "new_rating": new_rating,
        "idempotent": False,
    }


FORCE_END_PENDING_TIMEOUT_MINUTES = 5


async def expire_stale_pending_force_ends() -> int:
    """
    Zorla bitir: karşı taraf 5 dk içinde yanıtlamazsa otomatik onaylı (approved) tamamlanır.
    """
    n_done = 0
    try:
        r = supabase.table("tags").select("id, passenger_id, driver_id, status, end_request").in_(
            "status", ["matched", "in_progress"]
        ).execute()
    except Exception as e:
        logger.warning("expire_stale_pending_force_ends: select %s", e)
        return 0

    now_utc = datetime.now(timezone.utc)
    for tag in r.data or []:
        er = tag.get("end_request")
        if not isinstance(er, dict) or er.get("kind") != FORCE_END_COUNTERPARTY_KIND:
            continue
        if str(er.get("status") or "").lower() != "pending":
            continue
        req_at = er.get("requested_at")
        if not req_at:
            continue
        try:
            raw = str(req_at).replace("Z", "+00:00")
            rt = datetime.fromisoformat(raw)
            if rt.tzinfo is None:
                rt = rt.replace(tzinfo=timezone.utc)
            age_sec = (now_utc - rt.astimezone(timezone.utc)).total_seconds()
        except Exception:
            continue
        if age_sec < FORCE_END_PENDING_TIMEOUT_MINUTES * 60:
            continue

        tid = str(tag.get("id") or "").strip()
        ini_id = str(er.get("initiator_id") or "").strip()
        ini_type = str(er.get("initiator_type") or "").strip().lower()
        if not tid or not ini_id or ini_type not in ("driver", "passenger"):
            continue
        pid = tag.get("passenger_id")
        did = tag.get("driver_id")
        counterparty = pid if ini_type == "driver" else did
        if not counterparty:
            continue
        try:
            cp_r = await resolve_user_id(str(counterparty).strip())
            if cp_r:
                cp_r = str(cp_r).strip()
            else:
                cp_r = str(counterparty).strip()
            ini_resolved = await resolve_user_id(ini_id) if ini_id else None
            ini_r = str(ini_resolved).strip() if ini_resolved else ini_id
            res = await resolve_force_end_counterparty(tid, cp_r, ini_r, True)
            if res.get("success"):
                n_done += 1
                logger.info(
                    "⏱️ force_end pending timeout (>%sm) auto-approved tag=%s",
                    FORCE_END_PENDING_TIMEOUT_MINUTES,
                    tid[:8],
                )
        except Exception as ex:
            logger.warning("expire_stale_pending_force_ends tag=%s: %s", tid[:8], ex)
    return n_done


async def apply_force_end_trip_and_notify(
    tag_id: str,
    ender_id: str,
    ender_type: Optional[str] = None,
) -> dict:
    """
    Zorla bitir — istek aşaması: tag status matched/in_progress kalır, yalnızca end_request (pending).
    Karşı tarafa force_end_counterparty_prompt. trip_force_ended yalnızca resolve_force_end_counterparty sonrası gider.
    """
    if not tag_id or not ender_id:
        return {"success": False, "error": "tag_id ve ender_id gerekli"}
    tid = str(tag_id).strip()
    try:
        resolved_ender = await resolve_user_id(str(ender_id).strip())
        if resolved_ender:
            resolved_ender = str(resolved_ender).strip()
        else:
            resolved_ender = str(ender_id).strip()
    except Exception:
        resolved_ender = str(ender_id).strip()

    try:
        tr = supabase.table("tags").select("*").eq("id", tid).limit(1).execute()
    except Exception as e:
        logger.error(f"apply_force_end_trip: tag okunamadı: {e}")
        return {"success": False, "error": "TAG okunamadı"}

    if not tr.data:
        return {"success": False, "error": "TAG bulunamadı"}

    tag = tr.data[0]
    pid_raw = tag.get("passenger_id")
    did_raw = tag.get("driver_id")

    passenger_id = None
    driver_id = None
    if pid_raw:
        try:
            passenger_id = await resolve_user_id(str(pid_raw).strip())
            if passenger_id:
                passenger_id = str(passenger_id).strip()
        except Exception:
            passenger_id = str(pid_raw).strip()
    if did_raw:
        try:
            driver_id = await resolve_user_id(str(did_raw).strip())
            if driver_id:
                driver_id = str(driver_id).strip()
        except Exception:
            driver_id = str(did_raw).strip()

    et = (ender_type or "").strip().lower()
    if et not in ("passenger", "driver"):
        re_l = resolved_ender.lower()
        if passenger_id and re_l == passenger_id.lower():
            et = "passenger"
        elif driver_id and re_l == driver_id.lower():
            et = "driver"
        else:
            return {"success": False, "error": "ender_type belirsiz veya kullanıcı talebe dahil değil"}

    re_l = resolved_ender.lower()
    if et == "passenger":
        if not passenger_id or re_l != passenger_id.lower():
            return {"success": False, "error": "Bu işlem için yolcu olmalısınız"}
    else:
        if not driver_id or re_l != driver_id.lower():
            return {"success": False, "error": "Bu işlem için sürücü olmalısınız"}

    st = (tag.get("status") or "").lower()
    if st in ("completed", "cancelled"):
        logger.info(f"apply_force_end_trip: idempotent skip tag={tid} status={st}")
        return {"success": True, "idempotent": True, "message": "Yolculuk zaten sonlanmış"}

    if st not in ("matched", "in_progress"):
        return {"success": False, "error": "Aktif eşleşme yok (zorla bitirilemez)"}

    existing_er = tag.get("end_request")
    if isinstance(existing_er, dict) and str(existing_er.get("status") or "").lower() == "pending":
        if existing_er.get("kind") == FORCE_END_COUNTERPARTY_KIND:
            logger.info(f"apply_force_end_trip: idempotent pending force-end tag={tid}")
            return {
                "success": True,
                "idempotent": True,
                "pending_counterparty_review": True,
                "message": "Zorla bitir onayı zaten bekleniyor",
            }
        logger.info(f"apply_force_end_trip: başka pending end_request var, zorla bitir reddedildi tag={tid}")
        return {"success": False, "error": "Başka bir yolculuk bitirme isteği zaten beklemede"}

    now_iso = datetime.utcnow().isoformat()
    end_request_payload = {
        "kind": FORCE_END_COUNTERPARTY_KIND,
        "status": "pending",
        "initiator_id": resolved_ender,
        "initiator_type": et,
        "requested_at": now_iso,
    }
    try:
        supabase.table("tags").update({"end_request": end_request_payload}).eq("id", tid).execute()
    except Exception as e:
        logger.error(f"apply_force_end_trip: tag güncellenemedi: {e}")
        return {"success": False, "error": str(e)}

    invalidate_tag_cache(tid, passenger_id, driver_id)

    ender_name = ""
    try:
        _en = supabase.table("users").select("name").eq("id", resolved_ender).limit(1).execute()
        if _en.data:
            ender_name = (str(_en.data[0].get("name") or "")).strip()
    except Exception:
        pass

    other_user_id = driver_id if et == "passenger" else passenger_id
    ender_role = "Yolcu" if et == "passenger" else "Sürücü"
    if other_user_id:
        try:
            _fe_body = (
                f"{_push_first_name(ender_name)} ({ender_role}) bitirmek istiyor • Yanıt için dokun"
                if ender_name
                else f"{ender_role} yolculuğu bitirmek istiyor • Yanıt için dokun"
            )
            if len(_fe_body) > 72:
                _fe_body = _fe_body[:69] + "…"
            asyncio.create_task(
                send_push_notification(
                    other_user_id,
                    "Yolculuğu bitirme isteği",
                    _fe_body,
                    {
                        "type": "force_ended",
                        "tag_id": tid,
                        "ender_type": et,
                        "can_report": True,
                    },
                )
            )
        except Exception as push_err:
            logger.warning(f"apply_force_end_trip push: {push_err}")

    counterparty_id = passenger_id if et == "driver" else driver_id
    if counterparty_id:
        try:
            await emit_socket_event_to_user(
                counterparty_id,
                "force_end_counterparty_prompt",
                {
                    "tag_id": tid,
                    "initiator_id": resolved_ender,
                    "initiator_type": et,
                    "initiator_name": ender_name,
                },
            )
        except Exception as prompt_err:
            logger.warning(f"apply_force_end_trip force_end_counterparty_prompt: {prompt_err}")

    logger.info(f"✅ apply_force_end_trip: tag={tid} ender_type={et} ender={resolved_ender[:12]}…")
    return {
        "success": True,
        "new_points": None,
        "new_rating": None,
        "ender_type": et,
        "passenger_id": passenger_id,
        "driver_id": driver_id,
    }


async def dispatch_offer_to_next_driver(tag_id: str, tag_data: dict):
    """
    Sıradaki sürücüye teklif gönder
    Timeout sonrası otomatik olarak sonrakine geç
    """
    try:
        config = await get_dispatch_config()
        timeout = config.get("driver_offer_timeout", 10)
        merged = {**(dispatch_tag_context.get(tag_id) or {}), **(tag_data or {})}
        dispatch_tag_context[tag_id] = merged

        queue = dispatch_queues.get(tag_id, [])
        
        # Bekleyen sürücü bul
        next_entry = None
        for entry in queue:
            if entry["status"] == "waiting":
                next_entry = entry
                break
        
        if not next_entry:
            logger.info(f"📭 Dispatch: Tag {tag_id} - Kuyruk bitti, yayın yok (sıralı mod)")
            dispatch_tag_context.pop(tag_id, None)
            dispatch_queues.pop(tag_id, None)
            passenger_id = merged.get("passenger_id")
            if passenger_id:
                try:
                    await sio.emit(
                        "dispatch_exhausted",
                        {"tag_id": tag_id, "message": "Yakında uygun sürücü bulunamadı"},
                        room=_normalize_user_room(passenger_id),
                    )
                except Exception as emit_err:
                    logger.warning(f"dispatch_exhausted emit: {emit_err}")
            return
        
        driver_id = next_entry["driver_id"]
        driver_name = next_entry["driver_name"]

        offer_data = {
            "tag_id": tag_id,
            "passenger_id": merged.get("passenger_id"),
            "passenger_name": merged.get("passenger_name", "Yolcu"),
            "pickup_location": merged.get("pickup_location"),
            "pickup_lat": merged.get("pickup_lat"),
            "pickup_lng": merged.get("pickup_lng"),
            "dropoff_location": merged.get("dropoff_location"),
            "dropoff_lat": merged.get("dropoff_lat"),
            "dropoff_lng": merged.get("dropoff_lng"),
            "offered_price": merged.get("final_price") or merged.get("offered_price"),
            "distance_km": merged.get("distance_km", 0),
            "estimated_minutes": merged.get("estimated_minutes", 0),
            "distance_to_pickup": next_entry.get("distance_km", 0),
            "dispatch_timeout": timeout,
            "is_dispatch": True,  # Bu bir dispatch teklifi
            "passenger_vehicle_kind": merged.get("passenger_preferred_vehicle") or "car",
            "passenger_payment_method": merged.get("passenger_payment_method"),
        }

        logger.info(
            "[normal_ride_dispatch] tag_id=%s mode=sequential_queue driver_id=%s queue_waiting_left=%s",
            tag_id,
            str(driver_id)[:96],
            sum(1 for e in queue if e.get("status") == "waiting"),
        )
        sent_ok = await emit_new_passenger_offer_to_driver(driver_id, offer_data)
        if not sent_ok:
            logger.info(
                f"📭 Dispatch sıradaki sürücü atlandı (aktif değil): tag={tag_id} driver={driver_name}"
            )
            next_entry["status"] = "expired"
            try:
                supabase.table("dispatch_queue").update({
                    "status": "expired",
                    "responded_at": datetime.utcnow().isoformat(),
                }).eq("id", next_entry["id"]).execute()
            except Exception:
                pass
            await emit_passenger_offer_revoked(driver_id, tag_id, revoke_reason="emit_failed")
            fresh = dispatch_tag_context.get(tag_id, merged)
            await dispatch_offer_to_next_driver(tag_id, fresh)
            return

        next_entry["status"] = "sent"
        next_entry["sent_at"] = datetime.utcnow().isoformat()
        try:
            supabase.table("dispatch_queue").update({
                "status": "sent",
                "sent_at": next_entry["sent_at"],
            }).eq("id", next_entry["id"]).execute()
        except Exception:
            pass

        logger.info(f"📤 Dispatch teklif gönderildi: tag={tag_id}, sürücü={driver_name} (priority={next_entry['priority']})")
        # Push: emit_new_passenger_offer_to_driver içinde FCM (send_trip_push_and_log).

        # Timeout task başlat
        expired_driver_id = driver_id

        async def timeout_handler():
            await asyncio.sleep(timeout)
            
            # Tag hala waiting durumunda mı?
            tag_result = supabase.table("tags").select("status").eq("id", tag_id).execute()
            if tag_result.data and tag_result.data[0].get("status") == "waiting":
                # Bu sürücü yanıt vermedi, expired yap
                next_entry["status"] = "expired"
                try:
                    supabase.table("dispatch_queue").update({"status": "expired"}).eq("id", next_entry["id"]).execute()
                except Exception:
                    pass
                
                logger.info(f"⏱️ Dispatch timeout: tag={tag_id}, sürücü={driver_name}")
                await emit_passenger_offer_revoked(
                    expired_driver_id, tag_id, revoke_reason="dispatch_timeout"
                )

                # Sonraki sürücüye geç
                fresh = dispatch_tag_context.get(tag_id, merged)
                await dispatch_offer_to_next_driver(tag_id, fresh)
        
        # Task'ı kaydet
        task = asyncio.create_task(timeout_handler())
        active_dispatch_tasks[f"{tag_id}_{driver_id}"] = task
        
    except Exception as e:
        logger.error(f"❌ Dispatch offer error: {e}")

async def broadcast_offer_to_all(tag_id: str, tag_data: dict) -> int:
    """
    20 km içinde uygun online sürücülere (yolcu araç tercihi ile aynı tipteki sürücüler)
    mesafeye göre en yakın N kişiye aynı anda socket (`new_passenger_offer`) + push.
    İlk kabul eden kazanır (accept_ride atomik).
    Dönüş: bildirilen sürücü sayısı (0 = kimse yok / hata).
    """
    try:
        pickup_lat = tag_data.get("pickup_lat")
        pickup_lng = tag_data.get("pickup_lng")
        
        if not pickup_lat or not pickup_lng:
            logger.warning(f"📢 Broadcast atlandı: konum bilgisi yok")
            return 0

        pref = _canonical_vehicle_kind(tag_data.get("passenger_preferred_vehicle"))
        if pref is None and tag_data.get("passenger_id"):
            try:
                pr = (
                    supabase.table("users")
                    .select("driver_details")
                    .eq("id", tag_data["passenger_id"])
                    .limit(1)
                    .execute()
                )
                if pr.data:
                    pref = _passenger_preferred_vehicle_from_row(pr.data[0])
            except Exception:
                pass
        pref = pref or "car"
        
        now = datetime.utcnow().isoformat()
        q = supabase.table("users").select(
            "id, latitude, longitude, driver_details"
        ).eq("driver_online", True)
        drivers_result = _apply_driver_active_until_filter(q, now).execute()
        
        if not drivers_result.data:
            logger.info(f"📢 Broadcast: Uygun sürücü yok")
            return 0
        
        passenger_pid = tag_data.get("passenger_id")
        plat_b, plng_b = float(pickup_lat), float(pickup_lng)
        origin_points: list[tuple[str, float, float]] = []
        for driver in drivers_result.data:
            d_lat = driver.get("latitude")
            d_lng = driver.get("longitude")
            if not d_lat or not d_lng:
                continue
            if passenger_pid and str(driver["id"]) == str(passenger_pid):
                continue
            eff = _effective_driver_vehicle_kind(driver)
            if not _driver_matches_passenger_vehicle_pref(eff, pref):
                continue
            try:
                d_laf = float(d_lat)
                d_log = float(d_lng)
            except (TypeError, ValueError):
                continue
            if not _match_bbox_prefilter_deg(plat_b, plng_b, d_laf, d_log):
                continue
            origin_points.append((str(driver["id"]).strip().lower(), d_laf, d_log))

        _match_t0 = time.time()
        try:
            meta_br = await get_real_route_meta_batch_origins_to_dest(plat_b, plng_b, origin_points)
        except Exception as e:
            logger.error("[MATCH] broadcast batch failed tag_id=%s: %s", tag_id, e, exc_info=True)
            meta_br = {}
        logger.info("[MATCH] MATCH_TIME broadcast_offer_batch_s: %.4f tag_id=%s", time.time() - _match_t0, tag_id)
        with_distance = []
        for did, row in meta_br.items():
            road_km = float(row.get("distance_km", 0))
            if road_km > BROADCAST_RADIUS_KM:
                continue
            r_eta = int(max(1, round(float(row.get("duration_min", 1)))))
            with_distance.append((did, road_km, r_eta))
        if not with_distance:
            if not origin_points:
                logger.info("[MATCH] broadcast empty reason=no_origin_points tag_id=%s", tag_id)
            elif not meta_br:
                logger.info(
                    "[MATCH] broadcast empty reason=no_routing_results tag_id=%s origins=%d",
                    tag_id,
                    len(origin_points),
                )
            else:
                logger.info(
                    "[MATCH] broadcast empty reason=all_gt_radius tag_id=%s radius_km=%s meta=%d",
                    tag_id,
                    BROADCAST_RADIUS_KM,
                    len(meta_br),
                )
            logger.info(f"📢 Broadcast: {BROADCAST_RADIUS_KM} km yol içinde sürücü yok")
            return 0

        with_distance.sort(key=lambda x: x[1])
        top = with_distance[:BROADCAST_MAX_RECIPIENTS]
        logger.info(
            "[MATCH] broadcast final_included driver_ids=%s tag_id=%s",
            [t[0] for t in top],
            tag_id,
        )

        timeout_sec = BROADCAST_ACCEPT_WINDOW_SECONDS
        price = tag_data.get("final_price") or tag_data.get("offered_price", 0)
        trip_distance_km = tag_data.get("distance_km") or tag_data.get("trip_distance_km") or 0
        trip_dur = tag_data.get("estimated_minutes") or tag_data.get("trip_duration_min") or 0

        n_sent = 0
        for driver_id, r_pick_km, r_eta in top:
            offer_data = {
                "tag_id": tag_id,
                "passenger_id": tag_data.get("passenger_id"),
                "passenger_name": tag_data.get("passenger_name", "Yolcu"),
                "pickup_location": tag_data.get("pickup_location"),
                "pickup_lat": pickup_lat,
                "pickup_lng": pickup_lng,
                "dropoff_location": tag_data.get("dropoff_location"),
                "dropoff_lat": tag_data.get("dropoff_lat"),
                "dropoff_lng": tag_data.get("dropoff_lng"),
                "offered_price": tag_data.get("final_price") or tag_data.get("offered_price"),
                "distance_km": trip_distance_km,
                "estimated_minutes": trip_dur,
                "trip_distance_km": trip_distance_km,
                "trip_duration_min": trip_dur,
                "pickup_distance_km": round(r_pick_km, 1),
                "pickup_eta_min": r_eta,
                "distance_to_pickup": round(r_pick_km, 2),
                "time_to_passenger_min": r_eta,
                "dispatch_timeout": timeout_sec,
                "is_broadcast": True,
                "passenger_vehicle_kind": pref,
                "passenger_payment_method": tag_data.get("passenger_payment_method"),
            }
            did = str(driver_id).strip().lower()
            if not await is_driver_eligible_for_dispatch_offer(did):
                logger.info(f"📢 Broadcast atlandı (aktif değil): driver={did[:13]}… tag={tag_id}")
                continue
            ok = await emit_new_passenger_offer_to_driver(did, offer_data)
            if not ok:
                continue
            n_sent += 1
            # Push: emit_new_passenger_offer_to_driver içinde FCM (send_trip_push_and_log).
        
        logger.info(
            f"📢 Broadcast: tag={tag_id}, gönderilen={n_sent}/{BROADCAST_MAX_RECIPIENTS} sürücü "
            f"({BROADCAST_RADIUS_KM} km yol, {timeout_sec}s pencere, yolcu_araç_tipi={pref})"
        )
        return n_sent
    except Exception as e:
        logger.error(f"Broadcast error: {e}")
        return 0


# ==================== ROLLING BATCH DISPATCH (bellek + dispatch_queue senkronu) ====================


async def _expire_dispatch_queue_rows_for_tag(tag_id: str) -> None:
    """Aynı tag için eski waiting/sent satırlarını kapat (polling ile uyum)."""
    try:
        now = datetime.utcnow().isoformat()
        supabase.table("dispatch_queue").update(
            {"status": "expired", "responded_at": now}
        ).eq("tag_id", tag_id).in_("status", ["waiting", "sent"]).execute()
    except Exception as e:
        logger.warning("dispatch_queue expire tag=%s: %s", tag_id, e)


async def _dispatch_queue_insert_after_emit(
    tag_id: str,
    driver_id: str,
    priority: int,
) -> bool:
    """
    Socket emit sonrası tek sürücü satırı — /driver/dispatch-pending-offer ile uyum.
    Log satırı deploy doğrulaması için sabit: 'dispatch_queue rolling sync'
    """
    did = str(driver_id).strip().lower() if driver_id else ""
    if not did:
        logger.warning("dispatch_queue rolling sync tag=%s driver=(boş) ok=0", tag_id)
        return False
    now = datetime.utcnow().isoformat()
    row = {
        "id": str(uuid.uuid4()),
        "tag_id": tag_id,
        "driver_id": did,
        "priority": int(priority),
        "status": "sent",
        "created_at": now,
        "sent_at": now,
    }
    ins = {k: row[k] for k in DISPATCH_QUEUE_DB_KEYS if k in row}
    try:
        supabase.table("dispatch_queue").insert(ins).execute()
        logger.info(
            "dispatch_queue rolling sync tag=%s driver=%s priority=%s ok=1",
            tag_id,
            did,
            priority,
        )
        return True
    except Exception as e:
        logger.warning(
            "dispatch_queue rolling sync tag=%s driver=%s priority=%s ok=0 err=%s",
            tag_id,
            did,
            priority,
            e,
        )
        return False


async def rolling_dispatch_stop(
    tag_id: str,
    *,
    revoke_offers: bool = True,
    except_driver_id: Optional[str] = None,
) -> None:
    """Zamanlayıcıyı durdur, rolling state'i sil; isteğe bağlı batch'e remove_offer."""
    old = rolling_dispatch_tasks.pop(tag_id, None)
    if old is not None and not old.done():
        try:
            old.cancel()
        except Exception:
            pass
    st = rolling_dispatch_index.pop(tag_id, None)
    if revoke_offers and st:
        ex = str(except_driver_id).strip().lower() if except_driver_id else None
        for did in st.get("current_batch") or []:
            if ex and str(did).strip().lower() == ex:
                continue
            try:
                await emit_socket_event_to_user(did, "remove_offer", {"tag_id": tag_id})
            except Exception:
                pass
    await _expire_dispatch_queue_rows_for_tag(tag_id)


async def rolling_dispatch_batch(tag_id: str) -> None:
    """
    Pickup + anlık konumlara göre yeniden hesaplanan en yakın BATCH_SIZE uygun sürücü (kalıcı excluded).
    Önceki batch ile kıyas: yalnız çıkan sürücülere remove_offer; hem dalgalarda kalanlara dokunulmaz
    (gereksiz remove+offer flicker önlemi). DISPATCH_TIMEOUT sn sonra tag waiting ise dalga tekrarlanır.
    """
    state = rolling_dispatch_index.get(tag_id)
    if not state:
        return

    prev_batch = [
        str(x).strip().lower()
        for x in (state.get("current_batch") or [])
        if x is not None and str(x).strip() != ""
    ]

    old = rolling_dispatch_tasks.pop(tag_id, None)
    if old is not None and not old.done():
        try:
            old.cancel()
        except Exception:
            pass

    tag_data = state.get("full_tag") or {}
    pickup_lat = tag_data.get("pickup_lat")
    pickup_lng = tag_data.get("pickup_lng")
    if pickup_lat is None or pickup_lng is None:
        await rolling_dispatch_stop(tag_id, revoke_offers=False)
        return
    try:
        pickup_lat_f = float(pickup_lat)
        pickup_lng_f = float(pickup_lng)
    except (TypeError, ValueError):
        await rolling_dispatch_stop(tag_id, revoke_offers=False)
        return

    excluded_raw = state.get("excluded_driver_ids") or set()
    if isinstance(excluded_raw, set):
        excluded: set[str] = {str(x).strip().lower() for x in excluded_raw if x}
    else:
        excluded = {str(x).strip().lower() for x in excluded_raw if x}
    state["excluded_driver_ids"] = excluded

    passenger_id = tag_data.get("passenger_id")
    exclude_ids: list = []
    if passenger_id:
        exclude_ids.append(str(passenger_id).strip().lower())
    exclude_ids.extend(excluded)

    pref = _canonical_vehicle_kind(tag_data.get("passenger_preferred_vehicle")) or "car"
    if tag_data.get("passenger_id"):
        try:
            pr = (
                supabase.table("users")
                .select("driver_details")
                .eq("id", tag_data["passenger_id"])
                .limit(1)
                .execute()
            )
            if pr.data:
                pref = _passenger_preferred_vehicle_from_row(pr.data[0]) or pref
        except Exception:
            pass
    pref = pref or "car"

    use_relaxed_vehicle = bool(state.get("relax_vehicle_on_empty"))
    eligible = await find_eligible_drivers(
        pickup_lat_f,
        pickup_lng_f,
        exclude_ids=exclude_ids,
        passenger_vehicle_kind=pref,
        radius_km=DISPATCH_RADIUS_KM,
        vehicle_filter=not use_relaxed_vehicle,
    )
    if (
        not eligible
        and not use_relaxed_vehicle
        and _dispatch_env_flag("DISPATCH_RELAX_VEHICLE_ON_EMPTY")
    ):
        eligible = await find_eligible_drivers(
            pickup_lat_f,
            pickup_lng_f,
            exclude_ids=exclude_ids,
            passenger_vehicle_kind=pref,
            radius_km=DISPATCH_RADIUS_KM,
            vehicle_filter=False,
        )
        if eligible:
            state["relax_vehicle_on_empty"] = True
            use_relaxed_vehicle = True

    if not eligible:
        logger.info(
            "[DISPATCH_BATCH] tag=%s event=exhausted recomputed_eligible=0 excluded=%s relax=%s",
            tag_id,
            len(excluded),
            use_relaxed_vehicle,
        )
        for did in prev_batch:
            try:
                await emit_socket_event_to_user(did, "remove_offer", {"tag_id": tag_id})
            except Exception:
                pass
        pid = (tag_data or {}).get("passenger_id")
        await rolling_dispatch_stop(tag_id, revoke_offers=False)
        if pid:
            try:
                pid_r = await resolve_user_id(str(pid).strip())
                await sio.emit(
                    "dispatch_exhausted",
                    {"tag_id": tag_id, "message": "Yakında uygun sürücü kalmadı"},
                    room=_normalize_user_room(pid_r),
                )
            except Exception as ex:
                logger.warning("[DISPATCH_BATCH] tag=%s dispatch_exhausted_emit_err=%s", tag_id, ex)
        return

    batch_entries = eligible[:BATCH_SIZE]
    next_batch_ids = [str(e["driver_id"]).strip().lower() for e in batch_entries]
    prev_set = set(prev_batch)
    next_set = set(next_batch_ids)

    for did in prev_set - next_set:
        try:
            await emit_socket_event_to_user(did, "remove_offer", {"tag_id": tag_id})
        except Exception:
            pass

    newly_arrived_set = next_set - prev_set

    state["batch_seq"] = int(state.get("batch_seq") or 0) + 1
    bseq = state["batch_seq"]

    state["current_batch"] = list(next_batch_ids)

    logger.info(
        "[DISPATCH_BATCH] tag=%s event=batch_start batch_seq=%s driver_ids=%s eligible_total=%s "
        "timeout_sec=%s batch_size=%s radius_km=%s excluded=%s",
        tag_id,
        bseq,
        state["current_batch"],
        len(eligible),
        DISPATCH_TIMEOUT,
        BATCH_SIZE,
        DISPATCH_RADIUS_KM,
        len(excluded),
    )

    offer_base = {
        "tag_id": tag_id,
        "passenger_id": tag_data.get("passenger_id"),
        "passenger_name": tag_data.get("passenger_name", "Yolcu"),
        "pickup_location": tag_data.get("pickup_location"),
        "pickup_lat": tag_data.get("pickup_lat"),
        "pickup_lng": tag_data.get("pickup_lng"),
        "dropoff_location": tag_data.get("dropoff_location"),
        "dropoff_lat": tag_data.get("dropoff_lat"),
        "dropoff_lng": tag_data.get("dropoff_lng"),
        "offered_price": tag_data.get("final_price") or tag_data.get("offered_price"),
        "distance_km": tag_data.get("distance_km", 0),
        "estimated_minutes": tag_data.get("estimated_minutes", 0),
        "trip_distance_km": tag_data.get("trip_distance_km")
        or tag_data.get("distance_km", 0),
        "trip_duration_min": tag_data.get("trip_duration_min")
        or tag_data.get("estimated_minutes", 0),
        "dispatch_timeout": DISPATCH_TIMEOUT,
        "is_rolling_batch": True,
        "passenger_vehicle_kind": pref,
        "passenger_payment_method": tag_data.get("passenger_payment_method"),
    }

    # Bu batch için eski waiting/sent satırlarını kapat; insert her sürücüde emit SONRASI
    await _expire_dispatch_queue_rows_for_tag(tag_id)

    n_queue_ok = 0
    slot_i = 0
    for entry in batch_entries:
        d_id = str(entry["driver_id"]).strip().lower()
        if d_id not in newly_arrived_set:
            continue
        if not await is_driver_eligible_for_dispatch_offer(d_id):
            logger.info("rolling batch atlandı (aktif değil) tag=%s driver=%s", tag_id, d_id)
            continue
        pk_km = entry.get("distance_km", 0)
        pk_min = entry.get("duration_min")
        offer_data = {
            **offer_base,
            "distance_to_pickup": pk_km,
            "pickup_distance_km": round(float(pk_km), 1) if pk_km else None,
            "pickup_eta_min": int(pk_min) if pk_min is not None else None,
            "time_to_passenger_min": int(pk_min) if pk_min is not None else None,
        }
        if not await emit_new_passenger_offer_to_driver(d_id, offer_data):
            continue
        logger.info(
            "new_passenger_offer emitted tag=%s driver=%s (socket veya room)",
            tag_id,
            d_id,
        )
        slot_i += 1
        # Push: emit_new_passenger_offer_to_driver içinde FCM (send_trip_push_and_log).
        if await _dispatch_queue_insert_after_emit(tag_id, d_id, slot_i):
            n_queue_ok += 1

    logger.info(
        "dispatch_queue rolling sync tag=%s batch_summary drivers=%s queue_ok=%s excluded=%s",
        tag_id,
        len(batch_entries),
        n_queue_ok,
        len(excluded),
    )
    logger.info(
        "[DISPATCH_BATCH] tag=%s event=batch_emit_done batch_seq=%s sent_slots=%s excluded=%s",
        tag_id,
        bseq,
        n_queue_ok,
        len(excluded),
    )
    logger.info(
        "[normal_ride_dispatch] tag_id=%s batch_seq=%s eligible_total=%s sent_slots=%s vehicle_relaxed=%s",
        tag_id,
        bseq,
        len(eligible),
        n_queue_ok,
        use_relaxed_vehicle,
    )

    async def _timeout_tick():
        try:
            await asyncio.sleep(ROLLING_DISPATCH_BATCH_TIMEOUT_SECONDS)
            if tag_id not in rolling_dispatch_index:
                return
            tr = supabase.table("tags").select("status").eq("id", tag_id).limit(1).execute()
            if not tr.data or tr.data[0].get("status") != "waiting":
                logger.info(
                    "[DISPATCH_BATCH] tag=%s event=batch_timeout_skip status=%s (matched/cancelled/non-waiting)",
                    tag_id,
                    (tr.data[0].get("status") if tr.data else None),
                )
                await rolling_dispatch_stop(tag_id, revoke_offers=False)
                return
            logger.info(
                "[DISPATCH_BATCH] tag=%s event=batch_timeout_fired after_s=%.2f next_batch_scheduled=1",
                tag_id,
                ROLLING_DISPATCH_BATCH_TIMEOUT_SECONDS,
            )
            await rolling_dispatch_batch(tag_id)
        except asyncio.CancelledError:
            raise
        except Exception as ex:
            logger.warning(f"rolling_dispatch_batch timer tag={tag_id}: {ex}")

    rolling_dispatch_tasks[tag_id] = asyncio.create_task(_timeout_tick())


async def rolling_dispatch_start(tag_id: str) -> int:
    """DB'den tag; 20 km + vehicle_kind + mesafe sırası; ilk batch + timer. Dönüş: eligible sayısı."""
    logger.info("[normal_ride_dispatch_start] entering rolling_dispatch_start tag_id=%s", tag_id)
    await rolling_dispatch_stop(tag_id, revoke_offers=False)
    tr = supabase.table("tags").select("*").eq("id", tag_id).limit(1).execute()
    if not tr.data:
        logger.warning(f"rolling_dispatch_start: tag yok veya okunamadı tag_id={tag_id}")
        return 0
    row = tr.data[0]
    if row.get("status") != "waiting":
        logger.warning(
            f"rolling_dispatch_start: tag status≠waiting (status={row.get('status')!r}) tag_id={tag_id}"
        )
        return 0
    passenger_id = row.get("passenger_id")
    if passenger_id:
        passenger_id = await resolve_user_id(passenger_id)
    passenger_name = row.get("passenger_name") or "Yolcu"
    passenger_pref = _canonical_vehicle_kind(row.get("passenger_preferred_vehicle"))
    prow_row = None
    if passenger_id:
        try:
            prow = (
                supabase.table("users")
                .select("name, driver_details")
                .eq("id", passenger_id)
                .limit(1)
                .execute()
            )
            if prow.data:
                prow_row = prow.data[0]
                passenger_name = prow_row.get("name") or passenger_name
                if passenger_pref is None:
                    passenger_pref = _passenger_preferred_vehicle_from_row(prow_row)
        except Exception:
            pass
    passenger_pref = passenger_pref or "car"

    pickup_lat = row.get("pickup_lat")
    pickup_lng = row.get("pickup_lng")
    if pickup_lat is None or pickup_lng is None:
        logger.warning(
            f"rolling_dispatch_start: pickup koordinat eksik tag_id={tag_id} lat={pickup_lat} lng={pickup_lng}"
        )
        return 0
    try:
        pickup_lat_f = float(pickup_lat)
        pickup_lng_f = float(pickup_lng)
    except (TypeError, ValueError):
        logger.warning(
            f"rolling_dispatch_start: pickup koordinat sayısal değil tag_id={tag_id} lat={pickup_lat!r} lng={pickup_lng!r}"
        )
        return 0

    raw_drop = row.get("dropoff_location")
    drop_loc_str = str(raw_drop).strip() if raw_drop is not None and str(raw_drop).strip() else ""
    if not drop_loc_str:
        _dlat, _dlng = row.get("dropoff_lat"), row.get("dropoff_lng")
        if _dlat is not None and _dlng is not None:
            try:
                drop_loc_str = f"Hedef ({float(_dlat):.4f}, {float(_dlng):.4f})"
            except (TypeError, ValueError):
                drop_loc_str = "Haritadan seçilen hedef"
        else:
            drop_loc_str = "Hedef belirtilmedi"

    full_tag_data = {
        "passenger_id": passenger_id,
        "passenger_name": passenger_name,
        "pickup_lat": pickup_lat_f,
        "pickup_lng": pickup_lng_f,
        "pickup_location": row.get("pickup_location"),
        "dropoff_lat": row.get("dropoff_lat"),
        "dropoff_lng": row.get("dropoff_lng"),
        "dropoff_location": drop_loc_str,
        "final_price": row.get("final_price"),
        "offered_price": row.get("final_price"),
        "distance_km": row.get("distance_km", 0),
        "estimated_minutes": row.get("estimated_minutes", 0),
        "trip_distance_km": row.get("distance_km", 0),
        "trip_duration_min": row.get("estimated_minutes", 0),
        "passenger_preferred_vehicle": passenger_pref,
        "passenger_payment_method": row.get("passenger_payment_method"),
    }

    relax_used = False
    eligible = await find_eligible_drivers(
        pickup_lat_f,
        pickup_lng_f,
        exclude_ids=[passenger_id] if passenger_id else [],
        passenger_vehicle_kind=passenger_pref,
        radius_km=DISPATCH_RADIUS_KM,
    )
    if not eligible and _dispatch_env_flag("DISPATCH_RELAX_VEHICLE_ON_EMPTY"):
        logger.warning(
            "rolling_dispatch_start: DISPATCH_RELAX_VEHICLE_ON_EMPTY=1 — araç tipi filtresiz ikinci tarama tag_id=%s",
            tag_id,
        )
        eligible = await find_eligible_drivers(
            pickup_lat_f,
            pickup_lng_f,
            exclude_ids=[passenger_id] if passenger_id else [],
            passenger_vehicle_kind=passenger_pref,
            radius_km=DISPATCH_RADIUS_KM,
            vehicle_filter=False,
        )
        if eligible:
            relax_used = True
    if not eligible:
        logger.warning(
            f"rolling_dispatch_start: 0 uygun sürücü tag_id={tag_id} "
            f"radius={DISPATCH_RADIUS_KM}km pref={passenger_pref!r} pickup=({pickup_lat_f},{pickup_lng_f}). "
            f"Kontrol: users.driver_online=true, lat/lng dolu, mesafe≤{DISPATCH_RADIUS_KM}km, "
            f"araç tipi eşleşmesi (yolcu {passenger_pref!r}); isteğe bağlı DISPATCH_RELAX_VEHICLE_ON_EMPTY=1 veya DISPATCH_RADIUS_KM artırın. "
            f"Teklifler ayrıca dispatch_queue + socket ile gider; uvicorn server:socket_app ve mümkünse --workers 1 önerilir."
        )
        return 0

    rolling_dispatch_index[tag_id] = {
        "full_tag": full_tag_data,
        "current_batch": [],
        "batch_seq": 0,
        "excluded_driver_ids": set(),
        "relax_vehicle_on_empty": relax_used,
    }
    logger.info(
        "[DISPATCH_BATCH] tag=%s event=pipeline_start initial_eligible=%s batch_size=%s timeout_sec=%s "
        "radius_km=%s ordered_driver_ids=%s relax_vehicle_on_empty=%s",
        tag_id,
        len(eligible),
        BATCH_SIZE,
        DISPATCH_TIMEOUT,
        DISPATCH_RADIUS_KM,
        [e["driver_id"] for e in eligible],
        relax_used,
    )
    await rolling_dispatch_batch(tag_id)
    return len(eligible)


async def handle_dispatch_accept(tag_id: str, driver_id: str):
    """
    Sürücü dispatch teklifini kabul etti
    Queue'daki diğer kayıtları expire yap ve task'ları iptal et
    """
    try:
        queue = dispatch_queues.get(tag_id, [])
        did_norm = str(driver_id).strip().lower()

        for entry in queue:
            if str(entry.get("driver_id", "")).strip().lower() == did_norm:
                entry["status"] = "accepted"
                entry["responded_at"] = datetime.utcnow().isoformat()
            elif entry["status"] in ["waiting", "sent"]:
                entry["status"] = "expired"
        
        # Supabase güncelle
        try:
            supabase.table("dispatch_queue").update({"status": "accepted", "responded_at": datetime.utcnow().isoformat()}).eq("tag_id", tag_id).eq("driver_id", driver_id).execute()
            supabase.table("dispatch_queue").update({"status": "expired"}).eq("tag_id", tag_id).neq("driver_id", driver_id).in_("status", ["waiting", "sent"]).execute()
        except:
            pass
        
        # Bekleyen task'ları iptal et
        for key in list(active_dispatch_tasks.keys()):
            if key.startswith(f"{tag_id}_"):
                task = active_dispatch_tasks.pop(key, None)
                if task and not task.done():
                    task.cancel()
        
        # Queue'yu temizle
        dispatch_queues.pop(tag_id, None)
        dispatch_tag_context.pop(tag_id, None)
        
        logger.info(f"✅ Dispatch accept: tag={tag_id}, sürücü={driver_id}")
        
    except Exception as e:
        logger.error(f"Handle dispatch accept error: {e}")

async def handle_dispatch_reject(tag_id: str, driver_id: str):
    """Sürücü dispatch teklifini reddetti, sonrakine geç"""
    try:
        did_n = str(driver_id).strip().lower()
        rd = rolling_dispatch_index.get(tag_id)
        if rd:
            ex = rd.setdefault("excluded_driver_ids", set())
            if not isinstance(ex, set):
                ex = {str(x).strip().lower() for x in ex if x}
                rd["excluded_driver_ids"] = ex
            ex.add(did_n)
            try:
                await emit_socket_event_to_user(did_n, "remove_offer", {"tag_id": tag_id})
            except Exception:
                pass

        queue = dispatch_queues.get(tag_id, [])

        for entry in queue:
            if str(entry.get("driver_id", "")).strip().lower() == did_n:
                entry["status"] = "rejected"
                entry["responded_at"] = datetime.utcnow().isoformat()
                break

        # Supabase güncelle
        try:
            supabase.table("dispatch_queue").update({
                "status": "rejected",
                "responded_at": datetime.utcnow().isoformat()
            }).eq("tag_id", tag_id).eq("driver_id", driver_id).execute()
        except:
            pass

        # Bekleyen task'ı iptal et
        task_key = f"{tag_id}_{driver_id}"
        task = active_dispatch_tasks.pop(task_key, None)
        if task and not task.done():
            task.cancel()

        # Tag durumunu kontrol et
        tag_result = supabase.table("tags").select("status, passenger_id, passenger_name, pickup_lat, pickup_lng, pickup_location, dropoff_lat, dropoff_lng, dropoff_location, final_price").eq("id", tag_id).execute()

        if tag_result.data and tag_result.data[0].get("status") == "waiting":
            if tag_id not in rolling_dispatch_index:
                tag_row = tag_result.data[0]
                merged = {**(dispatch_tag_context.get(tag_id) or {}), **tag_row}
                await dispatch_offer_to_next_driver(tag_id, merged)

        logger.info(f"❌ Dispatch reject: tag={tag_id}, sürücü={driver_id}")
        
    except Exception as e:
        logger.error(f"Handle dispatch reject error: {e}")

logger.info("✅ Dispatch Queue sistemi yapılandırıldı")

