                asyncio.create_task(send_trip_push_and_log(
                    passenger_id, "driver_arrived",
                    "Sürücü geldi",
                    "Buluşma noktasına ulaştı • Görmek için dokun",
                    {"type": "driver_arrived", "tag_id": tag_id}
                ))
