# ==================== RATING SYSTEM ====================

@api_router.post("/trip/rate")
async def rate_user(rater_id: str, rated_user_id: str, rating: int, tag_id: str = None):
    """Kullanıcıyı puanla"""
    try:
        if rating < 1 or rating > 5:
            raise HTTPException(status_code=400, detail="Puan 1-5 arasında olmalı")
        
        # Mevcut rating bilgisi
        user_result = supabase.table("users").select("rating, total_ratings").eq("id", rated_user_id).execute()
        if not user_result.data:
            raise HTTPException(status_code=404, detail="Kullanıcı bulunamadı")
        
        user = user_result.data[0]
        current_rating = float(user.get("rating", 4.0))
        total_ratings = user.get("total_ratings", 0) or 0
        
        # Yeni ortalama hesapla
        new_total = total_ratings + 1
        new_rating = ((current_rating * total_ratings) + rating) / new_total
        new_rating = round(new_rating, 2)
        # Puan sütununu yıldız ortalaması ile hizala (1–5 → 0–100)
        new_points = int(round(max(0, min(100, (new_rating - 1.0) / 4.0 * 100))))

        supabase.table("users").update({
            "rating": new_rating,
            "total_ratings": new_total,
            "points": new_points,
        }).eq("id", rated_user_id).execute()
        
        return {"success": True, "new_rating": round(new_rating, 2)}
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"Rate user error: {e}")
        raise HTTPException(status_code=500, detail=str(e))

# ==================== PUSH NOTIFICATIONS ====================
# Kullanıcıya dönük kısa Türkçe metinler (Android önizleme ~60 karakter hedefi).
# Routing: _canonical_push_routing_data ve payload anahtarlarına dokunulmaz; yalnızca title/body iyileştirilir.


def _push_first_name(name: Optional[str], max_len: int = 10) -> str:
    n = (name or "").strip()
    if not n:
        return ""
    part = n.split()[0]
    if len(part) <= max_len:
        return part
    return part[: max_len - 1] + "…"


def _push_body_offer_from_context(offer_data: dict) -> str:
    """Sürücü yolculuk teklifi — TL, yol km, kabul penceresi (Android önizleme ~72)."""
    parts: List[str] = []
    try:
        raw = offer_data.get("offered_price") or offer_data.get("final_price")
        if raw is not None:
            p = int(float(raw))
            if p > 0:
                parts.append(f"{p} TL")
    except (TypeError, ValueError):
        pass
    try:
        dkm = offer_data.get("distance_km")
        if dkm is None:
            dkm = offer_data.get("trip_distance_km")
        if dkm is not None and float(dkm) > 0:
            parts.append(f"{float(dkm):.0f} km")
    except (TypeError, ValueError):
        pass
    to_sn = None
    try:
        raw_to = offer_data.get("dispatch_timeout")
        if raw_to is not None and int(raw_to) > 0:
            to_sn = int(raw_to)
    except (TypeError, ValueError):
        pass

    if parts and to_sn is not None:
        s = " • ".join(parts) + f" • {to_sn} sn içinde kabul et"
    elif parts:
        s = " • ".join(parts) + " • Detayları görmek için dokun"
    elif to_sn is not None:
        s = f"{to_sn} sn içinde kabul et"
    else:
        s = "Detayları görmek için dokun"
    return s if len(s) <= 72 else s[:69] + "…"


def _new_offer_push_data_from_offer(offer_data: dict) -> dict:
    """FCM data: type=new_offer + tag_id + yönlendirme alanları (socket sözleşmesine dokunulmaz)."""
    d: dict = {"type": "new_offer"}
    tid = offer_data.get("tag_id")
    if tid is not None:
        d["tag_id"] = str(tid)
    try:
        raw = offer_data.get("offered_price") or offer_data.get("final_price")
        if raw is not None:
            p = int(float(raw))
            if p > 0:
                d["price"] = p
    except (TypeError, ValueError):
        pass
    try:
        dkm = offer_data.get("distance_km") or offer_data.get("trip_distance_km")
        if dkm is not None:
            d["distance_km"] = float(dkm)
    except (TypeError, ValueError):
        pass
    to = offer_data.get("dispatch_timeout")
    if to is not None:
        try:
            d["timeout"] = int(to)
        except (TypeError, ValueError):
            pass
    if offer_data.get("is_broadcast"):
        d["is_broadcast"] = True
        d["action"] = "accept"
    if offer_data.get("is_dispatch"):
        d["is_dispatch"] = True
    if offer_data.get("is_rolling_batch"):
        d["is_rolling_batch"] = True
    return d


def build_call_push_payload(
    notification_type: str,
    caller_id: str,
    caller_name: str,
    call_type: str,
    *,
    call_id: str = None,
    channel_name: str = None,
    agora_token: str = None,
    room_url: str = None,
    room_name: str = None,
    tag_id: str = None,
    target_user_id: str = None,
):
    payload = {
        "type": notification_type,
        "caller_id": caller_id,
        "caller_name": caller_name,
        "call_type": call_type,
    }

    if target_user_id:
        payload["target_user_id"] = str(target_user_id).strip()
    if call_id:
        payload["call_id"] = call_id
    if channel_name:
        payload["channel_name"] = channel_name
    if agora_token:
        payload["agora_token"] = agora_token
    if room_url:
        payload["room_url"] = room_url
    if room_name:
        payload["room_name"] = room_name
    if tag_id:
        payload["tag_id"] = tag_id

    return payload

class ExpoPushService:
    EXPO_PUSH_URL = "https://exp.host/--/api/v2/push/send"
    
    @staticmethod
    def is_valid_token(token: str) -> bool:
        """
        Expo push token formatı:
        - Eski:  ExponentPushToken[...]
        - Yeni:  ExpoPushToken[...]
        Her iki formatı da kabul et.
        """
        if not token:
            return False
        return token.startswith("ExponentPushToken[") or token.startswith("ExpoPushToken[")
    
    @staticmethod
    async def send(tokens: list, title: str, body: str, data: dict = None) -> dict:
        if not tokens:
            return {"sent": 0, "failed": 0}
        
        valid_tokens = [t for t in tokens if ExpoPushService.is_valid_token(t)]
        if not valid_tokens:
            return {"sent": 0, "failed": len(tokens)}
        
        str_data = _expo_push_data_stringify(data or {})
        ch = expo_android_channel_id_for_data(str_data)
        messages = [
            {
                "to": t,
                "title": title,
                "body": body,
                "sound": "default",
                "priority": "high",
                "channelId": ch,
                "data": str_data,
            }
            for t in valid_tokens
        ]
        for t in valid_tokens:
            logger.info(f"🚀 Sending Expo push to {t}")

        try:
            async with httpx.AsyncClient(http2=False, timeout=30) as client:
                response = await client.post(
                    ExpoPushService.EXPO_PUSH_URL,
                    json=messages,
                    headers=_expo_push_request_headers(),
                    timeout=30,
                )
                result = response.json()
                tickets = result.get("data") or []
                sent = sum(1 for t in tickets if t.get("status") == "ok")
                for t in tickets:
                    if t.get("status") != "ok":
                        logger.warning(
                            f"Expo push ticket hata: status={t.get('status')} message={t.get('message')} details={t.get('details')}"
                        )
                return {"sent": sent, "failed": len(valid_tokens) - sent, "tickets": tickets}
        except Exception as e:
            logger.error(f"Push error: {e}")
            return {"sent": 0, "failed": len(valid_tokens)}


def _effective_register_transport(declared: Optional[str], raw_token: str) -> str:
    """
    Kayıt: expo vs fcm. token_type eksik/yanlışsa token şekline göre düzelt (FCM'nin expo alanına yazılmasını önle).
    Öncelik: geçerli Expo formatı → expo; aksi FCM benzeri (':' + uzun veya is_probable_fcm) → fcm; token_type=fcm → fcm.
    """
    t = (raw_token or "").strip()
    if not t:
        return "expo"
    if ExpoPushService.is_valid_token(t):
        return "expo"
    decl = (declared or "").strip().lower()
    if decl == "fcm":
        return "fcm"
    if ":" in t and len(t) >= 80:
        return "fcm"
    if is_probable_fcm_registration_token(t):
        return "fcm"
    return "expo"


class PushTokenRequest(BaseModel):
    user_id: str
    push_token: str
    platform: Optional[str] = "android"
    token_type: Optional[str] = Field(default=None, description="expo | fcm; null/omit = auto from token string")

@api_router.post("/user/register-push-token")
async def register_push_token_endpoint(
    request: Optional[PushTokenRequest] = Body(None),
    user_id: Optional[str] = Query(None),
    push_token: Optional[str] = Query(None),
    platform: Optional[str] = Query(None),
    token_type: Optional[str] = Query(None),
):
    """Push token kaydet — JSON body veya query (user_id, push_token, platform, token_type)."""
    try:
        _user_id = (request.user_id if request else None) or user_id
        _push_token = (request.push_token if request else None) or push_token
        _platform = (request.platform if request else None) or platform or "android"
        _declared = (request.token_type if request else None) or token_type
        _tok_type = _effective_register_transport(_declared, _push_token or "")
        if _tok_type not in ("expo", "fcm"):
            _tok_type = "expo"

        # Validasyonlar
        if not _user_id:
            return {"success": False, "detail": "user_id gerekli"}
        
        if not _push_token:
            return {"success": False, "detail": "push_token gerekli"}

        if _tok_type == "fcm":
            if ExpoPushService.is_valid_token(_push_token):
                return {"success": False, "detail": "token_type=fcm için Expo push token kabul edilmez"}
            if not is_probable_fcm_registration_token(_push_token):
                return {"success": False, "detail": "Geçersiz FCM registration token"}
        else:
            if not ExpoPushService.is_valid_token(_push_token):
                return {"success": False, "detail": "Sadece Expo push token desteklenir"}
        
        # Kullanıcıyı esnek şekilde bul:
        # 1) UUID (case-insensitive) / 2) legacy mongo_id / 3) telefon formatları
        resolved_user_id = None
        user_name = "Unknown"
        user_row = None
        raw_uid = str(_user_id).strip()

        # 1) ID ile doğrudan
        user_check = supabase.table("users").select("id, name, phone").eq("id", raw_uid).limit(1).execute()
        if not user_check.data and "-" in raw_uid:
            user_check = supabase.table("users").select("id, name, phone").eq("id", raw_uid.lower()).limit(1).execute()

        # 2) legacy mongo_id -> UUID
        if not user_check.data:
            try:
                rid = await resolve_user_id(raw_uid)
                if rid and rid != raw_uid:
                    user_check = supabase.table("users").select("id, name, phone").eq("id", str(rid).strip().lower()).limit(1).execute()
            except Exception as rid_err:
                logger.warning(f"⚠️ Push token resolve_user_id uyarısı: {rid_err}")

        # 3) Telefon fallback (id yerine telefon gönderildiyse)
        if not user_check.data:
            try:
                phone_e164 = normalize_phone_e164(raw_uid)
                if phone_e164:
                    digits_only = "".join(c for c in phone_e164 if c.isdigit())
                    ten_digit = digits_only[-10:] if len(digits_only) >= 10 else digits_only
                    candidates = [
                        phone_e164,                                  # +905...
                        digits_only,                                 # 905...
                        ten_digit,                                   # 5...
                        ("0" + ten_digit) if len(ten_digit) == 10 else None,  # 05...
                    ]
                    seen = set()
                    for candidate in candidates:
                        if not candidate or candidate in seen:
                            continue
                        seen.add(candidate)
                        user_check = supabase.table("users").select("id, name, phone").eq("phone", candidate).limit(1).execute()
                        if user_check.data:
                            break
            except Exception as phone_err:
                logger.warning(f"⚠️ Push token phone fallback uyarısı: {phone_err}")

        if user_check.data:
            user_row = user_check.data[0]
            resolved_user_id = str(user_row.get("id") or "").strip().lower()
            user_name = user_row.get("name", "Unknown")

        if not resolved_user_id:
            logger.warning("PUSH_REGISTER failed reason=user_not_found user_id=%s", _user_id)
            return {"success": False, "detail": "Kullanıcı bulunamadı"}

        if _tok_type == "fcm":
            try:
                supabase.table("users").update(
                    {
                        "fcm_push_token": _push_token,
                        "fcm_push_token_updated_at": datetime.utcnow().isoformat(),
                    }
                ).eq("id", resolved_user_id).execute()
                _user_push_token_upsert(resolved_user_id, _push_token)
                logger.info(
                    "PUSH_REGISTER transport=fcm user_id=%s",
                    resolved_user_id,
                )
            except Exception as col_err:
                logger.warning(
                    "PUSH_REGISTER failed transport=fcm user_id=%s err=%s",
                    resolved_user_id,
                    col_err,
                )
                return {
                    "success": False,
                    "detail": "fcm_push_token yazılamadı — Supabase migration (fcm_push_token kolonları) uygulayın",
                }
            return {
                "success": True,
                "message": f"FCM token kaydedildi: {user_name}",
                "platform": _platform,
                "token_type": "fcm",
                "resolved_user_id": resolved_user_id,
            }

        # users.push_token + users.expo_push_token (kolon yoksa kademeli fallback) — Expo yolu
        try:
            supabase.table("users").update({
                "push_token": _push_token,
                "expo_push_token": _push_token,
                "push_token_type": "expo",
                "push_token_updated_at": datetime.utcnow().isoformat()
            }).eq("id", resolved_user_id).execute()
        except Exception as col_err:
            logger.warning(f"⚠️ push_token tam alan güncellemesi başarısız, daraltılıyor: {col_err}")
            try:
                supabase.table("users").update({
                    "push_token": _push_token,
                    "expo_push_token": _push_token,
                    "push_token_updated_at": datetime.utcnow().isoformat()
                }).eq("id", resolved_user_id).execute()
            except Exception as col_err2:
                logger.warning(f"⚠️ expo_push_token yok, yalnızca push_token: {col_err2}")
                supabase.table("users").update({
                    "push_token": _push_token,
                    "push_token_updated_at": datetime.utcnow().isoformat()
                }).eq("id", resolved_user_id).execute()

        logger.info(
            "PUSH_REGISTER transport=expo user_id=%s",
            resolved_user_id,
        )
        return {
            "success": True,
            "message": f"Token kaydedildi: {user_name}",
            "platform": _platform,
            "token_type": "expo",
            "resolved_user_id": resolved_user_id,
        }
    except Exception as e:
        logger.exception("PUSH_REGISTER exception err=%s", e)
        return {"success": False, "detail": str(e)}


class RegisterPushTokenBody(BaseModel):
    """Oturumlu kullanıcı için Expo push token (Authorization: Bearer zorunlu)."""

    token: str
    platform: Optional[str] = "android"


@api_router.post("/register-push-token")
async def register_push_token_authenticated(
    body: RegisterPushTokenBody,
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """
    JWT ile kimliklenen kullanıcının Expo push token'ını kaydet.
    Body: {\"token\": \"ExpoPushToken[...]\", \"platform\": \"android\" | \"ios\"}
    """
    raw_uid = str(authenticated_user_id or "").strip()
    try:
        resolved = str(await resolve_user_id(raw_uid)).strip().lower()
    except Exception:
        resolved = ""
    if not resolved:
        raise HTTPException(status_code=401, detail="Geçersiz kullanıcı")
    tok = (body.token or "").strip()
    if not tok:
        raise HTTPException(status_code=400, detail="token gerekli")
    plat = (body.platform or "android").strip().lower() or "android"
    req = PushTokenRequest(user_id=resolved, push_token=tok, platform=plat, token_type="expo")
    result = await register_push_token_endpoint(request=req)
    if isinstance(result, dict) and result.get("success"):
        return result
    detail = (
        str(result.get("detail") or "Kayıt başarısız") if isinstance(result, dict) else "Kayıt başarısız"
    )
    raise HTTPException(status_code=400, detail=detail)


@api_router.post("/user/save-push-token")
async def save_push_token_alias(request: PushTokenRequest):
    """Expo token kaydı — register-push-token ile aynı gövde (POST /user/save-push-token)."""
    return await register_push_token_endpoint(request)


class UserFcmPushTokenBody(BaseModel):
    token: str


@api_router.post("/user/push-token")
async def user_push_token_register(
    body: UserFcmPushTokenBody,
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """
    Oturum kullanıcısı için FCM cihaz token'ı kaydet (user_push_tokens + users.fcm_push_token).
    Body: {\"token\": \"...\"}
    """
    try:
        raw_uid = str(authenticated_user_id or "").strip()
        resolved = str(await resolve_user_id(raw_uid)).strip().lower()
        if not resolved:
            raise HTTPException(status_code=401, detail="Geçersiz kullanıcı")
        tok = (body.token or "").strip()
        if not tok or not is_probable_fcm_registration_token(tok):
            raise HTTPException(status_code=400, detail="Geçersiz FCM token")
        _user_push_token_upsert(resolved, tok)
        try:
            supabase.table("users").update(
                {
                    "fcm_push_token": tok,
                    "fcm_push_token_updated_at": datetime.utcnow().isoformat(),
                }
            ).eq("id", resolved).execute()
        except Exception as col_err:
            logger.warning("user/push-token users.fcm update skipped user_id=%s err=%s", resolved[:12], col_err)
        logger.info("PUSH_REGISTER transport=fcm path=user/push-token user_id=%s", resolved[:12])
        return {"success": True, "message": "Push token kaydedildi"}
    except HTTPException:
        raise
    except Exception as e:
        logger.exception("user/push-token: %s", e)
        raise HTTPException(status_code=500, detail=str(e)) from e


@api_router.delete("/user/remove-push-token")
async def remove_push_token(user_id: str):
    """Push token sil"""
    try:
        try:
            supabase.table("user_push_tokens").delete().eq("user_id", str(user_id).strip().lower()).execute()
        except Exception as e:
            logger.debug("user_push_tokens clear on remove: %s", e)
        try:
            supabase.table("users").update({
                "push_token": None,
                "expo_push_token": None,
                "fcm_push_token": None,
                "fcm_push_token_updated_at": None,
                "push_token_updated_at": None
            }).eq("id", user_id).execute()
        except Exception:
            try:
                supabase.table("users").update({
                    "push_token": None,
                    "expo_push_token": None,
                    "push_token_updated_at": None
                }).eq("id", user_id).execute()
            except Exception:
                supabase.table("users").update({
                    "push_token": None,
                    "push_token_updated_at": None
                }).eq("id", user_id).execute()
        
        return {"success": True}
    except Exception as e:
        return {"success": False}

# Test endpoint - Push bildirim sistemini test et
@api_router.post("/test/push-notification")
async def test_push_notification(user_id: str, title: str = "Test Bildirimi", body: str = "Bu bir test bildirimidir"):
    """Push bildirim sistemini test et - DEBUG için"""
    try:
        logger.info(f"🧪 TEST: Push bildirim testi başlıyor: {user_id}")
        
        # Kullanıcı ve token bilgisi
        user_result = supabase.table("users").select("id, name, phone, push_token, push_token_updated_at").eq("id", user_id).execute()
        
        if not user_result.data:
            return {"success": False, "error": "Kullanıcı bulunamadı", "user_id": user_id}
        
        user = user_result.data[0]
        token = user.get("push_token")
        
        token_type = "expo" if token and ExpoPushService.is_valid_token(token) else "invalid"
        
        debug_info = {
            "user_id": user_id,
            "user_name": user.get("name"),
            "phone": user.get("phone"),
            "has_push_token": bool(token),
            "token_type": token_type,
            "token_preview": token[:40] + "..." if token else None,
            "token_updated_at": user.get("push_token_updated_at")
        }
        
        if not token:
            return {"success": False, "error": "Push token yok", "debug": debug_info}
        
        # Bildirimi gönder
        logger.info(f"🧪 TEST: Token tipi: {token_type}, gönderiliyor...")
        result = await send_push_notification(user_id, title, body, {"type": "test", "timestamp": datetime.utcnow().isoformat()})
        
        return {
            "success": result,
            "message": "Bildirim gönderildi" if result else "Bildirim gönderilemedi",
            "debug": debug_info
        }
    except Exception as e:
        logger.error(f"🧪 TEST: Hata: {e}")
        import traceback
        return {"success": False, "error": str(e), "traceback": traceback.format_exc()}


@api_router.post("/test/match-notification")
async def test_match_notification(
    passenger_id: str,
    driver_id: str,
    eta_min: int = 5,
    tag_id: str = None,
):
    """
    Eşleşme bildirimlerini test et: yolcuya ve sürücüye gerçek metinlerle push gönderir.
    Örnek: POST /api/test/match-notification?passenger_id=UUID&driver_id=UUID&eta_min=3
    """
    try:
        tag_id = tag_id or str(uuid.uuid4())
        passenger_title = "Eşleşme sağlandı"
        passenger_body = "Sürücü bulundu • Detayları görmek için dokun"
        driver_body = (
            f"Yolcuya ~{eta_min} dk • Rotayı görmek için dokun"
            if eta_min
            else "Yolcu hazır • Rotayı görmek için dokun"
        )
        results = {}
        # Yolcu
        ok_p = await send_trip_push_and_log(
            passenger_id,
            "matched",
            passenger_title,
            passenger_body,
            {"type": "match_found", "tag_id": tag_id, "driver_name": "Test Sürücü", "eta_min": eta_min},
        )
        results["passenger"] = {"success": ok_p, "title": passenger_title, "body": passenger_body}
        # Sürücü
        ok_d = await send_trip_push_and_log(
            driver_id,
            "matched",
            "Eşleşme sağlandı",
            driver_body,
            {"type": "match_confirmed", "tag_id": tag_id, "passenger_name": "Test Yolcu", "price": 0, "eta_min": eta_min},
        )
        results["driver"] = {"success": ok_d, "title": "Eşleşme sağlandı", "body": driver_body}
        return {
            "success": True,
            "message": "Eşleşme test bildirimleri gönderildi",
            "results": results,
        }
    except Exception as e:
        logger.error(f"🧪 TEST match-notification: {e}")
        import traceback
        return {"success": False, "error": str(e), "traceback": traceback.format_exc()}


@api_router.post("/test/push-notification-by-phone")
async def test_push_notification_by_phone(
    admin_phone: str,
    phone: str,
    title: str = "Test Bildirimi",
    body: str = "Leylek TAG bildirim sistemi testi – başarılı."
):
    """Admin: Telefon numarasına göre test push bildirimi gönder (sadece admin)."""
    if admin_phone not in ADMIN_PHONE_NUMBERS:
        raise HTTPException(status_code=403, detail="Admin yetkisi gerekli")
    clean_phone = phone.replace("+90", "").replace("90", "", 1).replace(" ", "").replace("-", "")
    try:
        user_result = supabase.table("users").select("id, name, push_token").eq("phone", clean_phone).execute()
        if not user_result.data:
            return {"success": False, "error": "Bu numaraya kayıtlı kullanıcı bulunamadı", "phone": clean_phone}
        user = user_result.data[0]
        user_id = user.get("id")
        token = user.get("push_token")
        if not token or not ExpoPushService.is_valid_token(token):
            logger.warning(f"Test push: geçersiz veya boş token user_id={user_id}, token_preview={str(token)[:80] if token else 'NONE'}")
            return {
                "success": False,
                "error": "Kullanıcının kayıtlı push token'ı yok veya geçersiz. Uygulama açılıp bildirim izni verilmiş olmalı.",
                "user_id": user_id,
            }
        success, receipt = await _send_expo_and_get_receipt(
            token,
            title,
            body,
            {"type": "test", "timestamp": datetime.utcnow().isoformat()},
            db_user_id=str(user_id) if user_id else None,
        )
        ticket_id = receipt.get("id") if isinstance(receipt, dict) else None
        expo_delivery = await _expo_get_push_receipts([ticket_id]) if ticket_id else {}
        return {
            "success": success,
            "message": "Test bildirimi gönderildi" if success else "Bildirim gönderilemedi",
            "user_id": user_id,
            "expo_receipt": receipt,
            "expo_delivery_receipts": expo_delivery,
        }
    except Exception as e:
        logger.error(f"Test push by phone error: {e}")
        import traceback
        return {"success": False, "error": str(e), "traceback": traceback.format_exc()}


@api_router.get("/test/push-user-by-phone")
async def test_push_user_by_phone(phone: str):
    """
    Telefon numarasına göre kullanıcı ve push token bilgisini döner (debug).
    Örnek: GET /api/test/push-user-by-phone?phone=5326427412
    """
    try:
        phone_e164 = normalize_phone_e164(phone)
        if not phone_e164:
            return {"found": False, "error": "Geçersiz telefon", "phone_raw": phone}
        digits_only = "".join(c for c in phone_e164 if c.isdigit())
        ten_digit = digits_only[-10:] if len(digits_only) >= 10 else digits_only
        candidates = [phone_e164, digits_only, ten_digit, "0" + ten_digit if len(ten_digit) == 10 else None]
        for candidate in candidates:
            if not candidate:
                continue
            r = supabase.table("users").select("id, name, phone, push_token").eq("phone", candidate).limit(1).execute()
            if r.data:
                row = r.data[0]
                token = row.get("push_token")
                return {
                    "found": True,
                    "user_id": row.get("id"),
                    "name": row.get("name"),
                    "phone_stored": row.get("phone"),
                    "has_push_token": bool(token and len(str(token)) > 10),
                    "token_preview": (token[:40] + "...") if token else None,
                    "tried_phone": candidate,
                }
        # Son deneme: phone içinde bu 10 rakam geçen kullanıcı (boşluk/tire ile kayıtlı olabilir)
        core = ten_digit
        if len(core) >= 10:
            r = supabase.table("users").select("id, name, phone, push_token").like("phone", f"%{core}%").limit(5).execute()
            if r.data:
                for row in r.data:
                    stored = (row.get("phone") or "")
                    if core in "".join(c for c in stored if c.isdigit()):
                        token = row.get("push_token")
                        return {
                            "found": True,
                            "user_id": row.get("id"),
                            "name": row.get("name"),
                            "phone_stored": stored,
                            "has_push_token": bool(token and len(str(token)) > 10),
                            "token_preview": (token[:40] + "...") if token else None,
                            "tried_phone": f"like(%{core}%)",
                        }
        return {"found": False, "tried_candidates": [c for c in candidates if c], "phone_e164": phone_e164}
    except Exception as e:
        return {"found": False, "error": str(e)}


