# --- Atomik eşleşme + tek aktif yolculuk (BUG-2 double-match) ---
MATCHABLE_TAG_STATUSES_FOR_ACCEPT_LIST = ["waiting", "offers_received", "pending"]


def _match_accept_log(event: str, **fields: object) -> None:
    try:
        body = dict(fields)
        body["event"] = event
        logger.info("%s %s", event, json.dumps(body, default=str, ensure_ascii=False))
    except Exception:
        logger.info("%s %s", event, fields)


def _norm_tag_id_str(tid: Optional[str]) -> str:
    s = str(tid or "").strip()
    if len(s) == 36 and s.count("-") == 4:
        return s.lower()
    return s


# Normal sürücü/yolcu "meşgul" kontrolü: yalnızca `tags`. ride_listings / muhabbet tablolarına bakılmaz.
# matched asla engel değildir; engel: in_progress / driver_arriving / passenger_onboard;
# accepted yalnızca created_at son 10 dk içindeyse engel.
_NORMAL_ACTIVE_QUERY_STATUSES = ["in_progress", "driver_arriving", "passenger_onboard", "accepted"]
_NORMAL_ACTIVE_ALWAYS_BLOCK = frozenset({"in_progress", "driver_arriving", "passenger_onboard"})


def _other_active_tag_id_sync(
    supabase_client: Client,
    *,
    column: str,
    user_id: str,
    exclude_tag_id: str,
) -> Optional[str]:
    """Başka bir tag'de gerçekten devam eden yolculuk varsa o tag id; yoksa None.

    Yalnızca `tags` okunur; ride_listings, muhabbet_conversations, muhabbet_messages yok.
    Yalnızca type='normal' tag'ler; matched / pending / offers_received / … bu kontrolde sorgulanmaz ve asla engel olmaz.
    """
    uid = str(user_id or "").strip()
    if not uid or column not in ("driver_id", "passenger_id"):
        ck = column if column in ("driver_id", "passenger_id") else "column"
        logger.info(
            "[normal-active-check] %s=%s blocking_tag_id=- blocking_status=- blocking_created_at=- allow=true reason=ignored_status",
            ck,
            (uid[:96] if uid else "-"),
        )
        return None
    ex = _norm_tag_id_str(exclude_tag_id)
    now = datetime.now(timezone.utc)
    accepted_fresh_seconds = 10 * 60
    who_key = "driver_id" if column == "driver_id" else "passenger_id"

    def _log(
        *,
        blocking_tag_id: str,
        blocking_status: str,
        blocking_created_at: str,
        allow: bool,
        reason: str,
    ) -> None:
        logger.info(
            "[normal-active-check] %s=%s blocking_tag_id=%s blocking_status=%s blocking_created_at=%s allow=%s reason=%s",
            who_key,
            uid[:96],
            blocking_tag_id[:96] if blocking_tag_id != "-" else "-",
            blocking_status,
            blocking_created_at[:96] if len(blocking_created_at) > 96 else blocking_created_at,
            str(allow).lower(),
            reason,
        )

    try:
        res = (
            supabase_client.table("tags")
            .select("id,status,created_at")
            .eq("type", TAG_TYPE_NORMAL)
            .eq(column, uid)
            .in_("status", list(_NORMAL_ACTIVE_QUERY_STATUSES))
            .execute()
        )
        for row in res.data or []:
            rid = _norm_tag_id_str(str(row.get("id") or ""))
            if not rid or rid == ex:
                continue
            st = str(row.get("status") or "").strip().lower()
            ca_raw = row.get("created_at")
            ca_log = str(ca_raw) if ca_raw is not None else ""

            if st in _NORMAL_ACTIVE_ALWAYS_BLOCK:
                _log(
                    blocking_tag_id=rid,
                    blocking_status=st,
                    blocking_created_at=ca_log,
                    allow=False,
                    reason="active_tag",
                )
                return str(row.get("id"))

            if st == "accepted":
                if not ca_raw:
                    _log(
                        blocking_tag_id=rid,
                        blocking_status=st,
                        blocking_created_at="-",
                        allow=True,
                        reason="stale_tag",
                    )
                    continue
                try:
                    t = _parse_iso_dt(str(ca_raw))
                    if t is None:
                        _log(
                            blocking_tag_id=rid,
                            blocking_status=st,
                            blocking_created_at=ca_log,
                            allow=True,
                            reason="stale_tag",
                        )
                        continue
                    if t.tzinfo is None:
                        t = t.replace(tzinfo=timezone.utc)
                    age_sec = (now - t).total_seconds()
                    if age_sec <= accepted_fresh_seconds:
                        _log(
                            blocking_tag_id=rid,
                            blocking_status=st,
                            blocking_created_at=ca_log,
                            allow=False,
                            reason="active_tag",
                        )
                        return str(row.get("id"))
                    _log(
                        blocking_tag_id=rid,
                        blocking_status=st,
                        blocking_created_at=ca_log,
                        allow=True,
                        reason="stale_tag",
                    )
                    continue
                except Exception:
                    _log(
                        blocking_tag_id=rid,
                        blocking_status=st,
                        blocking_created_at=ca_log,
                        allow=True,
                        reason="ignored_status",
                    )
                    continue

            _log(
                blocking_tag_id=rid,
                blocking_status=st,
                blocking_created_at=ca_log,
                allow=True,
                reason="ignored_status",
            )
    except Exception as exn:
        logger.warning("[normal-active-check] query failed: %s", exn)
    _log(
        blocking_tag_id="-",
        blocking_status="-",
        blocking_created_at="-",
        allow=True,
        reason="ignored_status",
    )
    return None


async def match_accept_cleanup_foreign_offers(
    resolved_driver_id: str,
    accepted_tag_id: str,
    *,
    log_path: str,
) -> None:
    """
    Bir sürücü tag T'yi kabul ettikten sonra: aynı sürücünün diğer tag'lerdeki
    bekleyen dispatch/offers satırlarını iptal et; remove_offer + passenger_offer_taken;
    rolling_dispatch_index / dispatch_queues bellek durumunu temizle.
    """
    did_raw = str(await resolve_user_id(str(resolved_driver_id).strip()) or resolved_driver_id).strip()
    did_low = did_raw.lower()
    acc = _norm_tag_id_str(accepted_tag_id)
    if not did_raw or not acc:
        return

    other_tag_ids: list[str] = []
    try:
        dq_sel = (
            supabase.table("dispatch_queue")
            .select("tag_id,id")
            .eq("driver_id", did_low)
            .in_("status", ["waiting", "sent"])
            .execute()
        )
        seen: set[str] = set()
        for row in dq_sel.data or []:
            ot = _norm_tag_id_str(str(row.get("tag_id") or ""))
            if ot and ot != acc and ot not in seen:
                seen.add(ot)
                other_tag_ids.append(ot)
    except Exception as e:
        logger.warning("MATCH_ACCEPT_CLEANUP dispatch_queue select failed: %s", e)

    try:
        supabase.table("dispatch_queue").update(
            {"status": "expired", "responded_at": datetime.utcnow().isoformat()}
        ).eq("driver_id", did_low).neq("tag_id", acc).in_("status", ["waiting", "sent"]).execute()
    except Exception as e:
        logger.warning("MATCH_ACCEPT_CLEANUP dispatch_queue bulk expire: %s", e)

    try:
        supabase.table("offers").update({"status": "rejected"}).eq("driver_id", did_raw).neq(
            "tag_id", acc
        ).eq("status", "pending").execute()
    except Exception as e:
        logger.warning("MATCH_ACCEPT_CLEANUP offers reject: %s", e)

    emit_count = 0
    for otid in other_tag_ids:
        payload = {
            "tag_id": otid,
            "revoke_reason": "driver_accepted_elsewhere",
            "accepted_tag_id": acc,
        }
        try:
            await emit_socket_event_to_user(did_raw, "remove_offer", payload)
            await emit_socket_event_to_user(did_raw, "passenger_offer_taken", payload)
            emit_count += 1
        except Exception as em:
            logger.warning("MATCH_ACCEPT_CLEANUP emit driver tag=%s: %s", otid, em)
        try:
            tr = supabase.table("tags").select("passenger_id").eq("id", otid).limit(1).execute()
            pid = None
            if tr.data:
                pid = tr.data[0].get("passenger_id")
            if pid:
                pid_r = await resolve_user_id(str(pid).strip())
                if pid_r:
                    await emit_socket_event_to_user(
                        str(pid_r),
                        "passenger_offer_taken",
                        {
                            "tag_id": otid,
                            "driver_id": did_raw,
                            "reason": "driver_locked_other_trip",
                            "accepted_tag_id": acc,
                        },
                    )
        except Exception as ep:
            logger.warning("MATCH_ACCEPT_CLEANUP passenger emit tag=%s: %s", otid, ep)

    for otid in list(dispatch_queues.keys()):
        if otid == acc:
            continue
        qmem = dispatch_queues.get(otid)
        if not qmem:
            continue
        newq = [
            e
            for e in qmem
            if str(e.get("driver_id", "")).strip().lower() != did_low
        ]
        if len(newq) != len(qmem):
            dispatch_queues[otid] = newq

    for otid, st in list(rolling_dispatch_index.items()):
        if otid == acc:
            continue
        cb = list(st.get("current_batch") or [])
        nb = [x for x in cb if str(x).strip().lower() != did_low]
        if len(nb) != len(cb):
            st["current_batch"] = nb
        ex_raw = st.get("excluded_driver_ids")
        if isinstance(ex_raw, set):
            ex_raw.add(did_low)
        else:
            ex_new = {did_low}
            if isinstance(ex_raw, (list, tuple)):
                ex_new.update(str(x).strip().lower() for x in ex_raw if x is not None)
            st["excluded_driver_ids"] = ex_new

    for otid in other_tag_ids:
        ot_norm = _norm_tag_id_str(otid)
        prefix = f"{ot_norm}_"
        for key in list(active_dispatch_tasks.keys()):
            if key.startswith(prefix):
                tsk = active_dispatch_tasks.pop(key, None)
                if tsk and not tsk.done():
                    try:
                        tsk.cancel()
                    except Exception:
                        pass

    logger.info(
        "MATCH_ACCEPT_CLEANUP path=%s driver=%s accepted_tag=%s other_tags=%s emits=%s",
        log_path,
        did_low[:13],
        acc[:13],
        len(other_tag_ids),
        emit_count,
    )
    logger.info(
        "MATCH_OTHER_OFFERS_CANCELLED driver=%s accepted_tag=%s cancelled_tags=%s",
        did_low[:13],
        acc[:13],
        json.dumps(other_tag_ids, default=str),
    )


# Socket event: MARTI TAG - Sürücü teklifi kabul eder (Uber-style: trip lock → push → socket)
@sio.on("driver_accept_offer")
async def handle_driver_accept_offer(sid, data):
    """
    Eşleşme: tags satırı id=tag_id için status='matched', driver_id, matched_at güncellenir.
    Yalnızca status in (waiting, offers_received, pending) iken atomik güncellenir; aksi halde already_taken.

    DB: modül geneli `supabase` = supabase_client.get_supabase() (create_client(URL, SERVICE_ROLE_KEY)).

    Push / socket / rolling_dispatch_stop hata verse bile offer_accepted_error üretilmez (eşleşme sonrası blok).
    """
    data = data or {}
    print("ACCEPT PAYLOAD:", data)
    tag_id = data.get("tag_id")
    driver_id = data.get("driver_id")
    auth_user_id = socket_id_to_user.get(sid)
    driver_name = (data.get("driver_name") or "Sürücü").strip() or "Sürücü"
    print("TAG:", tag_id, "DRIVER:", driver_id)
    logger.info(f"driver_accept_offer RECEIVED tag_id={tag_id} driver_id={str(driver_id)[:20] if driver_id else '?'}")
    logger.info("[driver/accept] tag_id=%s", str(tag_id or "")[:96])
    logger.info("[driver/accept] raw_driver_id=%s", str(driver_id or "")[:96])
    logger.info("[driver/accept] auth_user_id=%s", str(auth_user_id or "")[:96])
    if not tag_id:
        logger.warning("driver_accept_offer: tag_id veya driver_id eksik")
        await sio.emit("offer_accepted_error", {"error": "Eksik bilgi"}, room=sid)
        return

    resolved_driver_id, resolve_reason = await _resolve_driver_id_for_normal_ride_accept(
        raw_driver_id=driver_id,
        auth_user_id=auth_user_id,
    )
    logger.info("[driver/accept] resolved_driver_id=%s", str(resolved_driver_id or "")[:96])
    if not resolved_driver_id:
        logger.error("[driver/accept] resolve failed reason=%s", resolve_reason)
        await sio.emit("offer_accepted_error", {"error": "Geçersiz sürücü"}, room=sid)
        return

    if not supabase:
        logger.error("driver_accept_offer: supabase client yok — SERVICE_ROLE_KEY kontrol edin")
        await sio.emit(
            "offer_accepted_error",
            {"error": "Sunucu veritabanı yapılandırması eksik"},
            room=sid,
        )
        return

    tid = str(tag_id).strip()
    if len(tid) == 36 and tid.count("-") == 4:
        tid = tid.lower()

    trip_id = tid
    tag = None
    driver_phone = None

    # --- Tag + sürücü araç tipi; eşleşmezse reddet ---
    try:
        print("🚀 MATCH FLOW START")
        logger.info("MATCH FLOW START")
        tag_result = (
            supabase.table("tags")
            .select(
                "id, status, passenger_id, passenger_preferred_vehicle, passenger_payment_method, "
                "pickup_location, pickup_lat, pickup_lng, "
                "dropoff_location, dropoff_lat, dropoff_lng, final_price, distance_km, estimated_minutes"
            )
            .eq("id", tid)
            .limit(1)
            .execute()
        )
        if not tag_result.data:
            await sio.emit("offer_accepted_error", {"error": "Teklif bulunamadı"}, room=sid)
            return
        tag = tag_result.data[0]
        # status='waiting' şartı kaldırıldı — doğrudan id ile UPDATE

        dr = (
            supabase.table("users")
            .select("name, phone, push_token, driver_details")
            .eq("id", resolved_driver_id)
            .limit(1)
            .execute()
        )
        if not dr.data and "-" in str(resolved_driver_id):
            dr = (
                supabase.table("users")
                .select("name, phone, push_token")
                .eq("id", str(resolved_driver_id).lower())
                .limit(1)
                .execute()
            )
        if dr.data and dr.data[0].get("name"):
            driver_name = dr.data[0]["name"]
        driver_phone = (dr.data[0].get("phone") or "").strip() if dr.data else None

        driver_eff_sock = _effective_driver_vehicle_kind(dr.data[0] if dr.data else {})
        pu_row_sock = None
        if tag.get("passenger_id"):
            try:
                pids = await resolve_user_id(str(tag["passenger_id"]).strip())
                pus = (
                    supabase.table("users")
                    .select("driver_details")
                    .eq("id", pids)
                    .limit(1)
                    .execute()
                )
                if pus.data:
                    pu_row_sock = pus.data[0]
            except Exception:
                pass
        trip_pref_sock = _trip_passenger_vehicle_pref(tag, pu_row_sock)
        if not _driver_matches_passenger_vehicle_pref(driver_eff_sock, trip_pref_sock):
            await sio.emit(
                "offer_accepted_error",
                {"error": "Bu talep için araç tipiniz uygun değil"},
                room=sid,
            )
            return

        passenger_id_busy = None
        if tag.get("passenger_id"):
            try:
                passenger_id_busy = await resolve_user_id(str(tag["passenger_id"]).strip())
            except Exception:
                passenger_id_busy = str(tag["passenger_id"]).strip()

        _match_accept_log(
            "MATCH_ACCEPT_ATTEMPT",
            path="driver_accept_offer_socket",
            tag_id=tid,
            driver_id=resolved_driver_id,
            passenger_id=passenger_id_busy,
        )

        o_drv = _other_active_tag_id_sync(
            supabase,
            column="driver_id",
            user_id=str(resolved_driver_id),
            exclude_tag_id=tid,
        )
        if o_drv:
            _match_accept_log(
                "MATCH_ACCEPT_BLOCKED_DRIVER_BUSY",
                tag_id=tid,
                driver_id=resolved_driver_id,
                conflicting_tag_id=o_drv,
            )
            logger.info(
                "MATCH_DRIVER_LOCKED path=driver_accept_offer_socket tag_id=%s driver_id=%s conflict=%s",
                tid,
                str(resolved_driver_id)[:13],
                o_drv,
            )
            await sio.emit(
                "offer_accepted_error",
                {
                    "error": "Zaten devam eden bir yolculuğunuz var",
                    "code": "driver_busy",
                    "already_taken": False,
                },
                room=sid,
            )
            return

        if passenger_id_busy:
            o_pax = _other_active_tag_id_sync(
                supabase,
                column="passenger_id",
                user_id=str(passenger_id_busy),
                exclude_tag_id=tid,
            )
            if o_pax:
                _match_accept_log(
                    "MATCH_ACCEPT_BLOCKED_PASSENGER_BUSY",
                    tag_id=tid,
                    passenger_id=passenger_id_busy,
                    conflicting_tag_id=o_pax,
                )
                await sio.emit(
                    "offer_accepted_error",
                    {
                        "error": "Yolcu başka bir yolculukta",
                        "code": "passenger_busy",
                        "already_taken": False,
                    },
                    room=sid,
                )
                return

        _upd_body = {
            "status": "matched",
            "driver_id": resolved_driver_id,
            "driver_name": driver_name,
            "matched_at": datetime.now(timezone.utc).isoformat(),
        }
        ur_sock = (
            supabase.table("tags")
            .update(_upd_body)
            .eq("id", tid)
            .in_("status", MATCHABLE_TAG_STATUSES_FOR_ACCEPT_LIST)
            .execute()
        )
        if not ur_sock.data and str(tag_id).strip() != tid:
            alt_id = str(tag_id).strip()
            ur_sock = (
                supabase.table("tags")
                .update(_upd_body)
                .eq("id", alt_id)
                .in_("status", MATCHABLE_TAG_STATUSES_FOR_ACCEPT_LIST)
                .execute()
            )
        updated_tag_rows = ur_sock.data if ur_sock.data else []
        if not updated_tag_rows:
            ref = supabase.table("tags").select("*").eq("id", tid).limit(1).execute()
            row = ref.data[0] if ref.data else {}
            st = (row.get("status") or "").lower()
            did_row = str(row.get("driver_id") or "").strip().lower()
            if st == "matched" and did_row == str(resolved_driver_id).strip().lower():
                tag = row
                _match_accept_log(
                    "MATCH_ACCEPT_WON",
                    path="driver_accept_offer_socket",
                    tag_id=tid,
                    driver_id=resolved_driver_id,
                    note="idempotent_same_driver",
                )
            else:
                _match_accept_log(
                    "MATCH_ACCEPT_LOST_ALREADY_TAKEN",
                    path="driver_accept_offer_socket",
                    tag_id=tid,
                    driver_id=resolved_driver_id,
                    current_status=row.get("status"),
                    row_driver_id=row.get("driver_id"),
                )
                await sio.emit(
                    "offer_accepted_error",
                    {
                        "error": "Bu teklif artık mevcut değil veya başka sürücü ile eşleşti",
                        "already_taken": True,
                    },
                    room=sid,
                )
                return
        else:
            tag = updated_tag_rows[0]
            _match_accept_log(
                "MATCH_ACCEPT_WON",
                path="driver_accept_offer_socket",
                tag_id=tid,
                driver_id=resolved_driver_id,
            )

        logger.info(
            f"driver_accept_offer UPDATE tag={tid} driver={resolved_driver_id}"
        )
        logger.info(f"TRIP LOCK SUCCESS driver_accept_offer tag={tid} driver={resolved_driver_id}")
    except Exception as e:
        logger.exception(f"driver_accept_offer match (DB) error: {e}")
        await sio.emit("offer_accepted_error", {"error": str(e)}, room=sid)
        return

    # --- Eşleşme sonrası: best-effort; hata offer_accepted_error üretmez ---
    try:
        try:
            await rolling_dispatch_stop(
                tid, revoke_offers=True, except_driver_id=resolved_driver_id
            )
            logger.info(
                "[DISPATCH_BATCH] tag=%s event=matched_accepted driver=%s rolling_dispatch_stopped=1",
                tid,
                resolved_driver_id,
            )
        except Exception as _rds:
            logger.warning(f"rolling_dispatch_stop after driver_accept_offer (non-fatal): {_rds}")
        try:
            await handle_dispatch_accept(tid, resolved_driver_id)
        except Exception as _hda:
            logger.warning(f"handle_dispatch_accept after driver_accept_offer (non-fatal): {_hda}")
        try:
            await match_accept_cleanup_foreign_offers(
                resolved_driver_id, tid, log_path="driver_accept_offer_socket"
            )
        except Exception as _cl:
            logger.warning("match_accept_cleanup_foreign_offers socket (non-fatal): %s", _cl)

        passenger_id = tag.get("passenger_id")
        passenger_id = str(passenger_id).strip() if passenger_id else None
        if passenger_id:
            passenger_id = await resolve_user_id(passenger_id)
        passenger_name = "Yolcu"
        passenger_phone = None
        pr = None
        if passenger_id:
            pr = (
                supabase.table("users")
                .select("name, phone, push_token, latitude, longitude")
                .eq("id", passenger_id)
                .limit(1)
                .execute()
            )
            if not pr.data and "-" in passenger_id:
                pr = (
                    supabase.table("users")
                    .select("name, phone, push_token, latitude, longitude")
                    .eq("id", passenger_id.lower())
                    .limit(1)
                    .execute()
                )
            if pr and pr.data:
                if pr.data[0].get("name"):
                    passenger_name = pr.data[0]["name"]
                passenger_phone = (pr.data[0].get("phone") or "").strip()
        if not passenger_id:
            logger.warning(f"driver_accept_offer: tag {tid} için passenger_id yok (push/socket kısıtlı)")

        def _id_hint(uid):
            if not uid:
                return "?"
            s = str(uid).strip()
            if "-" in s:
                return f"uuid:{s[-8:]}"
            if s.isdigit() and len(s) >= 10:
                return f"phone:{s[:4]}***"
            return f"id:{s[:8]}"

        logger.info(f"MATCH PUSH: driver_id={_id_hint(resolved_driver_id)} passenger_id={_id_hint(passenger_id)}")
        match_data = {"event": "match", "trip_id": trip_id, "type": "matched", "tag_id": tid}

        _m_fp = 0
        try:
            _raw_p = tag.get("final_price") or tag.get("offered_price")
            if _raw_p is not None:
                _m_fp = int(float(_raw_p))
        except (TypeError, ValueError):
            _m_fp = 0
        _m_dkm = ""
        try:
            _dk = tag.get("distance_km")
            if _dk is not None and float(_dk) > 0:
                _m_dkm = f"{float(_dk):.0f} km"
        except (TypeError, ValueError):
            pass
        if _m_fp and _m_dkm:
            _match_driver_body = f"{_m_fp} TL • {_m_dkm} • Rotaya dokun"
        elif _m_fp:
            _match_driver_body = f"{_m_fp} TL • Rotayı görmek için dokun"
        else:
            _match_driver_body = "Yolcu bulundu • Rotayı görmek için dokun"
        if len(_match_driver_body) > 72:
            _match_driver_body = _match_driver_body[:69] + "…"
        _dn = _push_first_name(driver_name, 10)
        if _dn and _m_fp:
            _match_pass_body = f"{_dn} • {_m_fp} TL • Detay için dokun"
        elif _dn:
            _match_pass_body = f"{_dn} • Detayları görmek için dokun"
        elif _m_fp:
            _match_pass_body = f"{_m_fp} TL • Detayları görmek için dokun"
        else:
            _match_pass_body = "Sürücü bulundu • Detay için dokun"
        if len(_match_pass_body) > 72:
            _match_pass_body = _match_pass_body[:69] + "…"

        print("📲 SENDING PUSH DRIVER")
        push_driver_ok = await send_push_notification(
            resolved_driver_id,
            "Eşleşme sağlandı",
            _match_driver_body,
            match_data,
        )
        if not push_driver_ok and driver_phone and _looks_like_phone(driver_phone):
            push_driver_ok = await send_push_notification(
                driver_phone,
                "Eşleşme sağlandı",
                _match_driver_body,
                match_data,
            )
            if push_driver_ok:
                logger.info("PUSH DRIVER SENT (retry by phone)")
        logger.info("PUSH DRIVER SENT" if push_driver_ok else "PUSH DRIVER FAILED")

        if passenger_id:
            print("📲 SENDING PUSH PASSENGER")
            push_p_ok = await send_push_notification(
                passenger_id,
                "Eşleşme sağlandı",
                _match_pass_body,
                match_data,
            )
            if not push_p_ok and passenger_phone and _looks_like_phone(passenger_phone):
                push_p_ok = await send_push_notification(
                    passenger_phone,
                    "Eşleşme sağlandı",
                    _match_pass_body,
                    match_data,
                )
                if push_p_ok:
                    logger.info("PUSH PASSENGER SENT (retry by phone)")
            logger.info("PUSH PASSENGER SENT" if push_p_ok else "PUSH PASSENGER FAILED")

        pickup_distance_km = None
        pickup_eta_min = None
        trip_distance_km = None
        trip_duration_min = None
        route_info_payload: dict[str, Any] = {}
        try:
            udrv_sock = (
                supabase.table("users")
                .select("latitude, longitude")
                .eq("id", resolved_driver_id)
                .limit(1)
                .execute()
            )
            plat_s, plng_s = tag.get("pickup_lat"), tag.get("pickup_lng")
            dplat_s, dplng_s = tag.get("dropoff_lat"), tag.get("dropoff_lng")
            if (
                udrv_sock.data
                and plat_s is not None
                and plng_s is not None
                and dplat_s is not None
                and dplng_s is not None
            ):
                dlat_s, dlng_s = udrv_sock.data[0].get("latitude"), udrv_sock.data[0].get(
                    "longitude"
                )
                if dlat_s is not None and dlng_s is not None:
                    ri_sock = await get_route_info(
                        float(dlat_s), float(dlng_s), float(plat_s), float(plng_s)
                    )
                    ri_trip_sock = await get_route_info(
                        float(plat_s), float(plng_s), float(dplat_s), float(dplng_s)
                    )
                    if (
                        ri_sock
                        and ri_trip_sock
                        and str(ri_sock.get("source", "")).strip().lower() != "haversine_fallback"
                        and str(ri_trip_sock.get("source", "")).strip().lower() != "haversine_fallback"
                    ):
                        pickup_distance_km = float(ri_sock["distance_km"])
                        pickup_eta_min = int(round(float(ri_sock["duration_min"])))
                        trip_distance_km = float(ri_trip_sock["distance_km"])
                        trip_duration_min = int(round(float(ri_trip_sock["duration_min"])))
                        route_info_payload = {
                            "pickup_distance_km": pickup_distance_km,
                            "pickup_eta_min": pickup_eta_min,
                            "distance_to_passenger_km": pickup_distance_km,
                            "time_to_passenger_min": pickup_eta_min,
                            "trip_distance_km": trip_distance_km,
                            "trip_duration_min": trip_duration_min,
                            "distance_km": trip_distance_km,
                            "estimated_minutes": trip_duration_min,
                        }
                        op = ri_sock.get("overview_polyline") if isinstance(ri_sock, dict) else None
                        if isinstance(op, str) and len(op) > 2:
                            route_info_payload["overview_polyline"] = op
                        coords = ri_sock.get("coordinates") if isinstance(ri_sock, dict) else None
                        if isinstance(coords, list) and len(coords) >= 2:
                            route_info_payload["coordinates"] = coords
        except Exception as _pks:
            logger.warning(f"driver_accept_offer pickup_distance: {_pks}")

        matched_at = datetime.utcnow().isoformat()
        print("[ROUTE_ACCEPT] driver_to_pickup=", pickup_distance_km, pickup_eta_min)
        print("[ROUTE_ACCEPT] pickup_to_dropoff=", trip_distance_km, trip_duration_min)
        print("[ROUTE_ACCEPT] emit_driver_id=", resolved_driver_id, "tag_id=", tid)
        trip_dk_sock = trip_distance_km
        est_min_sock = trip_duration_min
        tag["pickup_distance_km"] = pickup_distance_km
        tag["pickup_eta_min"] = pickup_eta_min
        tag["distance_to_passenger_km"] = pickup_distance_km
        tag["time_to_passenger_min"] = pickup_eta_min
        tag["trip_distance_km"] = trip_distance_km
        tag["trip_duration_min"] = trip_duration_min
        tag["distance_km"] = trip_distance_km
        tag["estimated_minutes"] = trip_duration_min
        tag["route_info"] = route_info_payload
        passenger_location_sock: Optional[dict] = None
        if pr and pr.data:
            u_sock = pr.data[0]
            if u_sock.get("latitude") is not None and u_sock.get("longitude") is not None:
                try:
                    passenger_location_sock = {
                        "latitude": float(u_sock["latitude"]),
                        "longitude": float(u_sock["longitude"]),
                    }
                except (TypeError, ValueError):
                    passenger_location_sock = None
        if passenger_location_sock is None and tag.get("pickup_lat") is not None and tag.get(
            "pickup_lng"
        ) is not None:
            try:
                passenger_location_sock = {
                    "latitude": float(tag["pickup_lat"]),
                    "longitude": float(tag["pickup_lng"]),
                }
            except (TypeError, ValueError):
                passenger_location_sock = None
        payload = {
            "trip_id": trip_id,
            "tag_id": tid,
            "driver_id": resolved_driver_id,
            "driver_name": driver_name,
            "passenger_id": passenger_id,
            "passenger_name": passenger_name,
            "pickup_location": tag.get("pickup_location"),
            "dropoff_location": tag.get("dropoff_location"),
            "pickup_lat": tag.get("pickup_lat"),
            "pickup_lng": tag.get("pickup_lng"),
            "dropoff_lat": tag.get("dropoff_lat"),
            "dropoff_lng": tag.get("dropoff_lng"),
            "offered_price": tag.get("offered_price") or tag.get("final_price"),
            "final_price": tag.get("final_price"),
            "distance_km": trip_dk_sock,
            "trip_distance_km": trip_dk_sock,
            "estimated_minutes": est_min_sock,
            "trip_duration_min": est_min_sock,
            "pickup_distance_km": pickup_distance_km,
            "pickup_eta_min": pickup_eta_min,
            "distance_to_passenger_km": pickup_distance_km,
            "time_to_passenger_min": pickup_eta_min,
            "route_info": route_info_payload,
            "tag": {k: v for k, v in tag.items() if v is not None},
            "status": "matched",
            "matched_at": matched_at,
            "passenger_payment_method": tag.get("passenger_payment_method"),
        }
        if passenger_location_sock:
            payload["passenger_location"] = passenger_location_sock
        try:
            await _emit_driver_on_the_way_route(tag, resolved_driver_id)
        except Exception as _dotw_sock:
            logger.warning("driver_on_the_way socket (non-fatal): %s", _dotw_sock)
        driver_sid = connected_users.get(str(resolved_driver_id).strip().lower()) or connected_users.get(
            resolved_driver_id
        )
        driver_room = _normalize_user_room(resolved_driver_id)
        driver_target = driver_sid or driver_room
        if driver_target:
            await sio.emit("offer_accepted_success", payload, room=driver_target)
            await sio.emit("tag_matched", payload, room=driver_target)
        # İstenen net match event: sürücü room'una ride_matched
        await sio.emit("ride_matched", payload, room=f"user_{str(resolved_driver_id).strip().lower()}")
        if passenger_id:
            passenger_sids = _all_sids_for_registered_user(str(passenger_id))
            passenger_sid = connected_users.get(str(passenger_id).strip().lower()) or connected_users.get(passenger_id)
            passenger_room = _normalize_user_room(passenger_id)
            passenger_target = passenger_sid or passenger_room
            logger.info("[emit] passenger_id=%s", str(passenger_id)[:96])
            logger.info("[emit] passenger_sids=%s", passenger_sids)
            if passenger_target:
                logger.info("[emit] sending ride_matched")
                await sio.emit("driver_matched", payload, room=passenger_target)
                await sio.emit("tag_matched", payload, room=passenger_target)
            # İstenen net match event: yolcu room'una ride_matched
            await sio.emit("ride_matched", payload, room=f"user_{str(passenger_id).strip().lower()}")
            if not passenger_target:
                logger.error("[emit] passenger_sid_empty passenger_id=%s", str(passenger_id)[:96])
        logger.info("SOCKET EMIT DONE driver_accept_offer")
    except Exception as e:
        logger.warning(f"driver_accept_offer post-match (non-fatal): {e}")

    logger.info("MATCH FLOW END driver_accept_offer")


# ==================== CHAT MESSAGING SYSTEM (HYBRID) ====================
# Supabase = Source of Truth, Socket = Real-time notification (best-effort)

class ChatMessageCreate(BaseModel):
    tag_id: str
    sender_id: str
    receiver_id: str
    message: str
    sender_name: Optional[str] = None

@api_router.post("/chat/send-message")
async def send_chat_message(msg: ChatMessageCreate):
    """
    HYBRID CHAT:
    1. Supabase'e kaydet
    2. tags.first_message_sent atomik claim — başarılıysa push + first_chat_message socket (kolon zorunlu)

    Deploy doğrulama (sunucuda): grep CHAT_FIRST_PUSH backend/server.py
    Log önekleri: CHAT_FIRST_PUSH_CLAIM_OK | CHAT_FIRST_PUSH_SKIP | CHAT_FIRST_PUSH_SCHEDULED
    """
    try:
        _tid_send = str(msg.tag_id or "").strip()
        if _tid_send:
            try:
                _bd_chat = (
                    supabase.table("tags")
                    .select("boarding_confirmed_at")
                    .eq("id", _tid_send)
                    .limit(1)
                    .execute()
                )
                if _bd_chat.data and _bd_chat.data[0].get("boarding_confirmed_at"):
                    return {
                        "success": False,
                        "detail": "boarding_comm_closed",
                        "error": "boarding_comm_closed",
                    }
            except Exception as _e_board_chat:
                logger.warning("chat send_message boarding gate skipped: %s", _e_board_chat)

        prior_any = (
            supabase.table("chat_messages")
            .select("id")
            .eq("tag_id", msg.tag_id)
            .limit(1)
            .execute()
        )
        is_first_in_thread = not (prior_any.data and len(prior_any.data) > 0)

        message_data = {
            "tag_id": msg.tag_id,
            "sender_id": msg.sender_id,
            "receiver_id": msg.receiver_id,
            "message": msg.message,
            "created_at": datetime.utcnow().isoformat(),
        }

        result = supabase.table("chat_messages").insert(message_data).execute()

        if not result.data:
            raise HTTPException(status_code=500, detail="Failed to save message")

        saved_message = result.data[0]
        logger.info(f"💬 Chat message saved to Supabase: {saved_message['id']}")

        sender_result = supabase.table("users").select("name").eq("id", msg.sender_id).execute()
        sender_name = (
            (msg.sender_name or "").strip()
            or (sender_result.data[0].get("name", "Birisi") if sender_result.data else "Birisi")
        )

        tag_row = (
            supabase.table("tags")
            .select("driver_id, passenger_id")
            .eq("id", msg.tag_id)
            .limit(1)
            .execute()
        )
        driver_uid = None
        if tag_row.data:
            driver_uid = str(tag_row.data[0].get("driver_id") or "").strip() or None
        from_driver = bool(driver_uid and str(msg.sender_id).strip().lower() == driver_uid.lower())
        preview = (msg.message or "").strip()
        if len(preview) > 72:
            preview = preview[:69] + "..."

        # İlk push: tags.first_message_sent atomik bayrak.
        # NOT: PostgREST update+select bazen boş `data` döndürür; claim'i yalnız `claim.data` ile ölçmek push'u kalıcı olarak kesebilir.
        should_first_push = False
        tag_pre = (
            supabase.table("tags")
            .select("first_message_sent")
            .eq("id", msg.tag_id)
            .limit(1)
            .execute()
        )
        if not tag_pre.data:
            logger.info(
                "CHAT_FIRST_PUSH_SKIP tag_id=%s sender=%s receiver=%s reason=tag_not_found",
                msg.tag_id,
                msg.sender_id,
                msg.receiver_id,
            )
        else:
            fs0 = tag_pre.data[0].get("first_message_sent")
            already_sent = fs0 is True or str(fs0 or "").lower() == "true"
            if already_sent:
                logger.info(
                    "CHAT_FIRST_PUSH_SKIP tag_id=%s sender=%s receiver=%s reason=first_message_sent_already_true "
                    "chat_prior_row=%s",
                    msg.tag_id,
                    msg.sender_id,
                    msg.receiver_id,
                    0 if is_first_in_thread else 1,
                )
            else:
                try:
                    supabase.table("tags").update({"first_message_sent": True}).eq("id", msg.tag_id).or_(
                        "first_message_sent.is.null,first_message_sent.eq.false"
                    ).execute()
                except Exception as tag_flag_err:
                    logger.error(
                        "CHAT_FIRST_PUSH_SKIP tag_id=%s sender=%s receiver=%s reason=first_message_sent_update_failed "
                        "err=%s | migration=backend/migrations/add_expo_push_and_first_message_sent.sql",
                        msg.tag_id,
                        msg.sender_id,
                        msg.receiver_id,
                        tag_flag_err,
                    )
                    should_first_push = False
                else:
                    ver = (
                        supabase.table("tags")
                        .select("first_message_sent")
                        .eq("id", msg.tag_id)
                        .limit(1)
                        .execute()
                    )
                    fs1 = ver.data[0].get("first_message_sent") if ver.data else None
                    should_first_push = fs1 is True or str(fs1 or "").lower() == "true"
                    if should_first_push:
                        logger.info(
                            "CHAT_FIRST_PUSH_CLAIM_OK tag_id=%s sender=%s receiver=%s "
                            "is_first_chat_row=%s (prior_any before this insert)",
                            msg.tag_id,
                            msg.sender_id,
                            msg.receiver_id,
                            is_first_in_thread,
                        )
                    else:
                        logger.warning(
                            "CHAT_FIRST_PUSH_SKIP tag_id=%s sender=%s receiver=%s reason=flag_still_false_after_update",
                            msg.tag_id,
                            msg.sender_id,
                            msg.receiver_id,
                        )

        if should_first_push:
            if from_driver:
                _chat_title = "Sürücü size yazdı"
            else:
                _chat_title = "Yolcu size yazdı"
            _chat_body = "Cevap vermek için dokun"
            if len(_chat_body) > 72:
                _chat_body = _chat_body[:69] + "…"
            asyncio.create_task(
                send_trip_push_and_log(
                    msg.receiver_id,
                    "first_chat_message",
                    _chat_title,
                    _chat_body,
                    {
                        "type": "first_chat_message",
                        "tag_id": msg.tag_id,
                        "sender_id": msg.sender_id,
                        "from_driver": from_driver,
                    },
                )
            )
            logger.info(
                "CHAT_FIRST_PUSH_SCHEDULED receiver=%s tag=%s from_driver=%s title=%r",
                msg.receiver_id,
                msg.tag_id,
                from_driver,
                _chat_title,
            )

            try:
                await sio.emit(
                    "first_chat_message",
                    {
                        "tag_id": msg.tag_id,
                        "sender_id": msg.sender_id,
                        "sender_name": sender_name,
                        "message": msg.message,
                        "message_preview": preview,
                        "from_driver": from_driver,
                        "created_at": saved_message.get("created_at"),
                    },
                    room=_normalize_user_room(msg.receiver_id),
                )
            except Exception as socket_err:
                logger.warning(f"⚠️ first_chat_message socket failed: {socket_err}")

        return {
            "success": True,
            "message_id": saved_message["id"],
            "created_at": saved_message["created_at"],
            "first_from_sender": is_first_in_thread,
            "first_in_thread": is_first_in_thread,
        }
        
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"❌ Chat send error: {e}")
        raise HTTPException(status_code=500, detail=str(e))

@api_router.get("/chat/messages")
async def get_chat_messages(tag_id: str, limit: int = 50, offset: int = 0):
    """
    Supabase'den mesajları çek (SOURCE OF TRUTH)
    Pagination destekli
    """
    try:
        result = supabase.table("chat_messages")\
            .select("*")\
            .eq("tag_id", tag_id)\
            .order("created_at", desc=False)\
            .range(offset, offset + limit - 1)\
            .execute()
        
        messages = result.data or []
        
        return {
            "success": True,
            "messages": messages,
            "count": len(messages),
            "tag_id": tag_id
        }
        
    except Exception as e:
        logger.error(f"❌ Chat fetch error: {e}")
        # Hata durumunda boş array dön (UI kırılmasın)
        return {
            "success": False,
            "messages": [],
            "count": 0,
            "error": str(e)
        }

@api_router.post("/chat/mark-read")
async def mark_messages_read(tag_id: str, user_id: str):
    """
    Kullanıcının okuduğu mesajları işaretle
    """
    try:
        result = supabase.table("chat_messages")\
            .update({"read_at": datetime.utcnow().isoformat()})\
            .eq("tag_id", tag_id)\
            .eq("receiver_id", user_id)\
            .is_("read_at", "null")\
            .execute()
        
        return {"success": True, "updated": len(result.data or [])}
    except Exception as e:
        logger.error(f"❌ Mark read error: {e}")
        return {"success": False, "error": str(e)}

# ==================== MARTI TAG - FİYAT HESAPLAMA ====================

def haversine_distance(lat1: float, lng1: float, lat2: float, lng2: float) -> float:
    """İki nokta arası mesafe (km) - Kuş uçuşu"""
    import math
    R = 6371  # Dünya yarıçapı km
    dlat = math.radians(lat2 - lat1)
    dlng = math.radians(lng2 - lng1)
    a = math.sin(dlat/2)**2 + math.cos(math.radians(lat1)) * math.cos(math.radians(lat2)) * math.sin(dlng/2)**2
    return R * 2 * math.asin(math.sqrt(a))


def _eta_minutes(from_lat: float, from_lng: float, to_lat: float, to_lng: float) -> int:
    """Kuş uçuşu mesafeden tahmini varış süresi (dk) - şehir içi ~25 km/h"""
    if not all([from_lat, from_lng, to_lat, to_lng]):
        return 0
    km = haversine_distance(from_lat, from_lng, to_lat, to_lng)
    # Gerçek yol genelde 1.2–1.4x; ortalama hız ~25 km/h → dk = km * 2.5
    minutes = max(1, round(km * 2.5))
    return min(minutes, 120)  # max 120 dk

def _directions_leg_to_road_dict(leg: dict) -> dict:
    """Google Directions tek leg → distance_km / duration_min (trafik varsa duration_in_traffic)."""
    distance_km = leg["distance"]["value"] / 1000
    dur_src = leg.get("duration_in_traffic") or leg["duration"]
    duration_min = max(1, int(math.ceil(dur_src["value"] / 60)))
    base_min = max(1, int(math.ceil(leg["duration"]["value"] / 60)))
    used_traffic = "duration_in_traffic" in leg
    logger.info(
        f"📍 Google Directions: {distance_km:.1f} km, {duration_min} dk"
        f"{' (trafik dahil)' if used_traffic else ' (trafik yok, süre=duration)'}"
    )
    return {
        "distance_km": round(distance_km, 1),
        "duration_min": duration_min,
        "duration_min_no_traffic": base_min,
        "used_traffic": used_traffic,
    }


def _attach_overview_polyline(route: Optional[dict], leg_dict: dict) -> dict:
    """Aynı Directions yanıtından overview polyline (tek ek ücret yok)."""
    if route and isinstance(route, dict):
        op = route.get("overview_polyline") or {}
        enc = op.get("points")
        if isinstance(enc, str) and len(enc) > 2:
            leg_dict["overview_polyline"] = enc
    return leg_dict


async def get_road_distance(origin_lat: float, origin_lng: float, dest_lat: float, dest_lng: float) -> dict:
    """
    Google Directions API ile gerçek yol mesafesi hesapla
    Returns: {"distance_km": float, "duration_min": int, ...} veya None
    """
    try:
        import httpx

        api_key = (os.environ.get("GOOGLE_MAPS_API_KEY") or "").strip()
        if not api_key:
            logger.warning(
                "⚠️ GOOGLE_MAPS_API_KEY boş — Google Directions atlanıyor. "
                "Sunucuda ortam değişkeni (systemd Environment= veya .env) tanımlayıp uvicorn yeniden başlatın. "
                "get_route_info bu durumda OSRM fallback dener."
            )
            return None

        url = "https://maps.googleapis.com/maps/api/directions/json"
        base_params = {
            "origin": f"{origin_lat},{origin_lng}",
            "destination": f"{dest_lat},{dest_lng}",
            "mode": "driving",
            "key": api_key,
        }

        async with httpx.AsyncClient(http2=False, timeout=10.0) as client:
            # 1) Trafik tahmini (bazı API kısıtlarında INVALID_REQUEST döner)
            traffic_params = {
                **base_params,
                "departure_time": "now",
                "traffic_model": "best_guess",
            }
            response = await client.get(url, params=traffic_params)
            data = response.json()
            if data.get("status") == "OK" and data.get("routes"):
                r0 = data["routes"][0]
                ld = _directions_leg_to_road_dict(r0["legs"][0])
                return _attach_overview_polyline(r0, ld)
            logger.warning(
                "⚠️ Google Directions (trafikli) başarısız: %s — trafiksiz yeniden deneniyor",
                data.get("status"),
            )

            response2 = await client.get(url, params=base_params)
            data2 = response2.json()
            if data2.get("status") == "OK" and data2.get("routes"):
                logger.info("📍 Google Directions: trafik parametresiz rota kullanıldı")
                r0b = data2["routes"][0]
                ld2 = _directions_leg_to_road_dict(r0b["legs"][0])
                return _attach_overview_polyline(r0b, ld2)

            logger.warning(f"⚠️ Google Directions API hatası: {data2.get('status')}")
            return None

    except Exception as e:
        logger.error(f"❌ Google Directions API hatası: {e}")
        return None

def is_peak_hour() -> bool:
    """Yoğun saat kontrolü (08:00-10:00, 17:00-20:00)"""
    from datetime import datetime, timezone, timedelta
    try:
        # Türkiye saati UTC+3
        turkey_tz = timezone(timedelta(hours=3))
        now = datetime.now(turkey_tz)
        hour = now.hour
        # Yoğun saatler: 08:00-10:00 ve 17:00-20:00
        return (8 <= hour < 10) or (17 <= hour < 20)
    except:
        # Fallback: UTC+3
        hour = (datetime.utcnow().hour + 3) % 24
        return (8 <= hour < 10) or (17 <= hour < 20)

class CalculatePriceRequest(BaseModel):
    pickup_lat: float
    pickup_lng: float
    dropoff_lat: float
    dropoff_lng: float
    driver_lat: Optional[float] = None  # Sürücü konumu (opsiyonel)
    driver_lng: Optional[float] = None
    passenger_vehicle_kind: Optional[str] = None  # car | motorcycle
    # Yalnızca Muhabbet/Leylek teklif oluşturma — normal TAG /price/calculate gövdesi bunu göndermez
    muhabbet_listing: Optional[bool] = False


@api_router.post("/price/calculate")
async def calculate_price(request: CalculatePriceRequest):
    """
    Leylek TAG Fiyat Hesaplama - DİNAMİK SİSTEM
    Google Directions API ile gerçek yol mesafesi kullanır
    """
    try:
        # Tek kaynak route fonksiyonu (Google + backend fallback)
        route_info = await get_route_info(
            request.pickup_lat, request.pickup_lng,
            request.dropoff_lat, request.dropoff_lng
        )

        if not route_info:
            # Geçersiz koordinat vb.; get_route_info artık geçerli noktalarda haversine döner
            raise HTTPException(status_code=400, detail="Geçersiz koordinatlar")

        route_source = str(route_info.get("source") or "")
        route_distance_km = float(route_info["distance_km"])
        trip_distance_km = route_distance_km
        air_km_for_log: Optional[float] = None
        if bool(request.muhabbet_listing):
            air_km_for_log = float(
                haversine_distance(
                    float(request.pickup_lat),
                    float(request.pickup_lng),
                    float(request.dropoff_lat),
                    float(request.dropoff_lng),
                )
            )
            # Leylek teklif: fiyat için motor çıktısı mesafesinin tabanı (normal TAG'da kullanılmaz)
            trip_distance_km = max(route_distance_km, 3.0)

        estimated_minutes = int(route_info["duration_min"])
        logger.info(f"📍 Route engine ile hesaplandı: {trip_distance_km} km, {estimated_minutes} dk")
        
        # Minimum mesafe 1 km (fiyat için kullanılan mesafe)
        trip_distance_km = max(1.0, trip_distance_km)
        display_km = max(1.0, route_distance_km)
        estimated_minutes = max(5, estimated_minutes)  # Minimum 5 dakika
        
        # Yoğun saat kontrolü
        peak = is_peak_hour()

        # Yeni: Araç/Motor fiyat parametreleri
        vk = _canonical_vehicle_kind(request.passenger_vehicle_kind) or "car"
        if vk == "motorcycle":
            base = 25
            per_km = 12
            minimum = 80
        else:
            base = 40
            per_km = 20
            minimum = 120

        multiplier = 1.15 if peak else 1.0

        price = base + (float(trip_distance_km) * per_km)
        if price < minimum:
            price = float(minimum)
        price = price * multiplier

        # Tam sayıya yuvarla (TL)
        price_int_raw = int(round(price))
        price_int = price_int_raw
        leylek_minimum_price_applied = False
        if bool(request.muhabbet_listing):
            leylek_minimum_price_applied = price_int_raw < 30
            price_int = max(30, price_int_raw)
            logger.info(
                "[leylek_price] distanceSource=%s rawDistanceKm=%.3f routeDistanceKm=%.3f pricingDistanceKm=%.3f basePrice=%s finalSuggestedPrice=%s",
                route_source,
                float(air_km_for_log) if air_km_for_log is not None else 0.0,
                route_distance_km,
                trip_distance_km,
                base,
                price_int,
            )

        # Range: +/- %10
        min_price = int(round(price_int * 0.9))
        max_price = int(round(price_int * 1.1))
        suggested_price = price_int
        
        logger.info(f"💰 Fiyat hesaplama: Yolculuk {trip_distance_km:.1f}km, {estimated_minutes}dk, {min_price}-{max_price}TL (peak={peak})")
        
        out = {
            "success": True,
            "distance_km": round(display_km, 1),
            "trip_distance_km": round(display_km, 1),
            "estimated_minutes": estimated_minutes,
            "min_price": min_price,
            "max_price": max_price,
            "suggested_price": suggested_price,
            "is_peak_hour": peak,
            "currency": "TL",
            "vehicle_kind": vk,
            "base_price": base,
            "per_km": per_km,
            "minimum_price": minimum,
            "multiplier": multiplier,
        }
        if bool(request.muhabbet_listing):
            out["distance_source"] = route_source
            out["raw_air_distance_km"] = (
                round(air_km_for_log, 3) if air_km_for_log is not None else None
            )
            out["route_distance_km"] = round(route_distance_km, 1)
            out["pricing_distance_km"] = round(trip_distance_km, 1)
            out["leylek_minimum_price_applied"] = leylek_minimum_price_applied
        return out
    except Exception as e:
        logger.error(f"❌ Price calculation error: {e}")
        return {"success": False, "error": str(e)}

class CreateRideOfferRequest(BaseModel):
    tag_id: Optional[str] = None  # Frontend'den gelen UUID (yoksa sunucu üretir)
    passenger_id: str
    pickup_lat: float
    pickup_lng: float
    pickup_location: str = ""
    dropoff_lat: float
    dropoff_lng: float
    dropoff_location: str = ""
    offered_price: int
    distance_km: float
    estimated_minutes: int
    # car | motorcycle | motor — yoksa profil veya varsayılan car
    passenger_preferred_vehicle: Optional[str] = None
    # Frontend alias (ride/create); passenger_preferred_vehicle ile aynı anlam
    passenger_vehicle_kind: Optional[str] = None
    # Yolcu ödeme tercihi: cash | card (Supabase tags.passenger_payment_method)
    passenger_payment_method: Optional[str] = None

    @field_validator("offered_price", mode="before")
    @classmethod
    def _coerce_offered_price(cls, v):
        if v is None:
            raise ValueError("offered_price gerekli")
        return int(round(float(v)))

    @field_validator("distance_km", mode="before")
    @classmethod
    def _coerce_distance(cls, v):
        if v is None:
            return 0.0
        return float(v)

    @field_validator("estimated_minutes", mode="before")
    @classmethod
    def _coerce_estimated_minutes(cls, v):
        if v is None:
            return 0
        return int(round(float(v)))


async def _parse_create_ride_offer_json(http_request: Request) -> CreateRideOfferRequest:
    """JSON gövdesini açıkça oku — FastAPI Body enjeksiyonu bazen 422 'field required' üretebiliyor (proxy/eski imza)."""
    logger.info(
        "ride/create parse: path=%s content-type=%s content-length=%s",
        http_request.url.path,
        http_request.headers.get("content-type"),
        http_request.headers.get("content-length"),
    )
    try:
        raw = await http_request.json()
    except Exception as e:
        logger.warning("ride/create: JSON parse hatası: %s", e)
        raise HTTPException(status_code=422, detail="Geçersiz veya boş JSON gövdesi") from e
    if not isinstance(raw, dict):
        raise HTTPException(status_code=422, detail="İstek gövdesi JSON nesnesi olmalı")
    try:
        return CreateRideOfferRequest.model_validate(raw)
    except ValidationError as e:
        logger.warning(
            "ride/create: Pydantic hatası gönderilen_anahtarlar=%s hatalar=%s",
            sorted(raw.keys()),
            e.errors(),
        )
        raise HTTPException(status_code=422, detail=e.errors()) from e


async def _resolve_passenger_id_for_normal_ride_create(
    payload_passenger_id: Optional[str], auth_user_id: Optional[str] = None
) -> tuple[Optional[str], str]:
    """Normal ride/create için payload/auth kimliğini users.id UUID'ye çöz."""
    raw = str(payload_passenger_id or "").strip()
    auth_raw = str(auth_user_id or "").strip()
    # 1) payload UUID ise doğrudan users.id kontrolü
    if raw:
        try:
            uuid_raw = str(uuid.UUID(raw)).strip().lower()
            by_uuid = supabase.table("users").select("id").eq("id", uuid_raw).limit(1).execute()
            if by_uuid.data and by_uuid.data[0].get("id"):
                return str(by_uuid.data[0]["id"]).strip().lower(), "payload_uuid"
        except Exception:
            pass
        # 2) payload users.id
        try:
            by_id = supabase.table("users").select("id").eq("id", raw).limit(1).execute()
            if by_id.data and by_id.data[0].get("id"):
                return str(by_id.data[0]["id"]).strip().lower(), "payload_users_id"
        except Exception:
            pass
        # 3) payload users.auth_id
        try:
            by_auth = supabase.table("users").select("id").eq("auth_id", raw).limit(1).execute()
            if by_auth.data and by_auth.data[0].get("id"):
                return str(by_auth.data[0]["id"]).strip().lower(), "payload_auth_id"
        except Exception:
            pass
        # 4) payload users.mongo_id
        try:
            by_mongo = supabase.table("users").select("id").eq("mongo_id", raw).limit(1).execute()
            if by_mongo.data and by_mongo.data[0].get("id"):
                return str(by_mongo.data[0]["id"]).strip().lower(), "payload_mongo_id"
        except Exception:
            pass
    # 5) payload boş/çözümsüzse auth_user_id ile çöz
    if auth_raw:
        try:
            by_auth = supabase.table("users").select("id").eq("auth_id", auth_raw).limit(1).execute()
            if by_auth.data and by_auth.data[0].get("id"):
                return str(by_auth.data[0]["id"]).strip().lower(), "auth_user_id_auth_id"
        except Exception:
            pass
        try:
            by_uuid = supabase.table("users").select("id").eq("id", auth_raw).limit(1).execute()
            if by_uuid.data and by_uuid.data[0].get("id"):
                return str(by_uuid.data[0]["id"]).strip().lower(), "auth_user_id_users_id"
        except Exception:
            pass
    return None, "not_found"


async def _resolve_driver_id_for_normal_ride_accept(
    raw_driver_id: Optional[str], auth_user_id: Optional[str] = None
) -> tuple[Optional[str], str]:
    """Normal accept akışları için driver kimliğini users.id UUID'ye çözer."""
    def _clean(v: Optional[str]) -> str:
        s = str(v or "").strip()
        if not s:
            return ""
        if s.lower() in {"none", "undefined", "null"}:
            return ""
        return s

    raw = _clean(raw_driver_id)
    auth = _clean(auth_user_id)
    candidates = [("raw", raw)] if raw else []
    if auth and auth != raw:
        candidates.append(("auth", auth))

    for src, cand in candidates:
        # 1) UUID -> users.id doğrulama
        try:
            uid = str(uuid.UUID(cand)).strip().lower()
            by_uuid = supabase.table("users").select("id").eq("id", uid).limit(1).execute()
            if by_uuid.data and by_uuid.data[0].get("id"):
                return str(by_uuid.data[0]["id"]).strip().lower(), f"{src}_uuid"
        except Exception:
            pass
        # 2) users.id lookup
        try:
            by_id = supabase.table("users").select("id").eq("id", cand).limit(1).execute()
            if by_id.data and by_id.data[0].get("id"):
                return str(by_id.data[0]["id"]).strip().lower(), f"{src}_users_id"
        except Exception:
            pass
        # 3) users.auth_id lookup
        try:
            by_auth = supabase.table("users").select("id").eq("auth_id", cand).limit(1).execute()
            if by_auth.data and by_auth.data[0].get("id"):
                return str(by_auth.data[0]["id"]).strip().lower(), f"{src}_auth_id"
        except Exception:
            pass
        # 4) users.mongo_id lookup
        try:
            by_mongo = supabase.table("users").select("id").eq("mongo_id", cand).limit(1).execute()
            if by_mongo.data and by_mongo.data[0].get("id"):
                return str(by_mongo.data[0]["id"]).strip().lower(), f"{src}_mongo_id"
        except Exception:
            pass

    if not raw and not auth:
        return None, "empty_raw_and_auth"
    return None, "not_found"


async def _create_ride_offer_execute(
    payload: CreateRideOfferRequest,
    auth_user_id: Optional[str] = None,
):
    """Teklif oluşturma iş mantığı (tag insert + dispatch)."""
    try:
        raw_passenger_id = str(payload.passenger_id or "").strip()
        logger.info("[ride/create] raw passenger_id=%s", raw_passenger_id[:96])
        logger.info("[ride/create] auth_user_id=%s", str(auth_user_id or "")[:96])
        passenger_id, reason = await _resolve_passenger_id_for_normal_ride_create(
            payload_passenger_id=raw_passenger_id,
            auth_user_id=auth_user_id,
        )
        logger.info("[ride/create] resolved passenger_id=%s", str(passenger_id or "")[:96])
        if not passenger_id:
            logger.error("[ride/create] resolve failed reason=%s", reason)
            return {"success": False, "error": "Geçersiz yolcu kimliği"}
        # Tag ID - frontend'den gelen veya yeni oluştur
        tag_id = (payload.tag_id and str(payload.tag_id).strip()) or str(uuid.uuid4())
        logger.info(
            "[normal_ride_create_request] tag_id=%s passenger_id=%s pickup_lat=%s pickup_lng=%s offered_price=%s",
            tag_id,
            str(passenger_id or "")[:96],
            payload.pickup_lat,
            payload.pickup_lng,
            getattr(payload, "offered_price", None),
        )

        # Yolcu bilgisi + araç tercihi (driver_details.passenger_preferred_vehicle)
        passenger_result = (
            supabase.table("users")
            .select("name, driver_details")
            .eq("id", passenger_id)
            .execute()
        )
        pref_from_request = _canonical_vehicle_kind(
            payload.passenger_preferred_vehicle
        ) or _canonical_vehicle_kind(payload.passenger_vehicle_kind)
        passenger_name = "Yolcu"
        passenger_pref_vehicle = pref_from_request or "car"
        if passenger_result.data:
            prow = passenger_result.data[0]
            passenger_name = prow.get("name") or "Yolcu"
            from_profile = _passenger_preferred_vehicle_from_row(prow)
            passenger_pref_vehicle = pref_from_request or from_profile or "car"
            # Profilde son tercihi sakla (bir sonraki teklif için)
            try:
                dd = _driver_details_as_dict(prow)
                dd["passenger_preferred_vehicle"] = passenger_pref_vehicle
                supabase.table("users").update({"driver_details": dd}).eq("id", passenger_id).execute()
            except Exception as sync_ve:
                logger.warning(f"passenger_preferred_vehicle profil senkronu: {sync_ve}")
        
        # Tag oluştur - Mevcut tablo kolonlarını kullan
        tag_data = {
            "id": tag_id,
            "passenger_id": passenger_id,
            "passenger_name": passenger_name,
            "pickup_lat": payload.pickup_lat,
            "pickup_lng": payload.pickup_lng,
            "pickup_location": payload.pickup_location,
            "dropoff_lat": payload.dropoff_lat,
            "dropoff_lng": payload.dropoff_lng,
            "dropoff_location": payload.dropoff_location,
            "final_price": payload.offered_price,  # offered_price yerine final_price kullan
            "status": "waiting",
            "created_at": datetime.utcnow().isoformat(),
            "passenger_preferred_vehicle": passenger_pref_vehicle,
            "type": TAG_TYPE_NORMAL,
        }
        pay_pref = _canonical_passenger_payment_method(payload.passenger_payment_method)
        if pay_pref:
            tag_data["passenger_payment_method"] = pay_pref

        trip_km = float(payload.distance_km or 0)
        trip_min = int(payload.estimated_minutes or 0)
        try:
            ri = await get_route_info(
                float(payload.pickup_lat),
                float(payload.pickup_lng),
                float(payload.dropoff_lat),
                float(payload.dropoff_lng),
            )
            if ri:
                trip_km = float(ri["distance_km"])
                trip_min = int(ri["duration_min"])
                logger.info(
                    "ride/create: rota sunucuda doğrulandı %.2f km, %s dk",
                    trip_km,
                    trip_min,
                )
        except Exception as re_err:
            logger.warning("ride/create: get_route_info atlandı: %s", re_err)
        tag_data["distance_km"] = round(trip_km, 2)
        tag_data["estimated_minutes"] = max(1, trip_min or 1)

        def _try_tags_insert(rows: dict) -> tuple:
            """(data list | None, hata metni | None)"""
            try:
                _validate_tags_insert_payload(rows, source="ride")
                r = supabase.table("tags").insert(rows).execute()
                if r.data:
                    log_src = "muhabbet" if rows.get("type") == TAG_TYPE_MUHABBET else "ride"
                    logger.info("[tag-insert] type=%s source=%s", rows.get("type"), log_src)
                    return r.data, None
                return None, "Supabase insert boş data (kolon/kısıt hatası olabilir)"
            except ValueError as ve:
                return None, str(ve)
            except Exception as ins_ex:
                return None, str(ins_ex)

        insert_variants = [
            ("full", dict(tag_data)),
            ("no_payment_col", {k: v for k, v in tag_data.items() if k != "passenger_payment_method"}),
            (
                "no_pref_col",
                {
                    k: v
                    for k, v in tag_data.items()
                    if k not in ("passenger_payment_method", "passenger_preferred_vehicle")
                },
            ),
            (
                "core_with_route",
                {
                    "id": tag_data["id"],
                    "passenger_id": tag_data["passenger_id"],
                    "passenger_name": tag_data["passenger_name"],
                    "pickup_lat": tag_data["pickup_lat"],
                    "pickup_lng": tag_data["pickup_lng"],
                    "pickup_location": tag_data["pickup_location"] or "Mevcut konum",
                    "dropoff_lat": tag_data["dropoff_lat"],
                    "dropoff_lng": tag_data["dropoff_lng"],
                    "dropoff_location": tag_data["dropoff_location"] or "Hedef",
                    "final_price": tag_data["final_price"],
                    "status": tag_data["status"],
                    "distance_km": tag_data["distance_km"],
                    "estimated_minutes": tag_data["estimated_minutes"],
                    "type": TAG_TYPE_NORMAL,
                },
            ),
            (
                "core_only",
                {
                    "id": tag_data["id"],
                    "passenger_id": tag_data["passenger_id"],
                    "passenger_name": tag_data["passenger_name"],
                    "pickup_lat": tag_data["pickup_lat"],
                    "pickup_lng": tag_data["pickup_lng"],
                    "pickup_location": tag_data["pickup_location"] or "Mevcut konum",
                    "dropoff_lat": tag_data["dropoff_lat"],
                    "dropoff_lng": tag_data["dropoff_lng"],
                    "dropoff_location": tag_data["dropoff_location"] or "Hedef",
                    "final_price": tag_data["final_price"],
                    "status": tag_data["status"],
                    "type": TAG_TYPE_NORMAL,
                },
            ),
        ]

        result_data = None
        last_ins_err = None
        used_variant = None
        for vname, insert_row in insert_variants:
            if vname != "full" and insert_row == insert_variants[0][1]:
                continue
            rd, err = _try_tags_insert(insert_row)
            if rd:
                result_data = rd
                used_variant = vname
                if vname != "full":
                    logger.warning(
                        f"tags.insert başarılı (yedek şema): variant={vname} tag_id={tag_id}"
                    )
                break
            last_ins_err = err
            logger.warning(f"tags.insert denemesi başarısız variant={vname}: {err}")

        if result_data:
            result = type("R", (), {"data": result_data})()
        else:
            result = type("R", (), {"data": None})()

        if result.data:
            tag = result.data[0]
            # Eski şemada eksik kolonlar — istemci / dispatch için tamamla
            if not tag.get("passenger_preferred_vehicle"):
                tag["passenger_preferred_vehicle"] = passenger_pref_vehicle
            if pay_pref and not tag.get("passenger_payment_method"):
                tag["passenger_payment_method"] = pay_pref
            # Response'a ek bilgiler ekle
            tag["offered_price"] = payload.offered_price  # Frontend için
            tag["distance_km"] = trip_km
            tag["estimated_minutes"] = max(1, trip_min or 1)
            logger.info(
                "[normal_ride_create_success] tag_id=%s passenger_id=%s insert_variant=%s status=%s",
                str(tag.get("id") or tag_id),
                str(passenger_id or "")[:96],
                used_variant,
                str(tag.get("status") or "waiting"),
            )
            logger.info(
                f"🏷️ Yeni teklif oluşturuldu: {tag['id']} - {payload.offered_price}TL "
                f"(yolcu araç tercihi={passenger_pref_vehicle}, insert_variant={used_variant})"
            )
            logger.info(f"PASSENGER CREATED TAG {tag_id}")
            # Dağıtım hatası teklif oluşturmayı bozmasın (yolcu ekranında "Teklif oluşturulamadı" önlenir)
            notified = 0
            try:
                logger.info("[normal_ride_dispatch_start] tag_id=%s", tag_id)
                notified = await rolling_dispatch_start(tag_id)
            except Exception as dispatch_ex:
                logger.error(f"❌ rolling_dispatch_start hata (tag kaydı başarılı): {dispatch_ex}")
            if notified == 0:
                logger.warning(
                    "⚠️ rolling_dispatch 0 sürücü tag=%s — broadcast_offer_to_all yedek deneniyor",
                    tag_id,
                )
                try:
                    bc = await broadcast_offer_to_all(
                        tag_id,
                        {
                            "passenger_id": passenger_id,
                            "passenger_name": passenger_name,
                            "pickup_lat": tag.get("pickup_lat"),
                            "pickup_lng": tag.get("pickup_lng"),
                            "pickup_location": tag.get("pickup_location"),
                            "dropoff_lat": tag.get("dropoff_lat"),
                            "dropoff_lng": tag.get("dropoff_lng"),
                            "dropoff_location": tag.get("dropoff_location"),
                            "final_price": payload.offered_price,
                            "offered_price": payload.offered_price,
                            "distance_km": trip_km,
                            "estimated_minutes": max(1, trip_min or 1),
                            "passenger_preferred_vehicle": passenger_pref_vehicle,
                            "passenger_payment_method": pay_pref
                            or tag.get("passenger_payment_method"),
                        },
                    )
                    if bc > 0:
                        notified = bc
                        logger.info(
                            "ride/create: broadcast yedek OK tag=%s notified=%s",
                            tag_id,
                            bc,
                        )
                except Exception as bc_err:
                    logger.warning("ride/create: broadcast_offer_to_all yedek hata: %s", bc_err)
            if notified == 0:
                logger.warning(
                    "[normal_ride_no_driver] tag_id=%s passenger_id=%s rolling_and_broadcast_zero=1 radius_km=%s",
                    tag_id,
                    str(passenger_id or "")[:96],
                    int(DISPATCH_RADIUS_KM),
                )
                try:
                    await sio.emit(
                        "dispatch_exhausted",
                        {
                            "tag_id": tag_id,
                            "message": f"{int(DISPATCH_RADIUS_KM)} km içinde uygun sürücü bulunamadı",
                        },
                        room=_normalize_user_room(passenger_id),
                    )
                except Exception:
                    pass

            logger.info(
                "[normal_ride_create_response] tag_id=%s passenger_id=%s notified=%s insert_variant=%s",
                str(tag.get("id") or tag_id),
                str(passenger_id or "")[:96],
                notified,
                used_variant,
            )

            logger.info(
                "[normal-ride-create] tag_id=%s passenger_id=%s status=%s dispatch_started=%s",
                str(tag.get("id") or tag_id)[:96],
                str(passenger_id or "")[:96],
                str(tag.get("status") or "waiting"),
                bool(notified >= 0),
            )

            return {
                "success": True,
                "tag": tag,
                "dispatch_mode": "rolling_batch",
                "eligible_driver_count": notified,
                "message": "Teklifiniz sürücülere gönderildi"
                if notified > 0
                else "Talep kaydedildi; yakında uygun sürücü aranıyor",
            }

        return {
            "success": False,
            "error": f"Tag oluşturulamadı (veritabanı): {last_ins_err or 'tüm insert denemeleri başarısız'}",
        }
    except Exception as e:
        logger.error(f"❌ Create ride offer error: {e}")
        return {"success": False, "error": str(e)}


@api_router.post("/ride/create-offer")
async def create_ride_offer(http_request: Request):
    """Martı TAG — yolcu teklifi; gövde JSON, Request üzerinden okunur."""
    payload = await _parse_create_ride_offer_json(http_request)
    return await _create_ride_offer_execute(payload, auth_user_id=None)


@api_router.post("/ride/create")
async def create_ride(http_request: Request):
    """
    Yolcu teklif oluşturma — POST /api/ride/create
    create-offer ile aynı: tag insert + rolling_dispatch_start.
    """
    auth_user_id = None
    try:
        authorization = http_request.headers.get("Authorization")
        if authorization:
            parts = str(authorization).strip().split(None, 1)
            if len(parts) == 2 and parts[0].lower() == "bearer" and parts[1].strip():
                auth_user_id = verify_access_token(parts[1].strip())
    except Exception:
        auth_user_id = None
    payload = await _parse_create_ride_offer_json(http_request)
    return await _create_ride_offer_execute(payload, auth_user_id=auth_user_id)


@api_router.post("/ride/accept")
async def accept_ride(tag_id: str, driver_id: str = None, http_request: Request = None):
    """
    Martı TAG - Sürücü teklifi kabul eder
    İLK KABUL EDEN KAZANIR - Atomik işlem
    Yolcu araç tercihi ile sürücü vehicle_kind eşleşmezse kabul edilmez.
    """
    try:
        auth_user_id = None
        try:
            if http_request:
                authorization = http_request.headers.get("Authorization")
                if authorization:
                    parts = str(authorization).strip().split(None, 1)
                    if len(parts) == 2 and parts[0].lower() == "bearer" and parts[1].strip():
                        auth_user_id = verify_access_token(parts[1].strip())
        except Exception:
            auth_user_id = None
        logger.info("[driver/accept] tag_id=%s", str(tag_id or "")[:96])
        logger.info("[driver/accept] raw_driver_id=%s", str(driver_id or "")[:96])
        logger.info("[driver/accept] auth_user_id=%s", str(auth_user_id or "")[:96])
        resolved_driver_id, resolve_reason = await _resolve_driver_id_for_normal_ride_accept(
            raw_driver_id=driver_id,
            auth_user_id=auth_user_id,
        )
        logger.info("[driver/accept] resolved_driver_id=%s", str(resolved_driver_id or "")[:96])
        if not resolved_driver_id:
            logger.error("[driver/accept] resolve failed reason=%s", resolve_reason)
            return {"success": False, "error": "Geçersiz sürücü"}
        # Önce tag'in durumunu kontrol et (race condition önleme)
        tag_result = supabase.table("tags").select("*").eq("id", tag_id).execute()
        
        if not tag_result.data:
            return {"success": False, "error": "Teklif bulunamadı"}
        
        tag = tag_result.data[0]
        st0 = str(tag.get("status") or "").strip().lower()
        if st0 not in {s.lower() for s in MATCHABLE_TAG_STATUSES_FOR_ACCEPT_LIST}:
            _match_accept_log(
                "MATCH_ACCEPT_LOST_ALREADY_TAKEN",
                path="ride_accept_http",
                tag_id=tag_id,
                driver_id=driver_id,
                reason="tag_not_matchable",
                current_status=tag.get("status"),
            )
            return {"success": False, "error": "Bu teklif artık mevcut değil", "already_taken": True}

        logger.info("Accept: direct match mode")

        # Sürücü bilgisini al (araç tipi doğrulaması)
        driver_result = supabase.table("users").select("name, phone, driver_details").eq("id", resolved_driver_id).execute()
        if not driver_result.data:
            return {"success": False, "error": "Şoför bulunamadı"}
        driver_eff_ar = _effective_driver_vehicle_kind(driver_result.data[0])
        pu_row_ar = None
        pida = tag.get("passenger_id")
        if pida:
            try:
                pida_r = await resolve_user_id(str(pida).strip())
                pu_ar = (
                    supabase.table("users")
                    .select("driver_details")
                    .eq("id", pida_r)
                    .limit(1)
                    .execute()
                )
                if pu_ar.data:
                    pu_row_ar = pu_ar.data[0]
            except Exception:
                pass
        trip_pref_ar = _trip_passenger_vehicle_pref(tag, pu_row_ar)
        if not _driver_matches_passenger_vehicle_pref(driver_eff_ar, trip_pref_ar):
            return {"success": False, "error": "Bu talep için araç tipiniz uygun değil"}
        driver_name = driver_result.data[0]["name"] if driver_result.data else "Sürücü"
        
        # Yolcu bilgisini al - passenger_id kullan (tag'da bazen user_id olarak da saklanabilir)
        passenger_id = tag.get("passenger_id")
        if not passenger_id:
            refetch = supabase.table("tags").select("passenger_id").eq("id", tag_id).limit(1).execute()
            if refetch.data and refetch.data[0].get("passenger_id"):
                passenger_id = refetch.data[0]["passenger_id"]
        if passenger_id:
            passenger_id = await resolve_user_id(passenger_id)

        if passenger_id:
            passenger_result = supabase.table("users").select("name, phone").eq("id", passenger_id).execute()
            passenger_name = passenger_result.data[0]["name"] if passenger_result.data else "Yolcu"
        else:
            passenger_name = "Yolcu"

        _match_accept_log(
            "MATCH_ACCEPT_ATTEMPT",
            path="ride_accept_http",
            tag_id=tag_id,
            driver_id=resolved_driver_id,
            passenger_id=passenger_id,
        )

        o_drv_ra = _other_active_tag_id_sync(
            supabase,
            column="driver_id",
            user_id=str(resolved_driver_id),
            exclude_tag_id=tag_id,
        )
        if o_drv_ra:
            _match_accept_log(
                "MATCH_ACCEPT_BLOCKED_DRIVER_BUSY",
                tag_id=tag_id,
                driver_id=resolved_driver_id,
                conflicting_tag_id=o_drv_ra,
            )
            logger.info(
                "MATCH_DRIVER_LOCKED path=ride_accept_http tag_id=%s driver_id=%s conflict=%s",
                tag_id,
                str(resolved_driver_id)[:13],
                o_drv_ra,
            )
            return {
                "success": False,
                "error": "Zaten devam eden bir yolculuğunuz var",
                "driver_busy": True,
            }

        if passenger_id:
            o_pax_ra = _other_active_tag_id_sync(
                supabase,
                column="passenger_id",
                user_id=str(passenger_id),
                exclude_tag_id=tag_id,
            )
            if o_pax_ra:
                _match_accept_log(
                    "MATCH_ACCEPT_BLOCKED_PASSENGER_BUSY",
                    tag_id=tag_id,
                    passenger_id=passenger_id,
                    conflicting_tag_id=o_pax_ra,
                )
                return {
                    "success": False,
                    "error": "Yolcu başka bir yolculukta",
                    "passenger_busy": True,
                }

        # Atomik güncelleme — yalnızca waiting / pending / offers_received
        # postgrest-py 2.x: update().select() kullanılamaz; return=representation varsayılan → data dolu
        update_result = supabase.table("tags").update({
            "status": "matched",
            "driver_id": resolved_driver_id,
            "driver_name": driver_name,
            "matched_at": datetime.utcnow().isoformat()
        }).eq("id", tag_id).in_("status", MATCHABLE_TAG_STATUSES_FOR_ACCEPT_LIST).execute()
        
        if not update_result.data:
            _match_accept_log(
                "MATCH_ACCEPT_LOST_ALREADY_TAKEN",
                path="ride_accept_http",
                tag_id=tag_id,
                driver_id=resolved_driver_id,
                passenger_id=passenger_id,
            )
            return {"success": False, "error": "Bu teklif artık mevcut değil", "already_taken": True}
        
        updated_tag = update_result.data[0]
        updated_tag["passenger_name"] = passenger_name
        _match_accept_log(
            "MATCH_ACCEPT_WON",
            path="ride_accept_http",
            tag_id=tag_id,
            driver_id=resolved_driver_id,
            passenger_id=passenger_id,
        )

        try:
            await rolling_dispatch_stop(
                tag_id, revoke_offers=True, except_driver_id=resolved_driver_id
            )
        except Exception as _rds:
            logger.warning(f"rolling_dispatch_stop after accept_ride (non-fatal): {_rds}")
        try:
            await handle_dispatch_accept(tag_id, resolved_driver_id)
        except Exception as _hda:
            logger.warning(f"handle_dispatch_accept after accept_ride (non-fatal): {_hda}")
        try:
            await match_accept_cleanup_foreign_offers(
                resolved_driver_id, tag_id, log_path="ride_accept_http"
            )
        except Exception as _cl:
            logger.warning("match_accept_cleanup_foreign_offers ride/accept (non-fatal): %s", _cl)

        # Socket: yolcu / sürücü (DB dispatch_queue kullanılmıyor)
        match_socket_payload = {
            "tag_id": tag_id,
            "status": "matched",
            "driver_id": resolved_driver_id,
            "driver_name": driver_name,
            "passenger_id": passenger_id,
            "passenger_name": passenger_name,
            "pickup_location": updated_tag.get("pickup_location"),
            "pickup_lat": updated_tag.get("pickup_lat"),
            "pickup_lng": updated_tag.get("pickup_lng"),
            "dropoff_location": updated_tag.get("dropoff_location"),
            "dropoff_lat": updated_tag.get("dropoff_lat"),
            "dropoff_lng": updated_tag.get("dropoff_lng"),
            "final_price": updated_tag.get("final_price"),
            "matched_at": updated_tag.get("matched_at"),
            "passenger_payment_method": updated_tag.get("passenger_payment_method"),
        }
        try:
            pl_ar = await passenger_location_for_driver_socket(
                str(passenger_id) if passenger_id else None, updated_tag
            )
            if pl_ar:
                match_socket_payload["passenger_location"] = pl_ar
        except Exception as _pla:
            logger.warning(f"passenger_location (accept_ride socket): {_pla}")
        if passenger_id:
            logger.info("[emit] passenger_id=%s", str(passenger_id)[:96])
            logger.info("[emit] passenger_sids=%s", _all_sids_for_registered_user(str(passenger_id)))
            logger.info("[emit] sending ride_matched")
            await emit_socket_event_to_user(passenger_id, "ride_accepted", match_socket_payload)
            await emit_socket_event_to_user(passenger_id, "ride_matched", match_socket_payload)
            if not _all_sids_for_registered_user(str(passenger_id)):
                logger.error("[emit] passenger_sid_empty passenger_id=%s", str(passenger_id)[:96])
        await emit_socket_event_to_user(resolved_driver_id, "ride_matched", match_socket_payload)
        
        # Push (Expo) — teklif kanalıyla aynı
        await send_match_notification_to_both(tag_id, resolved_driver_id, passenger_id)
        
        logger.info(f"✅ Eşleşme: {tag_id} - Sürücü: {driver_name}")
        
        return {
            "success": True,
            "tag": updated_tag,
            "message": "Teklif kabul edildi!"
        }
    except Exception as e:
        logger.error(f"❌ Accept ride error: {e}")
        return {"success": False, "error": str(e)}

@api_router.get("/ride/available-offers")
async def get_available_offers(driver_id: str, lat: float, lng: float, radius_km: float = 20):
    """
    Martı TAG - Sürücü için mevcut teklifleri getir
    Sadece 'waiting' durumundaki ve yakındaki teklifler
    """
    try:
        resolved_driver_id = await resolve_user_id(driver_id)
        dr_row = (
            supabase.table("users")
            .select("driver_details")
            .eq("id", resolved_driver_id)
            .limit(1)
            .execute()
        )
        driver_eff = _effective_driver_vehicle_kind(dr_row.data[0] if dr_row.data else {})

        # Tüm bekleyen teklifleri al
        result = (
            supabase.table("tags")
            .select("*")
            .eq("type", TAG_TYPE_NORMAL)
            .eq("status", "waiting")
            .order("created_at", desc=True)
            .limit(50)
            .execute()
        )
        
        offers = []
        for tag in result.data or []:
            trip_pref = _trip_passenger_vehicle_pref(tag, None)
            if not _driver_matches_passenger_vehicle_pref(driver_eff, trip_pref):
                continue
            try:
                p_la = float(tag["pickup_lat"])
                p_lo = float(tag["pickup_lng"])
            except (TypeError, ValueError, KeyError):
                continue
            if not _bbox_road_prefilter_ok(float(lat), float(lng), p_la, p_lo, radius_km):
                continue
            ri_o = await get_route_info(float(lat), float(lng), p_la, p_lo)
            if not ri_o or float(ri_o["distance_km"]) > radius_km:
                continue
            road_o = round(float(ri_o["distance_km"]), 1)
            tag["distance_to_pickup"] = road_o
            tag["pickup_distance_km"] = road_o
            tag["pickup_eta_min"] = int(max(1, round(float(ri_o["duration_min"]))))
            tag["passenger_name"] = tag.get("passenger_name") or "Yolcu"
            offers.append(tag)
        
        # Mesafeye göre sırala (en yakın önce)
        offers.sort(key=lambda x: x["distance_to_pickup"])
        
        return {"success": True, "offers": offers, "count": len(offers)}
    except Exception as e:
        logger.error(f"❌ Get available offers error: {e}")
        return {"success": False, "error": str(e), "offers": []}

