def _looks_like_phone(uid: str) -> bool:
    """user_id 10 haneli rakam ise (Türkiye telefonu) telefon kabul et."""
    if not uid or len(uid) > 15:
        return False
    digits = "".join(c for c in uid if c.isdigit())
    return len(digits) >= 10 and digits[:1] in "59"  # 5xxxxxxxxx veya 9xxxxxxxxx


_PUSH_CANONICAL_EXEMPT_TYPES = frozenset(
    {
        "incoming_call",
        "missed_call",
        "call_ended",
        "call_missed",
        "test",
        "admin_push_test",
        # Leylek Muhabbeti — conversation_id / session_id ile yönlendirme; tag_id yok
        "muhabbet_message",
        "message",
        "call",
        "trip",
        "qr",
        "leylek_pair_match_request",
        "leylek_key_match_completed",
    }
)


def _canonical_push_routing_data(data: Optional[dict]) -> dict:
    """
    Client yönlendirme: data.type ∈ {chat, match, offer} ve tag_id (varsa).
    Eski `type` değeri detail_type olarak saklanır (arama / test tipleri aynen bırakılır).
    """
    d = dict(data or {})
    legacy = str(d.get("type") or "").strip()
    if legacy in _PUSH_CANONICAL_EXEMPT_TYPES:
        return d

    tid = d.get("tag_id") or d.get("trip_id")
    tid_s = str(tid).strip() if tid else ""

    leg_l = legacy.lower()
    route = "offer"
    if leg_l == "first_chat_message" or d.get("sender_id"):
        route = "chat"
    elif (
        d.get("event") == "match"
        or leg_l
        in (
            "match_confirmed",
            "match_found",
            "matched",
            "new_ride_request",
            "match",
            "tag_matched",
        )
    ):
        route = "match"
    elif leg_l in ("new_offer", "offer") or d.get("offer_id"):
        route = "offer"
    elif leg_l == "force_ended" and tid_s:
        route = "match"

    if legacy and legacy not in ("chat", "match", "offer"):
        d["detail_type"] = legacy
    d["type"] = route
    if tid_s:
        d["tag_id"] = tid_s
    return d


def _muhabbet_user_push_first_name(user_id: Optional[str]) -> str:
    uid = str(user_id or "").strip().lower()
    if not uid:
        return ""
    try:
        user_result = supabase.table("users").select("name").eq("id", uid).limit(1).execute()
        if user_result.data:
            return _push_first_name(user_result.data[0].get("name"), 12) or ""
    except Exception:
        pass
    return ""


def schedule_muhabbet_leylek_push(
    user_id: Optional[str],
    push_type: str,
    *,
    session_id: Optional[str] = None,
    conversation_id: Optional[str] = None,
    title: str,
    body: str,
    extra: Optional[dict] = None,
) -> None:
    """Muhabbet / Leylek Trip kanalı — data.type ∈ {message, call, trip, qr}; socket’a ek olarak FCM."""
    uid = str(user_id or "").strip().lower()
    if not uid:
        return
    data: dict = {
        "type": str(push_type or "").strip().lower(),
        "session_id": str(session_id or "").strip().lower(),
        "conversation_id": str(conversation_id or "").strip().lower(),
        "title": title,
        "body": body,
    }
    if extra:
        for k, v in extra.items():
            if v is None:
                continue
            data[str(k)] = v
    try:
        asyncio.create_task(send_push_notification(uid, title, body, data))
    except Exception as e:
        logger.warning("[muhabbet_leylek_push] schedule failed user=%s err=%s", uid[:12], e)


def _schedule_muhabbet_incoming_call_push(payload: dict, session_id: str, caller_uid: str) -> None:
    target_uid = str(payload.get("target_user_id") or "").strip().lower()
    if not target_uid:
        return
    nm = _muhabbet_user_push_first_name(caller_uid)
    cid_lo = str(payload.get("conversation_id") or "").strip().lower()
    sid = str(session_id or "").strip().lower()
    schedule_muhabbet_leylek_push(
        target_uid,
        "call",
        session_id=sid,
        conversation_id=cid_lo,
        title="Muhabbet araması",
        body=f"{nm or 'Karşı taraf'} sizi arıyor",
        extra={"caller_id": str(caller_uid).strip().lower()},
    )


def schedule_muhabbet_trip_convert_request_push(
    target_user_id: Optional[str],
    conversation_id: str,
    request_id: str,
    requester_user_id: str,
) -> None:
    nm = _muhabbet_user_push_first_name(requester_user_id) or "Sürücü"
    cid = str(conversation_id or "").strip().lower()
    schedule_muhabbet_leylek_push(
        target_user_id,
        "trip",
        session_id=None,
        conversation_id=cid,
        title="Yolculuk isteği",
        body=f"{nm} Muhabbet sohbetini yolculuğa çevirmek istiyor",
        extra={
            "request_id": str(request_id).strip().lower(),
            "requester_user_id": str(requester_user_id).strip().lower(),
        },
    )


def _schedule_muhabbet_boarding_qr_passenger_push(out: dict, session_id: str, driver_uid: str) -> None:
    emit_payload = out.get("emit_payload") if isinstance(out.get("emit_payload"), dict) else {}
    sess = emit_payload.get("session") if isinstance(emit_payload.get("session"), dict) else {}
    passenger_id = str(sess.get("passenger_id") or "").strip().lower()
    du = str(driver_uid or "").strip().lower()
    cid = str(sess.get("conversation_id") or emit_payload.get("conversation_id") or "").strip().lower()
    sid = str(session_id or "").strip().lower()
    if passenger_id and passenger_id != du:
        schedule_muhabbet_leylek_push(
            passenger_id,
            "qr",
            session_id=sid,
            conversation_id=cid,
            title="Biniş QR",
            body="Sürücü biniş QR kodunu gösterdi • Okutmak için dokunun",
            extra={"qr_mode": "boarding"},
        )


def _schedule_muhabbet_finish_qr_passenger_push(next_row: dict, session_id: str, driver_uid: str) -> None:
    passenger_id = str(next_row.get("passenger_id") or "").strip().lower()
    du = str(driver_uid or "").strip().lower()
    cid = str(next_row.get("conversation_id") or "").strip().lower()
    sid = str(session_id or "").strip().lower()
    if passenger_id and passenger_id != du:
        schedule_muhabbet_leylek_push(
            passenger_id,
            "qr",
            session_id=sid,
            conversation_id=cid,
            title="Bitiş QR",
            body="Sürücü bitiş QR kodunu gösterdi • Okutmak için dokunun",
            extra={"qr_mode": "finish"},
        )


def _receipt_device_not_registered(receipt: Optional[dict]) -> bool:
    if not receipt or not isinstance(receipt, dict):
        return False
    blob = json.dumps(receipt, ensure_ascii=False).lower()
    return "devicenotregistered" in blob


async def _clear_user_fcm_push_token(user_id: str) -> None:
    """FCM UNREGISTERED — yalnızca native FCM token alanını temizle (Expo token'a dokunma)."""
    uid = str(user_id or "").strip()
    if not uid:
        return
    logger.warning("PUSH_TOKEN_INVALIDATED transport=fcm db_clear user_id=%s", uid[:12])
    try:
        supabase.table("users").update(
            {"fcm_push_token": None, "fcm_push_token_updated_at": None}
        ).eq("id", uid).execute()
    except Exception as e:
        logger.warning("fcm_push_token DB temizliği başarısız (kolon yok olabilir): %s", e)


async def _clear_user_expo_push_tokens(user_id: str) -> None:
    """Expo DeviceNotRegistered — kullanıcı satırındaki push token alanlarını temizle."""
    uid = str(user_id or "").strip()
    if not uid:
        return
    logger.warning("📴 Expo DeviceNotRegistered — DB push token temizleniyor user_id=%s", uid[:12])
    try:
        try:
            supabase.table("users").update(
                {"push_token": None, "expo_push_token": None, "push_token_updated_at": None}
            ).eq("id", uid).execute()
        except Exception:
            supabase.table("users").update({"push_token": None, "push_token_updated_at": None}).eq("id", uid).execute()
    except Exception as e:
        logger.error("push token DB temizliği başarısız: %s", e)


def _users_select_push_columns() -> str:
    """fcm_push_token kolonu yoksa daraltılmış select (migration öncesi uyumluluk)."""
    return "push_token, expo_push_token, fcm_push_token, name, id, phone"


def _users_select_push_columns_fallback() -> str:
    return "push_token, expo_push_token, name, id, phone"


def _user_row_has_fcm_for_push(row: Optional[dict]) -> bool:
    """send_push_notification yalnızca FCM kullanır; toplu/admin hedef listesi buna göre seçilmeli."""
    if not row or not row.get("id"):
        return False
    ft = (row.get("fcm_push_token") or "").strip()
    if ft and is_probable_fcm_registration_token(ft):
        return True
    uid = str(row.get("id") or "").strip().lower()
    if not uid:
        return False
    try:
        chk = supabase.table("user_push_tokens").select("id").eq("user_id", uid).limit(1).execute()
        return bool(chk.data)
    except Exception:
        return False


def _collect_fcm_tokens_for_user(resolved_uid: str) -> list[str]:
    """user_push_tokens + users.fcm_push_token; sıra korunur, tekrarsız."""
    uid = str(resolved_uid or "").strip().lower()
    out: list[str] = []
    seen: set[str] = set()
    if not uid:
        return out
    try:
        r = supabase.table("user_push_tokens").select("token").eq("user_id", uid).execute()
        for row in r.data or []:
            t = (row.get("token") or "").strip()
            if t and is_probable_fcm_registration_token(t) and t not in seen:
                seen.add(t)
                out.append(t)
    except Exception as e:
        logger.debug("user_push_tokens read skipped user_id=%s err=%s", uid[:12], e)
    try:
        ur = supabase.table("users").select("fcm_push_token").eq("id", uid).limit(1).execute()
        if ur.data:
            lt = (ur.data[0].get("fcm_push_token") or "").strip()
            if lt and is_probable_fcm_registration_token(lt) and lt not in seen:
                seen.add(lt)
                out.append(lt)
    except Exception as e:
        logger.debug("users.fcm_push_token read skipped: %s", e)
    return out


def _user_push_token_upsert(user_id: str, token: str) -> None:
    uid = str(user_id or "").strip().lower()
    tok = (token or "").strip()
    if not uid or not tok or not is_probable_fcm_registration_token(tok):
        return
    try:
        supabase.table("user_push_tokens").upsert(
            {"user_id": uid, "token": tok},
            on_conflict="user_id,token",
        ).execute()
    except Exception as e:
        logger.warning("user_push_tokens upsert failed user_id=%s err=%s", uid[:12], e)


async def _remove_invalid_fcm_device_token(user_id: str, bad_token: str) -> None:
    uid = str(user_id or "").strip().lower()
    bt = (bad_token or "").strip()
    if not uid or not bt:
        return
    try:
        supabase.table("user_push_tokens").delete().eq("user_id", uid).eq("token", bt).execute()
    except Exception as e:
        logger.debug("user_push_tokens delete failed: %s", e)
    try:
        ur = supabase.table("users").select("fcm_push_token").eq("id", uid).limit(1).execute()
        if ur.data and (ur.data[0].get("fcm_push_token") or "").strip() == bt:
            await _clear_user_fcm_push_token(uid)
    except Exception:
        pass


async def send_push_notification(user_id: str, title: str, body: str, data: dict = None):
    """Tek kullanıcıya FCM: user_push_tokens + users.fcm_push_token (çoklu cihaz). Expo kullanılmaz."""
    try:
        uid = str(user_id).strip() if user_id else ""
        if not uid:
            logger.warning("PUSH_SEND_ERROR transport=fcm reason=user_id_empty")
            return False

        def _sel_u(cols: str, eq_key: str, eq_val: str):
            return supabase.table("users").select(cols).eq(eq_key, eq_val).limit(1).execute()

        cols_primary = _users_select_push_columns()
        cols_fb = _users_select_push_columns_fallback()
        try:
            user_result = _sel_u(cols_primary, "id", uid)
        except Exception:
            user_result = _sel_u(cols_fb, "id", uid)
        # UUID büyük/küçük harf farkı
        if not user_result.data and "-" in uid:
            try:
                user_result = _sel_u(cols_primary, "id", uid.lower())
            except Exception:
                user_result = _sel_u(cols_fb, "id", uid.lower())
        # Telefon ile fallback: E.164 normalize et, tüm olası DB formatlarını dene
        if not user_result.data and _looks_like_phone(uid):
            phone_e164 = normalize_phone_e164(uid)
            if phone_e164:
                digits_only = "".join(c for c in phone_e164 if c.isdigit())
                ten_digit = digits_only[-10:] if len(digits_only) >= 10 else digits_only
                candidates = [
                    phone_e164,
                    digits_only,
                    ten_digit,
                    "0" + ten_digit if len(ten_digit) == 10 else None,
                ]
                seen = set()
                for candidate in candidates:
                    if not candidate or candidate in seen:
                        continue
                    seen.add(candidate)
                    try:
                        user_result = _sel_u(cols_primary, "phone", candidate)
                    except Exception:
                        user_result = _sel_u(cols_fb, "phone", candidate)
                    if user_result.data:
                        break
                if not user_result.data and len(ten_digit) >= 10:
                    try:
                        like_r = (
                            supabase.table("users")
                            .select(cols_primary)
                            .like("phone", f"%{ten_digit}%")
                            .limit(5)
                            .execute()
                        )
                    except Exception:
                        like_r = (
                            supabase.table("users")
                            .select(cols_fb)
                            .like("phone", f"%{ten_digit}%")
                            .limit(5)
                            .execute()
                        )
                    if like_r.data:
                        for row in like_r.data:
                            if ten_digit in "".join(c for c in (row.get("phone") or "") if c.isdigit()):
                                class _R:
                                    pass

                                user_result = _R()
                                user_result.data = [row]
                                break
        if not user_result.data:
            logger.warning("PUSH_SEND_ERROR transport=fcm reason=user_not_found user_id=%s", uid[:36])
            return False
        row = user_result.data[0]
        uid_resolved = str(row.get("id") or uid).strip().lower()
        tokens = _collect_fcm_tokens_for_user(uid_resolved)
        if not tokens:
            logger.warning(
                "PUSH_SEND_ERROR transport=fcm reason=no_valid_fcm_token user_id=%s",
                str(uid_resolved),
            )
            return False

        if not is_fcm_configured():
            logger.warning("FCM not configured — falling back to socket only")
            return False

        payload = _canonical_push_routing_data(data)
        any_ok = False
        for fcm_token in tokens:
            ok_fcm, err_code = await asyncio.to_thread(
                send_fcm_notification_sync, fcm_token, title, body, payload
            )
            if ok_fcm:
                any_ok = True
            else:
                logger.warning(
                    "PUSH_SEND_ERROR transport=fcm user_id=%s err=%s",
                    str(uid_resolved),
                    err_code,
                )
                if err_code == "unregistered":
                    await _remove_invalid_fcm_device_token(uid_resolved, fcm_token)
        if any_ok:
            logger.info("PUSH_SEND_TRANSPORT=fcm")
            logger.info("PUSH_SEND_SUCCESS transport=fcm user_id=%s", str(uid_resolved))
            return True
        return False
    except Exception as e:
        logger.exception("PUSH_SEND_ERROR transport=fcm reason=exception err=%s", e)
        return False


async def send_push(user_id: str, title: str, body: str, data: dict = None) -> bool:
    """FCM push — send_push_notification ile aynı (çoklu cihaz + user_push_tokens)."""
    return await send_push_notification(user_id, title, body, data)


async def send_match_notification_to_both(tag_id: str, driver_id: str, passenger_id: str) -> dict:
    """
    Eşleşme tam bu anda – sürücü ve yolcuya anında bildirim.
    Teklif bildirimi çalıştığı için aynı type (new_offer) + event=match ile Expo'ya gidiyor.
    Returns: {"driver": bool, "passenger": bool}
    """
    out = {"driver": False, "passenger": False}
    logger.info(f"📢 EŞLEŞME BİLDİRİMİ BAŞLADI: tag_id={tag_id}, driver_id={driver_id}, passenger_id={passenger_id}")
    try:
        tag_row = supabase.table("tags").select("id, passenger_id, driver_id, pickup_lat, pickup_lng, final_price").eq("id", tag_id).limit(1).execute()
        if not tag_row.data:
            logger.warning(f"🔔 Eşleşme bildirimi: tag bulunamadı {tag_id}")
            return out
        row = tag_row.data[0]
        d_id = str(row.get("driver_id") or driver_id or "").strip() or None
        p_id = str(row.get("passenger_id") or passenger_id or "").strip() or None
        if not d_id and not p_id:
            logger.warning(f"🔔 Eşleşme bildirimi: driver_id ve passenger_id yok")
            return out
        eta_min = 0
        try:
            if d_id and row.get("pickup_lat") is not None and row.get("pickup_lng") is not None:
                loc = supabase.table("users").select("latitude, longitude").eq("id", d_id).limit(1).execute()
                if loc.data and loc.data[0].get("latitude") is not None:
                    eta_min = _eta_minutes(
                        loc.data[0].get("latitude"), loc.data[0].get("longitude"),
                        float(row["pickup_lat"]), float(row["pickup_lng"])
                    )
        except Exception:
            pass
        driver_body = (
            f"Yolcuya ~{eta_min} dk • Rotayı görmek için dokun"
            if eta_min
            else "Yolcu hazır • Rotayı görmek için dokun"
        )
        if len(driver_body) > 72:
            driver_body = driver_body[:69] + "…"
        passenger_title = "Eşleşme sağlandı"
        passenger_body = "Sürücü bulundu • Detayları görmek için dokun"
        # Teklif bildirimi gibi type=new_offer kullan (cihazda aynı kanal/aynı davranış); event=match ile uygulama eşleşme ekranına gidebilir
        base_data = {"type": "new_offer", "event": "match", "tag_id": tag_id, "eta_min": eta_min}
        if d_id:
            driver_data = {**base_data, "role": "driver", "price": int(row.get("final_price") or row.get("offered_price") or 0)}
            out["driver"] = await send_trip_push_and_log(d_id, "new_ride_request", "Eşleşme sağlandı", driver_body, driver_data)
            logger.info(f"🔔 Eşleşme push sürücü: {d_id[:8]}... sonuç={out['driver']}")
        if p_id:
            passenger_data = {**base_data, "role": "passenger"}
            out["passenger"] = await send_trip_push_and_log(p_id, "new_ride_request", passenger_title, passenger_body, passenger_data)
            logger.info(f"🔔 Eşleşme push yolcu: {p_id[:8]}... sonuç={out['passenger']}")
        logger.info(f"📢 EŞLEŞME BİLDİRİMİ BİTTİ: tag_id={tag_id}, driver={out['driver']}, passenger={out['passenger']}")
    except Exception as e:
        logger.exception(f"🔔 send_match_notification_to_both hata: {e}")
    return out


async def send_trip_push_and_log(user_id: str, notification_type: str, title: str, body: str, data: dict = None) -> bool:
    """
    Trip lifecycle (ve diğer) bildirimleri: önce notifications_log'a yaz, sonra push gönder.
    Tüm bildirimler loglanır (token yoksa bile). user_id users.id (UUID string) olmalı.
    """
    uid = str(user_id).strip() if user_id else None
    if not uid:
        logger.warning("⚠️ send_trip_push_and_log: user_id boş")
        return False
    payload = data or {}
    payload.setdefault("type", notification_type)
    try:
        supabase.table("notifications_log").insert({
            "type": notification_type,
            "user_id": uid,
            "title": title,
            "body": body,
            "created_at": datetime.utcnow().isoformat(),
        }).execute()
    except Exception as log_err:
        logger.warning(f"⚠️ notifications_log insert failed: {log_err}")
    ok = await send_push_notification(uid, title, body, payload)
    if not ok:
        logger.warning(f"⚠️ Trip push gönderilemedi: user_id={uid}, type={notification_type}, title={title!r}")
    return ok


async def send_push_notifications_to_users(user_ids: list, title: str, body: str, data: dict = None) -> dict:
    """Birden fazla kullanıcıya, tekil send_push_notification fonksiyonu ile gönder."""
    sent = 0
    failed = 0

    for user_id in user_ids or []:
        if await send_push_notification(user_id, title, body, data):
            sent += 1
        else:
            failed += 1

    return {"sent": sent, "failed": failed, "total": len(user_ids or [])}

def _expo_push_data_stringify(data: Optional[dict]) -> dict:
    """
    Expo Push HTTP API: data içindeki tüm değerler string olmalı.
    int/bool/float gönderildiğinde bildirim reddedilebilir veya cihaza hiç düşmez.
    """
    if not data:
        return {}
    out = {}
    for k, v in data.items():
        if v is None:
            continue
        key = str(k)
        if isinstance(v, (dict, list)):
            out[key] = json.dumps(v, ensure_ascii=False)
        elif isinstance(v, bool):
            out[key] = "true" if v else "false"
        else:
            out[key] = str(v)
    return out


async def _expo_get_push_receipts(ticket_ids: list) -> dict:
    """
    Expo Push getReceipts — gönderim cevabındaki bilet 'ok' olsa bile FCM/APNs teslim katmanında
    hata olabilir (DeviceNotRegistered, InvalidCredentials vb.). ~2 sn sonra sorgulanır.
    """
    import asyncio

    ids = [str(x).strip() for x in (ticket_ids or []) if x]
    if not ids:
        return {}
    await asyncio.sleep(1.8)
    try:
        import httpx

        async with httpx.AsyncClient(http2=False, timeout=30) as client:
            r = await client.post(
                "https://exp.host/--/api/v2/push/getReceipts",
                json={"ids": ids},
                headers=_expo_push_request_headers(),
            )
        if r.status_code != 200:
            logger.warning(f"Expo getReceipts HTTP {r.status_code}: {r.text[:500]}")
            return {"http_status": r.status_code, "body": r.text[:800]}
        return r.json()
    except Exception as e:
        logger.warning(f"Expo getReceipts: {e}")
        return {"exception": str(e)}


def _expo_push_send_requests_sync(
    token: str, title: str, body: str, data: Optional[dict] = None
) -> Tuple[bool, dict]:
    """
    Expo Push HTTP API — requests.post (exp.host).
    Yanıt gövdesi loglanır; (success, receipt_or_error) döner.
    """
    import requests

    tok = (token or "").strip()
    if not tok:
        logger.warning("Expo push: token boş — gönderilmedi")
        return False, {"error": "token_empty"}
    if not ExpoPushService.is_valid_token(tok):
        logger.warning(
            "Expo push: geçersiz token formatı (ExponentPushToken[...] veya ExpoPushToken[...]) — gönderilmedi"
        )
        return False, {"error": "invalid_token_format"}

    payload = _expo_push_data_stringify(data or {})
    notification_type = payload.get("type")
    channel_id = expo_android_channel_id_for_type(notification_type)
    message = {
        "to": tok,
        "title": title,
        "body": body,
        "sound": "default",
        "priority": "high",
        "channelId": channel_id,
    }
    if payload:
        message["data"] = payload
    messages_payload = [message]

    response = requests.post(
        "https://exp.host/--/api/v2/push/send",
        json=messages_payload,
        headers=_expo_push_request_headers(),
        timeout=25,
    )
    try:
        response_data = response.json()
    except Exception:
        response_data = {"_non_json": True, "text": (response.text or "")[:1500]}
    try:
        print(response_data)
    except Exception:
        pass
    logger.info("Expo push (requests) HTTP %s body=%s", response.status_code, str(response_data)[:2500])
    if response.status_code != 200:
        return False, {"http_status": response.status_code, "body": response_data}
    receipts = response_data.get("data") or []
    if not receipts:
        return False, {"error": "boş receipt listesi", "raw": response_data}
    first = receipts[0]
    if first.get("status") == "error":
        err_msg = first.get("message", "bilinmeyen hata")
        logger.error(
            "❌ Expo push receipt status=error | message=%s | full=%s",
            err_msg,
            json.dumps(first, ensure_ascii=False)[:2000],
        )
        return False, first
    tid = first.get("id")
    if tid:
        logger.info("✅ Expo push bilet id=%s", tid)
    else:
        logger.info("✅ Expo push receipt status=%s", first.get("status", "ok"))
    return True, first


async def _send_expo_and_get_receipt(
    token: str, title: str, body: str, data: dict = None, db_user_id: Optional[str] = None
):
    """Expo Push API'ye istek atar; (success, receipt_dict) döner."""
    try:
        if not token or not str(token).strip():
            return False, {"error": "token boş"}
        if not ExpoPushService.is_valid_token(str(token).strip()):
            return False, {"error": "invalid_token_format"}
        logger.info("🔔 Expo push (async thread): token=%s...", (token[:50] if token else ""))
        ok, receipt = await asyncio.to_thread(_expo_push_send_requests_sync, token, title, body, data)
        if (
            not ok
            and db_user_id
            and _receipt_device_not_registered(receipt if isinstance(receipt, dict) else None)
        ):
            await _clear_user_expo_push_tokens(db_user_id)
        return ok, receipt
    except Exception as e:
        logger.error(f"❌ Expo API exception: {e}")
        return False, {"exception": str(e)}


async def send_expo_notification(
    token: str, title: str, body: str, data: dict = None, db_user_id: Optional[str] = None
):
    """Expo Push API ile bildirim gönder"""
    success, _ = await _send_expo_and_get_receipt(token, title, body, data, db_user_id=db_user_id)
    return success


async def send_expo_push(token: str, title: str, body: str, data: Optional[dict] = None) -> bool:
    """
    Basit helper: token -> Expo Push API'ye gönder.
    data: new_offer yönlendirmesi için tag_id vb. (type her zaman new_offer kalır).
    """
    try:
        if not token:
            logger.warning("send_expo_push: token None/boş")
            return False

        # 5 saniyelik hard timeout: expo tarafı takılırsa event-loop bloke olmasın.
        if not ExpoPushService.is_valid_token(str(token).strip()):
            logger.warning("send_expo_push: geçersiz Expo token formatı")
            return False
        push_data: dict = {"type": "new_offer"}
        if data:
            for k, v in data.items():
                if v is not None and k != "type":
                    push_data[k] = v
        ok, _ = await asyncio.wait_for(
            _send_expo_and_get_receipt(
                token=token,
                title=title,
                body=body,
                data=push_data,
                db_user_id=None,
            ),
            timeout=5.0,
        )
        return ok
    except asyncio.TimeoutError:
        logger.warning("send_expo_push: timeout (5s)")
        return False
    except Exception as e:
        logger.warning(f"send_expo_push failed: {e}")
        return False

async def send_bulk_push_notification(title: str, body: str, target: str = "all", data: dict = None):
    """Toplu push bildirim gönder — send_push_notification (FCM) ile uyumlu kullanıcı seçimi."""
    try:
        query = supabase.table("users").select("id, push_token, fcm_push_token, driver_details, driver_online")
        
        if target == "drivers":
            # Sadece sürücülere (driver_details olan)
            query = query.not_.is_("driver_details", "null")
        elif target == "passengers":
            # Sadece yolculara (driver_details olmayan)
            query = query.is_("driver_details", "null")
        elif target == "online_drivers":
            # Sadece online sürücülere
            query = query.eq("driver_online", True)
        
        result = query.execute()
        
        if not result.data:
            return 0
        
        user_ids = [user["id"] for user in result.data if _user_row_has_fcm_for_push(user)]

        if not user_ids:
            logger.info(f"📭 FCM token'ı olan kullanıcı bulunamadı (target={target})")
            return 0

        send_result = await send_push_notifications_to_users(user_ids, title, body, data)
        sent_count = send_result["sent"]

        logger.info(f"📤 Toplu push gönderildi: {sent_count}/{send_result['total']} kullanıcı - {title}")
        
        # Admin bildirimini kaydet
        try:
            supabase.table("admin_notifications_log").insert({
                "title": title,
                "body": body,
                "target": target,
                "sent_count": sent_count,
                "created_at": datetime.utcnow().isoformat()
            }).execute()
        except:
            pass
        
        return sent_count
    except Exception as e:
        logger.error(f"Bulk push error: {e}")
        return 0

@api_router.post("/admin/notifications/send")
async def admin_send_push(admin_phone: str, title: str, body: str, target: str = "all", user_id: str = None, data: str = None):
    """Admin - Push bildirim gönder"""
    try:
        if admin_phone not in ADMIN_PHONE_NUMBERS:
            raise HTTPException(status_code=403, detail="Admin yetkisi gerekli")
        
        # Bildirimi kaydetmeyi dene (tablo yoksa atla)
        try:
            notification_data = {
                "title": title,
                "body": body,
                "target": target,
                "user_id": user_id,
                "sent_by": admin_phone,
                "created_at": datetime.utcnow().isoformat()
            }
            supabase.table("notifications").insert(notification_data).execute()
        except Exception as save_err:
            logger.warning(f"Bildirim kaydedilemedi (tablo olmayabilir): {save_err}")
        
        # Gönder
        payload = {"type": "admin_notification", "target": target}
        if data:
            payload["raw_data"] = data

        total_users = 0
        users_with_token = 0

        if user_id:
            success = await send_push_notification(user_id, title, body, payload)
            sent_count = 1 if success else 0
        else:
            # Hedef kitle sayıları (0 kişiye gidince nedenini göstermek için)
            try:
                if target == "all":
                    r = supabase.table("users").select("id, push_token, fcm_push_token").execute()
                    total_users = len(r.data or [])
                    users_with_token = sum(1 for u in (r.data or []) if _user_row_has_fcm_for_push(u))
                elif target == "drivers":
                    r = supabase.table("users").select("id, push_token, fcm_push_token, driver_details").not_.is_("driver_details", "null").execute()
                    total_users = len(r.data or [])
                    users_with_token = sum(1 for u in (r.data or []) if _user_row_has_fcm_for_push(u))
                elif target == "passengers":
                    r = supabase.table("users").select("id, push_token, fcm_push_token, driver_details").execute()
                    passengers = [u for u in (r.data or []) if not u.get("driver_details")]
                    total_users = len(passengers)
                    users_with_token = sum(1 for u in passengers if _user_row_has_fcm_for_push(u))
            except Exception:
                pass
            sent_count = await send_bulk_push_notification(title, body, target, payload)
        
        msg = f"{sent_count} kullanıcıya bildirim gönderildi"
        if sent_count == 0 and total_users >= 0:
            msg += f". (Toplam {total_users} kullanıcı, {users_with_token} tanesinde bildirim token'ı kayıtlı. Uygulamada bildirim iznini açıp uygulamayı kapatıp açın.)"
        
        return {
            "success": True,
            "sent_count": sent_count,
            "message": msg,
            "total_users": total_users,
            "users_with_token": users_with_token
        }
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"Admin send push error: {e}")
        raise HTTPException(status_code=500, detail=str(e))

