        gm = (
            supabase.table("group_members")
            .select("group_id, joined_at")
            .eq("user_id", uid)
            .execute()
        )
        gids_raw = [str(x["group_id"]) for x in (gm.data or []) if x.get("group_id")]
        gids = list(dict.fromkeys(gids_raw))
        if not gids:
            return {"success": True, "groups": []}
        gr = (
            supabase.table("groups")
            .select("*")
            .in_("id", gids)
            .eq("status", "approved")
            .order("name")
            .execute()
        )
        rows_raw = list(gr.data or [])
        seen_my: set[str] = set()
        rows: list = []
        for g in rows_raw:
            gid = str(g.get("id") or "").strip().lower()
            if not gid or gid in seen_my:
                continue
            seen_my.add(gid)
            rows.append(g)
        n_ids = list({str(g.get("neighborhood_id")) for g in rows if g.get("neighborhood_id")})
        name_map: dict[str, str] = {}
        if n_ids:
            nh = supabase.table("neighborhoods").select("id, name, city").in_("id", n_ids).execute()
            for n in nh.data or []:
                if n.get("id"):
                    name_map[str(n["id"])] = str(n.get("name") or "")
