@api_router.get("/muhabbet/posts/{post_id}/comments")
async def muhabbet_list_post_comments(
    post_id: str,
    limit: int = 80,
    offset: int = 0,
    authorization: Annotated[Optional[str], Header(alias="Authorization")] = None,
):
    """Tek seviye yorum listesi."""
    try:
        uid = _muhabbet_verify_bearer(authorization)
        pid = str(post_id).strip().lower()
        uuid.UUID(pid)
        await _muhabbet_require_post_viewer(pid, uid)
        lim = max(1, min(int(limit or 80), 120))
        off = max(0, int(offset or 0))
        res = (
            supabase.table("post_comments")
            .select("id, post_id, author_user_id, body, created_at")
            .eq("post_id", pid)
            .order("created_at", desc=False)
            .range(off, off + lim - 1)
            .execute()
        )
        rows = list(res.data or [])
        uids = list({str(r.get("author_user_id")) for r in rows if r.get("author_user_id")})
        name_map: dict[str, str] = {}
        if uids:
            ur = supabase.table("users").select("id, name").in_("id", uids).execute()
            for u in ur.data or []:
                if u.get("id"):
                    name_map[str(u["id"])] = str(u.get("name") or "Kullanıcı")
        enriched: list = []
        for r in rows:
            d = dict(r)
            aid = str(d.get("author_user_id") or "")
            d["author_name"] = name_map.get(aid, "Kullanıcı")
            enriched.append(d)
        return {"success": True, "comments": enriched}
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"muhabbet_list_post_comments: {e}")
        raise HTTPException(status_code=500, detail=str(e)) from e


@api_router.post("/muhabbet/posts/{post_id}/comments")
async def muhabbet_add_post_comment(
    post_id: str,
    body: MuhabbetCommentCreateBody,
    authorization: Annotated[Optional[str], Header(alias="Authorization")] = None,
):
    """Yorum ekle (grup üyesi)."""
    try:
        uid = await _muhabbet_verify_bearer_matches_claimed_user(authorization, body.user_id)
        pid = str(post_id).strip().lower()
        uuid.UUID(pid)
        post_row = await _muhabbet_require_post_viewer(pid, uid)
        gid_ctx = str(post_row.get("group_id") or "").strip().lower()
        txt = (body.body or "").strip()
        if len(txt) < 1:
            raise HTTPException(status_code=400, detail="Yorum metni gerekli")
        if len(txt) > 800:
            raise HTTPException(status_code=400, detail="Yorum en fazla 800 karakter")
        fp, clen = _muhabbet_text_fingerprint(txt)
        try:
            dec, mlabel, mdetail = await moderate_muhabbet_text(text=txt, target_kind="comment")
        except ModerationUnavailableError:
            raise HTTPException(
                status_code=503,
                detail="Metniniz şu an güvenlik denetiminden geçirilemedi. Lütfen kısa süre sonra tekrar deneyin.",
            ) from None
        if dec == "block":
            _muhabbet_log_ai_moderation_event(
                user_uid=uid,
                target_kind="comment",
                decision="block",
                group_id=gid_ctx or None,
                parent_post_id=pid,
                result_post_id=None,
                result_comment_id=None,
                content_sha256=fp,
                char_len=clen,
                model_label=mlabel,
                detail=mdetail,
            )
            raise HTTPException(
                status_code=400,
                detail="İçeriğiniz topluluk kurallarına uygun değil. Lütfen ifadenizi gözden geçirip tekrar deneyin.",
            )
        ins = (
            supabase.table("post_comments")
            .insert({"post_id": pid, "author_user_id": uid, "body": txt})
            .execute()
        )
        if not ins.data:
            return {"success": False, "detail": "Yorum kaydedilemedi"}
        row = dict(ins.data[0])
        new_cid = str(row.get("id") or "")
        _muhabbet_log_ai_moderation_event(
            user_uid=uid,
            target_kind="comment",
            decision="allow",
            group_id=gid_ctx or None,
            parent_post_id=pid,
            result_post_id=None,
            result_comment_id=new_cid or None,
            content_sha256=fp,
            char_len=clen,
            model_label=mlabel,
            detail=mdetail,
        )
        ur = (
            supabase.table("users")
            .select("name")
            .eq("id", uid)
            .limit(1)
            .execute()
        )
        row["author_name"] = (ur.data[0].get("name") if ur.data else None) or "Kullanıcı"
        return {"success": True, "comment": row}
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"muhabbet_add_post_comment: {e}")
        raise HTTPException(status_code=500, detail=str(e)) from e


@api_router.post("/muhabbet/reports")
async def muhabbet_create_report(
    body: MuhabbetReportBody,
    authorization: Annotated[Optional[str], Header(alias="Authorization")] = None,
):
    """Gönderi şikayeti kaydı (grup üyesi; aynı gönderiye tekrar idempotent)."""
    try:
        uid = await _muhabbet_verify_bearer_matches_claimed_user(authorization, body.user_id)
        pid = str(body.post_id).strip().lower()
        uuid.UUID(pid)
        await _muhabbet_require_post_viewer(pid, uid)
        ex = (
            supabase.table("post_reports")
            .select("id")
            .eq("post_id", pid)
            .eq("reporter_user_id", uid)
            .limit(1)
            .execute()
        )
        if ex.data:
            return {"success": True, "already_reported": True}
        supabase.table("post_reports").insert(
            {
                "post_id": pid,
                "reporter_user_id": uid,
                "reason": (body.reason or "").strip()[:200] or None,
                "details": (body.details or "").strip()[:2000] or None,
                "status": "pending",
            }
        ).execute()
        return {"success": True, "already_reported": False}
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"muhabbet_create_report: {e}")
        raise HTTPException(status_code=500, detail=str(e)) from e


# ==================== LEYLEK MUHABBETİ — FAZ 1: İLAN (ride_listings) + EŞLEŞME İSTEĞİ ====================


# İstemci CreateListingModal: driver -> gidiyorum + driver; passenger -> gidecegim + passenger
_MUHABBET_LISTING_TYPES = frozenset({"gidiyorum", "gidecegim", "beni_alsin", "ozel_sofor"})
_MUHABBET_LISTING_ROLES = frozenset({"driver", "passenger", "private_driver"})
_MUHABBET_LISTING_STATUSES = frozenset({"active", "pending_chat", "matched", "closed", "cancelled"})
_MUHABBET_LISTING_SCOPES = frozenset({"local", "intercity"})
_MUHABBET_REQ_STATUSES = frozenset({"pending", "accepted", "rejected", "cancelled"})


def _muhabbet_phone_digits10(phone: Optional[str]) -> str:
    """Admin telefon listesi ile karşılaştırma için son 10 hane."""
    if not phone:
        return ""
    s = "".join(ch for ch in str(phone) if ch.isdigit())
    return s[-10:] if len(s) >= 10 else s


def _muhabbet_user_can_act_as_driver(user_id: str) -> bool:
    """
    Leylek Muhabbeti sürücü yetkisi: driver_details.kyc_status=approved ve is_verified=True
    (GET /driver/kyc/status ile aynı). Admin telefonları her zaman sürücü sayılır.
    """
    uid = str(user_id or "").strip().lower()
    if not uid:
        return False
    try:
        r = supabase.table("users").select("phone, driver_details").eq("id", uid).limit(1).execute()
        if not r.data:
            return False
        u = dict(r.data[0])
        digits = _muhabbet_phone_digits10(str(u.get("phone") or ""))
        if digits and digits in ADMIN_PHONE_NUMBERS:
            return True
        dd = _driver_details_as_dict(u)
        if str(dd.get("kyc_status") or "").strip().lower() == "approved" and bool(dd.get("is_verified", False)):
            return True
        return False
    except Exception as e:
        logger.warning("_muhabbet_user_can_act_as_driver uid=%s err=%s", uid[:12], e)
        return False


def _muhabbet_viewer_effective_driver_vehicle_kind(user_id: str) -> str:
    """Yolcu ilanı talibi için efektif araç türü (car | motorcycle)."""
    uid = str(user_id or "").strip().lower()
    if not uid:
        return "car"
    try:
        r = supabase.table("users").select("id, driver_details, role").eq("id", uid).limit(1).execute()
        if not r.data:
            return "car"
        row = dict(r.data[0])
        v = _canonical_vehicle_kind(_effective_driver_vehicle_kind(row)) or "car"
        v = str(v).strip().lower()
        return v if v in ("car", "motorcycle") else "car"
    except Exception:
        return "car"


def _muhabbet_listing_offer_kind(row: Optional[dict]) -> str:
    """
    Talip CTA kuralları: driver_offer (sürücü ilanı) | passenger_offer (yolcu ilanı).
    Öncelik listing_type; belirsizse role_type ile geri dönüş.
    """
    if not row:
        return "passenger_offer"
    lt = str(row.get("listing_type") or "").strip().lower()
    if lt in ("gidiyorum", "ozel_sofor"):
        return "driver_offer"
    if lt in ("gidecegim", "beni_alsin"):
        return "passenger_offer"
    rt = str(row.get("role_type") or "").strip().lower()
    if rt in ("driver", "private_driver"):
        return "driver_offer"
    return "passenger_offer"


def _muhabbet_full_name(full_name: Optional[str], first_name: Optional[str], last_name: Optional[str]) -> str:
    fn = (str(first_name or "")).strip()
    ln = (str(last_name or "")).strip()
    if fn and ln:
        return f"{fn} {ln}".strip()
    if fn:
        return fn
    raw = str(full_name or "").strip()
    return raw


def _muhabbet_public_display_name(
    full_name: Optional[str],
    first_name: Optional[str] = None,
    last_name: Optional[str] = None,
) -> str:
    """Karşı tarafa gösterilen ad: Ad + Soyad baş harfi (ör. Ahmet C.)."""
    fn = (str(first_name or "")).strip()
    ln = (str(last_name or "")).strip()
    if fn and ln:
        return f"{fn} {ln[0].upper()}."
    if fn:
        return fn
    raw = str(full_name or "").strip()
    if raw:
        parts = [p for p in raw.split() if p]
        if len(parts) >= 2:
            return f"{parts[0]} {parts[1][0].upper()}."
        if len(parts) == 1:
            return parts[0]
    return "Leylek kullanıcısı"


def _muhabbet_match_semantic_roles_for_conversation(conversation_id: str) -> dict:
    """
    Kabul edilmiş listing_match_requests + ilan offer_kind (listing_type türevi) + actor_intent.
    - passenger_offer: ilan sahibi = yolcu (passenger), talep eden actor_intent (talip = driver).
    - driver_offer: ilan sahibi = sürücü (driver), talep eden actor_intent (talip = passenger).
    Dönüş: { uid_lower: 'driver'|'passenger', ... }.
    """
    cid = (conversation_id or "").strip().lower()
    out: dict = {}
    if not cid:
        return out
    try:
        mq = (
            supabase.table("listing_match_requests")
            .select("sender_user_id,receiver_user_id,listing_id,actor_intent,status")
            .eq("conversation_id", cid)
            .eq("status", "accepted")
            .order("updated_at", desc=True)
            .limit(1)
            .execute()
        )
        if not mq.data:
            return out
        row = dict(mq.data[0])
        sen = str(row.get("sender_user_id") or "").strip().lower()
        rec = str(row.get("receiver_user_id") or "").strip().lower()
        lid = str(row.get("listing_id") or "").strip().lower()
        intent = str(row.get("actor_intent") or "passenger").strip().lower()
        if intent not in ("driver", "passenger"):
            intent = "passenger"
        if not lid or not sen or not rec:
            return out
        lr = supabase.table("ride_listings").select("*").eq("id", lid).limit(1).execute()
        if not lr.data:
            return out
        lst = _ride_listing_response_row(dict(lr.data[0]))
        owner = _ride_listing_creator_uid(lst)
        if not owner or owner != rec:
            return out
        offer_kind = _muhabbet_listing_offer_kind(lst)
        owner_sem = "driver" if offer_kind == "driver_offer" else "passenger"
        out[owner] = owner_sem
        out[sen] = intent
        return out
    except Exception as e:
        logger.warning("match_semantic_roles conv=%s err=%s", cid[:12], e)
        return out


# ride_listings INSERT — migration: backend/migrations/leylek_muhabbet_ride_listings.sql
# + yaygın owner kolon adları. Tabloda olmayan anahtarlar sanitize ile atılır.
_RIDE_LISTINGS_INSERT_COLUMN_WHITELIST = frozenset(
    {
        "created_by_user_id",
        "user_id",
        "creator_user_id",
        "linked_user_route_id",
        "linked_pattern_hash",
        "city",
        "listing_scope",
        "origin_city",
        "destination_city",
        "from_text",
        "to_text",
        "start_lat",
        "start_lng",
        "end_lat",
        "end_lng",
        "departure_time",
        "listing_type",
        "role_type",
        "price_amount",
        "note",
        "status",
        "updated_at",
        "vehicle_kind",
        "expires_at",
        "accepted_match_request_id",
        "accepted_user_id",
        "matched_conversation_id",
    }
)


def _sanitize_ride_listing_insert_row(row: dict, owner_col: str) -> dict:
    """Supabase ride_listings şemasında olmayan kolonları insert'ten çıkar (owner_col her zaman izinli)."""
    out: dict = {}
    dropped: list = []
    oc = (owner_col or "").strip()
    for k, v in (row or {}).items():
        if k == oc or k in _RIDE_LISTINGS_INSERT_COLUMN_WHITELIST:
            out[k] = v
        else:
            dropped.append(k)
    if dropped:
        logger.warning("[muhabbet-listings] sanitize: tablo whitelist'inde olmayan kolonlar atıldı: %s", dropped)
    return out


def _ride_listings_owner_column() -> str:
    """ride_listings oluşturan kullanıcı FK kolon adı (Supabase şeması ile uyum).
    Bazı kurulumlarda tablo `user_id` ile oluşturulmuş olabiliyor — .env veya migration ile hizalayın."""
    return (os.getenv("RIDE_LISTINGS_OWNER_COLUMN") or "created_by_user_id").strip()


def _ride_listing_creator_uid(row: Optional[dict]) -> str:
    """Satır hangi FK adını kullanırsa kullansın oluşturan kullanıcı id."""
    if not row:
        return ""
    col = _ride_listings_owner_column()
    return str(row.get(col) or row.get("created_by_user_id") or row.get("user_id") or "").strip().lower()


def _ride_listing_response_row(row: dict) -> dict:
    """İstemci ve eski kodlar için her zaman created_by_user_id anahtarı üret."""
    r = dict(row)
    uid = _ride_listing_creator_uid(r)
    if uid and not r.get("created_by_user_id"):
        r["created_by_user_id"] = uid
    scope = str(r.get("listing_scope") or "local").strip().lower()
    if scope not in _MUHABBET_LISTING_SCOPES:
        scope = "local"
    r["listing_scope"] = scope
    city = str(r.get("city") or "").strip()
    if not str(r.get("origin_city") or "").strip():
        r["origin_city"] = city
    if not str(r.get("destination_city") or "").strip():
        r["destination_city"] = city
    vk = str(r.get("vehicle_kind") or "car").strip().lower()
    if vk not in ("car", "motorcycle"):
        vk = "car"
    r["vehicle_kind"] = vk
    r["transport_label"] = "Motor" if vk == "motorcycle" else "Araba"
    try:
        exp_d = _parse_iso_dt(r.get("expires_at"))
        if exp_d is not None:
            r["muhabbet_offer_expired"] = exp_d < datetime.now(timezone.utc)
        else:
            r["muhabbet_offer_expired"] = False
    except Exception:
        r["muhabbet_offer_expired"] = False
    return r


class MuhabbetListingCreateBody(BaseModel):
    """
    İlan oluşturma gövdesi.
    Not: İstemci geçici olarak seats_count / repeat_type / selected_days / time_window
    benzeri alanları `note` içinde gömebilir — kalıcı şema değil; sonraki fazda ayrı kolonlar eklenecek.
    """

    city: Optional[str] = None
    listing_scope: Optional[str] = Field(default="local", description="local | intercity")
    origin_city: Optional[str] = None
    destination_city: Optional[str] = None
    from_text: str
    to_text: str
    start_lat: Optional[float] = None
    start_lng: Optional[float] = None
    end_lat: Optional[float] = None
    end_lng: Optional[float] = None
    departure_time: Optional[datetime] = None
    listing_type: str
    role_type: str
    price_amount: Optional[float] = None
    note: Optional[str] = None
    linked_user_route_id: Optional[str] = None
    linked_pattern_hash: Optional[str] = None
    vehicle_kind: Optional[str] = Field(default="car", description="car | motorcycle")

    @field_validator("from_text", "to_text", mode="before")
    @classmethod
    def _strip_required(cls, v: str) -> str:
        s = (v or "").strip()
        if not s:
            raise ValueError("Zorunlu alan boş olamaz")
        return s

    @field_validator("city", "origin_city", "destination_city", mode="before")
    @classmethod
    def _strip_optional_city(cls, v: Optional[str]) -> Optional[str]:
        if v is None:
            return None
        s = str(v or "").strip()
        return s or None

    @field_validator("listing_scope", mode="before")
    @classmethod
    def _listing_scope_v(cls, v: Optional[str]) -> str:
        s = str(v or "local").strip().lower()
        if s not in _MUHABBET_LISTING_SCOPES:
            raise ValueError("listing_scope local veya intercity olmalı")
        return s

    @field_validator("listing_type", mode="before")
    @classmethod
    def _lt(cls, v: str) -> str:
        s = (v or "").strip()
        if s not in _MUHABBET_LISTING_TYPES:
            raise ValueError("Geçersiz listing_type")
        return s

    @field_validator("role_type", mode="before")
    @classmethod
    def _rt(cls, v: str) -> str:
        s = (v or "").strip()
        if s not in _MUHABBET_LISTING_ROLES:
            raise ValueError("Geçersiz role_type")
        return s

    @field_validator("note", mode="before")
    @classmethod
    def _note_len(cls, v: Optional[str]) -> Optional[str]:
        if v is None:
            return None
        t = (v or "").strip()
        if len(t) > 5000:
            raise ValueError("Not en fazla 5000 karakter olabilir")
        return t or None

    @field_validator("vehicle_kind", mode="before")
    @classmethod
    def _vehicle_kind_v(cls, v: Optional[str]) -> str:
        s = str(v or "car").strip().lower()
        if s not in ("car", "motorcycle"):
            raise ValueError("vehicle_kind car veya motorcycle olmalı")
        return s


