_LEYLEK_PAIR_REQUEST_COOLDOWN_SEC = 60


def _muhabbet_role_label_tr(role_raw: str) -> str:
    r = (role_raw or "").strip().lower()
    if r in ("driver", "private_driver"):
        return "Sürücü"
