@api_router.post("/muhabbet/leylek-key/create")
async def muhabbet_leylek_key_create(
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """
    Tek kullanımlık Leylek Anahtar üretir; TTL: 15 dk.
    Çakışmada (nadiren) yeniden dener.
    """
    try:
        uid = await _muhabbet_listing_uid(authenticated_user_id)
        now = datetime.now(timezone.utc)
        exp = now + timedelta(minutes=_LEYLEK_KEY_TTL_MIN)
        ts = now.isoformat()
        exs = exp.isoformat()
        last_exc: Optional[Exception] = None
        for _attempt in range(6):
            disp = _gen_leylek_key_display()
            kc = _normalize_leylek_key_input(disp)
            if not kc:
                continue
            try:
                ins = (
                    supabase.table("leylek_keys")
                    .insert(
                        {
                            "key_code": kc,
                            "key_display": disp,
                            "created_by_user_id": uid,
                            "status": "active",
                            "expires_at": exs,
                            "created_at": ts,
                            "updated_at": ts,
                        }
                    )
                    .select("*")
                    .execute()
                )
                if ins.data and ins.data[0].get("id"):
                    row = dict(ins.data[0])
                    return {
                        "success": True,
                        "key": row.get("key_display") or disp,
                        "key_id": str(row.get("id")).strip().lower(),
                        "expires_at": row.get("expires_at") or exs,
                    }
            except Exception as e:
                err = (str(e) or "").lower()
                last_exc = e
                if "unique" in err or "23505" in str(e) or "duplicate" in err:
                    continue
                raise
        raise HTTPException(
            status_code=500,
            detail="Anahtar oluşturulamadı" if not last_exc else str(last_exc),
        ) from last_exc
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"muhabbet_leylek_key_create: {e}")
        raise HTTPException(status_code=500, detail=str(e)) from e


@api_router.post("/muhabbet/leylek-key/redeem")
async def muhabbet_leylek_key_redeem(
    body: LeylekKeyRedeemBody,
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """
    Anahtarı girer: geçerli, süre içi, tek kullanımlık, oluşturucu değil.
    Muhabbet conversation üzerinde match_source=leylek_key yazar; yolculuk/QR etkilenmez.
    """
    try:
        uid = await _muhabbet_listing_uid(authenticated_user_id)
        kc = _normalize_leylek_key_input(body.code)
        if not kc:
            raise HTTPException(status_code=400, detail="Geçersiz anahtar formatı (LX-XXXX-XXXX).")
        now = datetime.now(timezone.utc)
        now_iso = now.isoformat()
        kr = supabase.table("leylek_keys").select("*").eq("key_code", kc).limit(1).execute()
        if not kr.data:
            raise HTTPException(status_code=404, detail="Anahtar bulunamadı.")
        row = dict(kr.data[0])
        creator = str(row.get("created_by_user_id") or "").strip().lower()
        if creator == uid:
            raise HTTPException(status_code=400, detail="Kendi anahtarınızı kullanamazsınız.")
        st = str(row.get("status") or "").strip().lower()
        if st != "active" or row.get("used_at"):
            raise HTTPException(status_code=400, detail="Bu anahtar artık geçerli değil.")
        exp_raw = row.get("expires_at")
        try:
            exp_d = _parse_iso_dt(exp_raw) if exp_raw else None
        except Exception:
            exp_d = None
        if exp_d is not None and exp_d < now:
            supabase.table("leylek_keys").update({"status": "expired", "updated_at": now_iso}).eq("id", row.get("id")).execute()
            raise HTTPException(status_code=400, detail="Anahtarın süresi doldu.")
        kid = str(row.get("id") or "").strip().lower()
        up = (
            supabase.table("leylek_keys")
            .update(
                {
                    "used_at": now_iso,
                    "used_by_user_id": uid,
                    "status": "used",
                    "updated_at": now_iso,
                }
            )
            .eq("id", kid)
            .eq("status", "active")
            .is_("used_at", None)
            .execute()
        )
        if not up.data:
            raise HTTPException(status_code=409, detail="Anahtar eşzamanlı olarak kullanıldı; tekrar deneyin.")
        try:
            uuid.UUID(creator)
            uuid.UUID(uid)
        except ValueError as e:
            raise HTTPException(status_code=500, detail="Geçersiz kullanıcı kaydı") from e
        conv_id = _muhabbet_conversation_get_or_create_id(creator, uid)
        supabase.table("conversations").update(
            {
                "matched_at": now_iso,
                "match_source": "leylek_key",
                "leylek_key_id": kid,
            }
        ).eq("id", conv_id).execute()
        supabase.table("leylek_keys").update({"related_conversation_id": conv_id, "updated_at": now_iso}).eq("id", kid).execute()
        await _muhabbet_notify_leylek_key_matched(creator, uid, conv_id)
        return {
            "success": True,
            "conversation_id": conv_id,
            "message": "Eşleşme Leylek Anahtar ile tamamlandı. Sohbetinizde ön bilgileri teyit edebilirsiniz.",
        }
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"muhabbet_leylek_key_redeem: {e}")
        raise HTTPException(status_code=500, detail=str(e)) from e


def _parse_iso_dt(val: object) -> Optional[datetime]:
    if val is None:
        return None
    s = str(val).strip()
    if not s:
        return None
    if s.endswith("Z"):
        s = s[:-1] + "+00:00"
    return datetime.fromisoformat(s)


def _muhabbet_conversation_get_or_create_id(sen: str, rec: str) -> str:
    """
    Pair-scoped eski Muhabbet sohbetleri için user_a/user_b sıralı tek sohbet.
    Listing match accept artık bu helper'ı kullanmaz; match-scoped yeni conversation açar.
    """
    sen = (sen or "").strip().lower()
    rec = (rec or "").strip().lower()
    if not sen or not rec or sen == rec:
        raise HTTPException(status_code=400, detail="Geçersiz eşleşme katılımcıları")
    ua, ub = (sen, rec) if sen < rec else (rec, sen)
    ex = supabase.table("conversations").select("id").eq("user_a", ua).eq("user_b", ub).limit(1).execute()
    if ex.data and ex.data[0].get("id"):
        return str(ex.data[0]["id"]).strip().lower()
    try:
        ins = supabase.table("conversations").insert({"user_a": ua, "user_b": ub}).execute()
        if ins.data and ins.data[0].get("id"):
            return str(ins.data[0]["id"]).strip().lower()
    except Exception as e:
        err = (str(e) or "").lower()
        if "23505" in str(e) or "unique" in err or "duplicate" in err:
            ex2 = (
                supabase.table("conversations")
                .select("id")
                .eq("user_a", ua)
                .eq("user_b", ub)
                .limit(1)
                .execute()
            )
            if ex2.data and ex2.data[0].get("id"):
                return str(ex2.data[0]["id"]).strip().lower()
        logger.error("muhabbet_conversation_get_or_create_id: %s", e)
        raise HTTPException(status_code=500, detail="Sohbet oluşturulamadı") from e
    raise HTTPException(status_code=500, detail="Sohbet oluşturulamadı")


def _muhabbet_conversation_create_for_match_request(sen: str, rec: str, request_id: str) -> str:
    """
    Listing match kabulü için yeni, match-scoped conversation.
    Aynı iki kullanıcının önceki Muhabbet sohbetleri okunabilir kalır; yeni kabul eski mesajları reuse etmez.
    """
    sen = (sen or "").strip().lower()
    rec = (rec or "").strip().lower()
    rid = (request_id or "").strip().lower()
    if not sen or not rec or sen == rec:
        raise HTTPException(status_code=400, detail="Geçersiz eşleşme katılımcıları")
    if not rid:
        raise HTTPException(status_code=400, detail="Geçersiz eşleşme isteği")
    ua, ub = (sen, rec) if sen < rec else (rec, sen)
    try:
        ins = (
            supabase.table("conversations")
            .insert(
                {
                    "user_a": ua,
                    "user_b": ub,
                    "conversation_kind": "listing_match_request",
                    "listing_match_request_id": rid,
                }
            )
            .execute()
        )
        if ins.data and ins.data[0].get("id"):
            conv_id = str(ins.data[0]["id"]).strip().lower()
            logger.info("[muhabbet_conversation] match_scoped_created request_id=%s conversation_id=%s", rid, conv_id)
            return conv_id
    except Exception as e:
        err = (str(e) or "").lower()
        logger.error("[muhabbet_conversation] match_scoped_create_failed request_id=%s err=%s", rid, e)
        if ("23505" in str(e) or "unique" in err or "duplicate" in err) and rid:
            try:
                ex = (
                    supabase.table("conversations")
                    .select("id")
                    .eq("listing_match_request_id", rid)
                    .limit(1)
                    .execute()
                )
                if ex.data and ex.data[0].get("id"):
                    return str(ex.data[0]["id"]).strip().lower()
            except Exception:
                pass
        if "conversation_kind" in err or "listing_match_request_id" in err or "column" in err:
            try:
                ins2 = supabase.table("conversations").insert({"user_a": ua, "user_b": ub}).execute()
                if ins2.data and ins2.data[0].get("id"):
                    conv_id = str(ins2.data[0]["id"]).strip().lower()
                    logger.info("[muhabbet_conversation] match_scoped_created_legacy_schema request_id=%s conversation_id=%s", rid, conv_id)
                    return conv_id
            except Exception as e2:
                err2 = (str(e2) or "").lower()
                if "23505" in str(e2) or "unique" in err2 or "duplicate" in err2:
                    raise HTTPException(
                        status_code=500,
                        detail="Muhabbet match-scoped conversation migration gerekli: conversations(user_a,user_b) unique kısıtı kaldırılmalı.",
                    ) from e2
                raise HTTPException(status_code=500, detail="Sohbet oluşturulamadı") from e2
        if "23505" in str(e) or "unique" in err or "duplicate" in err:
            raise HTTPException(
                status_code=500,
                detail="Muhabbet match-scoped conversation migration gerekli: conversations(user_a,user_b) unique kısıtı kaldırılmalı.",
            ) from e
        raise HTTPException(status_code=500, detail="Sohbet oluşturulamadı") from e
    raise HTTPException(status_code=500, detail="Sohbet oluşturulamadı")


def _muhabbet_apply_listing_after_match_request_accepted(
    listing_id: str,
    accepted_request_id: str,
    conversation_id: str,
    accepted_sender_uid: str,
) -> None:
    """
    Talip kabulü: ilan pending_chat + kabul alanları; feed'den düşer.
    Aynı ilandaki diğer bekleyen talepleri iptal eder.
    """
    lid = str(listing_id or "").strip().lower()
    rid = str(accepted_request_id or "").strip().lower()
    cid = str(conversation_id or "").strip().lower()
    sender = str(accepted_sender_uid or "").strip().lower()
    if not lid or not rid or not cid or not sender:
        return
    now_ts = _muhabbet_listing_row_ts()
    try:
        supabase.table("ride_listings").update(
            {
                "status": "pending_chat",
                "accepted_match_request_id": rid,
                "accepted_user_id": sender,
                "matched_conversation_id": cid,
                "updated_at": now_ts,
            }
        ).eq("id", lid).eq("status", "active").execute()
    except Exception as e:
        logger.warning("ride_listings->pending_chat lid=%s err=%s", lid[:12], e)
    try:
        supabase.table("listing_match_requests").update({"status": "cancelled", "updated_at": now_ts}).eq("listing_id", lid).eq("status", "pending").neq("id", rid).execute()
    except Exception as e:
        logger.warning("listing_match_requests cancel peers: %s", e)


def _muhabbet_conversation_apply_listing_match_metadata(conversation_id: str) -> None:
    """
    Teklif talebi kabulü: conversations üzerinde eşleşme tamam bayrağı (Yolculuğa çevir için trip_convert önkoşulu).
    Mevcut leylek_key / leylek_key_inchat eşleşmelerinin üzerine yazılmaz.
    """
    cid = str(conversation_id or "").strip().lower()
    if not cid:
        return
    now_iso = datetime.now(timezone.utc).isoformat()
    try:
        sel = supabase.table("conversations").select("match_source, matched_at").eq("id", cid).limit(1).execute()
        if not sel.data:
            return
        crow = dict(sel.data[0])
        ms = str(crow.get("match_source") or "").strip().lower()
        if ms in ("leylek_key", "leylek_key_inchat"):
            return
        if ms == "listing_match" and crow.get("matched_at"):
            return
        try:
            supabase.table("conversations").update(
                {"matched_at": now_iso, "match_source": "listing_match", "updated_at": now_iso}
            ).eq("id", cid).execute()
        except Exception as e1:
            err1 = (str(e1) or "").lower()
            logger.warning("conversation listing_match metadata update cid=%s err=%s", cid[:12], e1)
            if "column" in err1:
                supabase.table("conversations").update(
                    {"matched_at": now_iso, "match_source": "listing_match"}
                ).eq("id", cid).execute()
    except Exception as e:
        logger.warning("conversation_apply_listing_match_metadata cid=%s err=%s", cid[:12], e)


def _muhabbet_mark_ride_listing_matched_for_muhabbet_conversation(conversation_id: str) -> None:
    """Sohbet içi Leylek Anahtar kabulü: ilgili ilan matched (pending_chat → matched)."""
    cid = str(conversation_id or "").strip().lower()
    if not cid:
        return
    now_ts = _muhabbet_listing_row_ts()
    try:
        supabase.table("ride_listings").update({"status": "matched", "updated_at": now_ts}).eq("matched_conversation_id", cid).eq("status", "pending_chat").execute()
    except Exception as e:
        logger.warning("ride_listings->matched conv=%s err=%s", cid[:12], e)


@api_router.post("/muhabbet/match-requests/{request_id}/accept")
async def muhabbet_match_request_accept(
    request_id: str,
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """
    Kabul: yalnızca ilan sahibi (receiver). İdempotent: zaten kabul+conversation varsa aynı yanıt.
    Listing match kabulü her request için yeni conversation açar; eski pair sohbetleri okunabilir kalır.
    """
    try:
        uid = await _muhabbet_listing_uid(authenticated_user_id)
        rid = str(request_id).strip().lower()
        uuid.UUID(rid)
        rr = supabase.table("listing_match_requests").select("*").eq("id", rid).limit(1).execute()
        if not rr.data:
            raise HTTPException(status_code=404, detail="İstek bulunamadı")
        row = dict(rr.data[0])
        if str(row.get("receiver_user_id") or "").strip().lower() != uid:
            raise HTTPException(status_code=403, detail="Sadece ilan sahibi bu isteği kabul edebilir")
        st = str(row.get("status") or "").strip().lower()
        ecid_raw = row.get("conversation_id")
        ecid = str(ecid_raw).strip() if ecid_raw else ""
        if st == "accepted" and ecid:
            fin = supabase.table("listing_match_requests").select("*").eq("id", rid).limit(1).execute()
            out_req = dict(fin.data[0]) if fin.data else row
            lid_done = str(row.get("listing_id") or "").strip().lower()
            sen_done = str(row.get("sender_user_id") or "").strip().lower()
            ecid_n = str(ecid_raw).strip().lower()
            if lid_done and ecid_n and sen_done:
                _muhabbet_apply_listing_after_match_request_accepted(lid_done, rid, ecid_n, sen_done)
            _muhabbet_conversation_apply_listing_match_metadata(ecid_n)
            return {
                "success": True,
                "chat_unlocked": True,
                "conversation_id": ecid_n,
                "request": out_req,
                "message": "Eşleşme kabul edildi",
            }
        if st == "accepted" and not ecid:
            sen0 = str(row.get("sender_user_id") or "").strip().lower()
            rec0 = str(row.get("receiver_user_id") or "").strip().lower()
            lid_rec = str(row.get("listing_id") or "").strip().lower()
            conversation_id = _muhabbet_conversation_create_for_match_request(sen0, rec0, rid)
            nowx = _muhabbet_listing_row_ts()
            supabase.table("listing_match_requests").update(
                {"conversation_id": conversation_id, "updated_at": nowx}
            ).eq("id", rid).execute()
            fin = supabase.table("listing_match_requests").select("*").eq("id", rid).limit(1).execute()
            out_req = dict(fin.data[0]) if fin.data else {**row, "conversation_id": conversation_id}
            await _muhabbet_notify_match_accepted(sen0, rec0, conversation_id, lid_rec)
            if lid_rec and sen0:
                _muhabbet_apply_listing_after_match_request_accepted(lid_rec, rid, str(conversation_id).strip().lower(), sen0)
            _muhabbet_conversation_apply_listing_match_metadata(str(conversation_id).strip().lower())
            return {
                "success": True,
                "chat_unlocked": True,
                "conversation_id": conversation_id,
                "request": out_req,
                "message": "Eşleşme kabul edildi",
            }
        if st != "pending":
            raise HTTPException(status_code=400, detail="Bu istek zaten yanıtlanmış")
        lid = str(row.get("listing_id") or "").strip().lower()
        lr0 = supabase.table("ride_listings").select("*").eq("id", lid).limit(1).execute()
        if not lr0.data:
            raise HTTPException(status_code=400, detail="İlan bulunamadı")
        lst = _ride_listing_response_row(dict(lr0.data[0]))
        if _ride_listing_creator_uid(lst) != uid:
            raise HTTPException(status_code=403, detail="Sadece ilan sahibi bu isteği kabul edebilir")
        if str(lst.get("status") or "").strip().lower() != "active":
            raise HTTPException(status_code=400, detail="İlan artık eşleşme kabul edemiyor")
        if _muhabbet_listing_offer_expired(lst):
            raise HTTPException(status_code=400, detail="İlan süresi doldu")
        now_ts = _muhabbet_listing_row_ts()
        sen = str(row.get("sender_user_id") or "").strip().lower()
        rec = str(row.get("receiver_user_id") or "").strip().lower()
        conversation_id = _muhabbet_conversation_create_for_match_request(sen, rec, rid)
        supabase.table("listing_match_requests").update(
            {
                "status": "accepted",
                "updated_at": now_ts,
                "conversation_id": conversation_id,
            }
        ).eq("id", rid).execute()
        fin = supabase.table("listing_match_requests").select("*").eq("id", rid).limit(1).execute()
        out_req = dict(fin.data[0]) if fin.data else {**row, "conversation_id": conversation_id}
        await _muhabbet_notify_match_accepted(sen, rec, conversation_id, lid)
        if lid and sen:
            _muhabbet_apply_listing_after_match_request_accepted(lid, rid, str(conversation_id).strip().lower(), sen)
        _muhabbet_conversation_apply_listing_match_metadata(str(conversation_id).strip().lower())
        return {
            "success": True,
            "chat_unlocked": True,
            "conversation_id": conversation_id,
            "request": out_req,
            "message": "Eşleşme kabul edildi",
        }
    except HTTPException:
        raise
    except ValueError:
        raise HTTPException(status_code=400, detail="Geçersiz istek kimliği") from None
    except Exception as e:
        logger.error(f"muhabbet_match_request_accept: {e}")
        raise HTTPException(status_code=500, detail=str(e)) from e


@api_router.post("/muhabbet/match-requests/{request_id}/reject")
async def muhabbet_match_request_reject(
    request_id: str,
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """Red: yalnızca ilan sahibi (receiver)."""
    try:
        uid = await _muhabbet_listing_uid(authenticated_user_id)
        rid = str(request_id).strip().lower()
        uuid.UUID(rid)
        rr = supabase.table("listing_match_requests").select("*").eq("id", rid).limit(1).execute()
        if not rr.data:
            raise HTTPException(status_code=404, detail="İstek bulunamadı")
        row = dict(rr.data[0])
        if str(row.get("receiver_user_id") or "").strip().lower() != uid:
            raise HTTPException(status_code=403, detail="Sadece ilan sahibi bu isteği reddedebilir")
        if str(row.get("status") or "") != "pending":
            raise HTTPException(status_code=400, detail="Bu istek zaten yanıtlanmış")
        now_ts = _muhabbet_listing_row_ts()
        supabase.table("listing_match_requests").update(
            {"status": "rejected", "updated_at": now_ts}
        ).eq("id", rid).execute()
        fin = supabase.table("listing_match_requests").select("*").eq("id", rid).limit(1).execute()
        out_req = dict(fin.data[0]) if fin.data else row
        return {"success": True, "request": out_req, "message": "İstek reddedildi"}
    except HTTPException:
        raise
    except ValueError:
        raise HTTPException(status_code=400, detail="Geçersiz istek kimliği") from None
    except Exception as e:
        logger.error(f"muhabbet_match_request_reject: {e}")
        raise HTTPException(status_code=500, detail=str(e)) from e


def _muhabbet_conversation_for_member_or_403(conversation_id: str, uid: str) -> dict:
    """Sohbet satırı; yalnızca user_a | user_b erişir."""
    uid = (uid or "").strip().lower()
    cid = str(conversation_id or "").strip().lower()
    try:
        uuid.UUID(cid)
    except ValueError as e:
        raise HTTPException(status_code=400, detail="Geçersiz sohbet kimliği") from e
    r = supabase.table("conversations").select("*").eq("id", cid).limit(1).execute()
    if not r.data:
        raise HTTPException(status_code=404, detail="Sohbet bulunamadı")
    c = dict(r.data[0])
    a = str(c.get("user_a") or "").strip().lower()
    b = str(c.get("user_b") or "").strip().lower()
    if uid not in (a, b):
        raise HTTPException(status_code=403, detail="Bu sohbete erişim yetkiniz yok")
    return c


def _muhabbet_conversation_member_ok(conversation_id: str, uid: str) -> bool:
    try:
        _muhabbet_conversation_for_member_or_403(conversation_id, uid)
        return True
    except Exception:
        return False


def _muhabbet_messages_try_insert(cid: str, msg_id: str, sender_id: str, text: str, created_iso: str) -> tuple[bool, str]:
    """Kalıcı mesaj satırı; idempotent (aynı id+conversation varsa True)."""
    cid = str(cid or "").strip().lower()
    mid = str(msg_id or "").strip().lower()
    su = str(sender_id or "").strip().lower()
    row = {
        "id": mid,
        "conversation_id": cid,
        "sender_id": su,
        "text": text,
        "created_at": created_iso,
    }
    try:
        supabase.table("muhabbet_messages").insert(row).execute()
        return (True, "")
    except Exception as e:
        try:
            q = (
                supabase.table("muhabbet_messages")
                .select("id")
                .eq("id", mid)
                .eq("conversation_id", cid)
                .limit(1)
                .execute()
            )
            if q.data:
                return (True, "")
        except Exception:
            pass
        err_txt = str(e)
        logger.warning("[muhabbet_send] db insert failed conversation_id=%s message_id=%s err=%s", cid, mid, err_txt)
        if "relation" in err_txt.lower() and "muhabbet_messages" in err_txt.lower():
            logger.error(
                "[muhabbet_send] muhabbet_messages table missing or migration not applied; run leylek_muhabbet_messages_retention.sql"
            )
        return (False, err_txt)


def _muhabbet_message_fetch_by_id(cid: str, msg_id: str) -> Optional[dict]:
    cid = str(cid or "").strip().lower()
    mid = str(msg_id or "").strip().lower()
    if not cid or not mid:
        return None
    try:
        res = (
            supabase.table("muhabbet_messages")
            .select("id,conversation_id,sender_id,text,created_at")
            .eq("id", mid)
            .eq("conversation_id", cid)
            .limit(1)
            .execute()
        )
        return dict(res.data[0]) if res.data else None
    except Exception as e:
        logger.warning("muhabbet_message_fetch_by_id: %s", e)
        return None


_MUHABBET_CONV_LIST_BASE_FIELDS = (
    "id, user_a, user_b, created_at, matched_at, match_source, last_message, last_message_at, updated_at"
)
_MUHABBET_CONV_LIST_READ_FIELDS = "user_a_last_read_at, user_b_last_read_at"


def _muhabbet_pg_missing_column(exc: BaseException, *needles: str) -> bool:
    raw = str(exc)
    low = raw.lower()
    if "42703" in raw:
        return True
    if "does not exist" in low:
        return True
    for n in needles:
        if n and n.lower() in low:
            return True
    return False


def _muhabbet_conversations_me_query(uid: str, fetch_lim: int):
    """(execute_result, read_columns_selected). Kolonlar yoksa taban alanlarla tekrar dene."""
    sel_full = f"{_MUHABBET_CONV_LIST_BASE_FIELDS},{_MUHABBET_CONV_LIST_READ_FIELDS}"
    try:
        res = (
            supabase.table("conversations")
            .select(sel_full)
            .or_(f"user_a.eq.{uid},user_b.eq.{uid}")
            .order("created_at", desc=True)
            .limit(fetch_lim)
            .execute()
        )
        return res, True
    except Exception as e:
        if _muhabbet_pg_missing_column(e, "user_a_last_read_at", "user_b_last_read_at"):
            logger.warning("[muhabbet-conversations] read columns missing, fallback select: %s", e)
            res = (
                supabase.table("conversations")
                .select(_MUHABBET_CONV_LIST_BASE_FIELDS)
                .or_(f"user_a.eq.{uid},user_b.eq.{uid}")
                .order("created_at", desc=True)
                .limit(fetch_lim)
                .execute()
            )
            return res, False
        raise


def _muhabbet_reader_last_read_dt(conversation_row: dict, uid: str):
    uid_lo = str(uid or "").strip().lower()
    a = str(conversation_row.get("user_a") or "").strip().lower()
    b = str(conversation_row.get("user_b") or "").strip().lower()
    if uid_lo == a:
        raw = conversation_row.get("user_a_last_read_at")
    elif uid_lo == b:
        raw = conversation_row.get("user_b_last_read_at")
    else:
        return None
    return _muhabbet_trip_parse_dt(raw)


def _muhabbet_unread_count_for_member(
    conversation_row: dict, uid: str, *, read_columns_available: bool = True
) -> int:
    """Karşı tarafın gönderdiği, okuma zaman damgasından sonra gelen ve silinmemiş mesaj sayısı."""
    cid = str(conversation_row.get("id") or "").strip().lower()
    uid_lo = str(uid or "").strip().lower()
    if not cid or not uid_lo:
        return 0
    if not read_columns_available:
        return 0
    cur_dt = _muhabbet_reader_last_read_dt(conversation_row, uid_lo)
    if cur_dt is None:
        cur_dt = (
            _muhabbet_trip_parse_dt(conversation_row.get("last_message_at"))
            or _muhabbet_trip_parse_dt(conversation_row.get("updated_at"))
            or _muhabbet_trip_parse_dt(conversation_row.get("created_at"))
        )
    now_iso = datetime.now(timezone.utc).isoformat()
    try:
        res = (
            supabase.table("muhabbet_messages")
            .select("sender_id,created_at,deleted_for_user_ids")
            .eq("conversation_id", cid)
            .gt("expires_at", now_iso)
            .neq("sender_id", uid_lo)
            .execute()
        )
    except Exception as e:
        logger.warning("_muhabbet_unread_count_for_member: %s", e)
        return 0
    n = 0
    for r in res.data or []:
        del_ids = r.get("deleted_for_user_ids") or []
        del_lo = {str(x).strip().lower() for x in del_ids if x}
        if uid_lo in del_lo:
            continue
        msg_dt = _muhabbet_trip_parse_dt(r.get("created_at"))
        if msg_dt is None:
            continue
        if cur_dt is None or msg_dt > cur_dt:
            n += 1
    return n


def _muhabbet_bump_reader_cursor_to_max_iso(cid: str, reader_uid: str, candidate_iso: str) -> None:
    """Okuma işaretini en fazla candidate_iso olacak şekilde ilerlet (geri almaz)."""
    cid = str(cid or "").strip().lower()
    reader_uid = str(reader_uid or "").strip().lower()
    cand_raw = str(candidate_iso or "").strip()
    if not cid or not reader_uid or not cand_raw:
        return
    cand_dt = _muhabbet_trip_parse_dt(cand_raw)
    if cand_dt is None:
        return
    try:
        try:
            cr = (
                supabase.table("conversations")
                .select("user_a,user_b,user_a_last_read_at,user_b_last_read_at")
                .eq("id", cid)
                .limit(1)
                .execute()
            )
        except Exception as se:
            if _muhabbet_pg_missing_column(se, "user_a_last_read_at", "user_b_last_read_at"):
                logger.warning("_muhabbet_bump_reader_cursor_to_max_iso: read columns missing: %s", se)
                return
            raise
        if not cr.data:
            return
        row = dict(cr.data[0])
        a = str(row.get("user_a") or "").strip().lower()
        b = str(row.get("user_b") or "").strip().lower()
        now_patch_iso = datetime.now(timezone.utc).isoformat()
        patch: dict = {"updated_at": now_patch_iso}
        if reader_uid == a:
            prev_dt = _muhabbet_trip_parse_dt(row.get("user_a_last_read_at"))
            if prev_dt is not None and cand_dt <= prev_dt:
                return
            patch["user_a_last_read_at"] = cand_raw
        elif reader_uid == b:
            prev_dt = _muhabbet_trip_parse_dt(row.get("user_b_last_read_at"))
            if prev_dt is not None and cand_dt <= prev_dt:
                return
            patch["user_b_last_read_at"] = cand_raw
        else:
            return
        supabase.table("conversations").update(patch).eq("id", cid).execute()
    except Exception as e:
        logger.warning("_muhabbet_bump_reader_cursor_to_max_iso: %s", e)


async def _muhabbet_publish_message_after_persist(
    *,
    cid: str,
    msg_id: str,
    sender_id: str,
    text: str,
    created_iso: str,
    conversation_row: dict,
) -> None:
    """Persist sonrası Muhabbet realtime yayını; DB insert socket sid'e bağlı değildir."""
    cid = str(cid or "").strip().lower()
    msg_id = str(msg_id or "").strip().lower()
    sender_id = str(sender_id or "").strip().lower()
    a = str((conversation_row or {}).get("user_a") or "").strip().lower()
    b = str((conversation_row or {}).get("user_b") or "").strip().lower()
    recipient = b if a == sender_id else a
    try:
        _muhabbet_touch_conversation_last_message(conversation_id=cid, text=text, now_iso=created_iso)
    except Exception as e:
        logger.warning("muhabbet rest touch conversation failed cid=%s message_id=%s err=%s", cid, msg_id, e)
    payload = {
        "conversation_id": cid,
        "text": text,
        "sender_id": sender_id,
        "message_id": msg_id,
        "created_at": created_iso,
    }
    try:
        await sio.emit("message", payload, room=muhabbet_room(cid))
    except Exception as e:
        logger.warning("muhabbet rest room emit failed cid=%s message_id=%s err=%s", cid, msg_id, e)
    try:
        if recipient:
            await emit_socket_event_to_user(recipient, "message", payload)
        logger.info(
            "[socket_message_publish] %s",
            json.dumps(
                {"conversation_id": cid, "target_user_id": recipient or "", "message_id": msg_id},
                ensure_ascii=False,
            ),
        )
    except Exception as e:
        logger.warning("muhabbet rest user-target message emit failed: %s", e)
    try:
        await emit_socket_event_to_user(
            sender_id,
            "message_ack",
            {"conversation_id": cid, "message_id": msg_id, "status": "sent"},
        )
    except Exception as e:
        logger.warning("muhabbet rest ack emit failed: %s", e)
    try:
        conv_payload = {
            "conversation_id": cid,
            "last_message_body": text,
            "last_message_at": created_iso,
            "sender_id": sender_id,
            "unread_for_user_id": recipient,
        }
        for target in (sender_id, recipient):
            if target:
                await emit_socket_event_to_user(target, "muhabbet_conversation_updated", conv_payload)
    except Exception as e:
        logger.warning("muhabbet rest conversation_updated failed: %s", e)


def _muhabbet_messages_fetch_visible_for_user(cid: str, uid: str, limit: int = 200) -> list:
    """expires_at > şimdi; deleted_for_user_ids içinde uid yok."""
    uid_lo = str(uid or "").strip().lower()
    cid = str(cid or "").strip().lower()
    lim = max(1, min(int(limit or 200), 200))
    now_iso = datetime.now(timezone.utc).isoformat()
    try:
        res = (
            supabase.table("muhabbet_messages")
            .select("id,sender_id,text,created_at,deleted_for_user_ids")
            .eq("conversation_id", cid)
            .gt("expires_at", now_iso)
            .order("created_at", desc=True)
            .limit(min(lim * 2, 400))
            .execute()
        )
    except Exception as e:
        logger.warning("muhabbet_messages_fetch: %s", e)
        return []
    out: list = []
    for r in res.data or []:
        del_ids = r.get("deleted_for_user_ids") or []
        del_lo = {str(x).strip().lower() for x in del_ids if x}
        if uid_lo in del_lo:
            continue
        out.append(
            {
                "id": str(r.get("id") or "").strip().lower(),
                "body": r.get("text") or "",
                "sender_user_id": str(r.get("sender_id") or "").strip().lower(),
                "created_at": r.get("created_at"),
            }
        )
        if len(out) >= lim:
            break
    try:
        out.reverse()
    except Exception:
        pass
    return out


def _muhabbet_last_message_map_for_user(conversation_ids: list[str], uid: str) -> dict[str, dict]:
    """Sohbet listesi: kullanıcıya görünür son mesaj (expires_at + delete-for-me filtreli)."""
    cids = [str(x).strip().lower() for x in (conversation_ids or []) if x]
    cids = list(dict.fromkeys(cids))
    if not cids:
        return {}
    now_iso = datetime.now(timezone.utc).isoformat()
    uid_lo = str(uid or "").strip().lower()
    try:
        res = (
            supabase.table("muhabbet_messages")
            .select("conversation_id,text,created_at,deleted_for_user_ids")
            .in_("conversation_id", cids)
            .gt("expires_at", now_iso)
            .order("created_at", desc=True)
            .limit(min(max(600, len(cids) * 40), 3000))
            .execute()
        )
    except Exception as e:
        logger.warning("conversations_me last_message fetch: %s", e)
        return {}
    out: dict[str, dict] = {}
    for r in res.data or []:
        cid = str(r.get("conversation_id") or "").strip().lower()
        if not cid or cid in out:
            continue
        del_ids = {str(x).strip().lower() for x in (r.get("deleted_for_user_ids") or []) if x}
        if uid_lo in del_ids:
            continue
        out[cid] = {
            "last_message_body": str(r.get("text") or ""),
            "last_message_at": r.get("created_at"),
        }
    return out


def _muhabbet_touch_conversation_last_message(conversation_id: str, text: str, now_iso: str) -> None:
    """
    Mesaj DB'ye yazılsa da yazılmasa da sohbet listesi güncel kalsın:
    conversations.last_message, last_message_at, updated_at alanlarını best-effort güncelle.
    Şemada bu kolonlar yoksa sessizce updated_at veya no-op.
    """
    cid = str(conversation_id or "").strip().lower()
    if not cid:
        return
    try:
        supabase.table("conversations").update(
            {
                "last_message": str(text or "")[:2000],
                "last_message_at": now_iso,
                "updated_at": now_iso,
            }
        ).eq("id", cid).execute()
        return
    except Exception as e:
        logger.warning("touch conversation full fields failed cid=%s err=%s", cid[:12], e)
    try:
        supabase.table("conversations").update({"updated_at": now_iso}).eq("id", cid).execute()
    except Exception as e:
        logger.warning("touch conversation updated_at failed cid=%s err=%s", cid[:12], e)


def _muhabbet_message_delete_for_user_db(cid: str, mid: str, uid: str) -> str:
    """Dönüş: ok | not_found | error"""
    cid = str(cid or "").strip().lower()
    mid = str(mid or "").strip().lower()
    uid_lo = str(uid or "").strip().lower()
    try:
        uuid.UUID(mid)
        uuid.UUID(cid)
        uuid.UUID(uid_lo)
    except ValueError:
        return "error"
    try:
        r = (
            supabase.table("muhabbet_messages")
            .select("id,deleted_for_user_ids")
            .eq("id", mid)
            .eq("conversation_id", cid)
            .limit(1)
            .execute()
        )
        if not r.data:
            return "not_found"
        row = dict(r.data[0])
        arr_raw = list(row.get("deleted_for_user_ids") or [])
        have = {str(x).strip().lower() for x in arr_raw if x}
        if uid_lo in have:
            return "ok"
        arr_raw.append(uid_lo)
        supabase.table("muhabbet_messages").update({"deleted_for_user_ids": arr_raw}).eq("id", mid).eq(
            "conversation_id", cid
        ).execute()
        return "ok"
    except Exception as e:
        logger.warning("muhabbet_message_delete_for_user_db: %s", e)
        return "error"


@sio.on("join_muhabbet_conversation")
async def sio_join_muhabbet_conversation(sid, data):
    """Muhabbet sohbet odası — yalnızca JWT register sonrası; katılımcı doğrulanır."""
    if not isinstance(data, dict):
        data = {}
    try:
        _dj = json.dumps(data, default=str)[:480]
    except Exception:
        _dj = str(data)[:480]
    logger.info("[muhabbet_join] received sid=%s data=%s", sid, _dj)
    uid = _muhabbet_socket_uid_from_sid(sid)
    if not uid:
        logger.warning("[muhabbet_join] not_registered sid=%s", sid)
        await sio.emit("muhabbet_error", {"code": "not_registered", "detail": "Önce socket register gerekli"}, room=sid)
        return
    cid = str(data.get("conversation_id") or data.get("conversationId") or "").strip().lower()
    if not cid:
        return
    if not _muhabbet_conversation_member_ok(cid, uid):
        await sio.emit("muhabbet_error", {"code": "forbidden", "conversation_id": cid}, room=sid)
        return
    room = muhabbet_room(cid)
    await sio.enter_room(sid, room)
    await sio.emit("joined_muhabbet", {"conversation_id": cid, "room": room}, room=sid)
    logger.info("[muhabbet_join] ok sid=%s user=%s room=%s", sid, uid, room)
    logger.info(
        "[socket_join] %s",
        json.dumps({"event": "join_muhabbet_conversation", "user_id": uid, "sid": sid, "room": room}, ensure_ascii=False),
    )


@sio.on("leave_muhabbet_conversation")
async def sio_leave_muhabbet_conversation(sid, data):
    if not isinstance(data, dict):
        data = {}
    cid = str(data.get("conversation_id") or data.get("conversationId") or "").strip().lower()
    if not cid:
        return
    room = muhabbet_room(cid)
    try:
        await sio.leave_room(sid, room)
    except Exception as e:
        logger.warning("leave_muhabbet_conversation: %s", e)


@sio.on("muhabbet_send")
async def sio_muhabbet_send(sid, data):
    """Leylek Muhabbeti: mesaj DB'ye (90 gün), ardından ack + oda yayını + koşullu FCM."""
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    if not uid:
        logger.warning("[muhabbet_send] not_registered sid=%s", sid)
        await sio.emit("muhabbet_error", {"code": "not_registered", "detail": "Önce socket register gerekli"}, room=sid)
        return
    logger.info("[muhabbet_send] user=%s sid=%s", str(uid)[:13], sid)
    cid = str(data.get("conversation_id") or data.get("conversationId") or "").strip().lower()
    text = str(data.get("text") or data.get("body") or "").strip()
    if not cid or not text:
        return
    if len(text) > 2000:
        await sio.emit("muhabbet_error", {"code": "text_too_long", "max": 2000}, room=sid)
        return
    raw_mid = data.get("message_id") if "message_id" in data else data.get("messageId")
    parsed_mid, mid_err = _muhabbet_parse_client_message_id(raw_mid)
    if mid_err:
        await sio.emit(
            "muhabbet_error",
            {"code": "bad_message_id", "detail": mid_err, "conversation_id": cid},
            room=sid,
        )
        return
    msg_id = parsed_mid or str(uuid.uuid4())
    logger.info("[muhabbet_send] received sid=%s conversation_id=%s message_id=%s", sid, cid, msg_id)
    try:
        crow = _muhabbet_conversation_for_member_or_403(cid, uid)
    except HTTPException:
        logger.info("[muhabbet_send] participant_ok=false conversation_id=%s user=%s", cid, str(uid)[:13])
        await sio.emit("muhabbet_error", {"code": "forbidden", "conversation_id": cid, "message_id": msg_id}, room=sid)
        return
    logger.info("[muhabbet_send] participant_ok=true conversation_id=%s user=%s", cid, str(uid)[:13])
    a = str(crow.get("user_a") or "").strip().lower()
    b = str(crow.get("user_b") or "").strip().lower()
    recipient = b if a == uid else a
    logger.info(
        "[muhabbet_send] participants ok sender=%s receiver=%s conversation_id=%s",
        uid,
        recipient or None,
        cid,
    )
    now_iso = datetime.now(timezone.utc).isoformat()
    room = muhabbet_room(cid)
    try:
        await sio.enter_room(sid, room)
    except Exception as e:
        logger.warning("muhabbet_send enter_room: %s", e)
    peer_n = _muhabbet_room_peer_count(room)
    db_ok, db_err = _muhabbet_messages_try_insert(cid, msg_id, uid, text, now_iso)
    logger.info("[muhabbet_send] db_insert_ok=%s conversation_id=%s message_id=%s error=%s", db_ok, cid, msg_id, db_err[:300] if db_err else "")
    if not db_ok:
        await sio.emit(
            "muhabbet_error",
            {
                "code": "message_db_insert_failed",
                "message": "Mesaj gönderilemedi. Lütfen tekrar deneyin.",
                "detail": "Mesaj gönderilemedi. Lütfen tekrar deneyin.",
                "conversation_id": cid,
                "message_id": msg_id,
            },
            room=sid,
        )
        return
    if db_ok:
        try:
            _muhabbet_touch_conversation_last_message(
                conversation_id=cid,
                text=text,
                now_iso=now_iso,
            )
        except Exception as e:
            logger.error("muhabbet_send touch conversation failed cid=%s message_id=%s err=%s", cid, msg_id, e)
        try:
            # Leylek Teklif Sende only: a new chat message should restore the conversation
            # for both Muhabbet participants. This does not touch normal ride tags/dispatch/route.
            unhide_users = [x for x in [uid, recipient] if x]
            if unhide_users:
                supabase.table("user_conversation_hides").delete().eq("conversation_id", cid).in_(
                    "user_id", unhide_users
                ).execute()
                logger.info("[muhabbet-unhide] conversation_id=%s users=%s", cid, unhide_users)
        except Exception as e:
            logger.warning("muhabbet_send unhide conversation failed cid=%s err=%s", cid, e)
    try:
        await emit_socket_event_to_user(
            uid,
            "message_ack",
            {"conversation_id": cid, "message_id": msg_id, "status": "sent"},
        )
    except Exception as e:
        logger.warning("muhabbet_send message_ack: %s", e)
    else:
        logger.info("[muhabbet_send] ack_sent user=%s conversation_id=%s message_id=%s", str(uid)[:13], cid, msg_id)
    payload = {
        "conversation_id": cid,
        "text": text,
        "sender_id": uid,
        "message_id": msg_id,
        "created_at": now_iso,
    }
    await sio.emit("message", payload, room=room)
    logger.info("[muhabbet_send] emitted room=%s conversation_id=%s message_id=%s peers_in_room=%s", room, cid, msg_id, peer_n)
    try:
        if recipient:
            await emit_socket_event_to_user(recipient, "message", payload)
        logger.info(
            "[socket_message_publish] %s",
            json.dumps({"conversation_id": cid, "target_user_id": recipient or "", "message_id": msg_id}, ensure_ascii=False),
        )
    except Exception as e:
        logger.warning("muhabbet_send user-target message: %s", e)
    try:
        conv_payload = {
            "conversation_id": cid,
            "last_message_body": text,
            "last_message_at": now_iso,
            "sender_id": uid,
            "unread_for_user_id": recipient,
        }
        await emit_socket_event_to_user(uid, "muhabbet_conversation_updated", conv_payload)
        if recipient:
            await emit_socket_event_to_user(recipient, "muhabbet_conversation_updated", conv_payload)
    except Exception as e:
        logger.warning("muhabbet_send conversation_updated: %s", e)
    try:
        if recipient:
            ru = str(recipient).strip().lower()
            # İki taraf da aynı muhabbet odasındayken push yok; socket message zaten room'a gider.
            if peer_n >= 2:
                logger.info(
                    "[muhabbet_send] push skipped both_in_room conversation_id=%s peers_in_room=%s",
                    cid,
                    peer_n,
                )
            elif _muhabbet_message_push_rate_allow(ru, cid):
                preview = text[:50] + ("…" if len(text) > 50 else "")
                push_text = text[:400] + ("…" if len(text) > 400 else "")
                asyncio.create_task(
                    send_push_notification(
                        recipient,
                        "Yeni mesaj",
                        preview,
                        {
                            "type": "message",
                            "session_id": "",
                            "conversation_id": cid,
                            "title": "Yeni mesaj",
                            "body": preview,
                            "message_id": msg_id,
                            "sender_id": uid,
                            "text": push_text,
                            "created_at": now_iso,
                        },
                    )
                )
    except Exception as e:
        logger.warning("muhabbet_send push: %s", e)


@sio.on("delete_message")
async def sio_delete_message(sid, data):
    """İstemci uyumluluğu: yalnızca silen kullanıcı için gizle (delete-for-me); karşı taraf görür."""
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    if not uid:
        return
    mid = str(data.get("message_id") or data.get("messageId") or "").strip().lower()
    cid = str(data.get("conversation_id") or data.get("conversationId") or "").strip().lower()
    if not mid or not cid:
        return
    if not _muhabbet_conversation_member_ok(cid, uid):
        return
    st = _muhabbet_message_delete_for_user_db(cid, mid, uid)
    if st == "not_found":
        return
    if st != "ok":
        return
    try:
        await emit_socket_event_to_user(
            str(uid).strip().lower(),
            "message_deleted",
            {"message_id": mid, "conversation_id": cid},
        )
    except Exception as e:
        logger.warning("delete_message emit: %s", e)


async def _muhabbet_route_message_receipt(sid: str, data: Any, out_event: str) -> None:
    """message_delivered / message_seen: emitter alıcıdır; yazar (sender_id) aynı event adıyla bilgilendirilir."""
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    if not uid:
        logger.warning("[%s] not_registered sid=%s", out_event, sid)
        await sio.emit("muhabbet_error", {"code": "not_registered", "detail": "Önce socket register gerekli"}, room=sid)
        return
    cid = str(data.get("conversation_id") or data.get("conversationId") or "").strip().lower()
    mid = str(data.get("message_id") or data.get("messageId") or "").strip().lower()
    author = str(data.get("sender_id") or data.get("sender_user_id") or "").strip().lower()
    if not cid or not mid or not author:
        return
    try:
        crow = _muhabbet_conversation_for_member_or_403(cid, uid)
    except HTTPException:
        return
    a = str(crow.get("user_a") or "").strip().lower()
    b = str(crow.get("user_b") or "").strip().lower()
    if uid not in (a, b) or author not in (a, b) or uid == author:
        return
    await emit_socket_event_to_user(author, out_event, {"conversation_id": cid, "message_id": mid})
    if out_event == "message_seen":
        try:
            msg_row = _muhabbet_message_fetch_by_id(cid, mid)
            created_iso = str((msg_row or {}).get("created_at") or "").strip()
            if created_iso:
                _muhabbet_bump_reader_cursor_to_max_iso(cid, uid, created_iso)
        except Exception as bump_err:
            logger.warning("message_seen read cursor bump: %s", bump_err)


@sio.on("message_delivered")
async def sio_message_delivered(sid, data):
    await _muhabbet_route_message_receipt(sid, data, "message_delivered")


@sio.on("message_seen")
async def sio_message_seen(sid, data):
    await _muhabbet_route_message_receipt(sid, data, "message_seen")


def _leylek_pair_request_try(uid: str, conversation_id: str) -> dict:
    """
    Leylek Anahtar eşleşme isteği — Socket.IO ve REST ortak mantık (DB insert / cooldown / pending).
    Dönüş: {ok, request_id, pending, target, initiator_role} veya {ok: False, err, detail}
    """
    try:
        uid = (uid or "").strip().lower()
        cid = (conversation_id or "").strip().lower()
        print("[PAIR DEBUG]", {
            "uid": uid,
            "cid": cid,
        })
        if not uid or not cid:
            return {"ok": False, "err": "bad_request", "detail": "Eksik parametre"}
        try:
            c_row = _muhabbet_conversation_for_member_or_403(cid, uid)
        except HTTPException as he:
            return {"ok": False, "err": "forbidden", "detail": str(he.detail) if he.detail else "forbidden"}
        except Exception as e:
            return {"ok": False, "err": "error", "detail": str(e)}
        a = str(c_row.get("user_a") or "").strip().lower()
        b = str(c_row.get("user_b") or "").strip().lower()
        target = b if a == uid else a
        now = datetime.now(timezone.utc)
        lastq = (
            supabase.table("muhabbet_leylek_pair_requests")
            .select("id, status, created_at")
            .eq("conversation_id", cid)
            .eq("initiator_user_id", uid)
            .order("created_at", desc=True)
            .limit(1)
            .execute()
        )
        if lastq.data:
            last = dict(lastq.data[0])
            st = str(last.get("status") or "").strip().lower()
            if st == "pending":
                return {
                    "ok": True,
                    "pending": True,
                    "request_id": str(last.get("id")).strip().lower(),
                }
            created_at = last.get("created_at")
            try:
                cdt = _parse_iso_dt(created_at) if created_at else None
            except Exception:
                cdt = None
            if cdt is not None and (now - cdt).total_seconds() < float(_LEYLEK_PAIR_REQUEST_COOLDOWN_SEC):
                wait = int(_LEYLEK_PAIR_REQUEST_COOLDOWN_SEC - (now - cdt).total_seconds())
                return {
                    "ok": False,
                    "err": "cooldown",
                    "detail": f"Çok sık istek. {max(1, wait)} sn sonra tekrar deneyin.",
                }
        ir = supabase.table("users").select("id").eq("id", uid).limit(1).execute()
        initiator_role = ""
        if ir.data and ir.data[0].get("id"):
            initiator_role = str(ir.data[0].get("role") or "").strip().lower()
        sem = _muhabbet_match_semantic_roles_for_conversation(cid)
        if sem.get(uid):
            initiator_role = str(sem.get(uid) or "").strip().lower()
        other_user_id = target
        print("[PAIR INSERT]", {
            "initiator": uid,
            "target": other_user_id,
        })
        ins = (
            supabase.table("muhabbet_leylek_pair_requests")
            .insert(
                {
                    "conversation_id": cid,
                    "requester_user_id": uid,
                    "initiator_user_id": uid,
                    "target_user_id": target,
                    "status": "pending",
                }
            )
            .execute()
        )
        if not ins.data or not ins.data[0].get("id"):
            return {"ok": False, "err": "db", "detail": "İstek oluşturulamadı"}
        rid = str(ins.data[0]["id"]).strip().lower()
        return {
            "ok": True,
            "pending": False,
            "request_id": rid,
            "target": target,
            "initiator_role": initiator_role,
        }
    except Exception as e:
        import traceback
        print("❌ PAIR INTERNAL ERROR:", e)
        traceback.print_exc()
        raise


async def _leylek_pair_request_emit_success(uid: str, cid: str, r: dict) -> None:
    """Yeni oluşturulan istek için hedefe bildirim + istek sahibine leylek_pair_request_sent (socket ile uyumlu)."""
    rid = str(r.get("request_id") or "").strip().lower()
    target = str(r.get("target") or "").strip().lower()
    role = str(r.get("initiator_role") or "").strip().lower()
    if not rid or not target:
        logger.warning("_leylek_pair_request_emit_success missing fields uid=%s cid=%s r=%s", uid, cid, r)
        return
    logger.info("[leylek-key] request_created conversation_id=%s request_id=%s requester=%s target=%s", cid, rid, str(uid)[:13], str(target)[:13] if target else "")
    try:
        await _muhabbet_notify_leylek_pair_request(str(target), uid, cid, rid, role)
    except Exception as e:
        logger.warning("leylek_pair_request notify: %s", e)
    try:
        await emit_socket_event_to_user(
            str(uid).strip().lower(),
            "leylek_pair_request_sent",
            {"request_id": rid, "conversation_id": cid},
        )
        logger.info("[leylek_pair_request] ack sent requester=%s", str(uid)[:13])
    except Exception as e:
        logger.warning("leylek_pair_request_sent emit: %s", e)


async def _sio_leylek_pair_request_handler(sid, data):
    """İstemci: leylek_pair_request veya leylek_pair_match_request — DB + leylek_pair_match_request emit."""
    if not isinstance(data, dict):
        data = {}
    logger.info("[leylek_pair_request] received payload=%s", data)
    uid = _muhabbet_socket_uid_from_sid(sid)
    if not uid:
        logger.warning("[leylek_pair_request] not_registered sid=%s payload=%s", sid, data)
        await sio.emit(
            "leylek_pair_error",
            {"code": "not_registered", "message": "Bağlantı hazırlanıyor. Lütfen tekrar deneyin."},
            room=sid,
        )
        return
    cid = str(data.get("conversation_id") or data.get("conversationId") or "").strip().lower()
    if not cid:
        return
    logger.info("[leylek_pair_request] received sid=%s conversation_id=%s uid=%s", sid, cid, str(uid)[:13])
    if not _muhabbet_conversation_member_ok(cid, uid):
        await sio.emit("leylek_pair_error", {"code": "forbidden", "detail": "Bu sohbete erişim yok"}, room=sid)
        return
    try:
        await sio.enter_room(sid, muhabbet_room(cid))
    except Exception as e:
        logger.warning("leylek_pair_request enter_room: %s", e)
    logger.info("[leylek_pair_request] handler_start sid=%s uid=%s cid=%s", sid, uid, cid)
    try:
        r = _leylek_pair_request_try(uid, cid)
        logger.info("[leylek_pair_request] result=%s", r)
    except Exception as e:
        logger.exception("[leylek_pair_request] exception sid=%s uid=%s cid=%s", sid, uid, cid)
        await sio.emit(
            "leylek_pair_error",
            {
                "code": "server_error",
                "message": "Eşleşme isteği işlenemedi. Lütfen tekrar deneyin.",
            },
            to=sid,
        )
        return
    if not r.get("ok"):
        if r.get("err") == "cooldown":
            await sio.emit("leylek_pair_error", {"code": "cooldown", "detail": r.get("detail") or ""}, room=sid)
        else:
            await sio.emit("leylek_pair_error", {"code": r.get("err") or "error", "detail": r.get("detail") or ""}, room=sid)
        return
    if r.get("pending"):
        await sio.emit("leylek_pair_info", {"code": "pending", "request_id": r.get("request_id")}, room=sid)
        return
    logger.info("[leylek_pair_request] requester=%s target=%s conversation=%s", uid, r.get("target"), cid)
    logger.info(
        "[leylek_pair_request] participants requester=%s target=%s conversation_id=%s request_id=%s",
        str(uid)[:13],
        str(r.get("target") or "")[:13],
        cid,
        str(r.get("request_id") or "")[:13],
    )
    await _leylek_pair_request_emit_success(uid, cid, r)


@sio.on("leylek_pair_request")
async def sio_leylek_pair_request(sid, data):
    await _sio_leylek_pair_request_handler(sid, data)


@sio.on("leylek_pair_match_request")
async def sio_leylek_pair_match_request(sid, data):
    await _sio_leylek_pair_request_handler(sid, data)


async def _leylek_pair_accept(uid: str, cid: str, rid: str) -> dict:
    uid = (uid or "").strip().lower()
    cid = (cid or "").strip().lower()
    rid = (rid or "").strip().lower()
    try:
        uuid.UUID(rid)
    except ValueError:
        return {"ok": False, "detail": "Geçersiz istek"}
    c_row = _muhabbet_conversation_for_member_or_403(cid, uid)  # noqa: F841
    rr = (
        supabase.table("muhabbet_leylek_pair_requests")
        .select("*")
        .eq("id", rid)
        .eq("conversation_id", cid)
        .limit(1)
        .execute()
    )
    if not rr.data:
        return {"ok": False, "detail": "İstek bulunamadı"}
    row = dict(rr.data[0])
    if str(row.get("target_user_id") or "").strip().lower() != uid:
        return {"ok": False, "detail": "Sadece karşı taraf kabul edebilir"}
    if str(row.get("status") or "").strip().lower() != "pending":
        return {"ok": False, "detail": "İstek artık geçerli değil"}
    now_iso = datetime.now(timezone.utc).isoformat()
    initiator = str(row.get("initiator_user_id") or "").strip().lower()
    supabase.table("muhabbet_leylek_pair_requests").update(
        {"status": "accepted", "responded_at": now_iso}
    ).eq("id", rid).execute()
    supabase.table("conversations").update(
        {
            "matched_at": now_iso,
            "match_source": "leylek_key_inchat",
        }
    ).eq("id", cid).execute()
    _muhabbet_mark_ride_listing_matched_for_muhabbet_conversation(cid)
    await _muhabbet_notify_leylek_key_matched(initiator, uid, cid)
    session_row = await _muhabbet_create_trip_session_after_leylek_key_accept(
        acceptor_uid=uid,
        conversation_id=cid,
        pair_request_id=rid,
        initiator_uid=initiator,
    )
    return {"ok": True, "conversation_id": cid, "session_id": session_row.get("id") if session_row else None}


@sio.on("leylek_pair_accept")
async def sio_leylek_pair_accept(sid, data):
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    if not uid:
        return
    cid = str(data.get("conversation_id") or data.get("conversationId") or "").strip().lower()
    rid = str(data.get("request_id") or data.get("requestId") or "").strip().lower()
    if not cid or not rid:
        await sio.emit("leylek_pair_error", {"code": "bad_request", "detail": "conversation_id / request_id gerekli"}, room=sid)
        return
    if not _muhabbet_conversation_member_ok(cid, uid):
        await sio.emit("leylek_pair_error", {"code": "forbidden"}, room=sid)
        return
    try:
        await sio.enter_room(sid, muhabbet_room(cid))
    except Exception as e:
        logger.warning("leylek_pair_accept enter_room: %s", e)
    out = await _leylek_pair_accept(uid, cid, rid)
    if not out.get("ok"):
        await sio.emit("leylek_pair_error", {"code": "accept_failed", "detail": out.get("detail") or ""}, room=sid)


def _leylek_pair_decline(uid: str, cid: str, rid: str) -> dict:
    uid = (uid or "").strip().lower()
    cid = (cid or "").strip().lower()
    rid = (rid or "").strip().lower()
    try:
        uuid.UUID(rid)
    except ValueError:
        return {"ok": False, "detail": "Geçersiz istek"}
    _ = _muhabbet_conversation_for_member_or_403(cid, uid)  # noqa: F841
    rr = (
        supabase.table("muhabbet_leylek_pair_requests")
        .select("*")
        .eq("id", rid)
        .eq("conversation_id", cid)
        .limit(1)
        .execute()
    )
    if not rr.data:
        return {"ok": False, "detail": "İstek bulunamadı"}
    row = dict(rr.data[0])
    if str(row.get("target_user_id") or "").strip().lower() != uid:
        return {"ok": False, "detail": "Sadece karşı taraf yanıtlayabilir"}
    if str(row.get("status") or "").strip().lower() != "pending":
        return {"ok": True, "message": "zaten yanıtlanmış", "initiator_user_id": None}
    initiator_uid = str(row.get("initiator_user_id") or "").strip().lower()
    now_iso = datetime.now(timezone.utc).isoformat()
    supabase.table("muhabbet_leylek_pair_requests").update(
        {"status": "declined", "responded_at": now_iso}
    ).eq("id", rid).execute()
    return {"ok": True, "message": "declined", "initiator_user_id": initiator_uid or None}


@sio.on("leylek_pair_decline")
async def sio_leylek_pair_decline(sid, data):
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    if not uid:
        return
    cid = str(data.get("conversation_id") or data.get("conversationId") or "").strip().lower()
    rid = str(data.get("request_id") or data.get("requestId") or "").strip().lower()
    if not cid or not rid:
        return
    if not _muhabbet_conversation_member_ok(cid, uid):
        return
    try:
        await sio.enter_room(sid, muhabbet_room(cid))
    except Exception as e:
        logger.warning("leylek_pair_decline enter_room: %s", e)
    out = _leylek_pair_decline(uid, cid, rid)
    await _leylek_pair_decline_emit_to_initiator(cid, rid, out)


async def _leylek_pair_decline_emit_to_initiator(cid: str, rid: str, out: dict) -> None:
    """Decline sonrası initiator’a leylek_pair_declined (socket ile uyumlu)."""
    if not isinstance(out, dict) or not out.get("ok"):
        return
    ini = out.get("initiator_user_id")
    if ini and str(out.get("message") or "") == "declined":
        try:
            await emit_socket_event_to_user(
                str(ini).strip(),
                "leylek_pair_declined",
                {"conversation_id": cid, "request_id": rid},
            )
        except Exception as e:
            logger.warning("leylek_pair_declined emit: %s", e)




def _muhabbet_trip_conversion_context(uid: str, cid: str, *, require_driver_requester: bool = False) -> dict:
    """Leylek Teklif Sende only: build chat-to-trip intent context; never creates normal ride tags."""
    uid = str(uid or "").strip().lower()
    cid = str(cid or "").strip().lower()
    try:
        c_row = _muhabbet_conversation_for_member_or_403(cid, uid)
    except HTTPException as e:
        return {"ok": False, "code": "forbidden" if e.status_code == 403 else "bad_conversation", "detail": str(e.detail)}
    ms = str(c_row.get("match_source") or "").strip().lower()
    matched_at = c_row.get("matched_at")
    trip_sources_ok = ms in ("leylek_key", "leylek_key_inchat", "listing_match")
    listing_accepted_row = False
    try:
        chk = (
            supabase.table("listing_match_requests")
            .select("id")
            .eq("conversation_id", cid)
            .eq("status", "accepted")
            .limit(1)
            .execute()
        )
        listing_accepted_row = bool(chk.data)
    except Exception as e:
        logger.warning("[trip_convert_context] listing_match_requests lookup cid=%s err=%s", cid[:12], e)
    if not listing_accepted_row and (not matched_at or not trip_sources_ok):
        return {
            "ok": False,
            "code": "not_matched",
            "detail": "Önce teklif talebinin kabul edilmesi gerekir.",
        }

    a = str(c_row.get("user_a") or "").strip().lower()
    b = str(c_row.get("user_b") or "").strip().lower()
    target = b if a == uid else a
    roles = _muhabbet_match_semantic_roles_for_conversation(cid)
    driver_ids = [u for u, r in roles.items() if str(r).strip().lower() == "driver"]
    passenger_ids = [u for u, r in roles.items() if str(r).strip().lower() == "passenger"]
    logger.info(
        "[trip_convert_request] roles cid=%s uid=%s drivers=%s passengers=%s",
        cid,
        uid,
        driver_ids,
        passenger_ids,
    )
    if len(driver_ids) != 1 or len(passenger_ids) != 1:
        return {"ok": False, "code": "ambiguous_roles", "detail": "Sürücü/yolcu rolleri net değil."}
    if require_driver_requester and uid != driver_ids[0]:
        return {"ok": False, "code": "driver_required", "detail": "Yolculuğa çevirme isteğini sürücü başlatabilir."}
    if require_driver_requester and target != passenger_ids[0]:
        return {"ok": False, "code": "ambiguous_roles", "detail": "Hedef yolcu net değil."}

    mq = (
        supabase.table("listing_match_requests")
        .select("id, listing_id")
        .eq("conversation_id", cid)
        .eq("status", "accepted")
        .order("updated_at", desc=True)
        .limit(1)
        .execute()
    )
    lmr = dict(mq.data[0]) if mq.data else {}
    listing_id = str(lmr.get("listing_id") or "").strip().lower() or None
    listing = {}
    if listing_id:
        lr = supabase.table("ride_listings").select("*").eq("id", listing_id).limit(1).execute()
        if lr.data:
            listing = _ride_listing_response_row(dict(lr.data[0]))

    return {
        "ok": True,
        "conversation_id": cid,
        "requester_user_id": uid,
        "target_user_id": target,
        "driver_id": driver_ids[0],
        "passenger_id": passenger_ids[0],
        "listing_id": listing_id,
        "listing_match_request_id": str(lmr.get("id") or "").strip().lower() or None,
        "city": listing.get("city"),
        "pickup_text": listing.get("from_text"),
        "pickup_lat": listing.get("start_lat"),
        "pickup_lng": listing.get("start_lng"),
        "dropoff_text": listing.get("to_text"),
        "dropoff_lat": listing.get("end_lat"),
        "dropoff_lng": listing.get("end_lng"),
        "agreed_price": (
            _muhabbet_leylek_listing_agreed_price_floor(listing.get("price_amount"))
            if listing_id
            else None
        ),
        "vehicle_kind": _canonical_vehicle_kind(listing.get("vehicle_kind")),
        "payment_method": None,
    }


def _muhabbet_trip_convert_request_snapshot(uid: str, cid: str) -> dict | None:
    """En güncel conversion request satırı; GET messages içindeki trip_convert_request ile aynı şema."""
    uid_lo_ctx = str(uid or "").strip().lower()
    cid = str(cid or "").strip().lower()
    if not uid_lo_ctx or not cid:
        return None
    try:
        tcr_res = (
            supabase.table("muhabbet_trip_conversion_requests")
            .select("id,status,requester_user_id,target_user_id,created_at,updated_at")
            .eq("conversation_id", cid)
            .order("updated_at", desc=True)
            .limit(1)
            .execute()
        )
        if not tcr_res.data:
            return None
        trow = dict(tcr_res.data[0])
        rid_tc = str(trow.get("id") or "").strip().lower()
        st_tc = str(trow.get("status") or "").strip().lower()
        req_tc = str(trow.get("requester_user_id") or "").strip().lower()
        tgt_tc = str(trow.get("target_user_id") or "").strip().lower()
        session_id_tc = None
        trip_id_tc = None
        if rid_tc:
            try:
                tsr = (
                    supabase.table("muhabbet_trip_sessions")
                    .select("id")
                    .eq("conversion_request_id", rid_tc)
                    .limit(1)
                    .execute()
                )
                if tsr.data:
                    sid_tc = str(tsr.data[0].get("id") or "").strip().lower()
                    if sid_tc:
                        session_id_tc = sid_tc
                        trip_id_tc = sid_tc
            except Exception as e_ts:
                logger.warning("trip_convert_request_snapshot session lookup: %s", e_ts)
        return {
            "id": rid_tc,
            "status": st_tc,
            "requester_user_id": req_tc,
            "target_user_id": tgt_tc,
            "created_at": trow.get("created_at"),
            "updated_at": trow.get("updated_at"),
            "session_id": session_id_tc,
            "trip_id": trip_id_tc,
            "is_requester": req_tc == uid_lo_ctx,
            "is_target": tgt_tc == uid_lo_ctx,
            "pending": st_tc == "pending",
            "accepted": st_tc == "accepted",
            "declined": st_tc == "declined",
        }
    except Exception as e:
        logger.warning("_muhabbet_trip_convert_request_snapshot: %s", e)
        return None


