def _muhabbet_trip_session_for_member_or_403(session_id: str, uid: str) -> dict:
    sid = str(session_id or "").strip().lower()
    uid_lo = str(uid or "").strip().lower()
    try:
        uuid.UUID(sid)
    except ValueError as e:
        raise HTTPException(status_code=400, detail="Geçersiz Muhabbet yolculuk oturumu") from e
    r = supabase.table("muhabbet_trip_sessions").select("*").eq("id", sid).limit(1).execute()
    if not r.data:
        raise HTTPException(status_code=404, detail="Muhabbet yolculuk oturumu bulunamadı")
    row = dict(r.data[0])
    if uid_lo not in (
        str(row.get("passenger_id") or "").strip().lower(),
        str(row.get("driver_id") or "").strip().lower(),
    ):
        raise HTTPException(status_code=403, detail="Bu Muhabbet yolculuk oturumuna erişim yetkiniz yok")
    return row


def _muhabbet_trip_first_value(*values):
    for value in values:
        if value is None:
            continue
        if isinstance(value, str) and not value.strip():
            continue
        return value
    return None


def _muhabbet_trip_float_or_none(value):
    try:
        if value is None or (isinstance(value, str) and not value.strip()):
            return None
        out = float(value)
        return out if math.isfinite(out) else None
    except Exception:
        return None


def _muhabbet_leylek_listing_agreed_price_floor(value) -> Optional[float]:
    """İlan → Muhabbet trip: anlaşılan ücret tabanı (TL). Normal TAG ile ilgisi yok."""
    f = _muhabbet_trip_float_or_none(value)
    if f is None:
        return None
    return max(f, 30.0)


def _muhabbet_trip_hydrate_source(row: dict) -> dict:
    listing_id = str((row or {}).get("listing_id") or "").strip().lower()
    match_id = str((row or {}).get("listing_match_request_id") or "").strip().lower()
    logger.info("[muhabbet_trip_session] hydrate_source listing_id=%s match_id=%s", listing_id or None, match_id or None)

    match_row = {}
    if match_id:
        try:
            mr = supabase.table("listing_match_requests").select("*").eq("id", match_id).limit(1).execute()
            if mr.data:
                match_row = dict(mr.data[0])
                listing_id = listing_id or str(match_row.get("listing_id") or "").strip().lower()
        except Exception as e:
            logger.warning("[muhabbet_trip_session] hydrate match lookup failed match_id=%s err=%s", match_id, e)

    listing_raw = {}
    listing = {}
    if listing_id:
        try:
            lr = supabase.table("ride_listings").select("*").eq("id", listing_id).limit(1).execute()
            if lr.data:
                listing_raw = dict(lr.data[0])
                listing = _ride_listing_response_row(listing_raw)
        except Exception as e:
            logger.warning("[muhabbet_trip_session] hydrate listing lookup failed listing_id=%s err=%s", listing_id, e)

    pickup_lat = _muhabbet_trip_float_or_none(
        _muhabbet_trip_first_value(row.get("pickup_lat"), listing.get("start_lat"), listing_raw.get("start_lat"), listing_raw.get("pickup_lat"))
    )
    pickup_lng = _muhabbet_trip_float_or_none(
        _muhabbet_trip_first_value(row.get("pickup_lng"), listing.get("start_lng"), listing_raw.get("start_lng"), listing_raw.get("pickup_lng"))
    )
    dropoff_lat = _muhabbet_trip_float_or_none(
        _muhabbet_trip_first_value(row.get("dropoff_lat"), listing.get("end_lat"), listing_raw.get("end_lat"), listing_raw.get("dropoff_lat"))
    )
    dropoff_lng = _muhabbet_trip_float_or_none(
        _muhabbet_trip_first_value(row.get("dropoff_lng"), listing.get("end_lng"), listing_raw.get("end_lng"), listing_raw.get("dropoff_lng"))
    )
    if pickup_lat is None or pickup_lng is None or dropoff_lat is None or dropoff_lng is None:
        logger.warning("[muhabbet_trip_session] missing pickup/dropoff coordinates")

    route_distance = _muhabbet_trip_float_or_none(
        _muhabbet_trip_first_value(
            row.get("route_distance_km"),
            row.get("distance_km"),
            listing.get("route_distance_km"),
            listing.get("distance_km"),
            listing_raw.get("route_distance_km"),
            listing_raw.get("distance_km"),
        )
    )
    route_duration = _muhabbet_trip_float_or_none(
        _muhabbet_trip_first_value(
            row.get("route_duration_min"),
            row.get("estimated_minutes"),
            listing.get("route_duration_min"),
            listing.get("estimated_minutes"),
            listing_raw.get("route_duration_min"),
            listing_raw.get("estimated_minutes"),
        )
    )

    hydrated = {
        "listing_id": listing_id or None,
        "listing_match_request_id": match_id or None,
        "requester_user_id": row.get("requester_user_id"),
        "city": _muhabbet_trip_first_value(row.get("city"), listing.get("city"), listing_raw.get("city")),
        "pickup_text": _muhabbet_trip_first_value(row.get("pickup_text"), listing.get("from_text"), listing_raw.get("from_text"), listing_raw.get("pickup_text")),
        "pickup_lat": pickup_lat,
        "pickup_lng": pickup_lng,
        "dropoff_text": _muhabbet_trip_first_value(row.get("dropoff_text"), listing.get("to_text"), listing_raw.get("to_text"), listing_raw.get("dropoff_text")),
        "dropoff_lat": dropoff_lat,
        "dropoff_lng": dropoff_lng,
        "agreed_price": _muhabbet_leylek_listing_agreed_price_floor(
            _muhabbet_trip_first_value(
                row.get("agreed_price"),
                listing.get("price_amount"),
                listing_raw.get("price_amount"),
                match_row.get("agreed_price"),
            )
        ),
        "vehicle_kind": _canonical_vehicle_kind(_muhabbet_trip_first_value(row.get("vehicle_kind"), listing.get("vehicle_kind"), listing_raw.get("vehicle_kind"))),
        "payment_method": _canonical_passenger_payment_method(_muhabbet_trip_first_value(row.get("payment_method"), listing.get("payment_method"), listing_raw.get("payment_method"), listing_raw.get("passenger_payment_method"))),
        "route_polyline": _muhabbet_trip_first_value(row.get("route_polyline"), listing.get("route_polyline"), listing.get("overview_polyline"), listing_raw.get("route_polyline"), listing_raw.get("overview_polyline")),
        "route_distance_km": route_distance,
        "route_duration_min": int(round(route_duration)) if route_duration is not None else None,
        "route_source": _muhabbet_trip_first_value(row.get("route_source"), listing.get("route_source"), listing_raw.get("route_source")),
    }
    if hydrated.get("route_polyline") or hydrated.get("route_distance_km") is not None or hydrated.get("route_duration_min") is not None:
        hydrated["route_updated_at"] = datetime.now(timezone.utc).isoformat()
    logger.info(
        "[muhabbet_trip_session] hydrated pickup=%s dropoff=%s price=%s",
        {"text": hydrated.get("pickup_text"), "lat": hydrated.get("pickup_lat"), "lng": hydrated.get("pickup_lng")},
        {"text": hydrated.get("dropoff_text"), "lat": hydrated.get("dropoff_lat"), "lng": hydrated.get("dropoff_lng")},
        hydrated.get("agreed_price"),
    )
    return {k: v for k, v in hydrated.items() if v is not None}


def _muhabbet_trip_create_or_get_session_for_request(row: dict) -> dict:
    """Accepted conversion request -> isolated Muhabbet trip session. Never creates/touches tags."""
    rid = str((row or {}).get("id") or "").strip().lower()
    if not rid:
        raise ValueError("conversion request id missing")
    existing = (
        supabase.table("muhabbet_trip_sessions")
        .select("*")
        .eq("conversion_request_id", rid)
        .limit(1)
        .execute()
    )
    if existing.data:
        out = dict(existing.data[0])
        logger.info("[muhabbet_trip_session] ready session_id=%s request_id=%s", out.get("id"), rid)
        try:
            _muhabbet_trip_passenger_upsert_for_session(out, row)
        except Exception as e:
            logger.warning("[muhabbet_trip_passengers] upsert_failed session_id=%s err=%s", out.get("id"), e)
        return out

    hydrated = _muhabbet_trip_hydrate_source(row)
    now = datetime.now(timezone.utc)
    now_iso = now.isoformat()
    insert_payload = {
        "conversion_request_id": rid,
        "conversation_id": row.get("conversation_id"),
        "passenger_id": row.get("passenger_id"),
        "driver_id": row.get("driver_id"),
        "status": "ready",
        "expires_at": (now + timedelta(hours=1)).isoformat(),
        "updated_at": now_iso,
        **hydrated,
    }
    logger.info("[muhabbet_trip_session] insert_payload=%s", insert_payload)
    ins = (
        supabase.table("muhabbet_trip_sessions")
        .insert(insert_payload)
        .execute()
    )
    if not ins.data:
        raise RuntimeError("muhabbet_trip_sessions insert failed")
    out = dict(ins.data[0])
    logger.info("[muhabbet_trip_session] ready session_id=%s request_id=%s", out.get("id"), rid)

    try:
        _muhabbet_trip_passenger_upsert_for_session(out, row)
    except Exception as e:
        logger.warning("[muhabbet_trip_passengers] upsert_failed session_id=%s err=%s", out.get("id"), e)
    return out


async def _emit_muhabbet_trip_session_ready(session_row: dict) -> None:
    payload = {
        "request_id": session_row.get("conversion_request_id"),
        "conversation_id": session_row.get("conversation_id"),
        "session_id": session_row.get("id"),
    }
    for uid in (
        str(session_row.get("passenger_id") or "").strip(),
        str(session_row.get("driver_id") or "").strip(),
    ):
        if uid:
            logger.info(
                "[leylek-key] emit session_ready to uid=%s conversation_id=%s session_id=%s",
                uid[:13],
                payload.get("conversation_id"),
                payload.get("session_id"),
            )
            await emit_socket_event_to_user(uid, "muhabbet_trip_session_ready", payload)


async def _muhabbet_create_trip_session_after_leylek_key_accept(
    *,
    acceptor_uid: str,
    conversation_id: str,
    pair_request_id: str,
    initiator_uid: str,
) -> dict | None:
    """Leylek Anahtar accept -> Muhabbet trip session only; never touches normal ride state."""
    uid = str(acceptor_uid or "").strip().lower()
    cid = str(conversation_id or "").strip().lower()
    rid = str(pair_request_id or "").strip().lower()
    initiator = str(initiator_uid or "").strip().lower()
    logger.info("[leylek-key] accept_received conversation_id=%s pair_request_id=%s acceptor=%s initiator=%s", cid, rid, uid[:13], initiator[:13])
    if not uid or not cid:
        logger.warning("[leylek-key] accept_missing_context conversation_id=%s acceptor=%s", cid, uid[:13])
        return None

    try:
        existing = (
            supabase.table("muhabbet_trip_sessions")
            .select("*")
            .eq("conversation_id", cid)
            .in_("status", ["ready", "started", "active"])
            .order("updated_at", desc=True)
            .limit(1)
            .execute()
        )
        if existing.data:
            session_row = dict(existing.data[0])
            payload = {
                "request_id": session_row.get("conversion_request_id"),
                "conversation_id": cid,
                "session_id": session_row.get("id"),
            }
            for target_uid in (str(session_row.get("requester_user_id") or initiator).strip(), uid):
                if target_uid:
                    await emit_socket_event_to_user(target_uid, "muhabbet_trip_convert_confirmed", payload)
            await _emit_muhabbet_trip_session_ready(session_row)
            logger.info("[leylek-key] existing_session_ready session_id=%s conversation_id=%s", session_row.get("id"), cid)
            return session_row

        ctx = _muhabbet_trip_conversion_context(uid, cid)
        if not ctx.get("ok"):
            logger.warning("[leylek-key] conversion_context_failed conversation_id=%s code=%s detail=%s", cid, ctx.get("code"), ctx.get("detail"))
            return None

        requester_uid = initiator or str(ctx.get("driver_id") or ctx.get("requester_user_id") or uid).strip().lower()
        target_uid = uid
        now_iso = datetime.now(timezone.utc).isoformat()
        ins = (
            supabase.table("muhabbet_trip_conversion_requests")
            .insert(
                {
                    "conversation_id": cid,
                    "listing_id": ctx.get("listing_id"),
                    "listing_match_request_id": ctx.get("listing_match_request_id"),
                    "requester_user_id": requester_uid,
                    "target_user_id": target_uid,
                    "passenger_id": ctx.get("passenger_id"),
                    "driver_id": ctx.get("driver_id"),
                    "status": "accepted",
                    "city": ctx.get("city"),
                    "pickup_text": ctx.get("pickup_text"),
                    "pickup_lat": ctx.get("pickup_lat"),
                    "pickup_lng": ctx.get("pickup_lng"),
                    "dropoff_text": ctx.get("dropoff_text"),
                    "dropoff_lat": ctx.get("dropoff_lat"),
                    "dropoff_lng": ctx.get("dropoff_lng"),
                    "agreed_price": ctx.get("agreed_price"),
                    "vehicle_kind": ctx.get("vehicle_kind"),
                    "payment_method": ctx.get("payment_method"),
                    "requested_at": now_iso,
                    "responded_at": now_iso,
                    "updated_at": now_iso,
                }
            )
            .execute()
        )
        if not ins.data or not ins.data[0].get("id"):
            logger.warning("[leylek-key] request_create_failed conversation_id=%s", cid)
            return None
        conversion_row = dict(ins.data[0])
        conversion_request_id = str(conversion_row.get("id") or "").strip().lower()
        logger.info("[leylek-key] request_created conversation_id=%s request_id=%s", cid, conversion_request_id)
        logger.info("[leylek-key] conversion_status_updated request_id=%s status=accepted", conversion_request_id)

        session_row = _muhabbet_trip_create_or_get_session_for_request(conversion_row)
        logger.info("[leylek-key] trip_session_insert_ok session_id=%s request_id=%s", session_row.get("id"), conversion_request_id)
        payload = {
            "request_id": conversion_request_id,
            "conversation_id": cid,
            "session_id": session_row.get("id"),
        }
        for target in (requester_uid, target_uid):
            if target:
                await emit_socket_event_to_user(target, "muhabbet_trip_convert_confirmed", payload)
        await _emit_muhabbet_trip_session_ready(session_row)
        return session_row
    except Exception as e:
        logger.exception("[leylek-key] trip_session_create_failed conversation_id=%s pair_request_id=%s err=%s", cid, rid, e)
        return None


async def _broadcast_muhabbet_trip_session_state(session_row: dict, event_name: str = "muhabbet_trip_session_updated") -> None:
    payload = {
        "session_id": session_row.get("id"),
        "conversation_id": session_row.get("conversation_id"),
        "session": _muhabbet_trip_session_public(session_row),
    }
    await sio.emit(event_name, payload, room=muhabbet_trip_room(str(session_row.get("id") or "")))
    for uid in (
        str(session_row.get("passenger_id") or "").strip(),
        str(session_row.get("driver_id") or "").strip(),
    ):
        if uid:
            await emit_socket_event_to_user(uid, event_name, payload)


async def _emit_muhabbet_trip_force_finished(session_row: dict, response: str, responder_user_id: str | None = None) -> None:
    session_id = str(session_row.get("id") or "").strip().lower()
    requester_uid = str(session_row.get("forced_finish_requested_by_user_id") or "").strip().lower()
    payload = {
        "session_id": session_id,
        "conversation_id": session_row.get("conversation_id"),
        "requester_user_id": requester_uid,
        "responder_user_id": responder_user_id,
        "response": response,
        "score_delta": -3,
        "session": _muhabbet_trip_session_public(session_row),
    }
    await sio.emit("muhabbet_trip_force_finished", payload, room=muhabbet_trip_room(session_id))
    for target in (
        str(session_row.get("passenger_id") or "").strip(),
        str(session_row.get("driver_id") or "").strip(),
    ):
        if target:
            await emit_socket_event_to_user(target, "muhabbet_trip_force_finished", payload)


def _muhabbet_trip_force_finish_timeout_deadline_reached(row: dict, now: datetime) -> bool:
    """İstek bekleniyor ve en az 30 sn geçti (requested_at + 30) veya forced_finish_timeout_at doldu."""
    st = str(row.get("status") or "").strip().lower()
    if st in ("cancelled", "finished", "expired"):
        return False
    if row.get("forced_finish_confirmed_at"):
        return False
    if not row.get("forced_finish_requested_at"):
        return False
    req_dt = _muhabbet_trip_parse_dt(row.get("forced_finish_requested_at"))
    if not req_dt:
        return False
    due_req = req_dt + timedelta(seconds=30)
    if now >= due_req:
        return True
    to_dt = _muhabbet_trip_parse_dt(row.get("forced_finish_timeout_at"))
    return bool(to_dt and now >= to_dt)


def _muhabbet_force_finish_log(action: str, session_id: str, state: str, ms: int) -> None:
    logger.info(
        "[leylek_force_finish] %s",
        json.dumps({"action": action, "session_id": session_id, "state": state, "ms": ms}, ensure_ascii=False),
    )


async def _muhabbet_trip_force_finish_finalize_accept_or_timeout(
    session_id: str,
    row: dict,
    *,
    finish_method_val: str,
    response_val: str,
    responder_uid: Optional[str],
    emit_label: str,
) -> dict:
    """Karşı taraf onayı veya süre dolumu — oturumu kapatır. timeout_auto_accepted: ready+biniş yok → cancelled, aksi finished."""
    now_iso = datetime.now(timezone.utc).isoformat()
    requester_uid = str(row.get("forced_finish_requested_by_user_id") or "").strip().lower()
    trip_st = str(row.get("status") or "").strip().lower()
    boarded = bool(str(row.get("boarding_qr_confirmed_at") or "").strip())
    timeout_as_cancel = response_val == "timeout_auto_accepted" and trip_st == "ready" and not boarded

    if timeout_as_cancel:
        patch = {
            "status": "cancelled",
            "cancelled_at": now_iso,
            "cancelled_by_user_id": requester_uid or None,
            "cancel_reason": "forced_timeout",
            "finish_method": finish_method_val,
            "finish_score_delta": -3,
            "finish_note": f"Forced Muhabbet finish ({response_val})",
            "forced_finish_confirmed_by_user_id": responder_uid,
            "forced_finish_confirmed_at": now_iso,
            "forced_finish_other_user_response": response_val,
            "finished_at": None,
            "finished_by_user_id": None,
            "call_active": False,
            "call_caller_id": None,
            "call_started_at": None,
            "call_state": None,
            "call_channel_name": None,
            "forced_finish_started_at": None,
            "forced_finish_timeout_at": None,
            "updated_at": now_iso,
        }
    else:
        patch = {
            "status": "finished",
            "finish_method": finish_method_val,
            "finish_score_delta": -3,
            "finish_note": f"Forced Muhabbet finish ({response_val})",
            "forced_finish_confirmed_by_user_id": responder_uid,
            "forced_finish_confirmed_at": now_iso,
            "forced_finish_other_user_response": response_val,
            "finished_at": now_iso,
            "finished_by_user_id": requester_uid or (responder_uid or ""),
            "call_active": False,
            "call_caller_id": None,
            "call_started_at": None,
            "call_state": None,
            "call_channel_name": None,
            "forced_finish_started_at": None,
            "forced_finish_timeout_at": None,
            "updated_at": now_iso,
        }
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
    logger.info("[muhabbet_trip_force_finish] finalized session_id=%s response=%s terminal=%s", session_id, response_val, next_row.get("status"))
    await _emit_muhabbet_trip_force_finished(next_row, emit_label, responder_uid)
    await _broadcast_muhabbet_trip_session_state(next_row, "muhabbet_trip_session_updated")
    if timeout_as_cancel:
        _muhabbet_trip_passengers_update_for_user(
            session_id,
            str(next_row.get("passenger_id") or ""),
            {"status": "cancelled", "cancelled_at": now_iso},
        )
    else:
        _muhabbet_trip_passengers_update_for_user(
            session_id,
            str(next_row.get("passenger_id") or ""),
            {"status": "completed"},
        )
    sid_lo = str(session_id or "").strip().lower()
    try:
        await notify_trip_session_updated(sid_lo, "force_finished", responder_uid or requester_uid or "")
    except Exception as ne:
        logger.warning("[muhabbet_notify] force_finished notify failed: %s", ne)
    return next_row


async def _muhabbet_trip_force_finish_decline_resolve(session_id: str, row: dict, responder_uid: str) -> dict:
    """Onaylamıyorum — yolculuk active kalır; istek alanları temizlenir."""
    now_iso = datetime.now(timezone.utc).isoformat()
    responder_lo = str(responder_uid or "").strip().lower()
    patch = {
        "forced_finish_other_user_response": "declined",
        "forced_finish_resolved_at": now_iso,
        "forced_finish_requested_by_user_id": None,
        "forced_finish_requested_at": None,
        "forced_finish_timeout_at": None,
        "forced_finish_request_id": None,
        "forced_finish_started_at": None,
        "forced_finish_confirmed_by_user_id": None,
        "forced_finish_confirmed_at": None,
        "updated_at": now_iso,
    }
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
    logger.info("[muhabbet_trip_force_finish] declined session_id=%s by=%s", session_id, responder_lo)
    await _broadcast_muhabbet_trip_session_state(next_row, "muhabbet_trip_session_updated")
    sid_lo = str(session_id or "").strip().lower()
    try:
        await notify_trip_session_updated(sid_lo, "force_finish_declined", responder_lo)
    except Exception as ne:
        logger.warning("[muhabbet_notify] force_finish_declined notify failed: %s", ne)
    return next_row


async def _muhabbet_trip_force_finish_process_deadlines() -> int:
    """Zorla bitir — forced_finish_requested_at + 30 sn veya timeout_at geçmiş bekleyen istekleri kapatır."""
    now = datetime.now(timezone.utc)
    done = 0
    try:
        res = (
            supabase.table("muhabbet_trip_sessions")
            .select("*")
            .not_.is_("forced_finish_requested_at", "null")
            .is_("forced_finish_confirmed_at", "null")
            .execute()
        )
    except Exception as e:
        logger.warning("[muhabbet_trip_force_finish] deadline_select err=%s", e)
        return 0
    for raw in res.data or []:
        row = dict(raw)
        st = str(row.get("status") or "").strip().lower()
        if st not in ("ready", "active", "started"):
            continue
        if not _muhabbet_trip_force_finish_timeout_deadline_reached(row, now):
            continue
        sid = str(row.get("id") or "").strip().lower()
        if not sid:
            continue
        t0 = time.perf_counter()
        try:
            await _muhabbet_trip_force_finish_finalize_accept_or_timeout(
                sid,
                row,
                finish_method_val="forced_timeout",
                response_val="timeout_auto_accepted",
                responder_uid=None,
                emit_label="timeout_auto_accepted",
            )
            done += 1
            ms = int((time.perf_counter() - t0) * 1000)
            _muhabbet_force_finish_log("timeout_auto", sid, "timeout_auto_accepted", ms)
        except Exception as e:
            logger.warning("[muhabbet_trip_force_finish] deadline_finalize session_id=%s err=%s", sid[:12], e)
    return done


async def _muhabbet_trip_session_row_force_finish_timeout_if_due(session_id: str, row: dict) -> dict:
    """GET tek oturum: bu satır için süre dolumunu hemen uygula ve güncel satırı döndür."""
    sid = str(session_id or "").strip().lower()
    now = datetime.now(timezone.utc)
    if not sid or not _muhabbet_trip_force_finish_timeout_deadline_reached(row, now):
        return row
    try:
        return await _muhabbet_trip_force_finish_finalize_accept_or_timeout(
            sid,
            row,
            finish_method_val="forced_timeout",
            response_val="timeout_auto_accepted",
            responder_uid=None,
            emit_label="timeout_auto_accepted",
        )
    except Exception as e:
        logger.warning("[muhabbet_trip_force_finish] row_timeout session_id=%s err=%s", sid[:12], e)
        return row


def _muhabbet_trip_parse_dt(value):
    try:
        raw = str(value or "").strip()
        if not raw:
            return None
        out = datetime.fromisoformat(raw.replace("Z", "+00:00"))
        if out.tzinfo is None:
            out = out.replace(tzinfo=timezone.utc)
        return out
    except Exception:
        return None


async def _expire_stale_muhabbet_trip_sessions() -> list[dict]:
    """Expire unboarded Muhabbet trip sessions only; never touches normal ride state."""
    try:
        await _muhabbet_trip_force_finish_process_deadlines()
    except Exception as e:
        logger.warning("[muhabbet_trip_expiry] force_finish_deadlines err=%s", e)
    now = datetime.now(timezone.utc)
    now_iso = now.isoformat()
    stale_cutoff = now - timedelta(hours=2)
    expired_rows: list[dict] = []
    try:
        rows = (
            supabase.table("muhabbet_trip_sessions")
            .select("*")
            .eq("status", "ready")
            .is_("boarding_qr_confirmed_at", "null")
            .execute()
        )
    except Exception as e:
        logger.warning("[muhabbet_trip_expiry] select failed err=%s", e)
        return expired_rows

    for raw in rows.data or []:
        row = dict(raw)
        session_id = str(row.get("id") or "").strip().lower()
        if not session_id:
            continue
        reason = None
        expires_at = _muhabbet_trip_parse_dt(row.get("expires_at"))
        created_at = _muhabbet_trip_parse_dt(row.get("created_at"))
        if expires_at and expires_at < now:
            reason = "boarding_timeout"
        if created_at and created_at < stale_cutoff:
            reason = "stale_ready_cleanup"
        if not reason:
            continue
        # Geçerli biniş QR beklenirken oturumu süre/stale ile düşürme — yolcu onayı race'e düşmesin
        btok = str(row.get("boarding_qr_token") or "").strip()
        if btok and not _muhabbet_trip_qr_expired(row.get("boarding_qr_expires_at")):
            continue
        patch = {
            "status": "expired",
            "expired_at": now_iso,
            "expire_reason": reason,
            "boarding_qr_token": None,
            "finish_qr_token": None,
            "qr_finish_token": None,
            "call_active": False,
            "call_caller_id": None,
            "call_started_at": None,
            "call_state": None,
            "updated_at": now_iso,
        }
        try:
            upd = (
                supabase.table("muhabbet_trip_sessions")
                .update(patch)
                .eq("id", session_id)
                .eq("status", "ready")
                .execute()
            )
            next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
            expired_rows.append(next_row)
            logger.info("[muhabbet_trip_expiry] expired session_id=%s reason=%s", session_id, reason)
            _muhabbet_trip_passengers_update_for_user(
                session_id,
                str(next_row.get("passenger_id") or ""),
                {"status": "cancelled", "cancelled_at": now_iso},
            )
            await _broadcast_muhabbet_trip_session_state(next_row, "muhabbet_trip_expired")
        except Exception as e:
            logger.warning("[muhabbet_trip_expiry] expire failed session_id=%s err=%s", session_id, e)
    return expired_rows


def _muhabbet_trip_counterparty(row: dict, uid: str) -> str:
    uid_lo = str(uid or "").strip().lower()
    passenger_id = str((row or {}).get("passenger_id") or "").strip().lower()
    driver_id = str((row or {}).get("driver_id") or "").strip().lower()
    if uid_lo == passenger_id:
        return driver_id
    if uid_lo == driver_id:
        return passenger_id
    return ""


def _muhabbet_trip_qr_token() -> str:
    return secrets.token_urlsafe(9).replace("-", "").replace("_", "")[:10].upper()


def _muhabbet_trip_qr_expired(value) -> bool:
    try:
        raw = str(value or "").strip()
        if not raw:
            return True
        expires_at = datetime.fromisoformat(raw.replace("Z", "+00:00"))
        if expires_at.tzinfo is None:
            expires_at = expires_at.replace(tzinfo=timezone.utc)
        return expires_at <= datetime.now(timezone.utc)
    except Exception:
        return True


async def _muhabbet_trip_calculate_and_store_route(row: dict) -> dict:
    """Muhabbet-only route projection. Reads/writes only muhabbet_trip_sessions."""
    session_id = str((row or {}).get("id") or "").strip().lower()
    status = str((row or {}).get("status") or "").strip().lower()
    pickup = (
        _muhabbet_trip_float_or_none(row.get("pickup_lat")),
        _muhabbet_trip_float_or_none(row.get("pickup_lng")),
    )
    dropoff = (
        _muhabbet_trip_float_or_none(row.get("dropoff_lat")),
        _muhabbet_trip_float_or_none(row.get("dropoff_lng")),
    )
    driver = (
        _muhabbet_trip_float_or_none(row.get("driver_location_lat")),
        _muhabbet_trip_float_or_none(row.get("driver_location_lng")),
    )
    passenger = (
        _muhabbet_trip_float_or_none(row.get("passenger_location_lat")),
        _muhabbet_trip_float_or_none(row.get("passenger_location_lng")),
    )
    origin = None
    dest = None
    if status in ("started", "active"):
        origin = driver if driver[0] is not None and driver[1] is not None else pickup
        dest = dropoff
    else:
        # ready: sürücü → yolcu (veya pickup); gerçek rota yoksa kuş uçuşu polyline yazılmaz
        origin = driver if driver[0] is not None and driver[1] is not None else pickup
        dest = passenger if passenger[0] is not None and passenger[1] is not None else pickup
    if not origin or not dest or origin[0] is None or origin[1] is None or dest[0] is None or dest[1] is None:
        logger.warning(
            "[muhabbet_trip_route] missing coords session_id=%s status=%s origin=%s dest=%s",
            session_id,
            status,
            origin,
            dest,
        )
        return row
    try:
        route = await get_route_info(origin[0], origin[1], dest[0], dest[1])
    except Exception as e:
        logger.warning("[muhabbet_trip_route] calculate failed session_id=%s err=%s", session_id, e)
        route = None
    now_iso = datetime.now(timezone.utc).isoformat()

    def _patch_unavailable() -> dict:
        p = {
            "route_polyline": None,
            "route_source": "route_unavailable",
            "route_distance_km": None,
            "route_duration_min": None,
            "route_updated_at": now_iso,
            "updated_at": now_iso,
        }
        try:
            upd2 = supabase.table("muhabbet_trip_sessions").update(p).eq("id", session_id).execute()
            return dict(upd2.data[0]) if upd2.data else {**row, **p}
        except Exception as ue:
            logger.warning("[muhabbet_trip_route] route_unavailable patch failed session_id=%s err=%s", session_id, ue)
            return row

    if not isinstance(route, dict):
        logger.info("[muhabbet_trip_route] no route dict session_id=%s", session_id)
        return _patch_unavailable()
    src = str(route.get("source") or "").strip().lower()
    if src == "haversine_fallback":
        logger.info("[muhabbet_trip_route] haversine_fallback skipped session_id=%s", session_id)
        return _patch_unavailable()
    op = route.get("overview_polyline")
    if not isinstance(op, str) or len(op) < 2:
        logger.info("[muhabbet_trip_route] missing overview_polyline session_id=%s", session_id)
        return _patch_unavailable()
    patch = {
        "route_polyline": op,
        "route_distance_km": _muhabbet_trip_float_or_none(route.get("distance_km")),
        "route_duration_min": int(round(float(route.get("duration_min")))) if route.get("duration_min") is not None else None,
        "route_source": route.get("source") or "muhabbet_route",
        "route_updated_at": now_iso,
        "updated_at": now_iso,
    }
    patch = {k: v for k, v in patch.items() if v is not None}
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    out = dict(upd.data[0]) if upd.data else {**row, **patch}
    logger.info(
        "[muhabbet_trip_route] calculated session_id=%s distance=%s duration=%s source=%s",
        session_id,
        patch.get("route_distance_km"),
        patch.get("route_duration_min"),
        patch.get("route_source"),
    )
    return out


async def _muhabbet_trip_convert_accept_request(uid: str, conversation_id: str, request_id: str) -> dict:
    """pending isteği kabul et veya zaten accepted ise idempotent başarı + session döndür."""
    uid_lo = str(uid or "").strip().lower()
    cid = str(conversation_id or "").strip().lower()
    rid = str(request_id or "").strip().lower()
    if not uid_lo or not cid or not rid:
        return {
            "ok": False,
            "code": "bad_request",
            "detail": "conversation_id ve request_id gerekli.",
            "http_status": 400,
        }
    try:
        ctx = _muhabbet_trip_conversion_context(uid_lo, cid)
        if not ctx.get("ok"):
            return {
                "ok": False,
                "code": str(ctx.get("code") or "error"),
                "detail": str(ctx.get("detail") or "İstek kabul edilemedi."),
                "http_status": 400,
            }
        rr = (
            supabase.table("muhabbet_trip_conversion_requests")
            .select("*")
            .eq("id", rid)
            .eq("conversation_id", cid)
            .limit(1)
            .execute()
        )
        if not rr.data:
            return {"ok": False, "code": "not_found", "detail": "İstek bulunamadı.", "http_status": 404}
        row = dict(rr.data[0])
        if str(row.get("target_user_id") or "").strip().lower() != uid_lo:
            return {"ok": False, "code": "forbidden", "detail": "Sadece karşı taraf kabul edebilir.", "http_status": 403}
        if str(row.get("passenger_id") or "").strip().lower() != uid_lo:
            return {"ok": False, "code": "forbidden", "detail": "Sadece yolcu kabul edebilir.", "http_status": 403}
        st = str(row.get("status") or "").strip().lower()
        if st == "accepted":
            session_row = _muhabbet_trip_create_or_get_session_for_request(row)
            snap = _muhabbet_trip_convert_request_snapshot_for_request(uid_lo, cid, rid)
            return {
                "ok": True,
                "idempotent": True,
                "session": _muhabbet_trip_session_public(session_row),
                "trip_convert_request": snap,
            }
        if st != "pending":
            return {
                "ok": False,
                "code": "not_pending",
                "detail": "İstek artık geçerli değil.",
                "http_status": 409,
            }
        now_iso = datetime.now(timezone.utc).isoformat()
        supabase.table("muhabbet_trip_conversion_requests").update(
            {"status": "accepted", "responded_at": now_iso, "updated_at": now_iso}
        ).eq("id", rid).execute()
        row = {**row, "status": "accepted", "responded_at": now_iso, "updated_at": now_iso}
        session_row = _muhabbet_trip_create_or_get_session_for_request(row)
        logger.info("[trip_convert_accept] updated cid=%s request_id=%s target=%s", cid, rid, uid_lo)
        payload = {
            "request_id": rid,
            "conversation_id": cid,
            "session_id": session_row.get("id"),
        }
        await emit_socket_event_to_user(str(row.get("requester_user_id") or "").strip(), "muhabbet_trip_convert_confirmed", payload)
        await emit_socket_event_to_user(uid_lo, "muhabbet_trip_convert_confirmed", payload)
        await _emit_muhabbet_trip_session_ready(session_row)
        logger.info(
            "[trip_convert_confirmed] emitted cid=%s request_id=%s requester=%s target=%s",
            cid,
            rid,
            row.get("requester_user_id"),
            uid_lo,
        )
        snap = _muhabbet_trip_convert_request_snapshot_for_request(uid_lo, cid, rid)
        return {
            "ok": True,
            "idempotent": False,
            "session": _muhabbet_trip_session_public(session_row),
            "trip_convert_request": snap,
        }
    except Exception as e:
        logger.exception("_muhabbet_trip_convert_accept_request: %s", e)
        return {"ok": False, "code": "server_error", "detail": "Yanıt işlenemedi.", "http_status": 500}


async def _muhabbet_trip_convert_decline_request(uid: str, conversation_id: str, request_id: str) -> dict:
    """pending isteği reddet veya zaten declined ise idempotent başarı."""
    uid_lo = str(uid or "").strip().lower()
    cid = str(conversation_id or "").strip().lower()
    rid = str(request_id or "").strip().lower()
    if not uid_lo or not cid or not rid:
        return {"ok": False, "code": "bad_request", "detail": "conversation_id ve request_id gerekli.", "http_status": 400}
    try:
        ctx = _muhabbet_trip_conversion_context(uid_lo, cid)
        if not ctx.get("ok"):
            return {
                "ok": False,
                "code": str(ctx.get("code") or "error"),
                "detail": str(ctx.get("detail") or "İstek reddedilemedi."),
                "http_status": 400,
            }
        rr = (
            supabase.table("muhabbet_trip_conversion_requests")
            .select("*")
            .eq("id", rid)
            .eq("conversation_id", cid)
            .limit(1)
            .execute()
        )
        if not rr.data:
            return {"ok": False, "code": "not_found", "detail": "İstek bulunamadı.", "http_status": 404}
        row = dict(rr.data[0])
        if str(row.get("target_user_id") or "").strip().lower() != uid_lo:
            return {"ok": False, "code": "forbidden", "detail": "Sadece karşı taraf reddedebilir.", "http_status": 403}
        if str(row.get("passenger_id") or "").strip().lower() != uid_lo:
            return {"ok": False, "code": "forbidden", "detail": "Sadece yolcu reddedebilir.", "http_status": 403}
        st = str(row.get("status") or "").strip().lower()
        if st == "declined":
            snap = _muhabbet_trip_convert_request_snapshot_for_request(uid_lo, cid, rid)
            return {"ok": True, "idempotent": True, "trip_convert_request": snap}
        if st == "accepted":
            return {
                "ok": False,
                "code": "already_accepted",
                "detail": "İstek zaten kabul edilmiş.",
                "http_status": 409,
            }
        if st != "pending":
            return {
                "ok": False,
                "code": "not_pending",
                "detail": "İstek artık geçerli değil.",
                "http_status": 409,
            }
        now_iso = datetime.now(timezone.utc).isoformat()
        supabase.table("muhabbet_trip_conversion_requests").update(
            {"status": "declined", "responded_at": now_iso, "updated_at": now_iso}
        ).eq("id", rid).execute()
        await emit_socket_event_to_user(
            str(row.get("requester_user_id") or "").strip(),
            "muhabbet_trip_convert_declined",
            {"request_id": rid, "conversation_id": cid},
        )
        snap = _muhabbet_trip_convert_request_snapshot_for_request(uid_lo, cid, rid)
        return {"ok": True, "idempotent": False, "trip_convert_request": snap}
    except Exception as e:
        logger.warning("_muhabbet_trip_convert_decline_request: %s", e)
        return {"ok": False, "code": "server_error", "detail": "Yanıt işlenemedi.", "http_status": 500}


@sio.on("muhabbet_trip_convert_request")
async def sio_muhabbet_trip_convert_request(sid, data):
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    if not uid:
        await _emit_muhabbet_trip_conversion_error(sid, "not_registered", "Bağlantı hazırlanıyor. Lütfen tekrar deneyin.")
        return
    cid = str(data.get("conversation_id") or data.get("conversationId") or "").strip().lower()
    logger.info("[trip_convert_request] received sid=%s uid=%s cid=%s", sid, uid, cid)
    if not cid:
        await _emit_muhabbet_trip_conversion_error(sid, "bad_request", "conversation_id gerekli.")
        return
    try:
        ctx = _muhabbet_trip_conversion_context(uid, cid, require_driver_requester=True)
        if not ctx.get("ok"):
            await _emit_muhabbet_trip_conversion_error(sid, str(ctx.get("code") or "error"), str(ctx.get("detail") or "İstek oluşturulamadı."))
            return
        out = _muhabbet_trip_convert_request_ensure_pending(uid, cid, ctx)
        if not out.get("ok"):
            await _emit_muhabbet_trip_conversion_error(sid, str(out.get("code") or "error"), str(out.get("detail") or "İstek oluşturulamadı."))
            return
        request_id = str(out.get("request_id") or "").strip().lower()
        payload = {
            "request_id": request_id,
            "conversation_id": cid,
            "requester_user_id": uid,
            "target_user_id": ctx.get("target_user_id"),
            "passenger_id": ctx.get("passenger_id"),
            "driver_id": ctx.get("driver_id"),
        }
        try:
            await emit_socket_event_to_user(str(ctx.get("target_user_id") or "").strip(), "muhabbet_trip_convert_request", payload)
            await emit_socket_event_to_user(uid, "muhabbet_trip_convert_request_sent", payload)
        except Exception as e:
            logger.warning("[trip_convert_request] socket emit: %s", e)
        schedule_muhabbet_trip_convert_request_push(
            str(ctx.get("target_user_id") or "").strip(),
            cid,
            request_id,
            str(uid).strip().lower(),
        )
    except Exception as e:
        logger.exception("muhabbet_trip_convert_request: %s", e)
        await _emit_muhabbet_trip_conversion_error(sid, "server_error", "Yolculuğa çevirme isteği işlenemedi.")


@sio.on("muhabbet_trip_convert_accept")
async def sio_muhabbet_trip_convert_accept(sid, data):
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    if not uid:
        await _emit_muhabbet_trip_conversion_error(sid, "not_registered", "Bağlantı hazırlanıyor. Lütfen tekrar deneyin.")
        return
    rid = str(data.get("request_id") or data.get("requestId") or "").strip().lower()
    cid = str(data.get("conversation_id") or data.get("conversationId") or "").strip().lower()
    logger.info("[trip_convert_accept] received sid=%s uid=%s cid=%s request_id=%s", sid, uid, cid, rid)
    if not rid or not cid:
        await _emit_muhabbet_trip_conversion_error(sid, "bad_request", "request_id / conversation_id gerekli.")
        return
    try:
        result = await _muhabbet_trip_convert_accept_request(uid, cid, rid)
        if not result.get("ok"):
            await _emit_muhabbet_trip_conversion_error(
                sid,
                str(result.get("code") or "error"),
                str(result.get("detail") or "İstek kabul edilemedi."),
            )
            return
    except Exception as e:
        logger.exception("muhabbet_trip_convert_accept: %s", e)
        await _emit_muhabbet_trip_conversion_error(sid, "server_error", "Yanıt işlenemedi.")


@sio.on("muhabbet_trip_convert_decline")
async def sio_muhabbet_trip_convert_decline(sid, data):
    if not isinstance(data, dict):
        data = {}
