@api_router.get("/muhabbet/trip-sessions/active")
async def muhabbet_trip_session_active_get(
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """Latest unfinished Muhabbet trip session for the current user; never reads normal ride state."""
    uid = await _muhabbet_listing_uid(authenticated_user_id)
    uid_lo = str(uid or "").strip().lower()
    try:
        await _expire_stale_muhabbet_trip_sessions()
        passenger_rows = (
            supabase.table("muhabbet_trip_sessions")
            .select("*")
            .eq("passenger_id", uid_lo)
            .in_("status", ["ready", "started", "active"])
            .order("updated_at", desc=True)
            .limit(1)
            .execute()
        )
        driver_rows = (
            supabase.table("muhabbet_trip_sessions")
            .select("*")
            .eq("driver_id", uid_lo)
            .in_("status", ["ready", "started", "active"])
            .order("updated_at", desc=True)
            .limit(1)
            .execute()
        )
        candidates = [dict(x) for x in ((passenger_rows.data or []) + (driver_rows.data or []))]
        if not candidates:
            return {"success": True, "session": None}
        candidates.sort(key=lambda x: str(x.get("updated_at") or x.get("created_at") or ""), reverse=True)
        return {"success": True, "session": _muhabbet_trip_session_public(candidates[0])}
    except Exception as e:
        logger.warning("muhabbet_trip_session_active_get: %s", e)
        raise HTTPException(status_code=500, detail="Aktif Muhabbet yolculuğu alınamadı")


@api_router.get("/muhabbet/trip-sessions/{session_id}")
async def muhabbet_trip_session_get(
    session_id: str,
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """Leylek Teklif Sende Phase 2 session detail; never reads normal ride tags."""
    uid = await _muhabbet_listing_uid(authenticated_user_id)
    await _expire_stale_muhabbet_trip_sessions()
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    row = await _muhabbet_trip_session_row_force_finish_timeout_if_due(session_id, row)
    return {"success": True, "session": _muhabbet_trip_session_public(row)}


@api_router.get("/muhabbet/trip-sessions/{session_id}/agora-token")
async def muhabbet_trip_session_agora_token_get(
    session_id: str,
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """Muhabbet-only Agora voice token; validates muhabbet_trip_sessions membership."""
    uid = await _muhabbet_listing_uid(authenticated_user_id)
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    if str(row.get("status") or "").strip().lower() in ("cancelled", "finished"):
        raise HTTPException(status_code=409, detail="Oturum aktif değil.")
    return {"success": True, **_muhabbet_trip_call_payload(row, uid)}


def _muhabbet_trip_call_payload(session_row: dict, uid: str) -> dict:
    session_id = str(session_row.get("id") or "").strip().lower()
    channel_name = str(session_row.get("call_channel_name") or "").strip()
    if not channel_name:
        channel_name = f"muhabbet_trip_{session_id}"
    return {
        "session_id": session_id,
        "conversation_id": session_row.get("conversation_id"),
        "channel_name": channel_name,
        "agora_app_id": MUHABBET_AGORA_APP_ID,
        "agora_uid": agora_uid_from_user_id(uid),
        "agora_token": generate_muhabbet_agora_token(channel_name, user_id=uid),
    }


class _MuhabbetTripOpError(Exception):
    """Muhabbet trip iş kuralları — REST ve socket aynı mesajı kullanır."""

    __slots__ = ("socket_code", "message", "http_status")

    def __init__(self, socket_code: str, message: str, http_status: int = 400):
        super().__init__(message)
        self.socket_code = socket_code
        self.message = message
        self.http_status = http_status


def _muhabbet_trip_api_error_detail(code: str, message: str) -> dict[str, str]:
    """REST JSON { detail: { code, message } } — makine kodu + Türkçe kullanıcı mesajı."""
    return {"code": code, "message": message}


def _muhabbet_trip_boarding_qr_deep_link(session_id: str, token: str) -> str:
    from urllib.parse import urlencode

    sid = str(session_id or "").strip().lower()
    tok = str(token or "").strip().upper()
    qs = urlencode(
        {"scope": "muhabbet_trip", "mode": "boarding", "session_id": sid, "token": tok},
        encoding="utf-8",
    )
    return f"leylekmuhabbet://trip-qr?{qs}"


def _muhabbet_trip_boarding_confirm_reject_detail(status_raw: str) -> str:
    """Biniş QR confirm reddi — yalnızca terminal / bilinmeyen status."""
    st = str(status_raw or "").strip().lower()
    if st == "expired":
        return "Bu yolculuk süresi dolmuş."
    if st == "cancelled":
        return "Bu yolculuk iptal edilmiş."
    if st == "finished":
        return "Bu yolculuk tamamlanmış."
    return "Bu yolculuk biniş için uygun değil."


def _muhabbet_trip_boarding_gate_detail(status_raw: str) -> str:
    """Biniş QR (oluştur/onay) için status reddi — istemciye gösterilir."""
    st = str(status_raw or "").strip().lower()
    if st == "expired":
        return "Bu yolculuk süresi dolmuş."
    if st == "cancelled":
        return "Bu yolculuk iptal edilmiş."
    if st in ("active", "started"):
        return "Yolculuk zaten başlamış."
    if st == "finished":
        return "Bu yolculuk tamamlanmış."
    return "Bu yolculuk biniş için uygun değil."


async def _muhabbet_trip_boarding_qr_create_apply(uid: str, session_id: str) -> dict:
    """Biniş QR oluşturma — DB günceller; emit_payload döner. HTTPException | _MuhabbetTripOpError."""
    await _expire_stale_muhabbet_trip_sessions()
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    uid_lo = str(uid).strip().lower()
    if str(row.get("driver_id") or "").strip().lower() != uid_lo:
        raise _MuhabbetTripOpError("driver_required", "Biniş QR kodunu sürücü oluşturabilir.")
    st_row = str(row.get("status") or "").strip().lower()
    if st_row != "ready":
        raise _MuhabbetTripOpError("not_active", _muhabbet_trip_boarding_gate_detail(st_row))
    existing_tok = str(row.get("boarding_qr_token") or "").strip().upper()
    if existing_tok and not _muhabbet_trip_qr_expired(row.get("boarding_qr_expires_at")):
        expires_iso = str(row.get("boarding_qr_expires_at") or "")
        token = existing_tok
        qr_payload = _muhabbet_trip_boarding_qr_deep_link(session_id, token)
        emit_payload = {
            "session_id": session_id,
            "conversation_id": row.get("conversation_id"),
            "boarding_qr_token": token,
            "expires_at": expires_iso,
            "session": _muhabbet_trip_session_public(row),
        }
        logger.info(
            "[leylek_qr] %s",
            json.dumps({"action": "boarding_reuse", "session_id": session_id}, ensure_ascii=False),
        )
        return {
            "boarding_qr_token": token,
            "qr_payload": qr_payload,
            "expires_at": expires_iso,
            "emit_payload": emit_payload,
            "next_row": row,
        }
    token = _muhabbet_trip_qr_token()
    now = datetime.now(timezone.utc)
    now_iso = now.isoformat()
    expires_iso = (now + timedelta(minutes=5)).isoformat()
    patch = {
        "boarding_qr_token": token,
        "boarding_qr_created_at": now_iso,
        "boarding_qr_expires_at": expires_iso,
        "boarding_qr_confirmed_at": None,
        "boarding_qr_confirmed_by_user_id": None,
        "updated_at": now_iso,
    }
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
    qr_payload = _muhabbet_trip_boarding_qr_deep_link(session_id, token)
    emit_payload = {
        "session_id": session_id,
        "conversation_id": row.get("conversation_id"),
        "boarding_qr_token": token,
        "expires_at": expires_iso,
        "session": _muhabbet_trip_session_public(next_row),
    }
    return {
        "boarding_qr_token": token,
        "qr_payload": qr_payload,
        "expires_at": expires_iso,
        "emit_payload": emit_payload,
        "next_row": next_row,
    }


async def _muhabbet_emit_boarding_qr_created_after_apply(out: dict, session_id: str, actor_uid: str) -> None:
    """B boarding QR create (REST veya socket) sonrası oda + kullanıcılar + notify — tek davranış."""
    ep = out["emit_payload"]
    nr = out.get("next_row") or {}
    sid = str(session_id or "").strip().lower()
    trip_rm = muhabbet_trip_room(sid)
    await sio.emit("muhabbet_trip_boarding_qr_created", ep, room=trip_rm)
    for tgt in (str(nr.get("passenger_id") or "").strip(), str(nr.get("driver_id") or "").strip()):
        if tgt:
            await emit_socket_event_to_user(tgt, "muhabbet_trip_boarding_qr_created", ep)
    logger.info(
        "[socket_trip_event] %s",
        json.dumps(
            {"event": "boarding_qr_created", "session_id": sid, "targets": "trip_room+passenger+driver"},
            ensure_ascii=False,
        ),
    )
    _schedule_muhabbet_boarding_qr_passenger_push(out, sid, str(actor_uid).strip().lower())
    try:
        await notify_trip_session_updated(sid, "boarding_qr_created", actor_uid)
    except Exception as ne:
        logger.warning("[muhabbet_notify] boarding_qr_created notify failed: %s", ne)


async def _muhabbet_trip_boarding_qr_confirm_apply(uid: str, session_id: str, token: str) -> dict:
    """Biniş QR onayı — ready ise başlatır; active + zaten onaylıysa idempotent döner."""
    await _expire_stale_muhabbet_trip_sessions()
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    uid_lo = str(uid).strip().lower()
    tok = str(token or "").strip().upper()
    if not tok:
        raise _MuhabbetTripOpError("bad_request", "QR kodu gerekli.")
    if str(row.get("passenger_id") or "").strip().lower() != uid_lo:
        raise _MuhabbetTripOpError("passenger_required", "Biniş QR kodunu yolcu onaylayabilir.")
    st_row = str(row.get("status") or "").strip().lower()
    if st_row in ("cancelled", "finished", "expired"):
        raise _MuhabbetTripOpError("not_active", _muhabbet_trip_boarding_confirm_reject_detail(st_row))
    if st_row in ("active", "started"):
        if str(row.get("boarding_qr_confirmed_at") or "").strip():
            return {"session": _muhabbet_trip_session_public(row)}
    elif st_row != "ready":
        raise _MuhabbetTripOpError("not_active", _muhabbet_trip_boarding_confirm_reject_detail(st_row))

    expected = str(row.get("boarding_qr_token") or "").strip().upper()
    if not expected or not secrets.compare_digest(expected, tok):
        raise _MuhabbetTripOpError("bad_qr_token", "QR kod geçersiz.")
    if _muhabbet_trip_qr_expired(row.get("boarding_qr_expires_at")):
        raise _MuhabbetTripOpError("expired_qr_token", "QR kodun süresi doldu.")
    now_iso = datetime.now(timezone.utc).isoformat()
    patch = {
        "status": "active",
        "started_at": now_iso,
        "boarding_qr_token": None,
        "boarding_qr_confirmed_at": now_iso,
        "boarding_qr_confirmed_by_user_id": uid_lo,
        "updated_at": now_iso,
    }
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
    next_row = await _muhabbet_trip_calculate_and_store_route(next_row)
    _muhabbet_trip_passengers_update_for_user(
        session_id,
        str(row.get("passenger_id") or ""),
        {"status": "onboard", "boarded_at": now_iso},
    )
    await _broadcast_muhabbet_trip_session_state(next_row, "muhabbet_trip_started")
    return {"session": _muhabbet_trip_session_public(next_row)}


def _muhabbet_call_started_at_age_seconds(started_raw) -> float | None:
    """UTC'de call_started_at'ten bu yana geçen saniye; yoksa veya parse edilemezse None."""
    if started_raw is None:
        return None
    s = str(started_raw).strip()
    if not s:
        return None
    try:
        dt = datetime.fromisoformat(s.replace("Z", "+00:00"))
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return (datetime.now(timezone.utc) - dt).total_seconds()
    except Exception:
        return None


def _muhabbet_call_timing_log(action: str, session_id: str, ms: int, state: str) -> None:
    logger.info(
        "[leylek_call_timing] %s",
        json.dumps({"action": action, "session_id": session_id, "ms": ms, "state": state}, ensure_ascii=False),
    )


async def _muhabbet_trip_call_start_apply(uid: str, session_id: str) -> dict:
    """Sesli arama başlat — durum DB'de (REST + polling); socket yalnız bildirim."""
    sid_lo = str(session_id or "").strip().lower()
    uid_prefix = str(uid or "").strip()[:8]
    try:
        await _expire_stale_muhabbet_trip_sessions()
        row = _muhabbet_trip_session_for_member_or_403(sid_lo, uid)
        trip_st = str(row.get("status") or "").strip().lower()

        if trip_st in ("cancelled", "finished", "expired"):
            logger.warning(
                "[muhabbet_call_start_reject] session_id=%s uid=%s code=not_active status=%s call_active=%s",
                sid_lo,
                str(uid).strip().lower()[:12],
                trip_st,
                bool(row.get("call_active")),
            )
            raise _MuhabbetTripOpError(
                "not_active",
                "Bu yolculuk kapalı olduğu için sesli arama başlatılamaz.",
            )

        if trip_st not in ("ready", "active", "started"):
            logger.warning(
                "[muhabbet_call_start_reject] session_id=%s uid=%s code=bad_trip_phase status=%s",
                sid_lo,
                str(uid).strip().lower()[:12],
                trip_st,
            )
            raise _MuhabbetTripOpError(
                "bad_trip_phase",
                "Binişe hazır veya yolculuk aktifken sesli arama kullanılabilir.",
            )

        uid_lo = str(uid).strip().lower()
        passenger_id = str(row.get("passenger_id") or "").strip().lower()
        driver_id = str(row.get("driver_id") or "").strip().lower()
        target_uid = driver_id if uid_lo == passenger_id else passenger_id
        if not target_uid:
            logger.warning(
                "[muhabbet_call_start_reject] session_id=%s uid=%s code=no_counterparty status=%s",
                sid_lo,
                uid_lo[:12],
                trip_st,
            )
            raise _MuhabbetTripOpError(
                "no_counterparty",
                "Karşı taraf oturumda görünmüyor; arama başlatılamadı.",
            )

        stale_reset_detail: str | None = None
        if bool(row.get("call_active")):
            age_sec = _muhabbet_call_started_at_age_seconds(row.get("call_started_at"))
            stale = age_sec is None or age_sec > 30.0
            if stale:
                prev_caller = row.get("call_caller_id")
                now_iso = datetime.now(timezone.utc).isoformat()
                reset_patch = {
                    "call_active": False,
                    "call_caller_id": None,
                    "call_started_at": None,
                    "call_state": None,
                    "call_channel_name": None,
                    "updated_at": now_iso,
                }
                upd = supabase.table("muhabbet_trip_sessions").update(reset_patch).eq("id", sid_lo).execute()
                row = dict(upd.data[0]) if upd.data else {**row, **reset_patch}
                stale_reset_detail = "CALL_RESET_AND_RETRY"
                logger.info(
                    "[muhabbet_trip_call] stale_call_reset session_id=%s prev_caller=%s age_sec=%s",
                    sid_lo,
                    prev_caller,
                    age_sec,
                )
            else:
                cs_raw = str(row.get("call_state") or "").strip().lower()
                cs_eff = cs_raw if cs_raw else "ringing"
                if cs_eff in ("ringing", "active"):
                    caller_existing = str(row.get("call_caller_id") or "").strip().lower()
                    if caller_existing and caller_existing != uid_lo:
                        logger.warning(
                            "[muhabbet_call_start_reject] session_id=%s uid=%s code=call_in_progress_peer status=%s caller=%s",
                            sid_lo,
                            uid_lo[:12],
                            trip_st,
                            caller_existing[:12],
                        )
                        raise _MuhabbetTripOpError(
                            "call_in_progress",
                            "Karşı tarafın başlattığı bir çağrı sürüyor. Önce o çağrının bitmesini bekleyin.",
                        )
                    ch = str(row.get("call_channel_name") or "").strip() or f"muhabbet_trip_{sid_lo}"
                    payload = {
                        "session_id": sid_lo,
                        "conversation_id": row.get("conversation_id"),
                        "channel_name": ch,
                        "caller_id": caller_existing or uid_lo,
                        "target_user_id": target_uid,
                    }
                    logger.info(
                        "[leylek_call_timing] %s",
                        json.dumps(
                            {"action": "call_start_noop", "session_id": sid_lo, "state": cs_eff, "ms": 0},
                            ensure_ascii=False,
                        ),
                    )
                    return {
                        "call": payload,
                        "session": _muhabbet_trip_session_public(row),
                        "skip_notifications": True,
                    }
                logger.warning(
                    "[muhabbet_call_start_reject] session_id=%s uid=%s code=call_state_conflict status=%s call_state=%s",
                    sid_lo,
                    uid_lo[:12],
                    trip_st,
                    cs_raw or "(empty)",
                )
                raise _MuhabbetTripOpError(
                    "call_conflict",
                    "Çağrı kaydı şu an kullanılamıyor. Bir süre sonra tekrar deneyin.",
                )

        ch_name = f"muhabbet_trip_{sid_lo}"
        now_iso = datetime.now(timezone.utc).isoformat()
        patch = {
            "call_active": True,
            "call_caller_id": uid_lo,
            "call_started_at": now_iso,
            "call_state": "ringing",
            "call_channel_name": ch_name,
            "updated_at": now_iso,
        }
        upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", sid_lo).execute()
        next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
        payload = {
            "session_id": sid_lo,
            "conversation_id": row.get("conversation_id"),
            "channel_name": ch_name,
            "caller_id": uid_lo,
            "target_user_id": target_uid,
        }
        out: dict = {"call": payload, "session": _muhabbet_trip_session_public(next_row), "skip_notifications": False}
        if stale_reset_detail:
            out["detail"] = stale_reset_detail
        return out
    except _MuhabbetTripOpError:
        raise
    except HTTPException:
        raise
    except Exception as exc:
        logger.exception(
            "[muhabbet_call_start_unhandled] session_id=%s uid_prefix=%s",
            sid_lo,
            uid_prefix,
        )
        raise _MuhabbetTripOpError(
            "call_start_failed",
            "Sesli arama başlatılamadı. Lütfen bir süre sonra tekrar deneyin.",
            503,
        ) from exc


async def _muhabbet_trip_payment_method_set_apply(uid: str, session_id: str, payment_method_raw) -> dict:
    pm = _canonical_passenger_payment_method(payment_method_raw)
    if pm not in ("cash", "card"):
        raise _MuhabbetTripOpError("bad_payment_method", "Geçerli ödeme yöntemi seçin.")
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    uid_lo = str(uid).strip().lower()
    if str(row.get("passenger_id") or "").strip().lower() != uid_lo:
        raise _MuhabbetTripOpError("passenger_required", "Ödeme yöntemini yolcu seçebilir.", 403)
    if str(row.get("status") or "").strip().lower() in ("cancelled", "finished", "expired"):
        raise _MuhabbetTripOpError("not_active", "Oturum aktif değil.")
    cur_pm = str(row.get("payment_method") or "").strip().lower()
    if cur_pm == pm:
        logger.info(
            "[leylek_payment] %s",
            json.dumps({"action": "noop", "session_id": session_id, "method": pm}, ensure_ascii=False),
        )
        return row
    now_iso = datetime.now(timezone.utc).isoformat()
    patch = {
        "payment_method": pm,
        "payment_method_selected_at": now_iso,
        "updated_at": now_iso,
    }
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
    logger.info("[muhabbet_trip_payment] method_set session_id=%s method=%s", session_id, pm)
    return next_row


async def _muhabbet_trip_finish_qr_create_apply(uid: str, session_id: str) -> tuple[dict, dict]:
    await _expire_stale_muhabbet_trip_sessions()
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    uid_lo = str(uid).strip().lower()
    if str(row.get("driver_id") or "").strip().lower() != uid_lo:
        raise _MuhabbetTripOpError("driver_required", "Bitiriş QR kodunu sürücü oluşturabilir.", 403)
    if str(row.get("status") or "").strip().lower() not in ("active", "started"):
        raise _MuhabbetTripOpError("not_active", "Yolculuk başlamadan bitiriş QR oluşturulamaz.")
    existing_tok = str(row.get("finish_qr_token") or row.get("qr_finish_token") or "").strip().upper()
    exp_probe = row.get("finish_qr_expires_at") or row.get("finish_qr_created_at")
    if existing_tok and not _muhabbet_trip_qr_expired(exp_probe):
        expires_iso = str(row.get("finish_qr_expires_at") or "")
        token = existing_tok
        payload = {
            "session_id": session_id,
            "conversation_id": row.get("conversation_id"),
            "qr_finish_token": token,
            "finish_qr_token": token,
            "expires_at": expires_iso,
            "session": _muhabbet_trip_session_public(row),
        }
        logger.info(
            "[leylek_qr] %s",
            json.dumps({"action": "finish_reuse", "session_id": session_id}, ensure_ascii=False),
        )
        return payload, row
    token = _muhabbet_trip_qr_token()
    now = datetime.now(timezone.utc)
    now_iso = now.isoformat()
    expires_iso = (now + timedelta(minutes=5)).isoformat()
    patch = {
        "finish_qr_token": token,
        "finish_qr_created_at": now_iso,
        "finish_qr_expires_at": expires_iso,
        "finish_qr_confirmed_at": None,
        "finish_qr_confirmed_by_user_id": None,
        "qr_finish_token": token,
        "qr_finish_token_created_at": now_iso,
        "updated_at": now_iso,
    }
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
    payload = {
        "session_id": session_id,
        "conversation_id": row.get("conversation_id"),
        "qr_finish_token": token,
        "finish_qr_token": token,
        "expires_at": expires_iso,
        "session": _muhabbet_trip_session_public(next_row),
    }
    return payload, next_row


async def _muhabbet_trip_emit_finish_qr_created(payload: dict, session_id: str) -> None:
    sid = str(session_id or "").strip().lower()
    room = muhabbet_trip_room(sid)
    await sio.emit("muhabbet_trip_qr_created", payload, room=room)
    await sio.emit("muhabbet_trip_finish_qr_created", payload, room=room)
    sess = payload.get("session") if isinstance(payload.get("session"), dict) else {}
    for uid in (
        str(sess.get("passenger_id") or "").strip(),
        str(sess.get("driver_id") or "").strip(),
    ):
        if uid:
            await emit_socket_event_to_user(uid, "muhabbet_trip_qr_created", payload)
            await emit_socket_event_to_user(uid, "muhabbet_trip_finish_qr_created", payload)


async def _muhabbet_trip_finish_qr_confirm_apply(uid: str, session_id: str, token: str) -> dict:
    await _expire_stale_muhabbet_trip_sessions()
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    uid_lo = str(uid).strip().lower()
    tok = str(token or "").strip().upper()
    if not tok:
        raise _MuhabbetTripOpError("bad_request", "QR kodu gerekli.")
    if str(row.get("passenger_id") or "").strip().lower() != uid_lo:
        raise _MuhabbetTripOpError("passenger_required", "Bitiriş QR kodunu yolcu onaylayabilir.", 403)
    if str(row.get("status") or "").strip().lower() not in ("active", "started"):
        raise _MuhabbetTripOpError(
            "not_active",
            "Yolculuk henüz aktif değil; önce biniş QR ile başlatın veya hedef QR için bekleyin.",
        )
    expected = str(row.get("finish_qr_token") or row.get("qr_finish_token") or "").strip().upper()
    if not expected or not secrets.compare_digest(expected, tok):
        raise _MuhabbetTripOpError("bad_qr_token", "QR kod geçersiz.")
    if _muhabbet_trip_qr_expired(row.get("finish_qr_expires_at") or row.get("qr_finish_token_created_at")):
        raise _MuhabbetTripOpError("expired_qr_token", "QR kodun süresi doldu.")
    now_iso = datetime.now(timezone.utc).isoformat()
    patch = {
        "status": "finished",
        "finish_method": "qr",
        "finish_score_delta": 3,
        "finish_note": "QR confirmed clean Muhabbet finish",
        "finish_qr_token": None,
        "qr_finish_token": None,
        "finish_qr_confirmed_at": now_iso,
        "finish_qr_confirmed_by_user_id": uid_lo,
        "finished_at": now_iso,
        "finished_by_user_id": uid_lo,
        "call_active": False,
        "call_caller_id": None,
        "call_started_at": None,
        "call_state": None,
        "updated_at": now_iso,
    }
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
    logger.info("[muhabbet_trip_finish] qr_finished session_id=%s score=3", session_id)
    _muhabbet_trip_passengers_update_for_user(
        session_id,
        str(next_row.get("passenger_id") or ""),
        {"status": "completed"},
    )
    return next_row


async def _muhabbet_trip_cancel_apply(uid: str, session_id: str, reason: Optional[str]) -> tuple[dict, bool]:
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    if str(row.get("status") or "").strip().lower() in ("cancelled", "finished"):
        return row, False
    reason_clean = str(reason or "").strip()[:300] or None
    now_iso = datetime.now(timezone.utc).isoformat()
    patch = {
        "status": "cancelled",
        "cancelled_at": now_iso,
        "cancelled_by_user_id": str(uid).strip().lower(),
        "cancel_reason": reason_clean,
        "call_active": False,
        "call_caller_id": None,
        "call_started_at": None,
        "call_state": None,
        "updated_at": now_iso,
    }
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
    _muhabbet_trip_passengers_update_for_user(
        session_id,
        str(row.get("passenger_id") or ""),
        {"status": "cancelled", "cancelled_at": now_iso},
    )
    return next_row, True


async def _muhabbet_trip_force_finish_request_apply(uid: str, session_id: str) -> tuple[dict, dict, bool]:
    """İlk istek: broadcast; bekleyen duplicate: skip_broadcast=True."""
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    st = str(row.get("status") or "").strip().lower()
    if st in ("cancelled", "finished", "expired"):
        raise _MuhabbetTripOpError("not_active", "Oturum aktif değil.")
    allowed_ff = {"ready", "active", "started"}
    if st not in allowed_ff:
        raise _MuhabbetTripOpError("not_allowed", "Bu aşamada zorla bitir kullanılamaz.")
    uid_lo = str(uid).strip().lower()
    target_uid = _muhabbet_trip_counterparty(row, uid_lo)
    now = datetime.now(timezone.utc)
    now_iso = now.isoformat()

    req_at = row.get("forced_finish_requested_at")
    conf_at = row.get("forced_finish_confirmed_at")
    pending = bool(req_at) and not conf_at
    if pending:
        next_row = dict(row)
        rq_stored = str(row.get("forced_finish_requested_by_user_id") or "").strip().lower()
        cp = _muhabbet_trip_counterparty(row, rq_stored)
        payload = {
            "session_id": session_id,
            "conversation_id": row.get("conversation_id"),
            "requester_user_id": rq_stored,
            "target_user_id": cp,
            "forced_finish_request_id": row.get("forced_finish_request_id"),
            "session": _muhabbet_trip_session_public(next_row),
            "duplicate_pending": True,
        }
        return payload, next_row, True

    boarding_done = bool(row.get("boarding_qr_confirmed_at"))
    rid = str(uuid.uuid4())
    started_iso = now_iso if st == "ready" and not boarding_done else None
    timeout_iso = (now + timedelta(seconds=30)).isoformat()
    patch = {
        "forced_finish_requested_by_user_id": uid_lo,
        "forced_finish_requested_at": now_iso,
        "forced_finish_confirmed_by_user_id": None,
        "forced_finish_confirmed_at": None,
        "forced_finish_other_user_response": None,
        "forced_finish_resolved_at": None,
        "forced_finish_request_id": rid,
        "forced_finish_started_at": started_iso,
        "forced_finish_timeout_at": timeout_iso,
        "updated_at": now_iso,
    }
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
    payload = {
        "session_id": session_id,
        "conversation_id": row.get("conversation_id"),
        "requester_user_id": uid_lo,
        "target_user_id": target_uid,
        "forced_finish_request_id": rid,
        "session": _muhabbet_trip_session_public(next_row),
    }
    logger.info("[muhabbet_trip_finish] forced_requested session_id=%s by=%s", session_id, uid_lo)
    return payload, next_row, False


async def _muhabbet_trip_force_finish_request_broadcast(payload: dict, requester_uid: str, target_uid: Optional[str]) -> None:
    for target in (requester_uid, target_uid or ""):
        t = str(target or "").strip().lower()
        if t:
            await emit_socket_event_to_user(t, "muhabbet_trip_force_finish_requested", payload)
    tu = str(target_uid or "").strip().lower()
    if tu:
        sid = str(payload.get("session_id") or "").strip().lower()
        cid = str(payload.get("conversation_id") or "").strip().lower()
        rq = str(requester_uid or "").strip().lower()
        nm = _muhabbet_user_push_first_name(rq) or "Karşı taraf"
        schedule_muhabbet_leylek_push(
            tu,
            "trip",
            session_id=sid,
            conversation_id=cid,
            title="Zorla bitirme isteği",
            body=f"{nm} yanıt bekliyor • Dokunun",
            extra={"sub_action": "force_finish_request"},
        )


async def _muhabbet_trip_force_finish_respond_apply(uid: str, session_id: str, response_raw: str) -> tuple[dict, bool]:
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    st = str(row.get("status") or "").strip().lower()
    if st in ("cancelled", "finished", "expired"):
        return row, False
    uid_lo = str(uid).strip().lower()
    rq = str(row.get("forced_finish_requested_by_user_id") or "").strip().lower()
    if not rq:
        raise _MuhabbetTripOpError("no_request", "Bekleyen zorla bitir isteği yok.")
    if uid_lo == rq:
        raise _MuhabbetTripOpError("invalid", "Karşı taraf yanıt vermeli.")
    if row.get("forced_finish_confirmed_at"):
        return row, False
    rr = str(response_raw or "").strip().lower()
    response = rr if rr in ("accepted", "declined") else "declined"
    if response == "accepted":
        next_row = await _muhabbet_trip_force_finish_finalize_accept_or_timeout(
            session_id,
            row,
            finish_method_val="forced",
            response_val="accepted",
            responder_uid=uid_lo,
            emit_label="accepted",
        )
        return next_row, True
    next_row = await _muhabbet_trip_force_finish_decline_resolve(session_id, row, uid_lo)
    return next_row, False


async def _muhabbet_trip_call_response_broadcast(uid: str, session_id: str, event_name: str, user_field: str) -> dict:
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    uid_lo = str(uid).strip().lower()
    now_iso = datetime.now(timezone.utc).isoformat()
    patch: dict = {}

    if event_name == "muhabbet_trip_call_accept":
        if not bool(row.get("call_active")):
            raise _MuhabbetTripOpError("no_call", "Aktif çağrı yok.")
        caller = str(row.get("call_caller_id") or "").strip().lower()
        if not caller:
            raise _MuhabbetTripOpError("no_call", "Aktif çağrı yok.")
        if uid_lo == caller:
            raise _MuhabbetTripOpError("invalid", "Çağrıyı karşı taraf kabul etmeli.")
        cs = str(row.get("call_state") or "").strip().lower()
        if cs == "active":
            raise _MuhabbetTripOpError("invalid", "Çağrı zaten bağlı.")
        patch = {"call_state": "active", "updated_at": now_iso}
    elif event_name == "muhabbet_trip_call_decline":
        if not bool(row.get("call_active")):
            return _muhabbet_trip_session_public(row)
        patch = {
            "call_active": False,
            "call_caller_id": None,
            "call_started_at": None,
            "call_state": "ended",
            "updated_at": now_iso,
        }
    else:
        raise _MuhabbetTripOpError("bad_request", "Geçersiz çağrı olayı.")

    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}

    payload = {
        "session_id": session_id,
        "conversation_id": next_row.get("conversation_id"),
        "channel_name": f"muhabbet_trip_{session_id}",
        user_field: uid_lo,
    }
    await sio.emit(event_name, payload, room=muhabbet_trip_room(session_id))
    passenger_id = str(next_row.get("passenger_id") or "").strip()
    driver_id = str(next_row.get("driver_id") or "").strip()
    for target_uid in (passenger_id, driver_id):
        if target_uid:
            await emit_socket_event_to_user(target_uid, event_name, payload)

    return _muhabbet_trip_session_public(next_row)


async def _muhabbet_trip_call_end_broadcast(uid: str, session_id: str) -> dict:
    row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
    uid_lo = str(uid).strip().lower()
    now_iso = datetime.now(timezone.utc).isoformat()
    if not bool(row.get("call_active")):
        return _muhabbet_trip_session_public(row)
    patch = {
        "call_active": False,
        "call_caller_id": None,
        "call_started_at": None,
        "call_state": "ended",
        "updated_at": now_iso,
    }
    upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
    next_row = dict(upd.data[0]) if upd.data else {**row, **patch}

    payload = {
        "session_id": session_id,
        "conversation_id": next_row.get("conversation_id"),
        "channel_name": f"muhabbet_trip_{session_id}",
        "ended_by_user_id": uid_lo,
    }
    await sio.emit("muhabbet_trip_call_end", payload, room=muhabbet_trip_room(session_id))
    passenger_id = str(next_row.get("passenger_id") or "").strip()
    driver_id = str(next_row.get("driver_id") or "").strip()
    for target_uid in (passenger_id, driver_id):
        if target_uid:
            await emit_socket_event_to_user(target_uid, "muhabbet_trip_call_end", payload)

    return _muhabbet_trip_session_public(next_row)


