@sio.on("muhabbet_trip_join")
@sio.on("join_muhabbet_trip_session")
async def sio_join_muhabbet_trip_session(sid, data):
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    session_id = str(data.get("session_id") or data.get("sessionId") or "").strip().lower()
    if not uid:
        await sio.emit(
            "muhabbet_trip_error",
            {"code": "not_registered", "message": "Bağlantı hazırlanıyor, lütfen tekrar deneyin."},
            room=sid,
        )
        return
    if not session_id:
        await sio.emit(
            "muhabbet_trip_error",
            {"code": "bad_request", "message": "Yolculuk oturumu henüz hazır değil."},
            room=sid,
        )
        return
    try:
        await _expire_stale_muhabbet_trip_sessions()
        row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
        room = muhabbet_trip_room(session_id)
        await sio.enter_room(sid, room)
        joined_payload = {"session_id": session_id, "room": room, "session": _muhabbet_trip_session_public(row)}
        await sio.emit("muhabbet_trip_joined", joined_payload, room=sid)
        logger.info(
            "[socket_join] %s",
            json.dumps(
                {"event": "muhabbet_trip_join", "user_id": uid, "sid": sid, "room": room, "session_id": session_id},
                ensure_ascii=False,
            ),
        )
    except HTTPException as e:
        await sio.emit("muhabbet_trip_error", {"code": "forbidden", "message": str(e.detail)}, room=sid)
    except Exception as e:
        logger.warning("join_muhabbet_trip_session: %s", e)
        await sio.emit("muhabbet_trip_error", {"code": "server_error", "message": "Oturuma katılamadı."}, room=sid)


