@sio.on("muhabbet_trip_call_accept")
async def sio_muhabbet_trip_call_accept(sid, data):
    await _muhabbet_trip_forward_call_response(sid, data, "muhabbet_trip_call_accept", "accepted_by_user_id")


@sio.on("muhabbet_trip_call_decline")
async def sio_muhabbet_trip_call_decline(sid, data):
    await _muhabbet_trip_forward_call_response(sid, data, "muhabbet_trip_call_decline", "declined_by_user_id")


@sio.on("muhabbet_trip_call_join")
async def sio_muhabbet_trip_call_join(sid, data):
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    session_id = str(data.get("session_id") or data.get("sessionId") or "").strip().lower()
    if not uid or not session_id:
        return
    try:
        row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
        private_payload = {
            **_muhabbet_trip_call_payload(row, uid),
            "joined_user_id": str(uid).strip().lower(),
        }
        public_payload = {
            "session_id": session_id,
            "conversation_id": row.get("conversation_id"),
            "channel_name": f"muhabbet_trip_{session_id}",
            "joined_user_id": str(uid).strip().lower(),
        }
        await sio.emit("muhabbet_trip_call_join", public_payload, room=muhabbet_trip_room(session_id))
        await sio.emit("muhabbet_trip_call_join", private_payload, room=sid)
    except HTTPException as e:
        await sio.emit("muhabbet_trip_error", {"code": "forbidden", "message": str(e.detail)}, room=sid)
    except Exception as e:
        logger.warning("muhabbet_trip_call_join: %s", e)


@sio.on("muhabbet_trip_call_end")
async def sio_muhabbet_trip_call_end(sid, data):
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    session_id = str(data.get("session_id") or data.get("sessionId") or "").strip().lower()
    if not uid or not session_id:
        return
    try:
        await _muhabbet_trip_call_end_broadcast(uid, session_id)
    except HTTPException as e:
        await sio.emit("muhabbet_trip_error", {"code": "forbidden", "message": str(e.detail)}, room=sid)
    except Exception as e:
        logger.warning("muhabbet_trip_call_end: %s", e)


@sio.on("muhabbet_trip_trust_request")
async def sio_muhabbet_trip_trust_request(sid, data):
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    session_id = str(data.get("session_id") or data.get("sessionId") or "").strip().lower()
    if not uid or not session_id:
        return
    try:
        row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
        if str(row.get("status") or "").strip().lower() in ("cancelled", "finished"):
            await sio.emit("muhabbet_trip_error", {"code": "not_active", "message": "Oturum aktif değil."}, room=sid)
            return
        passenger_id = str(row.get("passenger_id") or "").strip().lower()
        driver_id = str(row.get("driver_id") or "").strip().lower()
        uid_lo = str(uid).strip().lower()
        target_uid = driver_id if uid_lo == passenger_id else passenger_id
        now_iso = datetime.now(timezone.utc).isoformat()
        patch = {
            "trust_status": "requested",
            "trust_requested_by_user_id": uid_lo,
            "trust_resolved_by_user_id": None,
            "trust_requested_at": now_iso,
            "trust_resolved_at": None,
            "updated_at": now_iso,
        }
        upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
        next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
        payload = {
            "session_id": session_id,
            "conversation_id": row.get("conversation_id"),
            "requester_user_id": uid_lo,
            "target_user_id": target_uid,
            "status": "requested",
            "session": _muhabbet_trip_session_public(next_row),
        }
        for target in (uid_lo, target_uid):
            if target:
                await emit_socket_event_to_user(target, "muhabbet_trip_trust_requested", payload)
    except HTTPException as e:
        await sio.emit("muhabbet_trip_error", {"code": "forbidden", "message": str(e.detail)}, room=sid)
    except Exception as e:
        logger.warning("muhabbet_trip_trust_request: %s", e)


async def _muhabbet_trip_trust_resolve(sid, data, status: str):
    if not isinstance(data, dict):
        data = {}
    uid = _muhabbet_socket_uid_from_sid(sid)
    session_id = str(data.get("session_id") or data.get("sessionId") or "").strip().lower()
    if not uid or not session_id:
        return
    try:
        row = _muhabbet_trip_session_for_member_or_403(session_id, uid)
        uid_lo = str(uid).strip().lower()
        requester_uid = str(row.get("trust_requested_by_user_id") or "").strip().lower()
        if not requester_uid or requester_uid == uid_lo or str(row.get("trust_status") or "").strip().lower() != "requested":
            await sio.emit("muhabbet_trip_error", {"code": "bad_trust_state", "message": "Güven isteği yanıtlanamaz."}, room=sid)
            return
        now_iso = datetime.now(timezone.utc).isoformat()
        patch = {
            "trust_status": status,
            "trust_resolved_by_user_id": uid_lo,
            "trust_resolved_at": now_iso,
            "updated_at": now_iso,
        }
        upd = supabase.table("muhabbet_trip_sessions").update(patch).eq("id", session_id).execute()
        next_row = dict(upd.data[0]) if upd.data else {**row, **patch}
        payload = {
            "session_id": session_id,
            "conversation_id": row.get("conversation_id"),
            "requester_user_id": requester_uid,
            "target_user_id": uid_lo,
            "status": status,
            "session": _muhabbet_trip_session_public(next_row),
        }
        await sio.emit("muhabbet_trip_trust_resolved", payload, room=muhabbet_trip_room(session_id))
        for target in (requester_uid, uid_lo):
            if target:
                await emit_socket_event_to_user(target, "muhabbet_trip_trust_resolved", payload)
    except HTTPException as e:
        await sio.emit("muhabbet_trip_error", {"code": "forbidden", "message": str(e.detail)}, room=sid)
    except Exception as e:
        logger.warning("muhabbet_trip_trust_%s: %s", status, e)


@sio.on("muhabbet_trip_trust_accept")
async def sio_muhabbet_trip_trust_accept(sid, data):
    await _muhabbet_trip_trust_resolve(sid, data, "accepted")


@sio.on("muhabbet_trip_trust_decline")
async def sio_muhabbet_trip_trust_decline(sid, data):
    await _muhabbet_trip_trust_resolve(sid, data, "declined")


@api_router.get("/muhabbet/conversations/me")
async def muhabbet_conversations_me(
    limit: int = 50,
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """Oturum kullanıcısının sohbetleri: karşı taraf, ilan özet, istek status; created_at desc."""
    try:
        uid = await _muhabbet_listing_uid(authenticated_user_id)
        logger.info(
            "conversations_me debug auth_sub=%s resolved_uid=%s",
            str(authenticated_user_id)[:96],
            str(uid)[:96],
        )
        logger.info("[muhabbet-conversations] uid=%s", uid)
        if not uid:
            raise HTTPException(status_code=401, detail="Geçersiz kullanıcı")
        lim = max(1, min(int(limit or 50), 100))
        hidden_ids: set = set()
        try:
            hid = (
                supabase.table("user_conversation_hides")
                .select("conversation_id")
                .eq("user_id", uid)
                .execute()
            )
            for h in hid.data or []:
                cid_h = str(h.get("conversation_id") or "").strip().lower()
                if cid_h:
                    hidden_ids.add(cid_h)
        except Exception as e:
            logger.warning("conversations_me hides: %s", e)
        fetch_lim = min(100, lim + len(hidden_ids))
        res, read_cols_ok = _muhabbet_conversations_me_query(uid, fetch_lim)
        logger.info("conversations_me debug query_rows=%s uid=%s", len(res.data or []), str(uid)[:96])
        logger.info("[muhabbet-conversations] query_rows=%s", len(res.data or []))
        logger.info("[muhabbet-conversations] hidden_count=%s", len(hidden_ids))
        raw_convs = [c for c in (res.data or []) if str(c.get("id") or "").strip().lower() not in hidden_ids]
        raw_cids = [str(c["id"]).strip().lower() for c in raw_convs if c.get("id")]
        logger.info("[muhabbet-conversations] raw_cids=%s", len(raw_cids))
        if not raw_cids:
            return {"success": True, "conversations": [], "count": 0}
        mreq = (
            supabase.table("listing_match_requests")
            .select("conversation_id, listing_id, status, created_at")
            .in_("conversation_id", raw_cids)
            .execute()
        )
        rows = list(mreq.data or [])
        rows.sort(key=lambda x: (str(x.get("created_at") or "")), reverse=True)
        lmr_by_cid: dict = {}
        for r in rows:
            cid0 = str(r.get("conversation_id") or "").strip().lower()
            if not cid0 or cid0 in lmr_by_cid:
                continue
            lmr_by_cid[cid0] = r
        last_map = _muhabbet_last_message_map_for_user(raw_cids, uid)
        logger.info("[muhabbet-conversations] last_message_map_count=%s", len(last_map))
        filtered_convs: list = []
        for c in raw_convs:
            cid0 = str(c.get("id") or "").strip().lower()
            if not cid0:
                continue
            reason = ""
            st = str((lmr_by_cid.get(cid0) or {}).get("status") or "").strip().lower()
            if st == "accepted":
                reason = "accepted_listing_match_request"
            elif str(c.get("last_message") or "").strip():
                reason = "conversation_last_message"
            elif c.get("last_message_at"):
                reason = "conversation_last_message_at"
            else:
                ms = str(c.get("match_source") or "").strip().lower()
                if c.get("matched_at") and ms in ("leylek_key", "leylek_key_inchat", "listing_match"):
                    reason = "listing_or_leylek_match"
                elif last_map.get(cid0):
                    reason = "visible_muhabbet_message"
            if reason:
                logger.info("[muhabbet-conversations] include conversation_id=%s reason=%s", cid0, reason)
                filtered_convs.append(c)
                continue
        logger.info("[muhabbet-conversations] filtered_count=%s", len(filtered_convs))
        convs: list = filtered_convs[:lim]
        if not convs:
            return {"success": True, "conversations": [], "count": 0}
        cids = [str(c["id"]).strip().lower() for c in convs if c.get("id")]
        lid_list: list = []
        for lmr in lmr_by_cid.values():
            lidv = lmr.get("listing_id")
            if lidv:
                lid_list.append(str(lidv).strip().lower())
        lid_list = list(dict.fromkeys(lid_list))
        listings_map: dict = {}
        if lid_list:
            lr = supabase.table("ride_listings").select("id, from_text, to_text").in_("id", lid_list).execute()
            for x in lr.data or []:
                if x.get("id"):
                    listings_map[str(x["id"]).strip().lower()] = x
        other_uids: list = []
        for c in convs:
            a_n = str(c.get("user_a") or "").strip().lower()
            o = str(c.get("user_b") or "").strip() if a_n == uid else str(c.get("user_a") or "").strip()
            if o and o not in other_uids:
                other_uids.append(o)
        name_map: dict = _muhabbet_listing_name_map_for_ids(other_uids) if other_uids else {}
        role_by_uid: dict = {}
        photo_by_uid: dict = {}
        kyc_driver_by_uid: dict = {}
        if other_uids:
            try:
                rr = supabase.table("users").select("id, role, profile_photo, driver_details").in_("id", other_uids).execute()
                for x in rr.data or []:
                    if x.get("id"):
                        xid = str(x["id"]).strip().lower()
                        role_by_uid[xid] = str(x.get("role") or "").strip().lower()
                        photo_by_uid[xid] = x.get("profile_photo")
                        ddx = _driver_details_as_dict(x)
                        kyc_driver_by_uid[xid] = (
                            str(ddx.get("kyc_status") or "").strip().lower() == "approved"
                            and bool(ddx.get("is_verified", False))
                        )
            except Exception as e:
                logger.warning("conversations_me roles: %s", e)
        role_map_full: dict = {}
        try:
            rr2 = supabase.table("users").select("id, role").in_("id", [uid] + other_uids).execute()
            for x in rr2.data or []:
                if x.get("id"):
                    role_map_full[str(x["id"]).strip().lower()] = str(x.get("role") or "").strip().lower()
        except Exception as e:
            logger.warning("conversations_me role_map_full: %s", e)
        out: list = []
        for c in convs:
            conv_id = str(c.get("id") or "").strip().lower()
            a = str(c.get("user_a") or "")
            b = str(c.get("user_b") or "")
            a_n = a.strip().lower()
            other = b.strip() if a_n == uid else a.strip()
            lmr0 = lmr_by_cid.get(conv_id) if conv_id else None
            lidk = (str(lmr0.get("listing_id") or "").strip().lower() if lmr0 and lmr0.get("listing_id") else None)
            li = listings_map.get(lidk) if lidk else None
            sem = _muhabbet_match_semantic_roles_for_conversation(conv_id)
            my_role = sem.get(uid) if sem else role_map_full.get(uid)
            other_role = sem.get(other.lower()) if sem else role_map_full.get(other.lower())
            lm = last_map.get(conv_id) or {}
            conv_last_body = str(c.get("last_message") or "").strip() or None
            conv_last_at = c.get("last_message_at")
            last_body = lm.get("last_message_body") or conv_last_body
            last_at = lm.get("last_message_at") or conv_last_at
            try:
                unread_n = _muhabbet_unread_count_for_member(
                    dict(c), uid, read_columns_available=read_cols_ok
                )
            except Exception as ue:
                logger.warning("conversations_me unread_count cid=%s err=%s", conv_id, ue)
                unread_n = 0
            out.append(
                {
                    "id": conv_id,
                    "conversation_id": conv_id,
                    "user_a": a,
                    "user_b": b,
                    "other_user_id": other,
                    "other_user_name": name_map.get((other or "").lower()) or "Leylek kullanıcısı",
                    "other_user_public_name": name_map.get((other or "").lower()) or "Leylek kullanıcısı",
                    "other_user_role": other_role or role_by_uid.get((other or "").strip().lower()),
                    "other_user_role_label": "Sürücü"
                    if bool(kyc_driver_by_uid.get((other or "").strip().lower()))
                    else "Yolcu",
                    "other_user_profile_photo_url": photo_by_uid.get((other or "").strip().lower()),
                    "my_role": my_role,
                    "other_role": other_role,
                    "listing_id": lidk,
                    "from_text": (li or {}).get("from_text"),
                    "to_text": (li or {}).get("to_text"),
                    "request_status": (lmr0 or {}).get("status"),
                    "match_source": c.get("match_source"),
                    "matched_at": c.get("matched_at"),
                    "created_at": c.get("created_at"),
                    "last_message_body": last_body,
                    "last_message": conv_last_body,
                    "last_message_at": last_at,
                    "unread_count": unread_n,
                }
            )
        logger.info("[muhabbet-conversations] returned_count=%s", len(out))
        return {"success": True, "conversations": out, "count": len(out)}
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"muhabbet_conversations_me: {e}")
        raise HTTPException(status_code=500, detail=str(e)) from e


@api_router.get("/muhabbet/conversations/{conversation_id}/messages")
async def muhabbet_conversation_messages_get(
    conversation_id: str,
    limit: int = 100,
    offset: int = 0,
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """Son mesajlar (varsayılan 200): muhabbet_messages; expires_at ve delete-for-me filtreli."""
    try:
        uid = await _muhabbet_listing_uid(authenticated_user_id)
        c_row = _muhabbet_conversation_for_member_or_403(conversation_id, uid)
        lim = max(1, min(int(limit or 100), 200))
        off = max(0, int(offset or 0))
        cid = str(conversation_id).strip().lower()
        a = str(c_row.get("user_a") or "").strip().lower()
        b = str(c_row.get("user_b") or "").strip().lower()
        other_uid = b if a == uid else a
        role_map: dict = {}
        photo_map: dict = {}
        kyc_map: dict = {}
        try:
            ur = (
                supabase.table("users")
                .select("id, role, profile_photo, driver_details")
                .in_("id", [uid, other_uid])
                .execute()
            )
            for x in ur.data or []:
                if x.get("id"):
                    xid = str(x["id"]).strip().lower()
                    role_map[xid] = str(x.get("role") or "").strip().lower()
                    photo_map[xid] = x.get("profile_photo")
                    ddx = _driver_details_as_dict(x)
                    kyc_map[xid] = (
                        str(ddx.get("kyc_status") or "").strip().lower() == "approved"
                        and bool(ddx.get("is_verified", False))
                    )
        except Exception as e:
            logger.warning("messages_get roles: %s", e)
        sem = _muhabbet_match_semantic_roles_for_conversation(cid)
        if sem:
            my_r = sem.get(uid)
            oth_r = sem.get(other_uid)
        else:
            my_r = role_map.get(uid)
            oth_r = role_map.get(other_uid)
        other_name_map = _muhabbet_listing_name_map_for_ids([other_uid]) if other_uid else {}
        other_public_name = other_name_map.get((other_uid or "").strip().lower()) or "Leylek kullanıcısı"
        ms = str(c_row.get("match_source") or "").strip().lower()
        matched_at = c_row.get("matched_at")
        leylek_matched = bool(matched_at) and ms in ("leylek_key", "leylek_key_inchat")
        listing_match_ok = bool(matched_at) and ms == "listing_match"
        trip_convert_eligible = leylek_matched or listing_match_ok
        if not trip_convert_eligible:
            try:
                lac = (
                    supabase.table("listing_match_requests")
                    .select("id")
                    .eq("conversation_id", cid)
                    .eq("status", "accepted")
                    .limit(1)
                    .execute()
                )
                trip_convert_eligible = bool(lac.data)
            except Exception as e:
                logger.warning("messages_get trip_convert_eligible listing lookup: %s", e)
        pending_pair_request_id = None
        pending_pair_request_direction = None
        pending_pair_request_requester_id = None
        pending_pair_request_target_id = None
        try:
            # Leylek Teklif Sende only: hydrate in-chat match state from Muhabbet tables.
            # This must not create/update normal ride tags, dispatch, route, QR, Guven Al, or Agora state.
            pr = (
                supabase.table("muhabbet_leylek_pair_requests")
                .select("id, initiator_user_id, target_user_id")
                .eq("conversation_id", cid)
                .eq("status", "pending")
                .or_(f"initiator_user_id.eq.{uid},target_user_id.eq.{uid}")
                .order("created_at", desc=True)
                .limit(1)
                .execute()
            )
            if pr.data:
                prow = dict(pr.data[0])
                req_uid = str(prow.get("initiator_user_id") or "").strip().lower()
                tgt_uid = str(prow.get("target_user_id") or "").strip().lower()
                if uid in (req_uid, tgt_uid):
                    pending_pair_request_id = str(prow.get("id") or "").strip().lower() or None
                    pending_pair_request_direction = "outgoing" if req_uid == uid else "incoming"
                    pending_pair_request_requester_id = req_uid or None
                    pending_pair_request_target_id = tgt_uid or None
        except Exception as e:
            logger.warning("messages_get pending_pair_request: %s", e)
        trip_convert_request_payload = None
        try:
            tcr_res = (
                supabase.table("muhabbet_trip_conversion_requests")
                .select("id,status,requester_user_id,target_user_id,created_at,updated_at")
                .eq("conversation_id", cid)
                .order("updated_at", desc=True)
                .limit(1)
                .execute()
            )
            if tcr_res.data:
                trow = dict(tcr_res.data[0])
                rid_tc = str(trow.get("id") or "").strip().lower()
                st_tc = str(trow.get("status") or "").strip().lower()
                req_tc = str(trow.get("requester_user_id") or "").strip().lower()
                tgt_tc = str(trow.get("target_user_id") or "").strip().lower()
                uid_lo_ctx = str(uid).strip().lower()
                session_id_tc = None
                trip_id_tc = None
                if rid_tc:
                    try:
                        tsr = (
                            supabase.table("muhabbet_trip_sessions")
                            .select("id")
                            .eq("conversion_request_id", rid_tc)
                            .limit(1)
                            .execute()
                        )
                        if tsr.data:
                            sid_tc = str(tsr.data[0].get("id") or "").strip().lower()
                            if sid_tc:
                                session_id_tc = sid_tc
                                trip_id_tc = sid_tc
                    except Exception as e_ts:
                        logger.warning("messages_get trip_convert_request session lookup: %s", e_ts)
                trip_convert_request_payload = {
                    "id": rid_tc,
                    "status": st_tc,
                    "requester_user_id": req_tc,
                    "target_user_id": tgt_tc,
                    "created_at": trow.get("created_at"),
                    "updated_at": trow.get("updated_at"),
                    "session_id": session_id_tc,
                    "trip_id": trip_id_tc,
                    "is_requester": req_tc == uid_lo_ctx,
                    "is_target": tgt_tc == uid_lo_ctx,
                    "pending": st_tc == "pending",
                    "accepted": st_tc == "accepted",
                    "declined": st_tc == "declined",
                }
        except Exception as e:
            logger.warning("messages_get trip_convert_request: %s", e)
        ctx = {
            "other_user_id": other_uid,
            "other_user_public_name": other_public_name,
            "public_name": other_public_name,
            "name": other_public_name,
            "other_user_profile_photo_url": photo_map.get(other_uid),
            "other_user_role_label": "Sürücü" if bool(kyc_map.get(other_uid)) else "Yolcu",
            "my_role": my_r,
            "other_role": oth_r,
            "matched_via_leylek_key": leylek_matched,
            "trip_convert_eligible": trip_convert_eligible,
            "matched_at": matched_at,
            "match_source": ms or None,
            "pending_pair_request_id": pending_pair_request_id,
            "pending_pair_request_direction": pending_pair_request_direction,
            "pending_pair_request_requester_id": pending_pair_request_requester_id,
            "pending_pair_request_target_id": pending_pair_request_target_id,
            "trip_convert_request": trip_convert_request_payload,
            "ephemeral_chat": False,
        }
        msgs = _muhabbet_messages_fetch_visible_for_user(cid, uid, lim)
        _ = off  # API uyumluluğu; sayfalama ileride genişletilebilir
        return {
            "success": True,
            "messages": msgs,
            "limit": lim,
            "offset": off,
            "context": ctx,
        }
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"muhabbet_conversation_messages_get: {e}")
        raise HTTPException(status_code=500, detail=str(e)) from e


@api_router.post("/muhabbet/conversations/{conversation_id}/messages")
async def muhabbet_conversation_messages_post(
    conversation_id: str,
    msg: MuhabbetChatMessageCreateBody,
    authenticated_user_id: str = Depends(get_authenticated_user_id_from_authorization),
):
    """Muhabbet-only REST fallback: DB insert socket sid'e bağlı değildir."""
    try:
        uid = await _muhabbet_listing_uid(authenticated_user_id)
        cid = str(conversation_id or "").strip().lower()
        crow = _muhabbet_conversation_for_member_or_403(cid, uid)
        text = str(msg.body or msg.text or "").strip()
        if not text:
            raise HTTPException(status_code=400, detail="Mesaj boş olamaz")
        if len(text) > 2000:
            raise HTTPException(status_code=400, detail="Mesaj en fazla 2000 karakter olabilir")
        raw_mid = msg.message_id or msg.client_message_id
        parsed_mid, mid_err = _muhabbet_parse_client_message_id(raw_mid)
        if mid_err:
            raise HTTPException(status_code=400, detail=mid_err)
        msg_id = parsed_mid or str(uuid.uuid4())
        now_iso = datetime.now(timezone.utc).isoformat()
        db_ok, db_err = _muhabbet_messages_try_insert(cid, msg_id, uid, text, now_iso)
        if not db_ok:
            logger.warning("[muhabbet_rest_send] db_insert_failed cid=%s message_id=%s err=%s", cid, msg_id, db_err[:300] if db_err else "")
            raise HTTPException(status_code=500, detail="Mesaj gönderilemedi. Lütfen tekrar deneyin.")
        row = _muhabbet_message_fetch_by_id(cid, msg_id) or {
            "id": msg_id,
            "conversation_id": cid,
            "sender_id": uid,
            "text": text,
            "created_at": now_iso,
        }
        created_iso = row.get("created_at") or now_iso
        await _muhabbet_publish_message_after_persist(
            cid=cid,
            msg_id=msg_id,
            sender_id=uid,
            text=str(row.get("text") or text),
            created_iso=created_iso,
            conversation_row=crow,
        )
        try:
            await notify_conversation_updated(cid, "message_created", uid)
        except Exception as ne:
            logger.warning("[muhabbet_notify] message_created notify failed: %s", ne)
        return {
            "success": True,
            "message": {
                "id": msg_id,
                "body": row.get("text") or text,
                "sender_user_id": uid,
                "created_at": created_iso,
            },
        }
    except HTTPException:
        raise
    except Exception as e:
        logger.error(f"muhabbet_conversation_messages_post: {e}")
        raise HTTPException(status_code=500, detail=str(e)) from e


